INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(1, 'Пока приезжий господин осматривал свою комнату, внесены были его пожитки.', 'Пока приезжий господин осматривал свою комнату, внесены были его пожитки: прежде всего чемодан из белой кожи, несколько поистасканный, показывавший, что был не в первый раз в дороге.', ' Чемодан внесли кучер Селифан, низенький человек в тулупчике, и лакей Петрушка, малый лет тридцати, в просторном подержанном сюртуке, как видно с барского плеча, малый немного суровый на взгляд, с очень крупными губами и носом. Вслед за чемоданом внесен был небольшой ларчик красного дерева с штучными выкладками из карельской березы, сапожные колодки и завернутая в синюю бумагу жареная курица. Когда все это было внесено, кучер Селифан отправился на конюшню возиться около лошадей, а лакей Петрушка стал устроиваться в маленькой передней, очень темной конурке, куда уже успел притащить свою шинель и вместе с нею какой-то свой собственный запах, который был сообщен и принесенному вслед за тем мешку с разным лакейским туалетом. В этой конурке он приладил к стене узенькую трехногую кровать, накрыв ее небольшим подобием тюфяка, убитым и плоским, как блин, и, может быть, так же замаслившимся, как блин, который удалось ему вытребовать у хозяина гостиницы.', '203.jpg', 51, '2026-04-10 16:28:42'),
(2, 'Покамест слуги управлялись и возились, господин отправился в общую залу.', 'Покамест слуги управлялись и возились, господин отправился в общую залу.', ' Какие бывают эти общие залы — всякий проезжающий знает очень хорошо: те же стены, выкрашенные масляной краской, потемневшие вверху от трубочного дыма и залосненные снизу спинами разных проезжающих, а еще более туземными купеческими, ибо купцы по торговым дням приходили сюда сам-шест и сам-сём испивать свою известную пару чаю; тот же закопченный потолок; та же копченая люстра со множеством висящих стеклышек, которые прыгали и звенели всякий раз, когда половой бегал по истертым клеенкам, помахивая бойко подносом, на котором сидела такая же бездна чайных чашек, как птиц на морском берегу; те же картины во всю стену, писанные масляными красками, — словом, все то же, что и везде; только и разницы, что на одной картине изображена была нимфа с такими огромными грудями, какие читатель, верно, никогда не видывал. Подобная игра природы, впрочем, случается на разных исторических картинах, неизвестно в какое время, откуда и кем привезенных к нам в Россию, иной раз даже нашими вельможами, любителями искусств, накупившими их в Италии по совету везших их курьеров. Господин скинул с себя картуз и размотал с шеи шерстяную, радужных цветов косынку, какую женатым приготовляет своими руками супруга, снабжая приличными наставлениями, как закутываться, а холостым — наверное не могу сказать, кто делает, бог их знает, я никогда не носил таких косынок. Размотавши косынку, господин велел подать себе обед. Покамест ему подавались разные обычные в трактирах блюда, как-то: щи с слоеным пирожком, нарочно сберегаемым для проезжающих в течение нескольких неделей, мозги с горошком, сосиски с капустой, пулярка жареная, огурец соленый и вечный слоеный сладкий пирожок, всегда готовый к услугам; покамест ему все это подавалось и разогретое, и просто холодное, он заставил слугу, или полового, рассказывать всякий вздор — о том, кто содержал прежде трактир и кто теперь, и много ли дает дохода, и большой ли подлец их хозяин; на что половой, по обыкновению, отвечал: «О, большой, сударь, мошенник».', '201.jpg', 10, '2026-04-01 13:58:55'),
(3, 'Поехали отыскивать Маниловку.', 'Поехали отыскивать Маниловку. Проехавши две версты, встретили поворот на проселочную дорогу, но уже и две, и три, и четыре версты, кажется, сделали, а каменного дома в два этажа все еще не было видно.', ' Тут Чичиков вспомнил, что если приятель приглашает к себе в деревню за пятнадцать верст, то значит, что к ней есть верных тридцать. Деревня Маниловка немногих могла заманить своим местоположением. Дом господский стоял одиночкой на юру, то есть на возвышении, открытом всем ветрам, какие только вздумается подуть; покатость горы, на которой он стоял, была одета подстриженным дерном. На ней были разбросаны по-английски две-три клумбы с кустами сиреней и желтых акаций; пять-шесть берез небольшими купами кое-где возносили свои мелколистные жиденькие вершины. Под двумя из них видна была беседка с плоским зеленым куполом, деревянными голубыми колоннами и надписью: «Храм уединенного размышления»; пониже пруд, покрытый зеленью, что, впрочем, не в диковинку в аглицких садах русских помещиков. У подошвы этого возвышения, и частию по самому скату, темнели вдоль и поперек серенькие бревенчатые избы, которые герой наш, неизвестно по каким причинам, в ту ж минуту принялся считать и насчитал более двухсот; нигде между ними растущего деревца или какой-нибудь зелени; везде глядело только одно бревно. Вид оживляли две бабы, которые, картинно подобравши платья и подтыкавшись со всех сторон, брели по колени в пруде, влача за два деревянные кляча изорванный бредень, где видны были два запутавшиеся рака и блестела попавшаяся плотва; бабы, казались, были между собою в ссоре и за что-то перебранивались. Поодаль в стороне темнел каким-то скучно-синеватым цветом сосновый лес. Даже самая погода весьма кстати прислужилась: день был не то ясный, не то мрачный, а какого-то светло-серого цвета, какой бывает только на старых мундирах гарнизонных солдат, этого, впрочем, мирного войска, но отчасти нетрезвого по воскресным дням. Для пополнения картины не было недостатка в петухе, предвозвестнике переменчивой погоды, который, несмотря на то что голова продолблена была до самого мозгу носами других петухов по известным делам волокитства, горланил очень громко и даже похлопывал крыльями, обдерганными, как старые рогожки.', '100.jpg', 39, '2026-03-24 12:25:24'),
(4, 'О себе приезжий, как казалось, избегал много говорить, если же говорил.', 'О себе приезжий, как казалось, избегал много говорить, если же говорил, то какими-то общими местами, с заметною скромностию, и разговор его в таких случаях принимал несколько книжные обороты, что он незначащий червь мира сего и не достоин того.', 'О себе приезжий, как казалось, избегал много говорить; если же говорил, то какими-то общими местами, с заметною скромностию, и разговор его в таких случаях принимал несколько книжные обороты: что он незначащий червь мира сего и не достоин того, чтобы много о нем заботились, что испытал много на веку своем, претерпел на службе за правду, имел много неприятелей, покушавшихся даже на жизнь его, и что теперь, желая успокоиться, ищет избрать наконец место для жительства, и что, прибывши в этот город, почел за непременный долг засвидетельствовать свое почтение первым его сановникам. Вот все, что узнали в городе об этом новом лице, которое очень скоро не преминуло показать себя на губернаторской вечеринке. Приготовление к этой вечеринке заняло с лишком два часа времени, и здесь в приезжем оказалась такая внимательность к туалету, какой даже не везде видывано. После небольшого послеобеденного сна он приказал подать умыться и чрезвычайно долго тер мылом обе щеки, подперши их извнутри языком; потом, взявши с плеча трактирного слуги полотенце, вытер им со всех сторон полное свое лицо, начав из-за ушей и фыркнув прежде раза два в самое лицо трактирного слуги. Потом надел перед зеркалом манишку, выщипнул вылезшие из носу два волоска и непосредственно за тем очутился во фраке брусничного цвета с искрой. Таким образом одевшись, покатился он в собственном экипаже по бесконечно широким улицам, озаренным тощим освещением из кое-где мелькавших океан. Впрочем, губернаторский дом был так освещен, хоть бы и для бала; коляска с фонарями, перед подъездом два жандарма, форейторские крики вдали — словом, всё как нужно. Вошедши в зал, Чичиков должен был на минуту зажмурить глаза, потому что блеск от свечей, ламп и дамских платьев был страшный. Все было залито светом.', '202.jpg', 42, '2026-04-09 14:56:03'),
(5, 'Манилов совершенно растерялся.', 'Манилов совершенно растерялся. Он чувствовал, что ему нужно что-то сделать, предложить вопрос, а какой вопрос — черт его знает. Кончил он наконец тем, что выпустил опять дым, но только уже не ртом, а чрез носовые ноздри.', '.', '002.jpg', 0, '2026-04-08 13:20:01'),
(6, 'Но Чичиков сказал просто, что подобное предприятие, или негоция.', 'Но Чичиков сказал просто, что подобное предприятие, или негоция, никак не будет несоответствующею гражданским постановлениям и дальнейшим видам России, а чрез минуту потом прибавил, что казна получит даже выгоды, ибо получит законные пошлины.', '.', '101.jpg', 37, '2026-04-01 07:00:21'),
(7, 'Такое мнение, весьма лестное для гостя, составилось о нем в городе.', 'Такое мнение, весьма лестное для гостя, составилось о нем в городе, и оно держалось до тех пор, покамест одно странное свойство гостя и предприятие, или, как говорят в провинциях, пассаж, о котором читатель скоро узнает.', 'Такое мнение, весьма лестное для гостя, составилось о нем в городе, и оно держалось до тех пор, покамест одно странное свойство гостя и предприятие, или, как говорят в провинциях, пассаж, о котором читатель скоро узнает, не привело в совершенное недоумение почти всего города.', '302.jpg', 16, '2026-04-02 12:40:36'),
(8, 'Чичиков согласился с этим совершенно, прибавивши.', 'Чичиков согласился с этим совершенно, прибавивши, что ничего не может быть приятнее, как жить в уединенье.', 'Чичиков согласился с этим совершенно, прибавивши, что ничего не может быть приятнее, как жить в уединенье.', '103.jpg', 21, '2026-03-24 11:11:44'),
(9, 'В большом зале генерал-губернаторского дома собралось все чиновное сословие.', 'В большом зале генерал-губернаторского дома собралось все чиновное сословие города, начиная от губернатора до титулярного советника, правители канцелярий и дел, советники, асессоры, Кислоедов, Красноносов, Самосвистов, не бравшие, бравшие.', 'В большом зале генерал-губернаторского дома собралось все чиновное сословие города, начиная от губернатора до титулярного советника: правители канцелярий и дел, советники, асессоры, Кислоедов, Красноносов, Самосвистов, не бравшие, бравшие, кривившие душой, полукривившие и вовсе не кривившие, — все ожидало с некоторым не совсем спокойным ожиданием генеральского выхода. Князь вышел ни мрачный, ни ясный: взор его был тверд, так же как и шаг… Все чиновное собрание поклонилось, многие — в пояс.', '203.jpg', 17, '2026-03-18 06:18:16'),
(10, '— Маниловка.', '— Маниловка! а как проедешь еще одну версту, так вот тебе, то есть, так прямо направо.', '.', '301.jpg', 58, '2026-03-23 12:51:07'),
(11, '— Направо, — сказал мужик.', '— Направо, — сказал мужик. — Это будет тебе дорога в Маниловку; а Заманиловки никакой нет. Она зовется так, то есть ее прозвание Маниловка, а Заманиловки тут вовсе нет.', ' Там прямо на горе увидишь дом, каменный, в два этажа, господский дом, в котором, то есть, живет сам господин. Вот это тебе и есть Маниловка, а Заманиловки совсем нет никакой здесь и не было.', '101.jpg', 17, '2026-03-17 11:35:42'),
(12, 'Поехали отыскивать Маниловку.', 'Поехали отыскивать Маниловку. Проехавши две версты, встретили поворот на проселочную дорогу, но уже и две, и три, и четыре версты, кажется, сделали, а каменного дома в два этажа все еще не было видно.', ' Тут Чичиков вспомнил, что если приятель приглашает к себе в деревню за пятнадцать верст, то значит, что к ней есть верных тридцать. Деревня Маниловка немногих могла заманить своим местоположением. Дом господский стоял одиночкой на юру, то есть на возвышении, открытом всем ветрам, какие только вздумается подуть; покатость горы, на которой он стоял, была одета подстриженным дерном. На ней были разбросаны по-английски две-три клумбы с кустами сиреней и желтых акаций; пять-шесть берез небольшими купами кое-где возносили свои мелколистные жиденькие вершины. Под двумя из них видна была беседка с плоским зеленым куполом, деревянными голубыми колоннами и надписью: «Храм уединенного размышления»; пониже пруд, покрытый зеленью, что, впрочем, не в диковинку в аглицких садах русских помещиков. У подошвы этого возвышения, и частию по самому скату, темнели вдоль и поперек серенькие бревенчатые избы, которые герой наш, неизвестно по каким причинам, в ту ж минуту принялся считать и насчитал более двухсот; нигде между ними растущего деревца или какой-нибудь зелени; везде глядело только одно бревно. Вид оживляли две бабы, которые, картинно подобравши платья и подтыкавшись со всех сторон, брели по колени в пруде, влача за два деревянные кляча изорванный бредень, где видны были два запутавшиеся рака и блестела попавшаяся плотва; бабы, казались, были между собою в ссоре и за что-то перебранивались. Поодаль в стороне темнел каким-то скучно-синеватым цветом сосновый лес. Даже самая погода весьма кстати прислужилась: день был не то ясный, не то мрачный, а какого-то светло-серого цвета, какой бывает только на старых мундирах гарнизонных солдат, этого, впрочем, мирного войска, но отчасти нетрезвого по воскресным дням. Для пополнения картины не было недостатка в петухе, предвозвестнике переменчивой погоды, который, несмотря на то что голова продолблена была до самого мозгу носами других петухов по известным делам волокитства, горланил очень громко и даже похлопывал крыльями, обдерганными, как старые рогожки.', '201.jpg', 18, '2026-03-07 05:30:40'),
(13, '— Павел Иванович! — вскричал он наконец, когда Чичиков вылезал из брички.', '— Павел Иванович! — вскричал он наконец, когда Чичиков вылезал из брички.', ' — Насилу вы таки нас вспомнили.', '102.jpg', 24, '2026-02-24 23:31:45'),
(14, 'Оба приятеля очень крепко поцеловались, и Манилов увел своего гостя в комнату.', 'Оба приятеля очень крепко поцеловались, и Манилов увел своего гостя в комнату.', ' Хотя время, в продолжение которого они будут проходить сени, переднюю и столовую, несколько коротковато, но попробуем, не успеем ли как-нибудь им воспользоваться и сказать кое-что о хозяине дома. Но тут автор должен признаться, что подобное предприятие очень трудно. Гораздо легче изображать характеры большого размера: там просто бросай краски со всей руки на полотно, черные палящие глаза нависшие брови, перерезанный морщиною лоб, перекинутый через плечо черный или алый, как огонь, плащ — и портрет готов; но вот эти все господа, которых много на свете, которые с вида очень похожи между собою, а между тем как приглядишься, увидишь много самых неуловимых особенностей, — эти господа страшно трудны для портретов. Тут придется сильно напрягать внимание, пока заставишь перед собою выступить все тонкие, почти невидимые черты, и вообще далеко придется углублять уже изощренный в науке выпытывания взгляд.', '302.jpg', 12, '2026-02-20 20:00:42'),
(15, '— Сделайте милость, не беспокойтесь так для меня, я пройду после.', '— Сделайте милость, не беспокойтесь так для меня, я пройду после, — говорил Чичиков.', '.', '201.jpg', 27, '2026-03-17 09:00:47'),
(16, '— Нет, Павел Иванович, нет, вы гость, — говорил Манилов.', '— Нет, Павел Иванович, нет, вы гость, — говорил Манилов, показывая ему рукою на дверь.', '.', '101.jpg', 0, '2026-03-11 05:05:58'),
(17, '— Не затрудняйтесь, пожалуйста, не затрудняйтесь.', '— Не затрудняйтесь, пожалуйста, не затрудняйтесь. Пожалуйста, проходите, — говорил Чичиков.', '.', '103.jpg', 21, '2026-03-06 03:52:34'),
(18, '— Нет уж извините, не допущу пройти позади такому приятному.', '— Нет уж извините, не допущу пройти позади такому приятному, образованному гостю.', '.', '100.jpg', 0, '2026-02-27 22:11:51'),
(19, '— Позвольте мне вам представить жену мою, — сказал Манилов.', '— Позвольте мне вам представить жену мою, — сказал Манилов.', ' — Душенька! Павел Иванович.', '002.jpg', 20, '2026-02-22 19:34:26'),
(20, 'Чичиков, точно, увидел даму, которую он совершенно было не приметил.', 'Чичиков, точно, увидел даму, которую он совершенно было не приметил, раскланиваясь в дверях с Маниловым Она была недурна, одета к лицу.', ' На ней хорошо сидел матерчатый шелковый капот бледного цвета; тонкая небольшая кисть руки ее что-то бросила поспешно на стол и сжала батистовый платок с вышитыми уголками. Она поднялась с дивана, на котором сидела; Чичиков не без удовольствия подошел к ее ручке. Манилова проговорила, несколько даже картавя, что он очень обрадовал их своим приездом и что муж ее не проходило дня, чтобы не вспоминал о нем.', '201.jpg', 53, '2026-02-17 19:00:39'),
(21, '— Да, — примолвил Манилов, — уж она, бывало, все спрашивает меня.', '— Да, — примолвил Манилов, — уж она, бывало, все спрашивает меня: «Да что же твой приятель не едет?» — «Погоди, душенька, приедет». А вот вы наконец и удостоили нас своим посещением.', ' Уж такое, право.', '101.jpg', 40, '2026-02-10 12:54:37'),
(22, 'Чичиков, услышавши, что дело уже дошло до именин сердца.', 'Чичиков, услышавши, что дело уже дошло до именин сердца, несколько даже смутился и отвечал скромно, что ни громкого имени не имеет, ни даже ранга заметного.', '.', '203.jpg', 18, '2026-02-05 08:55:01'),
(23, '— Вы всё имеете, — прервал Манилов с такою же приятною улыбкою, — всё имеете.', '— Вы всё имеете, — прервал Манилов с такою же приятною улыбкою, — всё имеете, даже еще более.', '.', '101.jpg', 4, '2026-01-30 08:30:42'),
(24, '— Как вам показался наш город? — примолвила Манилова.', '— Как вам показался наш город? — примолвила Манилова.', ' — Приятно ли провели там время.', '002.jpg', 52, '2026-01-24 05:09:13'),
(25, '— Очень хороший город, прекрасный город, — отвечал Чичиков.', '— Очень хороший город, прекрасный город, — отвечал Чичиков, — и время провел очень приятно: общество самое обходительное.', '.', '202.jpg', 16, '2026-01-15 01:51:22'),
(26, '— Не правда ли, что препочтеннейший и прелюбезнейший человек.', '— Не правда ли, что препочтеннейший и прелюбезнейший человек? — прибавил Манилов.', '.', '202.jpg', 9, '2026-01-12 00:28:46'),
(27, '— Совершенная правда, — сказал Чичиков, — препочтеннейший человек.', '— Совершенная правда, — сказал Чичиков, — препочтеннейший человек. И как он вошел в свою должность, как понимает ее! Нужно желать побольше таких людей.', '.', '201.jpg', 50, '2026-01-01 22:15:06'),
(28, '— Как он может этак, знаете, принять всякого.', '— Как он может этак, знаете, принять всякого, блюсти деликатность в своих поступках, — присовокупил Манилов с улыбкою и от удовольствия почти совсем зажмурил глаза, как кот, у которого слегка пощекотали за ушами пальцем.', '.', '101.jpg', 57, '2025-12-22 21:53:25'),
(29, '— Очень обходительный и приятный человек, — продолжал Чичиков.', '— Очень обходительный и приятный человек, — продолжал Чичиков, — и какой искусник! я даже никак не мог предполагать этого. Как хорошо вышивает разные домашние узоры! Он мне показывал своей работы кошелек: редкая дама может так искусно вышить.', '.', '102.jpg', 12, '2025-12-13 21:31:24'),
(30, '— А вице-губернатор, не правда ли, какой милый человек.', '— А вице-губернатор, не правда ли, какой милый человек? — сказал Манилов, опять несколько прищурив глаза.', '.', '101.jpg', 29, '2025-12-07 20:07:26'),
(31, '— Ну, позвольте, а как вам показался полицеймейстер.', '— Ну, позвольте, а как вам показался полицеймейстер? Не правда ли, что очень приятный человек.', '— Ну, позвольте, а как вам показался полицеймейстер? Не правда ли, что очень приятный человек.', '002.jpg', 31, '2025-12-05 18:41:20'),
(32, '— Чрезвычайно приятный, и какой умный, какой начитанный человек.', '— Чрезвычайно приятный, и какой умный, какой начитанный человек! Мы у него проиграли в вист вместе с прокурором и председателем палаты до самых поздних петухов; очень, очень достойный человек.', '.', '002.jpg', 22, '2025-11-26 17:48:23'),
(33, '— Ну, а какого вы мнения о жене полицеймейстера? — прибавила Манилова.', '— Ну, а какого вы мнения о жене полицеймейстера? — прибавила Манилова.', ' — Не правда ли, прелюбезная женщина.', '002.jpg', 17, '2025-11-22 15:30:57'),
(34, 'Засим не пропустили председателя палаты.', 'Засим не пропустили председателя палаты, почтмейстера и таким образом перебрали почти всех чиновников города, которые все оказались самыми достойными людьми.', '.', '201.jpg', 11, '2025-11-16 11:57:02'),
(35, '— Вы всегда в деревне проводите время.', '— Вы всегда в деревне проводите время? — сделал наконец, в свою очередь, вопрос Чичиков.', '.', '301.jpg', 0, '2025-11-14 11:41:22'),
(36, '— Больше в деревне, — отвечал Манилов.', '— Больше в деревне, — отвечал Манилов. — впрочем, приезжаем в город для того только, чтобы увидеться с образованными людьми. Одичаешь, знаете, будешь все время жить взаперти.', '.', '002.jpg', 16, '2025-11-11 09:43:51'),
(37, '— Конечно, — продолжал Манилов, — другое дело, если бы соседство было хорошее.', '— Конечно, — продолжал Манилов, — другое дело, если бы соседство было хорошее, если бы, например, такой человек, с которым бы в некотором роде можно было поговорить о любезности, о хорошем обращении, следить какую-нибудь этакую науку.', '— Конечно, — продолжал Манилов, — другое дело, если бы соседство было хорошее, если бы, например, такой человек, с которым бы в некотором роде можно было поговорить о любезности, о хорошем обращении, следить какую-нибудь этакую науку, чтобы этак расшевелило душу, дало бы, так сказать, паренье этакое… — Здесь он еще что-то хотел выразить, но, заметивши, что несколько зарапортовался, ковырнул только рукою в воздухе и продолжал: — Тогда, конечно, деревня и уединение имели бы очень много приятностей. Но решительно нет никого… Вот только иногда почитаешь «Сын отечества».', '202.jpg', 47, '2025-11-04 08:42:14'),
(38, 'Чичиков согласился с этим совершенно, прибавивши.', 'Чичиков согласился с этим совершенно, прибавивши, что ничего не может быть приятнее, как жить в уединенье.', 'Чичиков согласился с этим совершенно, прибавивши, что ничего не может быть приятнее, как жить в уединенье.', '102.jpg', 35, '2025-10-26 04:25:42'),
(39, '— Но знаете ли, — прибавил Манилов, — все если нет друга.', '— Но знаете ли, — прибавил Манилов, — все если нет друга.', '— Но знаете ли, — прибавил Манилов, — все если нет друга.', '002.jpg', 9, '2025-10-16 23:07:37'),
(40, '— О, это справедливо, это совершенно справедливо! — прервал Чичиков.', '— О, это справедливо, это совершенно справедливо! — прервал Чичиков. — Что все сокровища тогда в мире! «Не имей денег, имей хороших людей для обращения», сказал один мудрец.', '.', '102.jpg', 19, '2025-10-07 16:58:49'),
(41, '— И знаете, Павел Иванович.', '— И знаете, Павел Иванович! — сказал Манилов, явя в лице своем выражение не только сладкое, но даже приторное, подобное той микстуре, которую ловкий светский доктор засластил немилосердно, воображая ею обрадовать пациента.', ' — Тогда чувствуешь какое-то, в некотором роде, духовное наслаждение… Вот как, например, теперь, когда случай мне доставил счастие, можно сказать образцовое.', '201.jpg', 21, '2025-10-06 16:00:59'),
(42, '— Помилуйте, что ж за приятный разговор?..', '— Помилуйте, что ж за приятный разговор?.. Ничтожный человек, и больше ничего, — отвечал Чичиков.', '.', '100.jpg', 45, '2025-09-30 13:39:43'),
(43, '— О.', '— О! Павел Иванович, позвольте мне быть откровенным: я бы с радостию отдал половину всего моего состояния, чтобы иметь часть тех достоинств, которые имеете вы!..', '.', '101.jpg', 42, '2025-09-24 09:39:41'),
(44, 'Неизвестно, до чего бы дошло взаимное излияние чувств обоих приятелей.', 'Неизвестно, до чего бы дошло взаимное излияние чувств обоих приятелей, если бы вошедший слуга не доложил, что кушанье готово.', '.', '202.jpg', 4, '2025-09-19 08:28:01'),
(45, '— Прошу покорнейше, — сказал Манилов.', '— Прошу покорнейше, — сказал Манилов. — Вы извините, если у нас нет такого обеда, какой на паркетах и в столицах, у нас просто, по русскому обычаю, щи, но от чистого сердца. Покорнейше прошу.', '.', '103.jpg', 34, '2025-09-12 03:54:38'),
(46, '— Фемистоклюс.', '— Фемистоклюс! — сказал Манилов, обратившись к старшему, который старался освободить свой подбородок, завязанный лакеем в салфетку.', '.', '100.jpg', 3, '2026-03-17 04:45:02'),
(47, 'Чичиков поднял несколько бровь, услышав такое отчасти греческое имя, которому.', 'Чичиков поднял несколько бровь, услышав такое отчасти греческое имя, которому, неизвестно почему, Манилов дал окончание на «юс», но постарался тот же час привесть лицо в обыкновенное положение.', '.', '100.jpg', 33, '2026-03-08 02:02:30'),
(48, 'Здесь учитель обратил все внимание на Фемистоклюса и казалось.', 'Здесь учитель обратил все внимание на Фемистоклюса и казалось, хотел ему вскочить в глаза, но наконец совершенно успокоился и кивнул головою, когда Фемистоклюс сказал: «Париж».', '.', '101.jpg', 22, '2026-02-28 23:40:13'),
(49, '— Умница, душенька! — сказал на это Чичиков.', '— Умница, душенька! — сказал на это Чичиков. — Скажите, однако ж… — продолжал он, обратившись тут же с некоторым видом изумления к Маниловым, — в такие лета и уже такие сведения! Я должен вам сказать, что в этом ребенке будут большие способности.', '.', '202.jpg', 60, '2026-02-25 18:53:07'),
(50, '— О, вы еще не знаете его, — отвечал Манилов.', '— О, вы еще не знаете его, — отвечал Манилов, у него чрезвычайно много остроумия.', ' Вот меньшой, Алкид, тот не так быстр, а этот сейчас, если что-нибудь встретит, букашку, козявку, так уж у него вдруг глазенки и забегают; побежит за ней следом и тотчас обратит внимание. Я его прочу по дипломатической части.', '202.jpg', 12, '2026-02-18 18:11:43'),
(51, 'В это время стоявший позади лакей утер посланнику нос, и очень хорошо сделал.', 'В это время стоявший позади лакей утер посланнику нос, и очень хорошо сделал, иначе бы канула в суп препорядочная посторонняя капля.', ' Разговор начался за столом об удовольствии спокойной жизни, прерываемый замечаниями хозяйки о городском театре и об актерах. Учитель очень внимательно глядел на разговаривающих и, как только замечал, что они были готовы усмехнуться, в ту же минуту открывал рот и смеялся с усердием. Вероятно, он был человек признательный и хотел заплатить этим хозяину за хорошее обращение. Один раз, впрочем, лицо его приняло суровый вид, и он строго застучал по столу, устремив глаза на сидевших насупротив его детей. Это было у места, потому что Фемистоклюс укусил за ухо Алкида, и Алкид, зажмурив глаза и открыв рот, готов был зарыдать самым жалким образом, но, почувствовав, что за это легко можно было лишиться блюда, привел рот в прежнее положение и начал со слезами грызть баранью кость, от которой у него обе щеки лоснились жиром. Хозяйка очень часто обращалась к Чичикову с словами: «Вы ничего не кушаете, вы очень мало взяли». На что Чичиков отвечал всякий раз: «Покорнейше благодарю, я сыт, приятный разговор лучше всякого блюда».', '100.jpg', 47, '2026-02-15 15:09:55'),
(52, 'Уже встали из-за стола.', 'Уже встали из-за стола.', ' Манилов был доволен чрезвычайно и, поддерживая рукою спину своего гостя, готовился таким образом препроводить его в гостиную, как вдруг гость объявил с весьма значительным видом, что он намерен с ним поговорить об одном очень нужном деле.', '301.jpg', 24, '2026-02-10 13:16:43'),
(53, '— В таком случае позвольте мне вас попросить в мой кабинет.', '— В таком случае позвольте мне вас попросить в мой кабинет, — сказал Манилов и повел в небольшую комнату, обращенную окном на синевший лес. — Вот мой уголок, — сказал Манилов.', '.', '103.jpg', 59, '2026-02-09 11:26:44'),
(54, 'Комната была, точно, не без приятности.', 'Комната была, точно, не без приятности, стены были выкрашены какой-то голубенькой краской вроде серенькой, четыре стула, одно кресло, стол, на котором лежала книжка с заложенною закладкою, о которой мы уже имели случай упомянуть.', 'Комната была, точно, не без приятности: стены были выкрашены какой-то голубенькой краской вроде серенькой, четыре стула, одно кресло, стол, на котором лежала книжка с заложенною закладкою, о которой мы уже имели случай упомянуть, несколько исписанных бумаг, но больше всего было табаку. Он был в разных видах: в картузах и в табачнице, и, наконец, насыпан был просто кучею на столе. На своих окнах тоже помещены были горки выбитой из трубки золы, расставленные не без старания очень красивыми рядками. Заметно было, что это иногда доставляло хозяину препровождение времени.', '102.jpg', 42, '2026-02-08 07:29:21'),
(55, '— Позвольте вас попросить расположиться в этих креслах, — сказал Манилов.', '— Позвольте вас попросить расположиться в этих креслах, — сказал Манилов. — Здесь вам будет попокойнее.', '.', '301.jpg', 53, '2026-02-05 05:43:35'),
(56, '— Позвольте вам этого не позволить, — сказал Манилов с улыбкою.', '— Позвольте вам этого не позволить, — сказал Манилов с улыбкою. — Это кресло у меня уж ассигновано для гостя: ради или не ради, но должны сесть.', '.', '203.jpg', 49, '2026-02-03 02:07:22'),
(57, '— Позвольте мне вам заметить, что это предубеждение.', '— Позвольте мне вам заметить, что это предубеждение. Я полагаю даже, что курить трубку гораздо здоровее, нежели нюхать табак.', ' В нашем полку был поручик, прекраснейший и образованнейший человек, который не выпускал изо рта трубки не только за столом, но даже, с позволения сказать, во всех прочих местах. И вот ему теперь уже сорок с лишком лет, но, благодари бога, до сих пор так здоров, как нельзя лучше.', '103.jpg', 44, '2026-02-01 23:05:49'),
(58, 'Чичиков заметил, что это, точно, случается и что натуре находится много вещей.', 'Чичиков заметил, что это, точно, случается и что натуре находится много вещей, неизъяснимых даже для обширного ума.', '.', '100.jpg', 41, '2026-01-27 22:26:19'),
(59, '— Но позвольте прежде одну просьбу… — проговорил он голосом.', '— Но позвольте прежде одну просьбу… — проговорил он голосом, в котором отдалось какое-то странное или почти странное выражение, и вслед за тем неизвестно чего оглянулся назад.', ' — Как давно вы изволили подавать ревизскую сказку.', '100.jpg', 35, '2026-01-26 16:36:57'),
(60, '— А не могу знать; об этом, я полагаю, нужно спросить приказчика.', '— А не могу знать; об этом, я полагаю, нужно спросить приказчика. Эй, человек! позови приказчика, он должен быть сегодня здесь.', '.', '201.jpg', 7, '2026-01-17 13:45:46'),
(61, 'Приказчик явился.', 'Приказчик явился.', ' Это был человек лет под сорок, бривший бороду, ходивший в сюртуке и, по-видимому, проводивший очень покойную жизнь, потому что лицо его глядело какою-то пухлою полнотою, а желтоватый цвет кожи и маленькие глаза показывали, что он знал слишком хорошо, что такое пуховики и перины. Можно было видеть тотчас, что он совершил свое поприще, как совершают его все господские приказчики: был прежде просто грамотным мальчишкой в доме, потом женился на какой-нибудь Агашке-ключнице, барыниной фаворитке, сделался сам ключником, а там и приказчиком. А сделавшись приказчиком, поступал, разумеется, как все приказчики: водился и кумился с теми, которые на деревне были побогаче, подбавлял на тягла победнее, проснувшись в девятом часу утра, поджидал самовара и пил чай.', '203.jpg', 30, '2026-01-09 12:58:39'),
(62, '— Послушай, любезный.', '— Послушай, любезный! сколько у нас умерло крестьян с тех пор, как подавали ревизию.', '— Послушай, любезный! сколько у нас умерло крестьян с тех пор, как подавали ревизию.', '102.jpg', 40, '2025-12-30 12:18:45'),
(63, '— Да как сколько.', '— Да как сколько? Многие умирали с тех пор, — сказал приказчик и при этом икнул, заслонив рот слегка рукою, наподобие щитка.', '.', '101.jpg', 43, '2025-12-26 10:10:00'),
(64, '— Да, признаюсь, а сам так думал, — подхватил Манилов, — именно.', '— Да, признаюсь, а сам так думал, — подхватил Манилов, — именно, очень многие умирали! — Тут он оборотился к Чичикову и прибавил еще: — Точно, очень многие.', '.', '302.jpg', 12, '2025-12-16 07:05:57'),
(65, '— Да, именно, — сказал Манилов, обратясь к Чичикову, — я тоже предполагал.', '— Да, именно, — сказал Манилов, обратясь к Чичикову, — я тоже предполагал, большая смертность; совсем неизвестно, сколько умерло.', '.', '201.jpg', 49, '2025-12-14 05:08:07'),
(66, '— Ты, пожалуйста, их перечти, — сказал Чичиков.', '— Ты, пожалуйста, их перечти, — сказал Чичиков, — и сделай подробный реестрик всех поименно.', '.', '203.jpg', 60, '2025-12-06 00:01:18'),
(67, 'Этот вопрос, казалось, затруднил гостя.', 'Этот вопрос, казалось, затруднил гостя, в лице его показалось какое-то напряженное выражение, от которого он даже покраснел, — напряжение что-то выразить, не совсем покорное словам.', ' И в самом деле, Манилов наконец услышал такие странные и необыкновенные вещи, какие еще никогда не слыхали человеческие уши.', '002.jpg', 58, '2025-11-25 19:06:19'),
(68, '— Вы спрашиваете, для каких причин.', '— Вы спрашиваете, для каких причин? причины вот какие: я хотел бы купить крестьян… — сказал Чичиков, заикнулся и не кончил речи.', '.', '101.jpg', 52, '2025-11-20 14:20:21'),
(69, '— Но позвольте спросить вас, — сказал Манилов, — как желаете вы купить крестьян.', '— Но позвольте спросить вас, — сказал Манилов, — как желаете вы купить крестьян: с землею или просто на вывод, то есть без земли.', '— Но позвольте спросить вас, — сказал Манилов, — как желаете вы купить крестьян: с землею или просто на вывод, то есть без земли.', '302.jpg', 36, '2025-11-12 08:33:58'),
(70, '— Нет, я не то чтобы совершенно крестьян, — сказал Чичиков.', '— Нет, я не то чтобы совершенно крестьян, — сказал Чичиков.', '— Нет, я не то чтобы совершенно крестьян, — сказал Чичиков.', '203.jpg', 8, '2025-11-05 07:13:15'),
(71, '— Я полагаю приобресть мертвых, которые, впрочем.', '— Я полагаю приобресть мертвых, которые, впрочем, значились бы по ревизии как живые, — сказал Чичиков.', '.', '301.jpg', 57, '2025-10-30 06:46:43'),
(72, 'Манилов выронил тут же чубук с трубкою на пол и как разинул рот.', 'Манилов выронил тут же чубук с трубкою на пол и как разинул рот, так и остался с разинутым ртом в продолжение нескольких минут.', ' Оба приятеля, рассуждавшие о приятностях дружеской жизни, остались недвижимы, вперя друг в друга глаза, как те портреты, которые вешались в старину один против другого по обеим сторонам зеркала. Наконец Манилов поднял трубку с чубуком и поглядел снизу ему в лицо, стараясь высмотреть, не видно ли какой усмешки на губах его, не пошутил ли он; но ничего не было видно такого, напротив, лицо даже казалось степеннее обыкновенного; потом подумал, не спятил ли гость как-нибудь невзначай с ума, и со страхом посмотрел на него пристально; но глаза гостя были совершенно ясны, не было в них дикого, беспокойного огня, какой бегает в глазах сумасшедшего человека, все было прилично и в порядке. Как ни придумывал Манилов, как ему быть и что ему сделать, но ничего другого не мог придумать, как только выпустить изо рта оставшийся дым очень тонкой струею.', '203.jpg', 26, '2025-10-29 01:43:47'),
(73, '— Итак, я бы желал знать, можете ли вы мне таковых, не живых в действительности.', '— Итак, я бы желал знать, можете ли вы мне таковых, не живых в действительности, но живых относительно законной формы, передать, уступить или как вам заблагорассудится лучше.', '— Итак, я бы желал знать, можете ли вы мне таковых, не живых в действительности, но живых относительно законной формы, передать, уступить или как вам заблагорассудится лучше.', '203.jpg', 30, '2025-10-23 23:02:48'),
(74, '— Я?..', '— Я?..', ' нет, я не то, — сказал Манилов, — но я не могу постичь… извините… я, конечно, не мог получить такого блестящего образования, какое, так сказать, видно во всяком вашем движении; не имею высокого искусства выражаться… Может быть, здесь… в этом, вами сейчас выраженном изъяснении… скрыто другое… Может быть, вы изволили выразиться так для красоты слога.', '201.jpg', 7, '2025-10-13 16:54:31'),
(75, '— Нет, — подхватил Чичиков, — нет, я разумею предмет таков как есть.', '— Нет, — подхватил Чичиков, — нет, я разумею предмет таков как есть, то есть те души, которые, точно, уже умерли.', '.', '102.jpg', 49, '2025-10-12 16:18:37'),
(76, 'Манилов совершенно растерялся.', 'Манилов совершенно растерялся. Он чувствовал, что ему нужно что-то сделать, предложить вопрос, а какой вопрос — черт его знает. Кончил он наконец тем, что выпустил опять дым, но только уже не ртом, а чрез носовые ноздри.', '.', '101.jpg', 41, '2025-10-06 13:51:28'),
(77, '— Итак, если нет препятствий.', '— Итак, если нет препятствий, то с богом можно бы приступить к совершению купчей крепости, — сказал Чичиков.', '.', '102.jpg', 22, '2025-10-02 10:50:51'),
(78, '— А, нет! — сказал Чичиков.', '— А, нет! — сказал Чичиков. — Мы напишем, что они живы, так, как стоит действительно в ревизской сказке.', ' Я привык ни в чем не отступать от гражданских законов, хотя за это и потерпел на службе, но уж извините: обязанность для меня дело священное, закон — я немею пред законом.', '002.jpg', 21, '2025-09-28 07:38:23'),
(79, 'Последние слова понравились Манилову.', 'Последние слова понравились Манилову, но в толк самого дела он все-таки никак не вник и вместо ответа принялся насасывать свой чубук так сильно, что тот начал наконец хрипеть, как фагот.', ' Казалось, как будто он хотел вытянуть из него мнение относительно такого неслыханного обстоятельства; но чубук хрипел и больше ничего.', '201.jpg', 1, '2025-09-21 06:39:37'),
(80, '— О! помилуйте, ничуть.', '— О! помилуйте, ничуть. Я не насчет того говорю, чтобы имел какое-нибудь, то есть, критическое предосуждение о вас.', ' Но позвольте доложить, не будет ли это предприятие или, чтоб еще более, так сказать, выразиться, негоция, — так не будет ли эта негоция несоответствующею гражданским постановлениям и дальнейшим видам России.', '203.jpg', 35, '2025-09-18 02:19:24'),
(81, 'Здесь Манилов, сделавши некоторое движение головою.', 'Здесь Манилов, сделавши некоторое движение головою, посмотрел очень значительно в лицо Чичикова, показав во всех чертах лица своего и сжатых губах такое глубокое выражение, какого, может быть, и не видано было на человеческом лице.', 'Здесь Манилов, сделавши некоторое движение головою, посмотрел очень значительно в лицо Чичикова, показав во всех чертах лица своего и сжатых губах такое глубокое выражение, какого, может быть, и не видано было на человеческом лице, разве только у какого-нибудь слишком умного министра, да и то в минуту самого головоломного дела.', '103.jpg', 32, '2025-09-17 01:48:48'),
(82, 'Но Чичиков сказал просто, что подобное предприятие, или негоция.', 'Но Чичиков сказал просто, что подобное предприятие, или негоция, никак не будет несоответствующею гражданским постановлениям и дальнейшим видам России, а чрез минуту потом прибавил, что казна получит даже выгоды, ибо получит законные пошлины.', '.', '101.jpg', 35, '2025-09-13 19:34:27'),
(83, '— А, если хорошо, это другое дело, я против этого ничего.', '— А, если хорошо, это другое дело: я против этого ничего, — сказал Манилов и совершенно успокоился.', '.', '102.jpg', 16, '2025-09-03 18:29:53'),
(84, '— Как в цене? — сказал опять Манилов и остановился.', '— Как в цене? — сказал опять Манилов и остановился.', ' — Неужели вы полагаете, что я стану брать деньги за души, которые в некотором роде окончили свое существование? Если уж вам пришло этакое, так сказать, фантастическое желание, то с своей стороны я передаю их вам безынтересно и купчую беру на себя.', '302.jpg', 29, '2025-08-27 14:05:43'),
(85, 'Великий упрек был бы историку предлагаемых событий, если бы он упустил сказать.', 'Великий упрек был бы историку предлагаемых событий, если бы он упустил сказать, что удовольствие одолело гостя после таких слов, произнесенных Маниловым.', ' Как он ни был степенен и рассудителен, но тут чуть не произвел даже скачок по образцу козла, что, как известно, производится только в самых сильных порывах радости. Он поворотился так сильно в креслах, что лопнула шерстяная материя, обтягивавшая подушку; сам Манилов посмотрел на него в некотором недоумении. Побужденный признательностию, он наговорил тут же столько благодарностей, что тот смешался, весь покраснел, производил головою отрицательный жест и наконец уже выразился, что это сущее ничего, что он, точно, хотел бы доказать чем-нибудь сердечное влечение, магнетизм души, а умершие души в некотором роде совершенная дрянь.', '301.jpg', 1, '2025-08-17 11:11:44'),
(86, '— Очень не дрянь, — сказал Чичиков, пожав ему руку.', '— Очень не дрянь, — сказал Чичиков, пожав ему руку. Здесь был испущен очень глубокий вздох.', ' Казалось, он был настроен к сердечным излияниям; не без чувства и выражения произнес он наконец следующие слова: — Если б вы знали, какую услугу оказали сей, по-видимому, дрянью человеку без племени и роду! Да и действительно, чего не потерпел я? как барка какая-нибудь среди свирепых волн… Каких гонений, каких преследований не испытал, какого горя не вкусил, а за что? за то, что соблюдал правду, что был чист на своей совести, что подавал руку и вдовице беспомощной, и сироте-горемыке!.. — Тут даже он отер платком выкатившуюся слезу.', '203.jpg', 4, '2025-08-14 11:08:05'),
(87, 'Манилов был совершенно растроган.', 'Манилов был совершенно растроган. Оба приятеля долго жали друг другу руку и долго смотрели молча один другому в глаза, в которых видны были навернувшиеся слезы.', ' Манилов никак не хотел выпустить руки нашего героя и продолжал жать ее так горячо, что тот уже не знал, как ее выручить. Наконец, выдернувши ее потихоньку, он сказал, что не худо бы купчую совершить поскорее и хорошо бы, если бы он сам понаведался в город. Потом взял шляпу и стал откланиваться.', '101.jpg', 23, '2025-08-09 04:57:33'),
(88, '— Как? вы уж хотите ехать.', '— Как? вы уж хотите ехать? — сказал Манилов, вдруг очнувшись и почти испугавшись.', '.', '201.jpg', 6, '2025-07-30 00:23:30'),
(89, '— Лизанька, — сказал Манилов с несколько жалостливым видом.', '— Лизанька, — сказал Манилов с несколько жалостливым видом, — Павел Иванович оставляет нас.', '— Лизанька, — сказал Манилов с несколько жалостливым видом, — Павел Иванович оставляет нас.', '103.jpg', 46, '2025-07-21 20:13:25'),
(90, '— Сударыня.', '— Сударыня! здесь, — сказал Чичиков, — здесь, вот где, — тут он положил руку на сердце, — да, здесь пребудет приятность времени, проведенного с вами.', '— Сударыня! здесь, — сказал Чичиков, — здесь, вот где, — тут он положил руку на сердце, — да, здесь пребудет приятность времени, проведенного с вами! и поверьте, не было бы для меня большего блаженства, как жить с вами если не в одном доме, то по крайней мере в самом ближайшем соседстве.', '103.jpg', 35, '2025-07-11 15:46:48'),
(91, '— А знаете, Павел Иванович, — сказал Манилов.', '— А знаете, Павел Иванович, — сказал Манилов, которому очень понравилась такая мысль, — как было бы в самом деле хорошо, если бы жить этак вместе, под одною кровлею, или под тенью какого-нибудь вяза пофилософствовать о чем-нибудь, углубиться!..', '.', '103.jpg', 26, '2025-07-06 10:02:10'),
(92, '— О! это была бы райская жизнь! — сказал Чичиков, вздохнувши.', '— О! это была бы райская жизнь! — сказал Чичиков, вздохнувши. — Прощайте, сударыня! — продолжал он, подходя к ручке Маниловой.', ' — Прощайте, почтеннейший друг! Не позабудьте просьбы.', '103.jpg', 37, '2025-06-28 04:38:24'),
(93, '— О, будьте уверены! — отвечал Манилов.', '— О, будьте уверены! — отвечал Манилов. — Я с вами расстаюсь не долее как на два дни.', '.', '203.jpg', 39, '2025-06-23 01:42:42'),
(94, '— Прощайте, миленькие малютки.', '— Прощайте, миленькие малютки! — сказал Чичиков, увидевши Алкида и Фемистоклюса, которые занимались каким-то деревянным гусаром, у которого уже не было ни руки, ни носа. — Прощайте, мои крошки.', ' Вы извините меня, что я не привез вам гостинца, потому что, признаюсь, не знал даже, живете ли вы на свете, но теперь, как приеду, непременно привезу.', '202.jpg', 46, '2025-06-21 01:39:38'),
(95, '— А тебе барабан; не правда ли, тебе барабан.', '— А тебе барабан; не правда ли, тебе барабан? — продолжал он, наклонившись к Алкиду.', '.', '203.jpg', 30, '2025-06-15 21:07:58'),
(96, '— Хорошо, а тебе привезу барабан.', '— Хорошо, а тебе привезу барабан.', ' Такой славный барабан, этак все будет: туррр… ру… тра-та-та, та-та-та… Прощай, душенька! прощай! — Тут поцеловал он его в голову и обратился к Манилову и его супруге с небольшим смехом, с какие обыкновенно обращаются к родителям, давая им знать о невинности желаний их детей.', '002.jpg', 48, '2025-06-06 14:51:40'),
(97, '— Право, останьтесь, Павел Иванович.', '— Право, останьтесь, Павел Иванович! — сказал Манилов, когда уже все вышли на крыльцо. — Посмотрите, какие тучи.', '.', '302.jpg', 52, '2025-06-04 09:33:10'),
(98, 'Тут Манилов с такою же любезностью рассказал дело кучеру.', 'Тут Манилов с такою же любезностью рассказал дело кучеру, и сказал ему даже один раз «вы».', '.', '101.jpg', 26, '2025-05-26 08:16:23'),
(99, 'Кучер, услышав, что нужно пропустить два поворота и поворотить на третий.', 'Кучер, услышав, что нужно пропустить два поворота и поворотить на третий, сказал: «Потрафим, ваше благородие», — и Чичиков уехал, сопровождаемый долго поклонами и маханьями платка приподымавшихся на цыпочках хозяев.', '.', '202.jpg', 15, '2025-05-21 05:42:16'),
(100, 'Манилов долго стоял на крыльце, провожая глазами удалявшуюся бричку.', 'Манилов долго стоял на крыльце, провожая глазами удалявшуюся бричку, и когда она уже совершенно стала не видна, он все еще стоял, куря трубку.', ' Наконец вошел он в комнату, сел на стуле и предался размышлению, душевно радуясь, что доставил гостю своему небольшое удовольствие. Потом мысли его перенеслись незаметно к другим предметам и наконец занеслись бог знает куда. Он думал о благополучии дружеской жизни, о том, как бы хорошо было жить с другом на берегу какой-нибудь реки, потом чрез эту реку начал строиться у него мост, потом огромнейший дом с таким высоким бельведером, что можно оттуда видеть даже Москву и там пить вечером чай на открытом воздухе и рассуждать о каких-нибудь приятных предметах. Потом, что они вместе с Чичиковым приехали в какое-то общество в хороших каретах, где обворожают всех приятностию обращения, и что будто бы государь, узнавши о такой их дружбе, пожаловал их генералами, и далее, наконец, бог знает что такое, чего уже он и сам никак не мог разобрать. Странная просьба Чичикова прервала вдруг все его мечтания. Мысль о ней как-то особенно не варилась в его голове: как ни переворачивал он ее, но никак не мог изъяснить себе, и все время сидел он и курил трубку, что тянулось до самого ужина.', '103.jpg', 46, '2025-05-14 00:28:07'),
(101, 'А Чичиков в довольном расположении духа сидел в своей бричке.', 'А Чичиков в довольном расположении духа сидел в своей бричке, катившейся давно по столбовой дороге.', ' Из предыдущей главы уже видно, в чем состоял главный предмет его вкуса и склонностей, а потому не диво, что он скоро погрузился весь в него и телом и душою. Предположения, сметы и соображения, блуждавшие по лицу его, видно, были очень приятны, ибо ежеминутно оставляли после себя следы довольной усмешки. Занятый ими, он не обращал никакого внимания на то, как его кучер, довольный приемом дворовых людей Манилова, делал весьма дельные замечания чубарому пристяжному коню, запряженному с правой стороны. Этот чубарый конь был сильно лукав и показывал только для вида, будто бы везет, тогда как коренной гнедой и пристяжной каурой масти, называвшийся Заседателем, потому что был приобретен от какого-то заседателя, трудилися от всего сердца, так что даже в глазах их было заметно получаемое ими от того удовольствие. «Хитри, хитри! вот я тебя перехитрю! — говорил Селифан, приподнявшись и хлыснув кнутом ленивца. — Ты знай свое дело, панталонник ты немецкий! Гнедой — почтенный конь, он сполняет свой долг, я ему с охотою дам лишнюю меру, потому что он почтенный конь, и Заседатель тож хороший конь… Ну, ну! что потряхиваешь ушами? Ты, дурак, слушай, коли говорят! я тебя, невежа, не стану дурному учить. Ишь куда ползет!» Здесь он опять хлыснул его кнутом, примолвив; «У, варвар! Бонапарт ты проклятый!» Потом прикрикнул на всех: «Эй вы, любезные!» — и стегнул по всем по трем уже не в виде наказания, но чтобы показать, что был ими доволен. Доставив такое удовольствие, он опять обратил речь к чубарому: «Ты думаешь, что скроешь свое поведение. Нет, ты живи по правде, когда хочешь, чтобы тебе оказывали почтение. Вот у помещика, что мы были, хорошие люди. Я с удовольствием поговорю, коли хороший человек; с человеком хорошим мы всегда свои други, тонкие приятели; выпить ли чаю, или закусить — с охотою, коли хороший человек. Хорошему человеку всякой отдаст почтение.', '301.jpg', 35, '2025-05-08 20:10:39'),
(102, 'Так рассуждая, Селифан забрался наконец в самые отдаленные отвлеченности.', 'Так рассуждая, Селифан забрался наконец в самые отдаленные отвлеченности.', ' Если бы Чичиков прислушался, то узнал бы много подробностей, относившихся лично к нему; но мысли его так были заняты своим предметом, что один только сильный удар грома заставил его очнуться и посмотреть вокруг себя; все небо было совершенно обложено тучами, и пыльная почтовая дорога опрыскалась каплями дождя. Наконец громовый удар раздался в другой раз громче и ближе, и дождь хлынул вдруг как из ведра. Сначала, принявши косое направление, хлестал он в одну сторону кузова кибитки, потом в другую, потом, изменив и образ нападения и сделавшись совершенно прямым, барабанил прямо в верх его кузова; брызги наконец стали долетать ему в лицо. Это заставило его задернуться кожаными занавесками с двумя круглыми окошечками, определенными на рассматривание дорожных видов, и приказать Селифану ехать скорее. Селифан, прерванный тоже на самой середине речи, смекнул, что, точно, не нужно мешкать, вытащил тут же из-под козел какую-то дрянь из серого сукна, надел ее в рукава, схватил в руки вожжи и прикрикнул на свою тройку, которая чуть-чуть переступала ногами, ибо чувствовала приятное расслабление от поучительных речей. Но Селифан никак не мог припомнить, два или три поворота проехал. Сообразив и припоминая несколько дорогу, он догадался, что много было поворотов, которые все пропустил он мимо. Так как русский человек в решительные минуты найдется, что сделать, не вдаваясь в дальние рассуждения, то, поворотивши направо, на первую перекрестную дорогу, прикрикнул он: «Эй вы, други почтенные!» — и пустился вскачь, мало помышляя о том, куда приведет взятая дорога.', '203.jpg', 55, '2025-04-28 14:46:39');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(103, 'Дождь, однако же, казалось, зарядил надолго.', 'Дождь, однако же, казалось, зарядил надолго. Лежавшая на дороге пыль быстро замесилась в грязь, и лошадям ежеминутно становилось тяжелее тащить бричку. Чичиков уже начинал сильно беспокоиться, не видя так долго деревни Собакевича.', ' По расчету его, давно бы пора было приехать. Он высматривал по сторонам, но темнота была такая, хоть глаз выколи.', '203.jpg', 12, '2025-04-19 10:41:20'),
(104, '— Нет, барин, нигде не видно.', '— Нет, барин, нигде не видно! — После чего Селифан, помахивая кнутом, затянул песню не песню, но что-то такое длинное, чему и конца не было.', ' Туда все вошло: все ободрительные и побудительные крики, которыми потчевают лошадей по всей России от одного конца до другого; прилагательные всех родов без дальнейшего разбора, как что первое попалось на язык. Таким образом дошло до того, что он начал называть их наконец секретарями.', '100.jpg', 44, '2025-04-17 09:50:25'),
(105, 'Между тем Чичиков стал примечать.', 'Между тем Чичиков стал примечать, что бричка качалась на все стороны и наделяла его пресильными толчками; это дало ему почувствовать, что они своротили с дороги и, вероятно, тащились по взбороненному полю.', ' Селифан, казалось, сам смекнул, но не говорил ни слова.', '203.jpg', 53, '2025-04-16 04:36:09'),
(106, '— Да что ж, барин, делать, время-то такое; кнута не видишь, такая потьма.', '— Да что ж, барин, делать, время-то такое; кнута не видишь, такая потьма! — Сказавши это, он так покосил бричку, что Чичиков принужден был держаться обеими руками. Тут только заметил он, что Селифан подгулял.', '.', '202.jpg', 28, '2025-04-14 00:02:22'),
(107, '— Нет, барин, как можно, чтоб я опрокинул, — говорил Селифан.', '— Нет, барин, как можно, чтоб я опрокинул, — говорил Селифан. — Это нехорошо опрокинуть, я уж сам знаю; уж я никак не опрокину. — Затем начал он слегка поворачивать бричку, поворачивал, поворачивал и наконец выворотил ее совершенно набок.', ' Чичиков и руками и ногами шлепнулся в грязь. Селифан лошадей, однако ж, остановил, впрочем, они остановились бы и сами, потому что были сильно изнурены. Такой непредвиденный случай совершенно изумил его.', '302.jpg', 35, '2025-04-06 22:44:45'),
(108, '— Нет, барин, как можно, чтоб я был пьян.', '— Нет, барин, как можно, чтоб я был пьян! Я знаю, что это нехорошее дело быть пьяным. С приятелем поговорил, потому что с хорошим человеком можно поговорить, в том нет худого; и закусили вместе.', ' Закуска не обидное дело; с хорошим человеком можно закусить.', '100.jpg', 43, '2025-03-31 21:35:54'),
(109, '— А что я тебе сказал последний раз, когда ты напился? а? забыл.', '— А что я тебе сказал последний раз, когда ты напился? а? забыл? — сказал Чичиков.', '.', '203.jpg', 35, '2025-03-23 20:34:15'),
(110, '— Нет, ваше благородие, как можно, чтобы я позабыл Я уже дело свое знаю.', '— Нет, ваше благородие, как можно, чтобы я позабыл Я уже дело свое знаю. Я знаю, что нехорошо быть пьяным.', ' С хорошим человеком поговорил.', '302.jpg', 34, '2025-03-19 20:17:57'),
(111, '— Вот я тебя как высеку, так ты у меня будешь знать.', '— Вот я тебя как высеку, так ты у меня будешь знать, как говорить с хорошим человеком.', '— Вот я тебя как высеку, так ты у меня будешь знать, как говорить с хорошим человеком.', '103.jpg', 32, '2025-03-15 19:41:35'),
(112, '— Как милости вашей будет угодно, — отвечал на все согласный Селифан.', '— Как милости вашей будет угодно, — отвечал на все согласный Селифан, — коли высечь, то и высечь; я ничуть не прочь от того. Почему ж не посечь, коли за дело, на то воля господская.', ' Оно нужно посечь, потому что мужик балуется, порядок нужно наблюдать.', '202.jpg', 13, '2025-03-10 17:42:15'),
(113, 'На такое рассуждение барин совершенно не нашелся, что отвечать.', 'На такое рассуждение барин совершенно не нашелся, что отвечать. Но в это время, казалось, как будто сама судьба решилась над ним сжалиться. Издали послышался собачий лай. Обрадованный Чичиков дал приказание погонять лошадей.', ' Русский возница имеет доброе чутье вместо глаз; от этого случается, что он, зажмуря глаза, качает иногда во весь дух и всегда куда-нибудь да приезжает. Селифан, не видя ни зги, направил лошадей так прямо на деревню, что остановился тогда только, когда бричка ударилася оглоблями в забор и когда решительно уже некуда было ехать. Чичиков только заметил сквозь густое покрывало лившего дождя что-то похожее на крышу. Он послал Селифана отыскивать ворота, что, без сомнения, продолжалось бы долго, если бы на Руси не было вместо швейцаров лихих собак, которые доложили о нем так звонко, что он поднес пальцы к ушам своим. Свет мелькнул в одном окошке и досягнул туманною струею до забора, указавши нашим дорожным ворота.', '101.jpg', 44, '2025-03-04 13:21:01'),
(114, '— Вишь ты, какой востроногий, — сказала старуха, — приехал в какое время.', '— Вишь ты, какой востроногий, — сказала старуха, — приехал в какое время! Здесь тебе не постоялый двор: помещица живет.', '.', '302.jpg', 4, '2025-02-22 08:28:08'),
(115, '— Что ж делать, матушка: вишь, с дороги сбились.', '— Что ж делать, матушка: вишь, с дороги сбились. Не ночевать же в такое время в степи.', '.', '301.jpg', 19, '2025-02-18 04:58:49'),
(116, '— Погодите, я скажу барыне.', '— Погодите, я скажу барыне, — произнесла она и минуты через две уже возвратилась с фонарем в руке.', '.', '201.jpg', 25, '2025-02-09 02:40:19'),
(117, 'Ворота отперлись. Огонек мелькнул и в другом окне.', 'Ворота отперлись. Огонек мелькнул и в другом окне. Бричка, въехавши на двор, остановилась перед небольшим домиком, который за темнотою трудно было рассмотреть.', ' Только одна половина его была озарена светом, исходившим из окон; видна была еще лужа перед домом, на которую прямо ударял тот же свет. Дождь стучал звучно по деревянной крыше и журчащими ручьями стекал в подставленную бочку. Между тем псы заливались всеми возможными голосами: один, забросивши вверх голову, выводил так протяжно и с таким старанием, как будто за это получал бог знает какое жалованье; другой отхватывал наскоро, как пономарь; промеж них звенел, как почтовый звонок, неугомонный дискант, вероятно молодого щенка, и все это, наконец, повершал бас, может быть, старик, наделенный дюжею собачьей натурой, потому что хрипел, как хрипит певческий контрабас, когда концерт в полном разливе: тенора поднимаются на цыпочки от сильного желания вывести высокую ноту, и все, что ни есть, порывается кверху, закидывая голову, а он один, засунувши небритый подбородок в галстук, присев и опустившись почти до земли, пропускает оттуда свою ноту, от которой трясутся и дребезжат стекла. Уже по одному собачьему лаю, составленному из таких музыкантов, можно было предположить, что деревушка была порядочная; но промокший и озябший герой наш ни о чем не думал, как только о постели. Не успела бричка совершенно остановиться, как он уже соскочил на крыльцо, пошатнулся и чуть не упал. На крыльцо вышла опять какая-то женщина, помоложе прежней, но очень на нее похожая. Она проводила его в комнату. Чичиков кинул вскользь два взгляда: комната была обвешана старенькими полосатыми обоями; картины с какими-то птицами; между окон старинные маленькие зеркала с темными рамками в виде свернувшихся листьев; за всяким зеркалом заложены были или письмо, или старая колода карт, или чулок; стенные часы с нарисованными цветами на циферблате… невмочь было ничего более заметить. Он чувствовал, что глаза его липнули, как будто их кто-нибудь вымазал медом.', '301.jpg', 57, '2025-02-02 01:36:36'),
(118, '— Ничего, ничего, — сказала хозяйка.', '— Ничего, ничего, — сказала хозяйка. — В какое это время вас бог принес! Сумятица и вьюга такая… С дороги бы следовало поесть чего-нибудь, да пора-то ночная, приготовить нельзя.', '.', '102.jpg', 38, '2025-01-25 19:48:41'),
(119, 'Слова хозяйки были прерваны странным шипением, так что гость было испугался.', 'Слова хозяйки были прерваны странным шипением, так что гость было испугался; шум походил на то, как бы вся комната наполнилась змеями; но, взглянувши вверх, он успокоился, ибо смекнул, что стенным часам пришла охота бить.', ' За шипеньем тотчас же последовало хрипенье, и наконец, понатужась всеми силами, они пробили два часа таким звуком, как бы кто колотил палкой по разбитому горшку, после чего маятник пошел опять покойно щелкать направо и налево.', '100.jpg', 43, '2025-01-19 13:40:02'),
(120, 'Чичиков поблагодарил хозяйку, сказавши, что ему не нужно ничего.', 'Чичиков поблагодарил хозяйку, сказавши, что ему не нужно ничего, чтобы она не беспокоилась ни о чем, что, кроме постели, он ничего не требует, и полюбопытствовал только знать, в какие места заехал он и далеко ли отсюда пути к помещику Собакевичу.', 'Чичиков поблагодарил хозяйку, сказавши, что ему не нужно ничего, чтобы она не беспокоилась ни о чем, что, кроме постели, он ничего не требует, и полюбопытствовал только знать, в какие места заехал он и далеко ли отсюда пути к помещику Собакевичу, на что старуха сказала, что и не слыхивала такого имени и что такого помещика вовсе нет.', '202.jpg', 0, '2025-01-12 13:15:30'),
(121, '— Нет, отец, богатых слишком нет.', '— Нет, отец, богатых слишком нет. У кого двадцать душ, у кого тридцать, а таких, чтоб по сотне, таких нет.', '.', '301.jpg', 50, '2025-01-03 12:18:22'),
(122, '— А верст шестьдесят будет.', '— А верст шестьдесят будет.', ' Как жаль мне, что нечего вам покушать! не хотите ли, батюшка, выпить чаю.', '201.jpg', 60, '2024-12-29 09:30:41'),
(123, '— Правда, с такой дороги и очень нужно отдохнуть.', '— Правда, с такой дороги и очень нужно отдохнуть. Вот здесь и расположитесь, батюшка, на этом диване. Эй, Фетинья, принеси перину, подушки и простыню. Какое-то время послал бог: гром такой — у меня всю ночь горела свеча перед образом.', ' Эх, отец мой, да у тебя-то, как у борова, вся спина и бок в грязи! где так изволил засалиться.', '301.jpg', 36, '2024-12-19 04:53:32'),
(124, '— Еще славу богу, что только засалился, нужно благодарить.', '— Еще славу богу, что только засалился, нужно благодарить, что не отломал совсем боков.', '.', '102.jpg', 4, '2024-12-15 23:11:45'),
(125, '— Спасибо, спасибо.', '— Спасибо, спасибо. Не беспокойтесь, а прикажите только вашей девке повысушить и вычистить мое платье.', '.', '002.jpg', 13, '2024-12-14 19:34:26'),
(126, '— Слышишь, Фетинья.', '— Слышишь, Фетинья! — сказала хозяйка, обратясь к женщине, выходившей на крыльцо со свечою, которая успела уже притащить перину и, взбивши ее с обоих боков руками, напустила целый потоп перьев по всей комнате.', ' — Ты возьми ихний-то кафтан вместе с исподним и прежде просуши их перед огнем, как делывали покойнику барину, а после перетри и выколоти хорошенько.', '301.jpg', 1, '2024-12-10 16:25:42'),
(127, '— Слушаю, сударыня.', '— Слушаю, сударыня! — говорила Фетинья, постилая сверх перины простыню и кладя подушки.', '.', '100.jpg', 53, '2024-12-05 15:55:36'),
(128, '— Ну, вот тебе постель готова, — сказала хозяйка.', '— Ну, вот тебе постель готова, — сказала хозяйка. — Прощай, батюшка, желаю покойной ночи. Да не нужно ли еще чего? Может, ты привык, отец мой, чтобы кто-нибудь почесал на ночь пятки? Покойник мой без этого никак не засыпал.', '.', '201.jpg', 7, '2024-11-27 15:35:09'),
(129, 'Но гость отказался и от почесывания пяток.', 'Но гость отказался и от почесывания пяток. Хозяйка вышла, и он тот же час поспешил раздеться, отдав Фетинье всю снятую с себя сбрую, как верхнюю, так и нижнюю, и Фетинья, пожелав также с своей стороны покойной ночи, утащила эти мокрые доспехи.', ' Оставшись один, он не без удовольствия взглянул на свою постель, которая была почти до потолка. Фетинья, как видно, была мастерица взбивать перины. Когда, подставивши стул, взобрался он на постель, она опустилась под ним почти до самого пола, и перья, вытесненные им из пределов, разлетелись во все углы комнаты. Погасив свечу, он накрылся ситцевым одеялом и, свернувшись под ним кренделем, заснул в ту же минуту. Проснулся на другой лень он уже довольно поздним утром. Солнце сквозь окно блистало ему прямо в глаза, и мухи, которые вчера спали спокойно на стенах и на потолке, все обратились к нему: одна села ему на губу, другая на ухо, третья норовила как бы усесться на самый глаз, ту же, которая имела неосторожность подсесть близко к носовой ноздре, он потянул впросонках в самый нос, что заставило его крепко чихнуть, — обстоятельство, бывшее причиною его пробуждения. Окинувши взглядом комнату, он теперь заметил, что на картинах не всё были птицы: между ними висел портрет Кутузова и писанный масляными красками какой-то старик с красными обшлагами на мундире, как нашивали при Павле Петровиче. Часы опять испустили шипение и пробили десять; в дверь выглянуло женское лицо и в ту же минуту спряталось, ибо Чичиков, желая получше заснуть, скинул с себя совершенно все. Выглянувшее лицо показалось ему как будто несколько знакомо. Он стал припоминать себе: кто бы это был, и наконец вспомнил, что это была хозяйка. Он надел рубаху; платье, уже высушенное и вычищенное, лежало возле него. Одевшись, подошел он к зеркалу и чихнул опять так громко, что подошедший в это время к окну индейский петух — окно же было очень близко от земли — заболтал ему что-то вдруг и весьма скоро на своем странном языке, вероятно «желаю здравствовать», на что Чичиков сказал ему дурака. Подошедши к окну, он начал рассматривать бывшие перед ним виды: окно глядело едва ли не в курятник; по крайней мере, находившийся перед ним узенький дворик весь был наполнен птицами и всякой домашней тварью.', '202.jpg', 18, '2024-11-19 10:33:21'),
(130, '— Здравствуйте, батюшка.', '— Здравствуйте, батюшка. Каково почивали? — сказала хозяйка, приподнимаясь с места. Она была одета лучше, нежели вчера, — в темном платье и уже не в спальном чепце, но на шее все так же было что-то завязано.', '.', '202.jpg', 8, '2024-11-12 08:21:29'),
(131, '— Бессонница. Все поясница болит, и нога, что повыше косточки, так вот и ломит.', '— Бессонница. Все поясница болит, и нога, что повыше косточки, так вот и ломит.', '.', '201.jpg', 23, '2024-11-10 06:06:46'),
(132, '— Дай бог, чтобы прошло.', '— Дай бог, чтобы прошло. Я-то смазывала свиным салом и скипидаром тоже смачивала. А с чем прихлебаете чайку? Во фляжке фруктовая.', '.', '301.jpg', 46, '2024-11-07 05:54:00'),
(133, 'Читатель, я думаю, уже заметил, что Чичиков, несмотря на ласковый вид, говорил.', 'Читатель, я думаю, уже заметил, что Чичиков, несмотря на ласковый вид, говорил, однако же, с большею свободою, нежели с Маниловым, и вовсе не церемонился.', ' Надобно сказать, кто у нас на Руси если не угнались еще кой в чем другою за иностранцами, то далеко перегнали их в умении обращаться. Пересчитать нельзя всех оттенков и тонкостей нашего обращения. Француз или немец век не смекнет и не поймет всех его особенностей и различий; он почти тем же голосом и тем же языком станет говорить и с миллионщиком, и с мелким табачным торгашом, хотя, конечно, в душе поподличает в меру перед первым. У нас не то: у нас есть такие мудрецы, которые с помещиком, имеющим двести душ, будут говорить совсем иначе, нежели с тем, у которого их триста, а у которого их триста, будут говорить опять не так, как с тем, у которого их пятьсот, а с тем, у которого их пятьсот, опять не так, как с тем, у которого их восемьсот, — словом, хоть восходи до миллиона, всё найдут оттенки. Положим, например, существует канцелярия, не здесь, а в тридевятом государстве, а в канцелярии, положим, существует правитель канцелярии. Прошу смотреть на него, когда он сидит среди своих подчиненных, — да просто от страха и слова не выговоришь! гордость и благородство, и уж чего не выражает лицо его? просто бери кисть, да и рисуй: Прометей, решительный Прометей! Высматривает орлом, выступает плавно, мерно. Тот же самый орел, как только вышел из комнаты и приближается к кабинету своего начальника, куропаткой такой спешит с бумагами под мышкой, что мочи нет. В обществе и на вечеринке, будь все небольшого чина, Прометей так и останется Прометеем, а чуть немного повыше его, с Прометеем сделается такое превращение, какого и Овидий не выдумает: муха, меньше даже мухи, уничтожился в песчинку! «Да это не Иван Петрович, — говоришь, глядя на него. — Иван Петрович выше ростом, а этот и низенький и худенький; тот говорит громко, басит и никогда не смеется, а этот черт знает что: пищит птицей и все смеется». Подходишь ближе, глядишь — точно Иван Петрович! «Эхе-хе», — думаешь себе… Но, однако ж, обратимся к действующим лицам.', '201.jpg', 19, '2024-11-01 02:25:05'),
(134, '— Душ-то в ней, отец мой, без малого восемьдесят, — сказала хозяйка, — да беда.', '— Душ-то в ней, отец мой, без малого восемьдесят, — сказала хозяйка, — да беда, времена плохи, вот и прошлый год был такой неурожай, что боже храни.', '.', '202.jpg', 56, '2024-10-24 21:12:14'),
(135, '— Однако ж мужички на вид дюжие, избенки крепкие.', '— Однако ж мужички на вид дюжие, избенки крепкие. А позвольте узнать фамилию вашу. Я так рассеялся… приехал в ночное время..', '.', '102.jpg', 3, '2024-10-22 18:45:28'),
(136, '— Настасья Петровна? хорошее имя Настасья Петровна.', '— Настасья Петровна? хорошее имя Настасья Петровна. У меня тетка родная, сестра моей матери, Настасья Петровна.', '.', '201.jpg', 8, '2024-10-21 13:19:53'),
(137, '— Нет, матушка, — отвечал Чичиков, усмехнувшись, — чай, не заседатель.', '— Нет, матушка, — отвечал Чичиков, усмехнувшись, — чай, не заседатель, а так ездим по своим делишкам.', '.', '203.jpg', 26, '2024-10-13 10:18:37'),
(138, '— А, так вы покупщик.', '— А, так вы покупщик! Как же жаль, право, что я продала мед купцам так дешево, а вот ты бы, отец мой, у меня, верно, его купил.', '.', '002.jpg', 9, '2024-10-05 06:17:07'),
(139, '— Что ж другое? Разве пеньку.', '— Что ж другое? Разве пеньку? Да вить и пеньки у меня теперь маловато: полпуда всего.', '.', '102.jpg', 58, '2024-09-28 23:58:06'),
(140, '— Ох, батюшка, осьмнадцать человека — сказала старуха, вздохнувши.', '— Ох, батюшка, осьмнадцать человека — сказала старуха, вздохнувши. — И умер такой всё славный народ, всё работники. После того, правда, народилось, да что в них: все такая мелюзга; а заседатель подъехал — подать, говорит, уплачивать с души.', ' Народ мертвый, а плати, как за живого. На прошлой неделе сгорел у меня кузнец, такой искусный кузнец и слесарное мастерство знал.', '002.jpg', 17, '2024-09-20 18:22:18'),
(141, '— Бог приберег от такой беды, пожар бы еще хуже; сам сгорел, отец мой.', '— Бог приберег от такой беды, пожар бы еще хуже; сам сгорел, отец мой.', ' Внутри у него как-то загорелось, чересчур выпил, только синий огонек пошел от него, весь истлел, истлел и почернел, как уголь, а такой был преискусный кузнец! и теперь мне выехать не на чем: некому лошадей подковать.', '103.jpg', 25, '2024-09-16 14:52:09'),
(142, '— На все воля божья, матушка.', '— На все воля божья, матушка! — сказал Чичиков, вздохнувши, — против мудрости божией ничего нельзя сказать… Уступите-ка их мне, Настасья Петровна.', '— На все воля божья, матушка! — сказал Чичиков, вздохнувши, — против мудрости божией ничего нельзя сказать… Уступите-ка их мне, Настасья Петровна.', '102.jpg', 59, '2024-09-06 14:08:54'),
(143, '— Да как же? Я, право, в толк-то не возьму.', '— Да как же? Я, право, в толк-то не возьму.', ' Нешто хочешь ты их откапывать из земли.', '102.jpg', 46, '2024-08-29 09:47:55'),
(144, 'Чичиков увидел.', 'Чичиков увидел, что старуха хватила далеко и что необходимо ей нужно растолковать, в чем дело. В немногих словах объяснил он ей, что перевод или покупка будет значиться только на бумаге и души будут прописаны как бы живые.', '.', '002.jpg', 37, '2024-08-27 09:37:06'),
(145, '— Да кто же говорит, что они живые.', '— Да кто же говорит, что они живые? Потому-то и в убыток вам, что мертвые: вы за них платите, а теперь я вас избавлю от хлопот и платежа. Понимаете? Да не только избавлю, да еще сверх того дам вам пятнадцать рублей.', ' Ну, теперь ясно.', '101.jpg', 60, '2024-08-23 07:35:09'),
(146, '— Право, не знаю, — произнесла хозяйка с расстановкой.', '— Право, не знаю, — произнесла хозяйка с расстановкой. — Ведь я мертвых никогда еще не продавала.', '.', '103.jpg', 52, '2024-08-20 05:18:19'),
(147, '— Еще бы! Это бы скорей походило на диво, если бы вы их кому нибудь продали.', '— Еще бы! Это бы скорей походило на диво, если бы вы их кому нибудь продали.', ' Или вы думаете, что в них есть в самом деле какой-нибудь прок.', '201.jpg', 22, '2024-08-12 04:20:37'),
(148, '— Нет, этого-то я не думаю. Что ж в них за прок, проку никакого нет.', '— Нет, этого-то я не думаю. Что ж в них за прок, проку никакого нет. Меня только то и затрудняет, что они уже мертвые.', '.', '100.jpg', 14, '2024-08-10 03:57:14'),
(149, '— Послушайте, матушка.', '— Послушайте, матушка.', ' Да вы рассудите только хорошенько, — ведь вы разоряетесь, платите за него подать.', '203.jpg', 39, '2024-08-01 22:27:07'),
(150, '— Ох, отец мой, и не говори об этом! — подхватила помещица.', '— Ох, отец мой, и не говори об этом! — подхватила помещица. — Еще третью неделю взнесла больше полутораста. Да заседателя подмаслила.', '.', '201.jpg', 23, '2024-07-27 17:08:17'),
(151, '— Ну, видите, матушка.', '— Ну, видите, матушка. А теперь примите в соображение только то, что заседателя вам подмасливать больше не нужно, потому что теперь я плачу за них; я, а не вы; я принимаю на себя все повинности.', ' Я совершу даже крепость на свои деньги, понимаете ли вы это.', '202.jpg', 53, '2024-07-18 12:39:37'),
(152, 'Старуха задумалась.', 'Старуха задумалась. Она видела, что дело, точно, как будто выгодно, да только уж слишком новое и небывалое; а потому начала сильно побаиваться, чтобы как-нибудь не надул ее этот покупщик; приехал же бог знает откуда, да еще и в ночное время.', '.', '202.jpg', 36, '2024-07-13 08:21:29'),
(153, '— Право, отец мой, никогда еще не случалось продавать мне покойников.', '— Право, отец мой, никогда еще не случалось продавать мне покойников. Живых-то я уступила, вот и третьего года протопопу двух девок, по сту рублей каждую, и очень благодарил, такие вышли славные работницы: сами салфетки ткут.', '.', '103.jpg', 58, '2024-07-04 06:17:07'),
(154, '— Право, я боюсь на первых-то порах, чтобы как-нибудь не понести убытку.', '— Право, я боюсь на первых-то порах, чтобы как-нибудь не понести убытку. Может быть, ты, отец мой, меня обманываешь, а они того… они больше как-нибудь стоят.', '.', '102.jpg', 51, '2024-06-25 01:48:17'),
(155, '— Послушайте, матушка… эх, какие вы! что ж они могут стоить.', '— Послушайте, матушка… эх, какие вы! что ж они могут стоить? Рассмотрите: ведь это прах. Понимаете ли? это просто прах.', ' Вы возьмите всякую негодную, последнюю вещь, например даже простую тряпку, и тряпке есть цена: ее хоть по крайней мерз купят на бумажную фабрику, а ведь это ни на что не нужно.', '201.jpg', 1, '2024-06-20 00:12:51'),
(156, '— Уж это, точно, правда.', '— Уж это, точно, правда. Уж совсем ни на что не нужно; да ведь меня одно только и останавливает, что ведь они уже мертвые.', '.', '203.jpg', 7, '2024-06-10 22:59:54'),
(157, '«Эк ее, дубинноголовая какая.', '«Эк ее, дубинноголовая какая! — сказал про себя Чичиков, уже начиная выходить из терпения. — Пойди ты сладь с нею! в пот бросила, проклятая старуха!» Тут он, вынувши из кармана платок, начал отирать пот, в самом деле выступивший на лбу.', ' Впрочем, Чичиков напрасно сердился: иной и почтенный, и государственный даже человек, а на деле выходит совершенная Коробочка. Как зарубил что себе в голову, то уж ничем его не пересилить; сколько ни представляй ему доводов, ясных как день, все отскакивает от него, как резинный мяч отскакивает от стены. Отерши пот, Чичиков решился попробовать, нельзя ли ее навести на путь какою-нибудь иною стороною.', '103.jpg', 34, '2024-06-08 22:15:30'),
(158, '— Вы, матушка, — сказал он, — или не хотите понимать слов моих.', '— Вы, матушка, — сказал он, — или не хотите понимать слов моих, или так нарочно говорите, лишь бы что-нибудь говорить… Я вам даю деньги: пятнадцать рублей ассигнациями. Понимаете ли? Ведь это деньги. Вы их не сыщете на улице.', ' Ну, признайтесь, почем продали мед.', '002.jpg', 46, '2024-06-03 17:22:44'),
(159, '— Ну видите ль? Так зато это мед.', '— Ну видите ль? Так зато это мед. Вы собирали его, может быть, около года, с заботами, со старанием, хлопотами; ездили, морили пчел, кормили их в погребе целую зиму; а мертвые души дело не от мира сего.', ' Тут вы с своей стороны никакого не прилагали старания, на то была воля божия, чтоб они оставили мир сей, нанеся ущерб вашему хозяйству. Там вы получили за труд, за старание двенадцать рублей, а тут вы берете ни за что, даром, да и не двенадцать, а пятнадцать, да и не серебром, а все синими ассигнациями. — После таких сильных убеждений Чичиков почти уже не сомневался, что старуха наконец подастся.', '102.jpg', 17, '2024-06-02 12:24:59'),
(160, '— Право, — отвечала помещица, — мое такое неопытное вдовье дело.', '— Право, — отвечала помещица, — мое такое неопытное вдовье дело! лучше ж я маненько повременю, авось понаедут купцы, да примерюсь к ценам.', '.', '002.jpg', 3, '2024-05-31 07:24:33'),
(161, '— Страм, страм, матушка! просто страм! Ну что вы это говорите, подумайте сами.', '— Страм, страм, матушка! просто страм! Ну что вы это говорите, подумайте сами! Кто же станет покупать их? Ну какое употребление он может из них сделать.', '— Страм, страм, матушка! просто страм! Ну что вы это говорите, подумайте сами! Кто же станет покупать их? Ну какое употребление он может из них сделать.', '100.jpg', 22, '2024-05-26 02:01:28'),
(162, '— А может.', '— А может, в хозяйстве-то как-нибудь под случай понадобятся… — возразила старуха, да и не кончила речи, открыта рот и смотрела на него почти со страхом, желая знать, что он на это скажет.', '.', '002.jpg', 16, '2024-05-21 20:55:38'),
(163, '— Мертвые в хозяйстве! Эк куда хватили.', '— Мертвые в хозяйстве! Эк куда хватили! Воробьев разве пугать по ночам в вашем огороде, что ли.', '— Мертвые в хозяйстве! Эк куда хватили! Воробьев разве пугать по ночам в вашем огороде, что ли.', '100.jpg', 8, '2024-05-12 18:54:25'),
(164, '— С нами крестная сила! Какие ты страсти говоришь.', '— С нами крестная сила! Какие ты страсти говоришь! — проговорила старуха, крестясь.', '.', '202.jpg', 58, '2024-05-07 12:40:14'),
(165, '— Куда ж еще вы их хотели пристроить.', '— Куда ж еще вы их хотели пристроить? Да, впрочем, ведь кости и могилы — все вам остается, перевод только на бумаге. Ну, так что же? Как же? отвечайте по крайней мере.', '.', '302.jpg', 38, '2024-05-03 07:28:09'),
(166, '— Да что ж пенька.', '— Да что ж пенька? Помилуйте, я вас прошу совсем о другом, а вы мне пеньку суете! Пенька пенькою, в другой раз приеду, заберу и пеньку.', ' Так как же, Настасья Петровна.', '301.jpg', 35, '2024-05-02 01:37:01'),
(167, 'Здесь Чичиков вышел совершенно из границ всякого терпения.', 'Здесь Чичиков вышел совершенно из границ всякого терпения, хватил в сердцах стулом об пол и посулил ей черта.', '.', '202.jpg', 30, '2024-04-21 22:19:19'),
(168, '— Ох, не припоминай его, бог с ним! — вскрикнула она, вся побледнев.', '— Ох, не припоминай его, бог с ним! — вскрикнула она, вся побледнев. — Еще третьего дня всю ночь мне снился окаянный. Вздумала было на ночь загадать на картах после молитвы, да, видно, в наказание-то бог и наслал его.', ' Такой гадкий привиделся; а рога-то длиннее бычачьих.', '100.jpg', 32, '2024-04-15 21:12:18'),
(169, '— Я дивлюсь, как они вам десятками не снятся.', '— Я дивлюсь, как они вам десятками не снятся. Из одного христианского человеколюбия хотел: вижу, бедная вдова убивается, терпит нужду… да пропади и околей со всей вашей деревней!..', '.', '102.jpg', 35, '2024-04-13 18:18:05'),
(170, '— Ах, какие ты забранки пригинаешь! — сказала старуха, глядя на него со страхом.', '— Ах, какие ты забранки пригинаешь! — сказала старуха, глядя на него со страхом.', '.', '002.jpg', 23, '2024-04-07 17:56:14'),
(171, '— Да не найдешь слов с вами.', '— Да не найдешь слов с вами! Право, словно какая-нибудь, не говоря дурного слова, дворняжка, что лежит на сене и сам не ест сена, и другим не лает.', ' Я хотел было закупать у вас хозяйственные продукты разные, потому что я и казенные подряды тоже веду… — Здесь он прилгнул, хоть и вскользь и без всякого дальнейшего размышления, но неожиданно удачно.', '301.jpg', 21, '2024-03-30 14:29:21'),
(172, '— Да чего ж ты рассердился так горячо.', '— Да чего ж ты рассердился так горячо? Знай я прежде, что ты такой сердитый, да я бы совсем тебе и не прекословила.', '.', '201.jpg', 49, '2024-03-27 08:41:45'),
(173, '— Есть из чего сердиться.', '— Есть из чего сердиться! Дело яйца выеденного не стоит, а я стану из-за него сердиться.', '— Есть из чего сердиться! Дело яйца выеденного не стоит, а я стану из-за него сердиться.', '201.jpg', 39, '2024-03-22 03:42:11'),
(174, '— Ну, да изволь, я готова отдать за пятнадцать ассигнацией.', '— Ну, да изволь, я готова отдать за пятнадцать ассигнацией! Только смотри, отец мой, а насчет подрядов-то: если случится муки брать ржаной, или гречневой, или круп, или скотины битой, так уж, пожалуйста, не обидь меня.', '.', '002.jpg', 15, '2024-03-11 23:29:53'),
(175, '— Нет, матушка, не обижу, — говорил он, а между тем отирал рукою пот.', '— Нет, матушка, не обижу, — говорил он, а между тем отирал рукою пот, который в три ручья катился по лицу его.', ' Он расспросил ее, не имеет ли она в городе какого-нибудь поверенного или знакомого, которого бы могла уполномочить на совершение крепости и всего, что следует.', '103.jpg', 48, '2024-03-08 18:39:23'),
(176, 'Чичиков попросил ее написать к нему доверенное письмо и.', 'Чичиков попросил ее написать к нему доверенное письмо и, чтобы избавить от лишних затруднений, сам даже взялся сочинить.', '.', '100.jpg', 14, '2024-03-05 13:53:40'),
(177, '«Хорошо бы было, — подумала между тем про себя Коробочка.', '«Хорошо бы было, — подумала между тем про себя Коробочка, — если бы он забрал у меня в казну муку и скотину.', ' Нужно его задобрить: теста со вчерашнего вечера еще осталось, так пойти сказать Фетинье, чтоб спекла блинов; хорошо бы также загнуть пирог пресный с яйцом, у меня его славно загибают, да и времени берет немного». Хозяйка вышла с тем чтобы привести в исполнение мысль насчет загнутия пирога и, вероятно, пополнить ее другими произведениями домашней пекарни и стряпни; а Чичиков вышел в гостиную, где провел ночь, с тем чтобы вынуть нужные бумаги из своей шкатулки. В гостиной давно уже было все прибрано, роскошные перины вынесены вон, перед диваном стоял покрытый стол. Поставив на него шкатулку, он несколько отдохнул, ибо чувствовал, что был весь в поту, как в реке: все, что ни было на нем, начиная от рубашки до чулок, все было мокро. «Эк уморила как проклятая старуха» — сказал он, немного отдохнувши, и отпер шкатулку. Автор уверен, что есть читатели такие любопытные, которые пожелают даже узнать план и внутреннее расположение шкатулки. Пожалуй, почему же не удовлетворить! Вот оно, внутреннее расположение: в самой средине мыльница, за мыльницею шесть-семь узеньких перегородок для бритв; потом квадратные закоулки для песочницы и чернильницы с выдолбленною между ними лодочкой для перьев, сургучей и всего, что подлиннее; потом всякие перегородки с крышечками и без крышечек для того, что покороче, наполненные билетами визитными, похоронными, театральными и другими, которые складывались на память. Весь верхний ящик со всеми перегородками вынимался, и под ним находилось пространство, занятое кипами бумаг в лист, потом следовал маленький потаенный ящик для денег, выдвигавшийся незаметно сбоку шкатулки. Он всегда так поспешно выдвигался и задвигался в ту же минуту хозяином, что наверно нельзя сказать, сколько было там денег. Чичиков тут же занялся и, очинив перо, начал писать. В это время вошла хозяйка.', '201.jpg', 59, '2024-02-28 09:14:31'),
(178, '— Хорош у тебя ящик, отец мой, — сказала она, подсевши к нему.', '— Хорош у тебя ящик, отец мой, — сказала она, подсевши к нему.', ' — Чай, в Москве купил его.', '301.jpg', 35, '2024-02-25 08:17:07'),
(179, '— Я уж знала это: там все хорошая работа.', '— Я уж знала это: там все хорошая работа. Третьего года сестра моя привезла оттуда теплые сапожки для детей: такой прочный товар, до сих пор носится. Ахти, сколько у тебя тут гербовой бумаги! — продолжала она заглянувши к нему в шкатулку.', ' И в самом деле, гербовой бумаги было там немало. — Хоть бы мне листок подарил! а у меня такой недостаток; случится в суд просьбу подать, а и не на чем.', '203.jpg', 55, '2024-02-20 07:14:58'),
(180, 'Чичиков объяснил ей, что эта бумага не такого рода.', 'Чичиков объяснил ей, что эта бумага не такого рода, что она назначена для совершения крепостей, а не для просьб. Впрочем, чтобы успокоить ее, он дал ей какой-то лист в рубль ценою.', ' Написавши письмо, дал он ей подписаться и попросил маленький списочек мужиков. Оказалось, что помещица не вела никаких записок, ни списков, а знала почти всех наизусть; он заставил ее тут же продиктовать их. Некоторые крестьяне несколько изумили его своими фамилиями, а еще более прозвищами, так что он всякий раз, слыша их, прежде останавливался, а потом уже начинал писать. Особенно поразил его какой-то Петр Савельев Неуважай-Корыто, так что он не мог не сказать: «Экой длинный!» Другой имел прицепленный к имени «Коровий кирпич», иной оказался просто: Колесо Иван. Оканчивая писать, он потянул несколько к себе носом воздух и услышал завлекательный запах чего-то горячего в масле.', '103.jpg', 33, '2024-02-12 02:44:05'),
(181, 'Чичиков оглянулся и увидел, что на столе стояли уже грибки, пирожки, скородумки.', 'Чичиков оглянулся и увидел, что на столе стояли уже грибки, пирожки, скородумки, шанишки, пряглы, блины, лепешки со всякими припеками: припекой с лучком, припекой с маком, припекой с творогом, припекой со сняточками, и невесть чего не было.', '.', '202.jpg', 28, '2024-02-06 23:42:55'),
(182, '— У вас, матушка, блинцы очень вкусны, — сказал Чичиков.', '— У вас, матушка, блинцы очень вкусны, — сказал Чичиков, принимаясь за принесенные горячие.', '.', '102.jpg', 34, '2026-03-06 05:17:32'),
(183, '— Да у меня-то их хорошо пекут, — сказала хозяйка, — да вот беда, урожай плох.', '— Да у меня-то их хорошо пекут, — сказала хозяйка, — да вот беда: урожай плох, мука уж такая неважная… Да что же, батюшка, вы так спешите? — проговорила она, увидя, что Чичиков взял в руки картуз, — ведь и бричка еще не заложена.', '.', '101.jpg', 42, '2026-03-05 03:56:16'),
(184, '— Может быть, понадобится птичьих перьев.', '— Может быть, понадобится птичьих перьев. У меня к Филиппову посту будут и птичьи перья.', '.', '103.jpg', 58, '2026-02-27 22:02:56'),
(185, '— Вот видишь, отец мой, и бричка твоя еще не готова, — сказала хозяйка.', '— Вот видишь, отец мой, и бричка твоя еще не готова, — сказала хозяйка, когда они вышли на крыльцо.', '.', '201.jpg', 42, '2026-02-17 16:03:30'),
(186, '— Как же бы это сделать? — сказала хозяйка.', '— Как же бы это сделать? — сказала хозяйка. — Рассказать-то мудрено, поворотов много; разве я тебе дам девчонку, чтобы проводила. Ведь у тебя, чай, место есть на козлах, где бы присесть ей.', '.', '301.jpg', 45, '2026-02-11 10:59:19'),
(187, '— Пожалуй, я тебе дам девчонку; она у меня знает дорогу, только ты смотри.', '— Пожалуй, я тебе дам девчонку; она у меня знает дорогу, только ты смотри! не завези ее, у меня уже одну завезли купцы.', '.', '101.jpg', 47, '2026-02-06 10:37:49'),
(188, 'Чичиков уверил ее, что не завезет, и Коробочка, успокоившись.', 'Чичиков уверил ее, что не завезет, и Коробочка, успокоившись, уже стала рассматривать все, что было во дворе ее, вперила глаза на ключницу, выносившую из кладовой деревянную побратиму с медом, на мужика, показавшегося в воротах.', 'Чичиков уверил ее, что не завезет, и Коробочка, успокоившись, уже стала рассматривать все, что было во дворе ее; вперила глаза на ключницу, выносившую из кладовой деревянную побратиму с медом, на мужика, показавшегося в воротах, и мало-помалу вся переселилась в хозяйственную жизнь. Но зачем так долго заниматься Коробочкой? Коробочка ли, Манилова ли, хозяйственная ли жизнь, или нехозяйственная — мимо их! Не то на свете дивно устроено: веселое мигом обратится в печальное, если только долго застоишься перед ним, и тогда бог знает что взбредет в голову. Может быть, станешь даже думать: да полно, точно ли Коробочка стоит так низко на бесконечной лестнице человеческого совершенствования? Точно ли так велика пропасть, отделяющая ее от сестры ее, недосягаемо огражденной стенами аристократического дома с благовонными чугунными лестницами, сияющей медью, красным деревом и коврами, зевающей за недочитанной книгой в ожидании остроумно-светского визита, где ей предстанет поле блеснуть умом и высказать вытверженные мысли, мысли, занимающие по законам моды на целую неделю город, мысли не о том, что делается в ее доме и в ее поместьях, запутанных и расстроенных благодаря незнанью хозяйственного дела, а о том, какой политический переворот готовится во Франции, какое направление принял модный католицизм. Но мимо, мимо! зачем говорить об этом? Но зачем же среди недумающих.', '102.jpg', 48, '2026-01-27 10:12:02'),
(189, '— А вот бричка, вот бричка.', '— А вот бричка, вот бричка! — вскричал Чичиков, увидя наконец подъезжавшую свою бричку. — Что ты, болван, так долго копался? Видно, вчерашний хмель у тебя не весь еще выветрило.', '.', '101.jpg', 15, '2026-01-19 05:13:12'),
(190, '— Эй, Пелагея.', '— Эй, Пелагея! — сказала помещица стоявшей около крыльца девчонке лет одиннадцати, в платье из домашней крашенины и с босыми ногами, которые издали можно было принять за сапоги, так они были облеплены свежею грязью. — Покажи-ка барину дорогу.', '.', '201.jpg', 5, '2026-01-09 00:04:43'),
(191, 'Селифан помог взлезть девчонке на козлы, которая.', 'Селифан помог взлезть девчонке на козлы, которая, ставши одной ногой на барскую ступеньку, сначала запачкала ее грязью, а потом уже взобралась на верхушку и поместилась возле него.', ' Вслед за нею и сам Чичиков занес ногу на ступеньку и, понагнувши бричку на правую сторону, потому что был тяжеленек, наконец поместился, сказавши.', '101.jpg', 46, '2026-01-02 22:15:04'),
(192, 'Селифан был во всю дорогу суров, и с тем вместе очень внимателен к своему делу.', 'Селифан был во всю дорогу суров, и с тем вместе очень внимателен к своему делу, что случалося с ним всегда после того, когда либо в чем провинился, либо был пьян. Лошади были удивительно как вычищены.', ' Хомут на одной из них, надевавшийся дотоле почти всегда в разодранном виде, так что из-под кожи выглядывала пакля, был искусно зашит. Во всю дорогу был он молчалив, только похлестывал кнутом, и не обращал никакой поучительной речи к лошадям, хотя чубарому коню, конечно, хотелось бы выслушать что-нибудь наставительное, ибо в это время вожжи всегда как-то лениво держались в руках словоохотного возницы и кнут только для формы гулял поверх спин. Но из угрюмых уст слышны были на сей раз одни однообразно неприятные восклицания: «Ну же, ну, ворона! зевай! зевай!» — и больше ничего. Даже сам гнедой и Заседатель были недовольны, не услышавши ни разу ни «любезные», ни «почтенные». Чубарый чувствовал пренеприятные удары по своим полным и широким частям. «Вишь ты, как разнесло его! — думал он сам про себя, несколько припрядывая ушами. — Небось знает, где бить! Не хлыснет прямо по спине, а так и выбирает место, где поживее: по ушам зацепит или под брюхо захлыснет».', '002.jpg', 6, '2025-12-31 20:00:55'),
(193, '— Направо, что ли.', '— Направо, что ли? — с таким сухим вопросом обратился Селифан к сидевшей возле него девчонке, показывая ей кнутом на почерневшую от дождя дорогу между яркозелеными, освещенными полями.', '.', '302.jpg', 35, '2025-12-23 15:16:49'),
(194, '— Эх ты! — сказал Селифан.', '— Эх ты! — сказал Селифан.', ' — Да это и есть направо: не знает, где право, где лево.', '101.jpg', 54, '2025-12-21 13:37:52'),
(195, 'Хотя день был очень хорош, но земля до такой степени загрязнилась.', 'Хотя день был очень хорош, но земля до такой степени загрязнилась, что колеса брички, захватывая ее, сделались скоро покрытыми ею, как войлоком, что значительно отяжелило экипаж; к тому же почва была глиниста и цепка необыкновенно.', ' То и другое было причиною, что они не могли выбраться из проселков раньше полудня. Без девчонки было бы трудно сделать и это, потому что дороги расползались во все стороны, как пойманные раки, когда их высыпают из мешка, и Селифану довелось бы поколесить уже не по своей вине.', '103.jpg', 44, '2025-12-20 10:37:22'),
(196, 'Чичиков дал ей медный грош, и она побрела восвояси, уже довольная тем.', 'Чичиков дал ей медный грош, и она побрела восвояси, уже довольная тем, что посидела на козлах.', '.', '302.jpg', 29, '2025-12-15 08:57:55'),
(197, 'Подъехавши к трактиру, Чичиков велел остановиться по двум причинам.', 'Подъехавши к трактиру, Чичиков велел остановиться по двум причинам. С одной стороны, чтоб дать отдохнуть лошадям, а с другой стороны, чтоб и самому несколько закусить и подкрепиться.', ' Автор должен признаться, что весьма завидует аппетиту и желудку такого рода людей. Для него решительно ничего не значат все господа большой руки, живущие в Петербурге и Москве, проводящие время в обдумывании, что бы такое поесть завтра и какой бы обед сочинить на послезавтра, и принимающиеся за этот обед не иначе, как отправивши прежде в рот пилюлю; глотающие устерс, морских пауков и прочих чуд, а потом отправляющиеся в Карлсбад или на Кавказ. Нет, эти господа никогда не возбуждали в нем зависти. Но господа средней руки, что на одной станции потребуют ветчины, на другой поросенка, на третьей ломоть осетра или какую-нибудь запеканную колбасу с луком и потом как ни в чем не бывало садятся за стол в какое хочешь время, и стерляжья уха с налимами и молоками шипит и ворчит у них меж зубами, заедаемая расстегаем или кулебякой с сомовьим плёсом, так что вчуже пронимает аппетит, — вот эти господа, точно, пользуются завидным даянием неба! Не один господин большой руки пожертвовал бы сию же минуту половину душ крестьян и половину имений, заложенных и только, чтобы иметь такой желудок, какой имеет господин средней руки; но то беда, что ни за какие деньги, ниже&#769; имения, с улучшениями и без улучшений, нельзя приобресть такого желудка, какой бывает у господина средней руки.', '203.jpg', 6, '2025-12-14 04:27:48'),
(198, 'Деревянный потемневший трактир принял Чичикова...', 'Деревянный потемневший трактир принял Чичикова... под свой узенький гостеприимный навес на деревянных выточенных столбиках, похожих на старинные церковные подсвечники. Трактир был что-то вроде русской избы, несколько в большем размере.', ' Резные узорочные карнизы из свежего дерева вокруг окон и под крышей резко и живо пестрели темные его стены; на ставнях были нарисованы кувшины с цветами.', '202.jpg', 3, '2025-12-05 04:01:53'),
(199, 'Взобравшись узенькою деревянною лестницею наверх, в широкие сени.', 'Взобравшись узенькою деревянною лестницею наверх, в широкие сени, он встретил отворявшуюся со скрипом дверь и толстую старуху в пестрых ситцах, проговорившую: «Сюда пожалуйте.', 'Взобравшись узенькою деревянною лестницею наверх, в широкие сени, он встретил отворявшуюся со скрипом дверь и толстую старуху в пестрых ситцах, проговорившую: «Сюда пожалуйте!» В комнате попались всё старые приятели, попадающиеся всякому в небольших деревянных трактирах, каких немало выстроено по дорогам, а именно заиндевелый самовар, выскобленные гладко сосновые стены, трехугольный шкаф с чайниками и чашками в углу, фарфоровые вызолоченные яички пред образами, висевшие на голубых и красных ленточках, окотившаяся недавно кошка, зеркало, показывавшее вместо двух четыре глаза, а вместо лица какую-то лепешку; наконец натыканные пучками душистые травы и гвоздики у образов, высохшие до такой степени, что желавший понюхать их только чихал и больше ничего.', '102.jpg', 10, '2025-11-30 01:01:17'),
(200, 'Старуха пошла копаться и принесла тарелку, салфетку.', 'Старуха пошла копаться и принесла тарелку, салфетку, накрахмаленную до того что дыбилась, как засохшая кора, потом нож с пожелтевшею костяною колодочкою, тоненький, как перочинный, двузубую вилку и солонку.', 'Старуха пошла копаться и принесла тарелку, салфетку, накрахмаленную до того что дыбилась, как засохшая кора, потом нож с пожелтевшею костяною колодочкою, тоненький, как перочинный, двузубую вилку и солонку, которую никак нельзя было поставить прямо на стол.', '100.jpg', 29, '2025-11-25 22:47:06'),
(201, 'Герой наш, по обыкновению, сейчас вступил с нею в разговор и расспросил.', 'Герой наш, по обыкновению, сейчас вступил с нею в разговор и расспросил, сама ли она держит трактир, или есть хозяин, а сколько дает доходу трактир, и с ними ли живут сыновья, и что старший сын холостой или женатый человек, и какую взял жену.', 'Герой наш, по обыкновению, сейчас вступил с нею в разговор и расспросил, сама ли она держит трактир, или есть хозяин, а сколько дает доходу трактир, и с ними ли живут сыновья, и что старший сын холостой или женатый человек, и какую взял жену, с большим ли приданым, или нет, и доволен ли был тесть, и не сердился ли, что мало подарков получил на свадьбе, — словом, не пропустил ничего. Само собою разумеется, что полюбопытствовал узнать, какие в окружности находятся у них помещики, и узнал, что всякие есть помещики: Плотин, Почитаев, Мыльной, Чепраков-полковник, Собакевич. «А! Собакевича знаешь?» — спросил он и тут же услышал, что старуха знает не только Собакевича, но и Манилова, и что Манилов будет поделикатней Собакевича: велит тотчас сварить курицу, спросит и телятинки; коли есть баранья печенка, то и бараньей печенки спросит, и всего только что попробует, а Собакевич одного чего-нибудь спросит, да уж зато всё съест, даже и подбавки потребует за ту же цену.', '202.jpg', 51, '2025-11-21 18:34:24'),
(202, 'Когда он таким образом разговаривал, кушая поросенка.', 'Когда он таким образом разговаривал, кушая поросенка, которого оставался уже последний кусок, послышался стук колес подьехавшего экипажа.', ' Взглянувши в окно, увидел он остановившуюся перед трактиром легонькую бричку, запряженную тройкою добрых лошадей. Из брички вылезали двое какие-то мужчин. Один белокурый, высокого роста; другой немного пониже, чернявый. Белокурый был в темно-синей венгерке, чернявый просто в полосатом архалуке. Издали тащилась еще колясчонка, пустая, влекомая какой-то длинношерстной четверней с изорванными хомутами и веревочной упряжью. Белокурый тотчас же отправился по лестнице наверх, между тем как черномазый еще оставался и щупал что-то в бричке, разговаривая тут же со слугою и махая в то же время ехавшей за ними коляске. Голос его показался Чичикову как будто несколько знакомым. Пока он его рассматривал, белокурый успел уже нащупать дверь и отворить ее. Это был мужчина высокого роста, лицом худощавый, или что называют издержанный, с рыжими усиками. По загоревшему лицу его можно было заключить, что он знал, что такое дым, если не пороховой, то по крайней мере табачный. Он вежливо поклонился Чичикову, на что последний ответил тем же. В продолжение немногих минут они вероятно бы разговорились и хорошо познакомились между собою, потому что уже начало было сделано, и оба почти в одно и то же время изъявили удовольствие, что пыль по дороге была совершенно прибита вчерашним дождем и теперь ехать и прохладно и приятно, как вошел чернявый его товарищ, сбросив с головы на стол картуз свой, молодцевато взъерошив рукой свои черные густые волосы. Это был среднего роста, очень недурно сложенный молодец с полными румяными щеками, с белыми, как снег, зубами и черными, как смоль, бакенбардами. Свеж он был, как кровь с молоком; здоровье, казалось, так и прыскало с лица его.', '301.jpg', 40, '2025-11-11 16:18:43'),
(203, '— Ба, ба, ба! — вскричал он вдруг, расставив обе руки при виде Чичикова.', '— Ба, ба, ба! — вскричал он вдруг, расставив обе руки при виде Чичикова.', ' — Какими судьбами.', '302.jpg', 3, '2025-11-06 12:40:23'),
(204, 'Чичиков узнал Ноздрева, того самого.', 'Чичиков узнал Ноздрева, того самого, с которым он вместе обедал у прокурора и который с ним в несколько минут сошелся на такую короткую ногу, что начал уже говорить «ты», хотя, впрочем, он с своей стороны не подал к тому никакого повода.', '.', '202.jpg', 3, '2025-11-04 07:09:11'),
(205, '— Куда ездил.', '— Куда ездил? — говорил Ноздрев и, не дождавшись ответа, продолжал: — А я, брат, с ярмарки. Поздравь: продулся в пух! Веришь ли, что никогда в жизни так не продувался.', ' Ведь я на обывательских приехал! Вот посмотри нарочно в окно! — Здесь он нагнул сам голову Чичикова, так что тот чуть не ударился ею об рамку. — Видишь, какая дрянь! Насилу дотащили, проклятые, я уже перелез вот в его бричку. — Говоря это, Ноздрев показал пальцем на своего товарища. — А вы еще не знакомы? Зять мой Мижуев! Мы с ним все утро говорили о тебе. «Ну, смотри, говорю, если мы не встретим Чичикова» Ну, брат, если б ты знал, как я продулся! Поверишь ли, что не только убухал четырех рысаков — всё спустил. Ведь на мне нет ни цепочки, ни часов… — Чичиков взглянул и увидел точно, что на нем не было ни цепочки, ни часов. Ему даже показалось, что и один бакенбард был у него меньше и не так густ, как другой. — А ведь будь только двадцать рублей в кармане, — продолжал Ноздрев, — именно не больше как двадцать, я отыграл бы все, то есть кроме того, что отыграл бы, вот как честный человек, тридцать тысяч сейчас положил бы в бумажник.', '201.jpg', 26, '2025-11-01 05:16:30'),
(206, '— Ты, однако, и тогда так говорил, — отвечал белокурый.', '— Ты, однако, и тогда так говорил, — отвечал белокурый, — а когда я тебе дал пятьдесят рублей, тут же просадил их.', '.', '103.jpg', 32, '2025-10-26 02:25:04'),
(207, '— И не просадил бы! ей-богу, не просадил бы.', '— И не просадил бы! ей-богу, не просадил бы! Не сделай я сам глупость, право, не просадил бы. Не загни я после пароле на проклятой семерке утку, я бы мог сорвать весь банк.', '.', '301.jpg', 37, '2025-10-17 22:32:00'),
(208, '— Не сорвал потому, что загнул утку не вовремя.', '— Не сорвал потому, что загнул утку не вовремя.', ' А ты думаешь, майор твой хорошо играет.', '203.jpg', 36, '2025-10-10 16:51:14');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(209, '— Эка важность! — сказал Ноздрей, — этак и я его обыграю.', '— Эка важность! — сказал Ноздрей, — этак и я его обыграю. Нет, вот попробуй он играть дублетом, так вот тогда я посмотрю, я посмотрю тогда, какой он игрок! Зато, брат Чичиков, как покатили мы в первые дни! Правда, ярмарка была отличнейшая.', ' Сами купцы говорят, что никогда не было такого съезда. У меня все, что ни привезли из деревни, продали по самой выгоднейшей цене. Эх, братец, как покутили! Теперь даже, как вспомнишь… черт возьми! то есть как жаль, что ты не был. Вообрази, что в трех верстах от города стоял драгунский полк. Веришь ли, что офицеры, сколько их ни было, сорок человек одних офицеров было в городе; как начали мы, братец, пить… Штабс-ротмистр Поцелуев… такой славный! усы, братец, такие! Бордо называет просто бурдашкой. «Принеси-ка, брат, говорит, бурдашки!» Поручик Кувшинников… Ах, братец, какой премилый человек! вот уж, можно сказать, во всей форме кутила. Мы все были с ним вместе. Какого вина отпустил нам Пономарев! Нужно тебе знать, что он мошенник и в его лавке ничего нельзя брать: в вино мешает всякую дрянь: сандал, жженую пробку и даже бузиной, подлец, затирает; но зато уж если вытащит из дальней комнатки, которая называется у него особенной, какую-нибудь бутылочку — ну просто, брат, находишься в эмпиреях. Шампанское у нас было такое — что пред ним губернаторское? просто квас. Вообрази, не клико, а какое-то клико-матрадура, это значит двойное клико. И еще достал одну бутылочку французского под названием: бонбон. Запах? — розетка и все что хочешь. Уж так покутили!.. После нас приехал какой-то князь, послал в лавку за шампанским, нет ни одной бутылки во всем городе, все офицеры выпили.', '102.jpg', 18, '2025-10-09 12:06:16'),
(210, '— Ты можешь себе говорить все что хочешь, а я тебе говорю.', '— Ты можешь себе говорить все что хочешь, а я тебе говорю, что и десяти не выпьешь.', '.', '301.jpg', 30, '2025-10-03 09:20:30'),
(211, '— Да, был бы ты без ружья, как без шапки.', '— Да, был бы ты без ружья, как без шапки. Эх, брат Чичиков, то есть как я жалел, что тебя не было Я знаю, что ты бы не расстался с поручиком Кувшинниковым.', ' Уж как бы вы с ним хорошо сошлись! Это не то что прокурор и все губернские скряги в нашем городе, которые так и трясутся за каждую копейку. Этот, братец, и в гальбик, и в банчишку, и во все что хочешь. Эх, Чичиков, ну что бы тебе стоило приехать? Право, свинтус ты за это, скотовод эдакой! Поцелуй меня, душа, смерть люблю тебя! Мижуев, смотри, вот судьба свела: ну что он мне или я ему? Он приехал бог знает откуда, я тоже здесь живу… А сколько было, брат, карет, и все это en gros. В фортунку крутнул: выиграл две банки помады, фарфоровую чашку и гитару; потом опять поставил один раз и прокрутил, канальство, еще сверх шесть целковых. А какой, если б ты знал, волокита Кувшинников! Мы с ним были на всех почти балах. Одна была такая разодетая, рюши на ней, и трюши, и черт знает чего не было… я думаю себе только: «черт возьми!» А Кувшинников, то есть это такая бестия, подсел к ней и на французском языке подпускает ей такие комплименты… Поверишь ли, простых баб не пропустил. Это он называет: попользоваться насчет клубнички. Рыб и балыков навезли чудных. Я таки привез с собою один; хорошо, что догадался купить, когда были еще деньги.', '101.jpg', 34, '2025-09-26 08:50:44'),
(212, 'Здесь Ноздрей захохотал тем звонким смехом, каким заливается только свежий.', 'Здесь Ноздрей захохотал тем звонким смехом, каким заливается только свежий, здоровый человек, у которого все до последнего выказываются белые, как сахар, зубы, дрожат и прыгают щеки, а сосед за двумя дверями, в третьей комнате, вскидывается со сна.', 'Здесь Ноздрей захохотал тем звонким смехом, каким заливается только свежий, здоровый человек, у которого все до последнего выказываются белые, как сахар, зубы, дрожат и прыгают щеки, а сосед за двумя дверями, в третьей комнате, вскидывается со сна, вытаращив очи и произнося: «Эк его разобрало.', '201.jpg', 21, '2025-09-22 04:37:15'),
(213, '— Да ведь ты жизни не будешь рад, когда приедешь к нему, это просто жидомор.', '— Да ведь ты жизни не будешь рад, когда приедешь к нему, это просто жидомор! Ведь я знаю твой характер, ты жестоко опешишься, если думаешь найти там банчишку и добрую бутылку какого-нибудь бонбона.', ' Послушай, братец: ну к черту Собакевича, поедем во мне! каким балыком попотчую! Пономарев, бестия, так раскланивался, говорит: «Для вас только, всю ярмарку, говорит, обыщите, не найдете такого». Плут, однако ж, ужасный. Я ему в глаза это говорил: «Вы, говорю, с нашим откупщиком первые мошенники!» Смеется, бестия, поглаживая бороду. Мы с Кувшинниковым каждый день завтракали в его лавке. Ах, брат, вот позабыл тебе сказать: знаю, что ты теперь не отстанешь, но за десять тысяч не отдам, наперед говорю. Эй, Порфирий! — закричал он, подошедши к окну, на своего человека, который держал в одной руке ножик, а в другой корку хлеба с куском балыка, который посчастливилось ему мимоходом отрезать, вынимая что-то из брички. — Эй, Порфирий, — кричал Ноздрев, — принеси-ка щенка! Каков щенок! — продолжал он, обращаясь к Чичикову. — Краденый, ни за самого себя не отдавал хозяин. Я ему сулил каурую кобылу, которую, помнишь, выменял у Хвостырева… — Чичиков, впрочем, отроду не видел ни каурой кобылы, ни Хвостырева.', '203.jpg', 37, '2025-09-21 04:04:18'),
(214, '— Барин! ничего не хотите закусить.', '— Барин! ничего не хотите закусить? — сказала в это время, подходя к нему, старуха.', '.', '101.jpg', 51, '2025-09-10 22:05:44'),
(215, '— Ничего.', '— Ничего.', ' Эх, брат, как покутили! Впрочем, давай рюмку водки; какая у тебя есть.', '203.jpg', 26, '2025-09-04 16:16:54'),
(216, '— Вот щенок! — сказал Ноздрев, взявши его за приподнявши рукою.', '— Вот щенок! — сказал Ноздрев, взявши его за приподнявши рукою. Щенок испустил довольно жалобный вой.', '.', '002.jpg', 43, '2026-02-23 02:40:08'),
(217, '— Ты, однако ж, не сделал того, что я тебе говорил, — сказал Ноздрев.', '— Ты, однако ж, не сделал того, что я тебе говорил, — сказал Ноздрев, обратившись к Порфирию и рассматривая брюхо щенка, — и не подумал вычесать его.', '— Ты, однако ж, не сделал того, что я тебе говорил, — сказал Ноздрев, обратившись к Порфирию и рассматривая брюхо щенка, — и не подумал вычесать его.', '100.jpg', 58, '2026-02-15 00:41:31'),
(218, '— Врешь, врешь, и не воображал чесать; я думаю, дурак, еще своих напустил.', '— Врешь, врешь, и не воображал чесать; я думаю, дурак, еще своих напустил. Вот посмотри-ка, Чичиков, посмотри, какие уши, на-ка пощупай рукою.', '.', '101.jpg', 12, '2026-02-06 23:44:04'),
(219, '— Настоящий мордаш, — продолжал Ноздрев, — а, признаюсь.', '— Настоящий мордаш, — продолжал Ноздрев, — а, признаюсь, давно острил зубы на мордаша.', ' На, Порфирий, отнеси его.', '103.jpg', 25, '2026-01-28 21:32:50'),
(220, '— Послушай, Чичиков, ты должен непременно теперь ехать ко мне, пять верст всего.', '— Послушай, Чичиков, ты должен непременно теперь ехать ко мне, пять верст всего, духом домчимся, а там, пожалуй, можешь и к Собакевичу.', '.', '201.jpg', 48, '2026-01-21 16:52:32'),
(221, '«А что ж, — подумал про себя Чичиков, — заеду я в самом деле к Ноздреву.', '«А что ж, — подумал про себя Чичиков, — заеду я в самом деле к Ноздреву. Чем же он хуже других, такой же человек, да еще и проигрался. Горазд он, как видно, на все, стало быть у него даром можно кое-что выпросить».', '.', '102.jpg', 7, '2026-01-20 10:48:34'),
(222, '— Ну, душа, вот это так! Вот это хорошо, постой же, я тебя поцелую за это.', '— Ну, душа, вот это так! Вот это хорошо, постой же, я тебя поцелую за это. — Здесь Ноздрев и Чичиков поцеловались.', ' — И славно: втроем и покатим.', '002.jpg', 43, '2026-01-19 08:06:13'),
(223, '— Нет, ты уж, пожалуйста, меня-то отпусти, — говорил белокурый.', '— Нет, ты уж, пожалуйста, меня-то отпусти, — говорил белокурый, — мне нужно домой.', '.', '103.jpg', 44, '2026-01-16 06:27:30'),
(224, '— Право, жена будет сердиться, теперь же ты можешь.', '— Право, жена будет сердиться; теперь же ты можешь, пересесть вот в ихнюю бричку.', '.', '202.jpg', 14, '2026-01-13 05:52:37'),
(225, 'Белокурый был один из тех людей.', 'Белокурый был один из тех людей, в характере которых на первый взгляд есть какое-то упорство.', ' Еще не успеешь открыть рта, как они уже готовы спорить и, кажется, никогда не согласятся на то, что явно противуположно их образу мыслей, что никогда не назовут глупого умным и что в особенности не согласятся плясать по чужой дудке; а кончится всегда тем, что в характере их окажется мягкость, что они согласятся именно на то, что отвергали, глупое назовут умным и пойдут потом поплясывать как нельзя лучше под чужую дудку, — словом, начнут гладью, а кончат гадью.', '203.jpg', 36, '2026-01-10 00:30:51'),
(226, '— Вздор.', '— Вздор! — сказал Ноздрев в ответ на каков-то ставление белокурого, надел ему на голову картуз, и — белокурый отправился вслед за ними.', '.', '203.jpg', 53, '2026-01-07 22:48:26'),
(227, '— А, хорошо, хорошо, матушка. Послушай, зятек! заплати, пожалуйста.', '— А, хорошо, хорошо, матушка. Послушай, зятек! заплати, пожалуйста. У меня нет ни копейки в кармане.', '.', '002.jpg', 21, '2026-01-05 19:08:14'),
(228, '— Маловато, барин, — сказала старуха.', '— Маловато, барин, — сказала старуха, однако ж взяла деньги с благодарностию и еще побежала впопыхах отворять им дверь. Она была не в убытке, потому что запросила вчетверо против того, что стоила водка.', '.', '203.jpg', 21, '2025-12-26 18:16:40'),
(229, 'Приезжие уселись.', 'Приезжие уселись. Бричка Чичикова ехала рядом с бричкой, в которой сидели Ноздрев и его зять, и потому они все трое могли свободно между собою разговаривать в продолжение дороги.', ' За ними следовала, беспрестанно отставая, небольшая колясчонка Ноздрева на тощих обывательских лошадях. В ней сидел Порфирий с щенком.', '002.jpg', 35, '2025-12-16 18:00:51'),
(230, 'Так как разговор, который путешественники вели между собою.', 'Так как разговор, который путешественники вели между собою, был не очень интересен для читателя, то сделаем лучше, если скажем что-нибудь о самом Ноздреве, которому, может быть, доведется сыграть не вовсе последнюю роль в нашей поэме.', '.', '100.jpg', 6, '2025-12-09 14:38:45'),
(231, 'Лицо Ноздрева, верно, уже сколько-нибудь знакомо читателю.', 'Лицо Ноздрева, верно, уже сколько-нибудь знакомо читателю. Таких людей приходилось всякому встречать немало. Они называются разбитными малыми, слывут еще в детстве и в школе за хороших товарищей и при всем том бывают весьма больно поколачиваемы.', ' В их лицах всегда видно что-то открытое, прямое, удалое. Они скоро знакомятся, и не успеешь оглянуться, как уже говорят тебе «ты». Дружбу заведут, кажется, навек: но всегда почти так случается, что подружившийся подерется с ними того же вечера на дружеской пирушке. Они всегда говоруны, кутилы, лихачи, народ видный. Ноздрев в тридцать пять лет был таков же совершенно, каким был в осьмнадцать и двадцать: охотник погулять. Женитьба его ничуть не переменила, тем более что жена скоро отправилась на тот свет, оставивши двух ребятишек, которые решительно ему были не нужны. За детьми, однако ж, присматривала смазливая нянька. Дома он больше дня никак не мог усидеть. Чуткий нос его слышал за несколько десятков верст, где была ярмарка со всякими съездами и балами; он уж в одно мгновенье ока был там, спорил и заводил сумятицу за зеленым столом, ибо имел, подобно всем таковым, страстишку к картишкам. В картишки, как мы уже видели из первой главы, играл он не совсем безгрешно и чисто, зная много разных передержек и других тонкостей, и потому игра весьма часто оканчивалась другою игрою: или поколачивали его сапогами, или же задавали передержку его густым и очень хорошим бакенбардам, так что возвращался домой он иногда с одной только бакенбардой, и то довольно жидкой. Но здоровые и полные щеки его так хорошо были сотворены и вмещали в себе столько растительной силы, что бакенбарды скоро вырастали вновь, еще даже лучше прежних. И что всего страннее, что может только на одной Руси случиться, он чрез несколько времени уже встречался опять с теми приятелями, которые его тузили, и встречался как ни в чем не бывало, и он, как говорится, ничего, и они ничего.', '100.jpg', 18, '2025-11-30 11:13:26'),
(232, 'Ноздрев был в некотором отношении исторический человек.', 'Ноздрев был в некотором отношении исторический человек. Ни на одном собрании, где он был, не обходилось без истории.', ' Какая-нибудь история непременно происходила: или выведут его под руки из зала жандармы, или принуждены бывают вытолкать свои же приятели. Если же этого не случится, то все-таки что-нибудь да будет такое, чего с другим никак не будет: или нарежется в буфете таким образом, что только смеется, или проврется самым жестоким образом, так что наконец самому сделается совестно. И наврет совершенно без всякой нужды: вдруг расскажет, что у него была лошадь какой-нибудь голубой или розовой шерсти, и тому подобную чепуху, так что слушающие наконец все отходят, произнесши: «Ну, брат, ты, кажется, уже начал пули лить». Есть люди, имеющие страстишку нагадить ближнему, иногда вовсе без всякой причины. Иной, например, даже человек в чинах, с благородною наружностию, со звездой на груди, будет вам жать руку, разговорится с вами о предметах глубоких, вызывающих на размышления, а потом, смотришь, тут же, пред вашими глазами, и нагадит вам. И нагадит так, как простой коллежский регистратор, а вовсе не так, как человек во звездой на груди, разговаривающий о предметах, вызывающих на размышление, так что стоишь только да дивишься, пожимая плечами, да и ничего более. Такую же странную страсть имел и Ноздрев. Чем кто ближе с ним сходился, тому он скорее всех насаливал: распускал небылицу, глупее которой трудно выдумать, расстроивал свадьбу, торговую сделку и вовсе не почитал себя вашим неприятелем; напротив, если случай приводил его опять встретиться с вами, он обходился вновь по-дружески и даже говорил: «Ведь ты такой подлец, никогда ко мне не заедешь». Ноздрев во многих отношениях был многосторонний человек, то есть человек на все руки. В ту же минуту он предлагал вам ехать куда угодно, хоть на край света, войти в какое хотите предприятие, менять все что ни есть на все, что хотите. Ружье, собака, лошадь — все было предметом мены, но вовсе не с тем, чтобы выиграть: это происходило просто от какой-то неугомонной юркости и бойкости характера.', '301.jpg', 20, '2025-11-21 04:55:07'),
(233, 'Между тем три экипажа подкатили уже к крыльцу дома Ноздрева.', 'Между тем три экипажа подкатили уже к крыльцу дома Ноздрева. В доме не было никакого приготовления к их принятию.', ' Посередине столовой стояли деревянные козлы, и два мужика, стоя на них, белили стены, затягивая какую-то бесконечную песню; пол весь был обрызган белилами. Ноздрев приказал тот же час мужиков и козлы вон и выбежал в другую комнату отдавать повеления. Гости слышали, как он заказывал повару обед; сообразив это, Чичиков, начинавший уже несколько чувствовать аппетит, увидел, что раньше пяти часов они не сядут за стол. Ноздрев, возвратившись, повел гостей осматривать все, что ни было у него на деревне, и в два часа с небольшим показал решительно все, так что ничего уж больше не осталось показывать. Прежде всего пошли они обсматривать конюшню, где видели двух кобыл, одну серую в яблоках, другую каурую, потом гнедого жеребца, на вид и неказистого, но за которого Ноздрев божился, что заплатил десять тысяч.', '101.jpg', 21, '2025-11-12 02:08:52'),
(234, 'Потом Ноздрев показал пустые стойла, где были прежде тоже хорошие лошади.', 'Потом Ноздрев показал пустые стойла, где были прежде тоже хорошие лошади.', ' В этой же конюшне видели козла, которого, по старому поверью, почитали необходимым держать при лошадях, который, как казалось, был с ними в ладу, гулял под их брюхами, как у себя дома. Потом Ноздрев повел их глядеть волчонка, бывшего на привязи. «Вот волчонок! — сказал он. — Я его нарочно кормлю сырым мясом. Мне хочется, чтобы он был совершенным зверем!» Пошли смотреть пруд, в котором, по словам Ноздрева, водилась рыба такой величины, что два человека с трудом вытаскивали штуку, в чем, однако ж, родственник не преминул усомниться. «Я тебе, Чичиков, — сказал Ноздрев, — покажу отличнейшую пару собак: крепость черных мясом просто наводит изумление, щиток — игла!» — и повел их к выстроенному очень красиво маленькому домику, окруженному большим загороженным со всех сторон двором. Вошедши на двор, увидели там всяких собак, и густопсовых, и чистопсовых, всех возможных цветов и мастей: муругих, черных с подпалинами, полво-пегих, муруго-пегих, красно-пегих, черноухих, сероухих… Тут были все клички, все повелительные наклонения: стреляй, обругай, порхай, пожар, скосырь, черкай, допекай, припекай, северга, касатка, награда, попечительница. Ноздрев был среди их совершенно как отец среди семейства; все они, тут же пустивши вверх хвосты, зовомые у собачеев прави&#769;лами, полетели прямо навстречу гостям и стали с ними здороваться. Штук десять из них положили свои лапы Ноздреву на плеча. Обругай оказал такую же дружбу Чичикову и, поднявшись на задние ноги, лизнул его языком в самые губы, так что Чичиков тут же выплюнул. Осмотрели собак, наводивших изумление крепостью черных мясов, — хорошие были собаки. Потом пошли осматривать крымскую суку, которая была уже слепая и, по словам Ноздрева, должна была скоро издохнуть, но года два тому назад была очень хорошая сука; осмотрели и суку — сука, точно, была слепая. Потом пошли осматривать водяную мельницу, где недоставало порхлицы, в которую утверждается верхний камень, быстро вращающийся на веретене, — «порхающий», по чудному выражению русского мужика.', '202.jpg', 49, '2025-11-09 01:47:08'),
(235, '— А вот тут скоро будет и кузница! — сказал Ноздрев.', '— А вот тут скоро будет и кузница! — сказал Ноздрев. Немного прошедши, они увидели, точно, кузницу, осмотрели и кузницу.', '.', '102.jpg', 20, '2025-10-31 22:03:50'),
(236, '— Вот на этом поле, — сказал Ноздрев, указывая пальцем на поле.', '— Вот на этом поле, — сказал Ноздрев, указывая пальцем на поле, — русаков такая гибель, что земли не видно; я сам своими руками поймал одного за задние ноги.', '.', '201.jpg', 1, '2025-10-21 17:35:12'),
(237, '— А вот же поймал, нарочно поймал.', '— А вот же поймал, нарочно поймал! — отвечал Ноздрев — Теперь я поведу тебя посмотреть, — продолжал он, обращаясь к Чичикову, — границу, где оканчивается моя земля.', '.', '201.jpg', 10, '2025-10-19 15:32:13'),
(238, 'Ноздрев повел своих гостей полем, которое во многих местах состояло из кочек.', 'Ноздрев повел своих гостей полем, которое во многих местах состояло из кочек. Гости должны были пробираться между перелогами и взбороненными нивами. Чичиков начинал чувствовать усталость.', ' Во многих местах ноги их выдавливали под собою воду, до такой степени место было низко. Сначала они было береглись и переступали осторожно, но потом, увидя, что это ни к чему не служит, брели прямо, не разбирая, где бо&#769;льшая, а где меньшая грязь. Прошедши порядочное расстояние, увидели, точно, границу, состоявшую из деревянного столбика и узенького рва.', '201.jpg', 16, '2025-10-16 15:29:38'),
(239, '— Вот граница! — сказал Ноздрев.', '— Вот граница! — сказал Ноздрев. — Все, что ни видишь по эту сторону, все это мое, и даже по ту сторону, весь этот лес, которым вон синеет, и все, что за лесом, все мое.', '.', '201.jpg', 37, '2025-10-06 11:00:20'),
(240, '— Да когда же этот лес сделался твоим? — спросил зять.', '— Да когда же этот лес сделался твоим? — спросил зять. — Разве ты недавно купил его? Ведь он не был твой.', '.', '102.jpg', 46, '2025-09-27 06:56:27'),
(241, '— Эх ты, Софрон! Разве нельзя быть в одно время и на ярмарке и купить землю.', '— Эх ты, Софрон! Разве нельзя быть в одно время и на ярмарке и купить землю? Ну, я был на ярмарке, а приказчик мой тут без меня и купил.', '.', '103.jpg', 0, '2025-09-18 06:19:58'),
(242, 'Гости воротились тою же гадкою дорогою к дому.', 'Гости воротились тою же гадкою дорогою к дому.', ' Ноздрев повел их в свой кабинет, в котором, впрочем, не было заметно следов того, что бывает в кабинетах, то есть книг или бумаги; висели только сабли и два ружья — одно в триста, а другое в восемьсот рублей. Зять, осмотревши, покачал только головою. Потом были показаны турецкие кинжалы, на одном из которых по ошибке было вырезано: «Мастер Савелий Сибиряков». Вслед за тем показалась гостям шарманка. Ноздрев тут же провертел пред ними кое-что. Шарманка играла не без приятности, но в средине ее, кажется, что-то случилось, ибо мазурка оканчивалась песнею: «Мальбруг в поход поехал», а «Мальбруг в поход поехал» неожиданно завершался каким-то давно знакомым вальсом. Уже Ноздрев давно перестал вертеть, но в шарманке была одна дудка очень бойкая, никак не хотевшая угомониться, и долго еще потому свистела она одна. Потом показались трубки — деревянные, глиняные, пенковые, обкуренные и необкуренные, обтянутые замшею и необтянутые, чубук с янтарным мундштуком, недавно выигранный, кисет, вышитый какою-то графинею, где-то на почтовой станции влюбившеюся в него по уши, у которой ручки, по словам его, были самой субдительной сюперфлю, — слово, вероятно означавшее у него высочайшую точку совершенства. Закусивши балыком, они сели за стол близ пяти часов. Обед, как видно, не составлял у Ноздрева главного в жизни; блюда не играли большой роли: кое-что и пригорело, кое-что и вовсе не сварилось. Видно, что повар руководствовался более каким-то вдохновеньем и клал первое, что попадалось под руку: стоял ли возле него перец — он сыпал перец, капуста ли попалась — совал капусту, пичкал молоко, ветчину, горох — словом, катай-валяй, было бы горячо, а вкус какой-нибудь, верно, выдет. Зато Ноздрев налег на вина: еще не подавали супа, он уже налил гостям по большому стакану портвейна и по другому госотерна, потому что в губернских и уездных городах не бывает простого сотерна. Потому Ноздрев велел принести бутылку мадеры, лучше которой не пивал сам фельдмаршал.', '202.jpg', 59, '2025-09-13 02:31:47'),
(243, '— Нет, не обижай меня, друг мой, право, поеду говорил зять.', '— Нет, не обижай меня, друг мой, право, поеду говорил зять, — ты меня очень обидишь.', '.', '201.jpg', 30, '2025-09-04 23:45:04'),
(244, '— Нет, сооружай, брат, сам, а я не могу, жена будет в большой претензии, право.', '— Нет, сооружай, брат, сам, а я не могу, жена будет в большой претензии, право, я должен ей рассказать о ярмарке Нужно, брат, право, нужно доставить ей удовольствие.', ' Нет, ты не держи меня.', '100.jpg', 14, '2025-08-28 23:15:34'),
(245, '— Нет, брат! она такая почтенная и верная.', '— Нет, брат! она такая почтенная и верная! Услуги оказывает такие… поверишь, у меня слезы на глазах. Нет, ты не держи меня; как честный человек, поеду. Я тебя в этом уверяю по истинной совести.', '.', '202.jpg', 26, '2025-08-18 23:02:53'),
(246, '— А и вправду! — сказал Ноздрев.', '— А и вправду! — сказал Ноздрев.', ' — Смерть не люблю таких растепелей! — и прибавил вслух: — Ну, черт с тобою, поезжай бабиться с женою, фетюк.', '203.jpg', 58, '2025-08-17 20:28:51'),
(247, '— Нет, брат, ты не ругай меня фетюком, — отвечал зять, — я ей жизнью обязан.', '— Нет, брат, ты не ругай меня фетюком, — отвечал зять, — я ей жизнью обязан. Такая, право, добрая, милая, такие ласки оказывает… до слез разбирает; спросит, что видел на ярмарке нужно все рассказать, такая, право, милая.', '.', '301.jpg', 51, '2025-08-10 20:16:00'),
(248, '— Нет, брат, тебе совсем не следует о ней так отзываться, этим ты.', '— Нет, брат, тебе совсем не следует о ней так отзываться; этим ты, можно сказать, меня самого обижаешь, она такая милая.', '.', '100.jpg', 4, '2025-08-01 18:40:06'),
(249, 'Зять еще долго повторял свои извинения, не замечая.', 'Зять еще долго повторял свои извинения, не замечая, что сам уже давно сидел в бричке, давно выехал за ворота и перед ним давно были одни пустые поля. Должно думать, что жена не много слышала подробностей о ярмарке.', '.', '103.jpg', 60, '2025-07-26 12:26:34'),
(250, '— Такая дрянь! — говорил Ноздрев, стоя перед окном и глядя на уезжавший экипаж.', '— Такая дрянь! — говорил Ноздрев, стоя перед окном и глядя на уезжавший экипаж. — Вон как потащился! конек пристяжной недурен, я давно хотел подцепить его. Да ведь с ним нельзя никак сойтиться.', ' Фетюк, просто фетюк.', '103.jpg', 14, '2025-07-23 08:54:24'),
(251, 'Засим вошли они в комнату.', 'Засим вошли они в комнату. Порфирий подал свечи, и Чичиков заметил в руках хозяина неизвестно откуда взявшуюся колоду карт.', '.', '202.jpg', 9, '2025-07-13 08:51:27'),
(252, '— А что брат, — говорил Ноздрев.', '— А что брат, — говорил Ноздрев, прижавши бока колоды пальцами и несколько погнувши ее, так что треснула и отскочила бумажка.', ' — Ну, для препровождения времени, держу триста рублей банку.', '101.jpg', 18, '2025-07-05 06:03:54'),
(253, 'Но Чичиков прикинулся, как будто и не слышал, о чем речь, и сказал.', 'Но Чичиков прикинулся, как будто и не слышал, о чем речь, и сказал, как бы вдруг припомнив.', 'Но Чичиков прикинулся, как будто и не слышал, о чем речь, и сказал, как бы вдруг припомнив.', '101.jpg', 14, '2025-06-28 00:07:44'),
(254, '— Вот какая просьба, у тебя есть, чай, много умерших крестьян.', '— Вот какая просьба: у тебя есть, чай, много умерших крестьян, которые еще не вычеркнуть из ревизии.', '— Вот какая просьба: у тебя есть, чай, много умерших крестьян, которые еще не вычеркнуть из ревизии.', '100.jpg', 38, '2025-06-25 23:49:53'),
(255, '— Ох, какой любопытный.', '— Ох, какой любопытный! ему всякую дрянь хотелось бы пощупать рукой, да еще и понюхать.', '— Ох, какой любопытный! ему всякую дрянь хотелось бы пощупать рукой, да еще и понюхать.', '201.jpg', 8, '2025-06-17 19:45:22'),
(256, '— Ну вот видишь, вот уж и нечестно с твоей стороны, слово дал.', '— Ну вот видишь, вот уж и нечестно с твоей стороны: слово дал, да и на попятный двор.', '.', '102.jpg', 45, '2025-06-14 16:22:50'),
(257, '«Что бы такое сказать ему.', '«Что бы такое сказать ему?» — подумал Чичиков в после минутного размышления объявил, что мертвые души нужны ему для приобретения весу в обществе, что он поместьев больших не имеет, так до того времени хоть бы какие-нибудь душонки.', '.', '102.jpg', 57, '2025-06-13 10:58:58'),
(258, '— Ну, так я ж тебе скажу прямее, — сказал он, поправившись, — только.', '— Ну, так я ж тебе скажу прямее, — сказал он, поправившись, — только, пожалуйста, не проговорись никому. Я задумал жениться; но нужно тебе знать, что отец и мать невесты преамбициозные люди.', ' Такая, право, комиссия, не рад, что связался, хотят непременно, чтоб у жениха было никак не меньше трехсот душ.', '102.jpg', 4, '2025-06-06 09:09:59'),
(259, '— Ну вот уж здесь, — сказал Чичиков, — ни вот на столько не солгал.', '— Ну вот уж здесь, — сказал Чичиков, — ни вот на столько не солгал, — и показал большим пальцем на своем мизинце самую маленькую часть.', '.', '203.jpg', 50, '2025-05-29 08:05:32'),
(260, '— Ну да ведь я знаю тебя, ведь ты большой мошенник.', '— Ну да ведь я знаю тебя: ведь ты большой мошенник, позволь мне это сказать тебе по дружбе! Ежели бы я был твоим начальником, я бы тебя повесил на первом дереве.', '.', '302.jpg', 4, '2025-05-24 08:02:28'),
(261, 'Чичиков оскорбился таким замечанием.', 'Чичиков оскорбился таким замечанием. Уже всякое выражение, сколько-нибудь грубое или оскорбляющее благопристойность, было ему неприятно.', ' Он даже не любил допускать с собой ни в каком случае фамильярного обращения, разве только если особа была слишком высокого звания. И потому теперь он совершенно обиделся.', '102.jpg', 58, '2025-05-16 03:30:47'),
(262, '— Ей-богу, повесил бы, — повторил Ноздрев, — я тебе говорю это откровенно.', '— Ей-богу, повесил бы, — повторил Ноздрев, — я тебе говорю это откровенно, не с тем чтобы тебя обидеть, а просто по-дружески говорю.', '.', '101.jpg', 25, '2025-05-10 02:49:10'),
(263, '— Всему есть границы, — сказал Чичиков с чувством достоинства.', '— Всему есть границы, — сказал Чичиков с чувством достоинства. — Если хочешь пощеголять подобными речами, так ступай в казармы, — и потом присовокупил: — Не хочешь подарить, так продай.', '.', '302.jpg', 54, '2025-05-07 21:52:51'),
(264, '— Помилуй, брат, что ж у тебя за жидовское побуждение.', '— Помилуй, брат, что ж у тебя за жидовское побуждение. Ты бы должен просто отдать мне их.', '.', '101.jpg', 15, '2025-05-03 20:30:29'),
(265, '— Ну, послушай, чтоб доказать тебе, что я вовсе не какой-нибудь скалдырник.', '— Ну, послушай, чтоб доказать тебе, что я вовсе не какой-нибудь скалдырник, я не возьму за них ничего. Купи у меня жеребца, я тебе дам их в придачу.', '.', '203.jpg', 49, '2025-04-26 17:15:19'),
(266, '— Помилуй, на что ж мне жеребец.', '— Помилуй, на что ж мне жеребец? — сказал Чичиков, изумленный в самом деле таким предложением.', '.', '203.jpg', 44, '2025-04-16 13:24:31'),
(267, '— Да послушай, ты не понимаешь.', '— Да послушай, ты не понимаешь: ведь я с тебя возьму теперь всего только три тысячи, а остальную тысячу ты можешь заплатить мне после.', '.', '100.jpg', 47, '2025-04-15 13:21:59'),
(268, '— За кобылу и за серого коня, которого ты у меня видел.', '— За кобылу и за серого коня, которого ты у меня видел, возьму я с тебя только две тысячи.', '.', '202.jpg', 12, '2025-04-10 07:47:14'),
(269, 'Чичиков поблагодарил за расположение, и напрямик отказался и от серого коня.', 'Чичиков поблагодарил за расположение, и напрямик отказался и от серого коня, и от каурой кобылы.', '.', '100.jpg', 10, '2025-04-06 07:37:02'),
(270, '— Ну так купи собак.', '— Ну так купи собак. Я тебе продам такую пару, просто мороз по коже подирает! брудастая, с усами, шерсть стоит вверх, как щетина. Бочковатость ребр уму непостижимая, лапа вся в комке, земли не заденет.', '.', '101.jpg', 27, '2025-03-28 01:31:08'),
(271, '— Да мне хочется, чтобы у тебя были собаки.', '— Да мне хочется, чтобы у тебя были собаки. Послушай, если уж не хочешь собак, так купи у меня шарманку, чудная шарманка; самому, как честный человек, обошлась в полторы тысячи. тебе отдаю за девятьсот рублей.', '.', '201.jpg', 16, '2025-03-24 20:59:58'),
(272, '— Да зачем же мне шарманка.', '— Да зачем же мне шарманка? Ведь я не немец, чтобы, тащася с ней по дорогам, выпрашивать деньги.', '.', '302.jpg', 33, '2025-03-15 16:34:30'),
(273, '— Да ведь это не такая шарманка, как носят немцы.', '— Да ведь это не такая шарманка, как носят немцы. Это орган; посмотри нарочно: вся из красного дерева.', ' Вот я тебе покажу ее еще! — Здесь Ноздрев, схвативши за руку Чичикова, стал тащить его в другую комнату, и как тот ни упирался ногами в пол и ни уверял, что он знает уже, какая шарманка, но должен был услышать еще раз, каким образом поехал в поход Мальбруг. — Когда ты не хочешь на деньги, так вот что, слушай: я тебе дам шарманку и все, сколько ни есть у меня, мертвые души, а ты мне дай свою бричку и триста рублей придачи.', '101.jpg', 60, '2025-03-09 13:42:06'),
(274, '— Я тебе дам другую бричку.', '— Я тебе дам другую бричку. Вот пойдем в сарай, я тебе покажу ее! Ты ее только перекрасишь, и будет чудо бричка.', '.', '100.jpg', 4, '2025-03-04 12:04:12'),
(275, '«Эк его неугомонный бес как обуял.', '«Эк его неугомонный бес как обуял!» — подумал про себя Чичиков и решился во что бы то ни стало отделаться от всяких бричек, шарманок и всех возможных собак, несмотря на непостижимую уму бочковатость ребр и комкость лап.', '.', '302.jpg', 60, '2025-03-02 05:46:27'),
(276, '— Экой ты, право, такой.', '— Экой ты, право, такой! с тобой, как я вижу, нельзя, как водится между хорошими друзьями и товарищами, такой, право!..', ' Сейчас видно, что двуличный человек.', '100.jpg', 9, '2025-02-21 05:30:39'),
(277, '— Да что же я, дурак, что ли.', '— Да что же я, дурак, что ли? ты посуди сам: зачем же приобретать вещь, решительно для меня ненужную.', '— Да что же я, дурак, что ли? ты посуди сам: зачем же приобретать вещь, решительно для меня ненужную.', '301.jpg', 40, '2025-02-11 05:02:03'),
(278, '— Ну уж, пожалуйста, не говори. Теперь я очень хорошо тебя знаю.', '— Ну уж, пожалуйста, не говори. Теперь я очень хорошо тебя знаю. Такая, право, ракалия! Ну, послушай, хочешь метнем банчик? Я поставлю всех умерших на карту, шарманку тоже.', '.', '002.jpg', 29, '2025-02-10 00:21:46'),
(279, '— Ну, решаться в банк, значит подвергаться неизвестности.', '— Ну, решаться в банк, значит подвергаться неизвестности, — говорил Чичиков и между тем взглянул искоса на бывшие в руках у него карты. Обе талии ему показались очень похожими на искусственные, и самый крап глядел весьма подозрительно.', '.', '203.jpg', 51, '2025-02-08 21:27:06'),
(280, '— Ну оттого, что не расположен.', '— Ну оттого, что не расположен. Да, признаться сказать, а вовсе не охотник играть.', '.', '202.jpg', 58, '2026-02-16 22:33:18'),
(281, '— Фетюк просто.', '— Фетюк просто! Я думал было прежде, что ты хоть сколько-нибудь порядочный человек, а ты никакого не понимаешь обращения.', ' С тобой никак нельзя говорить, как с человеком близким… никакого прямодушия, ни искренности! совершенный Собакевич, такой подлец.', '301.jpg', 20, '2026-02-15 19:58:11'),
(282, '— Да за что же ты бранишь меня? Виноват разве я, что не играю.', '— Да за что же ты бранишь меня? Виноват разве я, что не играю? Продай мне душ одних, если уж ты такой человек, что дрожишь из-за этого вздору.', '.', '302.jpg', 39, '2026-02-09 15:55:01'),
(283, '— Черта лысого получишь.', '— Черта лысого получишь! хотел было, даром хотел отдать, но теперь вот не получишь же! Хоть три царства давай, не отдам. Такой шильник, печник гадкий! С этих пор с тобой никакого дела не хочу иметь.', ' Порфирий, ступай скажи конюху, чтобы не давал овса лошадям его, пусть их едят одно сено.', '302.jpg', 8, '2026-02-02 11:48:15'),
(284, 'Несмотря, однако ж, на такую размолвку, гость и хозяин поужинали вместе.', 'Несмотря, однако ж, на такую размолвку, гость и хозяин поужинали вместе, хотя на этот раз не стояло на столе никаких вин с затейливыми именами.', ' Торчала одна только бутылка с какие-то кипрским, которое было то, что называют кислятина во всех отношениях.', '301.jpg', 16, '2026-01-26 10:36:52'),
(285, 'Чичиков остался по уходе Ноздрева в самом неприятном расположении духа.', 'Чичиков остался по уходе Ноздрева в самом неприятном расположении духа.', ' Он внутренно досадовал на себя, бранил себя за то, что к нему заехал и потерял даром время Но еще более бранил себя за то, что заговорил с ним о деле, поступил неосторожно, как ребенок, как дурак: ибо дело совсем не такого роду, чтобы быть вверену Ноздреву… Ноздрев человек-дрянь, Ноздрев может наврать, прибавить, распустить черт знает что, выйдут еще какие-нибудь сплетни — нехорошо, нехорошо. «Просто дурак я». — говорил он сам себе. Ночь спал он очень дурно. Какие-то маленькие пребойкие насекомые кусали его нестерпимо больно, так что он всей горстью скреб по уязвленному месту, приговаривая: «А, чтоб вас черт побрал вместе с Ноздревым!» Проснулся он ранним утром. Первым делом его было, надевши халат и сапоги, отправиться через двор в конюшню приказать Селифану сей же час закладывать бричку. Возвращаясь через двор, он встретился с Ноздревым, который был также в халате, с трубкою в зубах.', '301.jpg', 37, '2026-01-21 10:16:22'),
(286, '— А я, брат, — говорил Ноздрев, — такая мерзость лезла всю ночь.', '— А я, брат, — говорил Ноздрев, — такая мерзость лезла всю ночь, что гнусно рассказывать, и во рту после вчерашнего точно эскадрон переночевал.', ' Представь: снилось, что меня высекли, ей-ей! и, вообрази, кто? Вот ни за что не угадаешь: штабс-ротмистр Поцелуев вместе с Кувшинниковым.', '302.jpg', 53, '2026-01-17 09:28:11'),
(287, '— Ей-богу! да пребольно.', '— Ей-богу! да пребольно! Проснулся: черт возьми, в самом деле что-то почесывается, — верно, ведьмы блохи. Ну, ты ступай теперь одевайся, я к тебе сейчас приду. Нужно только ругнуть подлеца приказчика.', '.', '101.jpg', 28, '2026-01-14 04:07:29'),
(288, 'Чичиков ушел в комнату одеться и умыться.', 'Чичиков ушел в комнату одеться и умыться. Когда после того вышел он в столовую, там уже стоял на столе чайный прибор с бутылкою рома. В комнате были следы вчерашнего обеда и ужина; кажется, половая щетка не притрогивалась вовсе.', ' На полу валялись хлебные крохи, а табачная зола видна даже была на скатерти. Сам хозяин, не замедливший скоро войти, ничего не имел у себя под халатом, кроме открытой груди, на которой росла какая-то борода. Держа в руке чубук и прихлебывая из чашки, он был очень хорош для живописца, не любящего страх господ прилизанных и завитых, подобно цирюльным вывескам, или выстриженных под гребенку.', '301.jpg', 59, '2026-01-08 00:52:00'),
(289, '— Ну, так как же думаешь? — сказал Ноздрев, немного помолчавши.', '— Ну, так как же думаешь? — сказал Ноздрев, немного помолчавши.', ' — Не хочешь играть на души.', '203.jpg', 7, '2025-12-31 21:11:33'),
(290, '— Продать я не хочу, это будет не по-приятельски.', '— Продать я не хочу, это будет не по-приятельски. Я не стану снимать плевы с черт знает чего. В бантик — другое дело.', ' Прокинем хоть талию.', '302.jpg', 15, '2025-12-24 18:27:54'),
(291, '— Ну, послушай, сыграем в шашки, выиграешь — твои все.', '— Ну, послушай, сыграем в шашки, выиграешь — твои все. Ведь у меня много таких, которых нужно вычеркнуть из ревизии. Эй, Порфирий, принеси-ка сюда шашечницу.', '.', '201.jpg', 54, '2025-12-14 14:25:52'),
(292, '— Да ведь это не в банк, тут никакого не может быть счастия или фальши.', '— Да ведь это не в банк; тут никакого не может быть счастия или фальши: все ведь от искусства; я даже тебя предваряю, что я совсем не умею играть, разве что-нибудь мне дашь вперед.', '.', '201.jpg', 9, '2025-12-10 08:14:23'),
(293, '«Сем-ка я, — подумал про себя Чичиков, — сыграю с ним в шашки.', '«Сем-ка я, — подумал про себя Чичиков, — сыграю с ним в шашки! В шашки игрывал я недурно, а на штуки ему здесь трудно подняться».', '.', '103.jpg', 58, '2025-12-04 05:15:38'),
(294, '— Нет, что ж за куш пятьдесят.', '— Нет, что ж за куш пятьдесят? Лучше ж в эту сумму я включу тебе какого-нибудь щенка средней руки или золотую печатку к часам.', '.', '201.jpg', 22, '2025-12-02 03:17:48'),
(295, '— Знаем мы вас, как вы плохо играете.', '— Знаем мы вас, как вы плохо играете! — сказал Ноздрев, подвигая шашку, да в то же самое время подвинул обшлагом рукава и другую шашку.', '.', '002.jpg', 13, '2025-11-30 01:37:59'),
(296, '— Давненько не брал я в руки!..', '— Давненько не брал я в руки!.. Э, э! это, брат, что? отсади-ка ее назад! — говорил Чичиков.', '.', '100.jpg', 41, '2025-11-25 01:32:50'),
(297, '— Нет, брат, я все ходы считал и все помню; ты ее только теперь пристроил.', '— Нет, брат, я все ходы считал и все помню; ты ее только теперь пристроил.', ' Ей место вон где.', '103.jpg', 7, '2026-02-08 18:05:51'),
(298, '— Как, где место? — сказал Ноздрев, покрасневши.', '— Как, где место? — сказал Ноздрев, покрасневши.', ' — Да, ты, брат, как я вижу, сочинитель.', '101.jpg', 38, '2026-02-03 11:58:10'),
(299, '— Я имею право отказаться, потому что ты не так играешь.', '— Я имею право отказаться, потому что ты не так играешь, как прилично честному человеку.', '.', '201.jpg', 12, '2026-02-01 06:26:40'),
(300, '— Этого ты меня не заставишь сделать, — сказал Чичиков хладнокровно и.', '— Этого ты меня не заставишь сделать, — сказал Чичиков хладнокровно и, подошедши к доске, смешал шашки.', '.', '103.jpg', 29, '2026-01-29 04:01:14'),
(301, 'Ноздрев вспыхнул и подошел к Чичикову так близко.', 'Ноздрев вспыхнул и подошел к Чичикову так близко, что тот отступил шага два назад.', '.', '100.jpg', 30, '2026-01-20 00:01:57'),
(302, '— Я тебя заставлю играть! Это ничего, что ты смешал шашки, я помню все ходы.', '— Я тебя заставлю играть! Это ничего, что ты смешал шашки, я помню все ходы. Мы их поставим опять так, как были.', '.', '100.jpg', 28, '2026-01-14 19:05:24'),
(303, '— Нет, скажи напрямик, ты не хочешь играть.', '— Нет, скажи напрямик, ты не хочешь играть? — говорил Ноздрев, подступая еще ближе.', '.', '002.jpg', 60, '2026-01-13 13:52:27'),
(304, '— Не хочу.', '— Не хочу! — сказал Чичиков и поднес, однако ж, обе руки на всякий случай поближе к лицу, ибо дело становилось в самом деле жарко.', '.', '101.jpg', 57, '2026-01-04 11:39:35'),
(305, 'Эта предосторожность была весьма у места.', 'Эта предосторожность была весьма у места, потому что Ноздрев размахнулся рукой… и очень бы могло статься, что одна из приятных и полных щек нашего героя покрылась бы несмываемым бесчестием, но, счастливо отведши удар.', 'Эта предосторожность была весьма у места, потому что Ноздрев размахнулся рукой… и очень бы могло статься, что одна из приятных и полных щек нашего героя покрылась бы несмываемым бесчестием; но, счастливо отведши удар, он схватил Ноздрева за обе задорные его руки и держал его крепко.', '100.jpg', 7, '2026-01-03 09:24:32'),
(306, 'Услыша эти слова, Чичиков.', 'Услыша эти слова, Чичиков, чтобы не сделать дворовых людей свидетелями соблазнительной сцены и вместе с тем чувствуя, что держать Ноздрева было бесполезно, выпустил его руки.', ' В это самое время вошел Порфирий и с ним Павлушка, парень дюжий, с которым иметь дело было совсем невыгодно.', '302.jpg', 7, '2025-12-30 08:17:32'),
(307, '— Так ты не хочешь оканчивать партии? — говорил Ноздрев.', '— Так ты не хочешь оканчивать партии? — говорил Ноздрев.', ' — Отвечай мне напрямик.', '201.jpg', 3, '2025-12-23 06:52:16'),
(308, '— Партии нет возможности оканчивать, — говорил Чичиков и заглянул в окно.', '— Партии нет возможности оканчивать, — говорил Чичиков и заглянул в окно.', ' Он увидел свою бричку, которая стояла совсем готовая, а Селифан ожидал, казалось, мановения, чтобы подкатить под крыльцо, но из комнаты не было никакой возможности выбраться: в дверях стояли два дюжих крепостных дурака.', '203.jpg', 56, '2025-12-13 03:35:41'),
(309, '— Так ты не хочешь доканчивать партии.', '— Так ты не хочешь доканчивать партии? — повторил Ноздрев с лицом, горевшим, как в огне.', '.', '302.jpg', 39, '2025-12-10 03:24:22'),
(310, '— Позвольте узнать, кто здесь господин Ноздрев.', '— Позвольте узнать, кто здесь господин Ноздрев? — сказал незнакомец, посмотревши в некотором недоумении на Ноздрева, который стоял с чубуком в руке, и на Чичикова, который едва начинал оправляться от своего невыгодного положения.', '.', '100.jpg', 19, '2026-02-09 17:10:04'),
(311, '— Позвольте прежде узнать, с кем имею честь говорить.', '— Позвольте прежде узнать, с кем имею честь говорить? — сказал Ноздрев, подходя к нему ближе.', '.', '100.jpg', 54, '2026-02-04 12:12:45'),
(312, '— Я приехал вам объявить сообщенное мне извещение.', '— Я приехал вам объявить сообщенное мне извещение, что вы находитесь под судом до времени окончания решения по вашему делу.', '.', '202.jpg', 18, '2026-02-02 09:49:30'),
(313, '— Вы были замешаны в историю.', '— Вы были замешаны в историю, по случаю нанесения помещику Максимову личной обиды розгами в пьяном виде.', '.', '100.jpg', 20, '2026-01-28 06:27:00'),
(314, '— Милостивый государь! позвольте вам доложить, что я офицер.', '— Милостивый государь! позвольте вам доложить, что я офицер.', ' Вы можете это сказать вашему слуге, а не мне.', '202.jpg', 53, '2026-01-23 03:51:14'),
(315, 'Здесь Чичиков, не дожидаясь, что будет отвечать на это Ноздрев.', 'Здесь Чичиков, не дожидаясь, что будет отвечать на это Ноздрев, скорее за шапку да по-за спиною капитана-исправника выскользнул на крыльцо, сел в бричку и велел Селифану погонять лошадей во весь дух.', '.', '002.jpg', 25, '2026-01-18 03:19:32'),
(316, 'Герой наш трухнул, однако ж, порядком.', 'Герой наш трухнул, однако ж, порядком. Хотя бричка мчалась во всю пропащую и деревня Ноздрева давно унеслась из вида, закрывшись полями, отлогостями и пригорками, но он все еще поглядывал назад со страхом, как бы ожидая, что вот-вот налетит погоня.', ' Дыхание его переводилось с трудом, и когда он попробовал приложить руку к сердцу, то почувствовал, что оно билось, как перепелка в клетке. «Эк какую баню задал! смотри ты какой!» Тут много было посулено Ноздреву всяких нелегких и сильных желаний; попались даже и нехорошие слова. Что ж делать? Русский человек, да еще и в сердцах. К тому ж дело было совсем нешуточное. «Что ни говори, — сказал он сам в себе, — а не подоспей капитан-исправник, мне бы, может быть, не далось бы более и на свет божий взглянуть! Пропал бы, как волдырь на воде, без всякого следа, не оставивши потомков, не доставив будущим детям ни состояния, ни честного имени!» Герой наш очень заботился о своих потомках.', '203.jpg', 12, '2026-01-12 21:52:12'),
(317, '«Экой скверный барин! — думал про себя Селифан. — Я еще не видал такого барина.', '«Экой скверный барин! — думал про себя Селифан. — Я еще не видал такого барина. То есть плюнуть бы ему за это! Ты лучше человеку не дай есть, а коня ты должен кормить, потому что конь любит овес.', ' Это его продовольство: что, примером, нам кошт, то для него овес, он его продовольство».', '202.jpg', 11, '2026-01-02 21:39:42'),
(318, 'Кони тоже, казалось, думали невыгодно об Ноздреве.', 'Кони тоже, казалось, думали невыгодно об Ноздреве: не только гнедой и Заседатель, но и сам чубарый был не в духе.', ' Хотя ему на часть и доставался всегда овес потуже и Селифан не иначе всыпал ему в корыто, как сказавши прежде: «Эх ты, подлец!» — но, однако ж, это все-таки был овес, а не простое сено, он жевал его с удовольствием и часто засовывал длинную морду свою в корытца к товарищам поотведать, какое у них было продовольствие, особливо когда Селифана не было в конюшне, но теперь одно сено… нехорошо; все были недовольны.', '103.jpg', 23, '2025-12-31 18:49:42'),
(319, 'Но герой наш уже был средних лет и осмотрительно-охлажденного характера.', 'Но герой наш уже был средних лет и осмотрительно-охлажденного характера. Он тоже задумался и думал, но положительнее, не так безотчетны и даже отчасти очень основательны были его мысли.', ' «Славная бабешка! — сказал он, открывши табакерку и понюхавши табаку. — Но ведь что, главное, в ней хорошо? Хорошо то, что она сейчас только, как видно, выпущена из какого-нибудь пансиона или института, что в ней, как говорится, нет еще ничего бабьего, то есть именно того, что у них есть самого неприятного. Она теперь как дитя, все в ней просто, она скажет, что ей вздумается, засмеется, где захочет засмеяться. Из нее все можно сделать, она может быть чудо, а может выйти и дрянь, и выдет дрянь! Вот пусть-на только за нее примутся теперь маменьки и тетушки. В один год так ее наполнят всяким бабьем, что сам родной отец не узнает. Откуда возьмется и надутость, и чопорность, станет ворочаться по вытверженным наставлениям, станет ломать голову и придумывать, с кем, и как, и сколько нужно говорить, как на кого смотреть, всякую минуту будет бояться, чтобы не сказать больше, чем нужно, запутается наконец сама, и кончится тем, что станет наконец врать всю жизнь, и выдет просто черт знает что!» Здесь он несколько времени помолчал и потом прибавил: «А любопытно бы знать, чьих она? что, как ее отец? богатый ли помещик почтенного нрава, или просто благомыслящий человек с капиталом, приобретенным на службе? Ведь если, положим, этой девушке да придать тысячонок двести приданого, из нее бы мог выйти очень, очень лакомый кусочек. Это бы могло составить, так сказать, счастье порядочного человека». Двести тысячонок так привлекательно стали рисоваться в голове его, что он внутренно начал досадовать на самого себя, зачем в продолжение хлопотни около экипажей не разведал от форейтора или кучера, кто такие были проезжающие. Скоро, однако ж, показавшаяся деревня Собакевича рассеяла его мысли и заставила их обратиться к своему постоянному предмету.', '202.jpg', 4, '2026-02-01 15:05:27'),
(320, 'Деревня показалась ему довольно велика, два леса, березовый и сосновый.', 'Деревня показалась ему довольно велика, два леса, березовый и сосновый, как два крыла, одно темнее, другое светлее, были у ней справа и слева, посреди виднелся деревянный дом с мезонином, красной крышей и темными или, лучше, дикими стенами.', 'Деревня показалась ему довольно велика; два леса, березовый и сосновый, как два крыла, одно темнее, другое светлее, были у ней справа и слева; посреди виднелся деревянный дом с мезонином, красной крышей и темными или, лучше, дикими стенами, — дом вроде тех, как у нас строят для военных поселений и немецких колонистов. Было заметно, что при постройке его зодчий беспрестанно боролся со вкусом хозяина. Зодчий был педант и хотел симметрии, хозяин — удобства и, как видно, вследствие того заколотил на одной стороне все отвечающие окна и провертел на место их одно маленькое, вероятно понадобившееся для темного чулана. Фронтон тоже никак не пришелся посреди дома, как ни бился архитектор, потому что хозяин приказал одну колонну сбоку выкинуть, и оттого очутилось не четыре колонны, как было назначено, а только три. Двор окружен был крепкою и непомерно толстою деревянною решеткой. Помещик, казалось, хлопотал много о прочности. На конюшни, сараи и кухни были употреблены полновесные и толстые бревна, определенные на вековое стояние. Деревенские избы мужиков тож срублены были на диво: не было кирчёных стен, резных узоров и прочих затей, но все было пригнано плотно и как следует. Даже колодец был обделан в такой крепкий дуб, какой идет только на мельницы да на корабли. Словом, все, на что ни глядел он, было упористо, без пошатки, в каком-то крепком и неуклюжем порядке. Подъезжая к крыльцу, заметил он выглянувшие из окна почти в одно время два лица: женское, в венце, узкое, длинное, как огурец, и мужское, круглое, широкое, как молдаванские тыквы, называемые горлянками, изо которых делают на Руси балалайки, двухструнные легкие балалайки, красу и потеху ухватливого двадцатилетнего парня, мигача и щеголя, и подмигивающего и посвистывающего на белогрудых и белошейных девиц, собравшихся послушать его тихострунного треньканья. Выглянувши, оба лица в ту же минуту спрятались. На крыльцо вышел лакей в серой куртке с голубым стоячим воротником и ввел Чичикова в сени, куда вышел уже сам хозяин.', '202.jpg', 13, '2026-01-30 10:13:49');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(321, 'Когда Чичиков взглянул искоса на Собакевича.', 'Когда Чичиков взглянул искоса на Собакевича, он ему на этот раз показался весьма похожим на средней величины медведя.', ' Для довершение сходства фрак на нем был совершенно медвежьего цвета, рукава длинны, панталоны длинны, ступнями ступал он и вкривь и вкось и наступал беспрестанно на чужие ноги. Цвет лица имел каленый, горячий, какой бывает на медном пятаке. Известно, что есть много на свете таких лиц, над отделкою которых натура недолго мудрила, не употребляла никаких мелких инструментов, как-то: напильников, буравчиков и прочего, но просто рубила со своего плеча: хватила топором раз — вышел нос, хватила в другой — вышли губы, большим сверлом ковырнула глаза и, не обскобливши, пустила на свет, сказавши: «Живет!» Такой же самый крепкий и на диво стаченный образ был у Собакевича: держал он его более вниз, чем вверх, шеей не ворочал вовсе и в силу такого неповорота редко глядел на того, с которым говорил, но всегда или на угол печки, или на дверь. Чичиков еще раз взглянул на него искоса, когда проходили они столовую: медведь! совершенный медведь! Нужно же такое странное сближение: его даже звали Михайлом Семеновичем. Зная привычку его наступать на ноги, он очень осторожно передвигал своими и давал ему дорогу вперед. Хозяин, казалось, сам чувствовал за собою этот грех и тот же час спросил: «Не побеспокоил ли я вас?» Но Чичиков поблагодарил, сказав, что еще не произошло никакого беспокойства.', '202.jpg', 33, '2026-01-29 08:57:23'),
(322, '— Душенька, рекомендую тебе, — продолжал Собакевич, — Павел Иванович Чичиков.', '— Душенька, рекомендую тебе, — продолжал Собакевич, — Павел Иванович Чичиков! У губернатора и почтмейстера имел честь познакомиться.', '.', '302.jpg', 28, '2026-01-27 11:40:57'),
(323, 'Феодулия Ивановна попросила садиться, сказавши тоже: «Прошу.', 'Феодулия Ивановна попросила садиться, сказавши тоже: «Прошу!» — и сделав движение головою, подобно актрисам, представляющим королев. Затем она уселась на диване, накрылась своим мериносовым платком и уже не двигнула более ни глазом, ни бровью.', '.', '101.jpg', 0, '2026-01-22 06:27:15'),
(324, 'Чичиков опять поднял глаза вверх и опять увидел Канари с толстыми ляжками.', 'Чичиков опять поднял глаза вверх и опять увидел Канари с толстыми ляжками, и нескончаемыми усами, Бобелину и дрозда в клетке.', '.', '102.jpg', 29, '2026-01-13 01:54:15'),
(325, 'Почти в течение целых пяти минут все хранили молчание, раздавался только стук.', 'Почти в течение целых пяти минут все хранили молчание; раздавался только стук, производимый носом дрозда о дерево деревянной клетки, на дне которой удил он хлебные зернышки.', ' Чичиков еще раз окинул комнату, и все, что в ней ни было, — все было прочно, неуклюже в высочайшей степени и имело какое-то странное сходство с самим хозяином дома; в углу гостиной стояло пузатое ореховое бюро на пренелепых четырех ногах, совершенный медведь.', '002.jpg', 0, '2026-01-10 01:38:00'),
(326, '— Мы об вас вспоминали у председателя палаты, у Ивана Григорьевича.', '— Мы об вас вспоминали у председателя палаты, у Ивана Григорьевича, — сказал наконец Чичиков, видя, что никто не располагается начинать разговора, — в прошедший четверг. Очень приятно провели там время.', '.', '302.jpg', 27, '2026-01-01 23:39:45'),
(327, '— Ну, может быть, это вам так показалось, он только что масон, а такой дурак.', '— Ну, может быть, это вам так показалось: он только что масон, а такой дурак, какого свет не производил.', '.', '202.jpg', 2, '2025-12-29 19:46:07'),
(328, 'Чичиков немного озадачился таким отчасти резким определением, но потом.', 'Чичиков немного озадачился таким отчасти резким определением, но потом, поправившись, продолжал.', 'Чичиков немного озадачился таким отчасти резким определением, но потом, поправившись, продолжал.', '201.jpg', 21, '2025-12-26 17:35:16'),
(329, '— Конечно, всякий человек не без слабостей.', '— Конечно, всякий человек не без слабостей, но зато губернатор какой превосходный человек.', '— Конечно, всякий человек не без слабостей, но зато губернатор какой превосходный человек.', '002.jpg', 58, '2025-12-21 12:18:59'),
(330, '— Как, губернатор разбойник.', '— Как, губернатор разбойник? — сказал Чичиков и совершенно не мог понять, как губернатор мог попасть в разбойники. — Признаюсь, этого я бы никак не подумал, — продолжал он.', ' — Но позвольте, однако же, заметить: поступки его совершенно не такие, напротив, скорее даже мягкости в нем много. — Тут он привел в доказательство даже кошельки, вышитые его собственными руками, и отозвался с похвалою об ласковом выражении лица его.', '102.jpg', 12, '2025-12-12 06:45:31'),
(331, '— И лицо разбойничье! — сказал Собакевич.', '— И лицо разбойничье! — сказал Собакевич.', ' — Дайте ему только нож да выпустите его на большую дорогу — зарежет, за копейку зарежет! Он да еще вице-губернатор — это Гога и Магога.', '103.jpg', 0, '2025-12-04 05:21:43'),
(332, '«Нет, он с ними не в ладах, — подумал про себя Чичиков.', '«Нет, он с ними не в ладах, — подумал про себя Чичиков. — А вот заговорю я с ним о полицеймейстере: он, кажется, друг его».', '.', '102.jpg', 41, '2025-11-24 03:26:41'),
(333, '— Впрочем, что до меня, — сказал он, — мне, признаюсь.', '— Впрочем, что до меня, — сказал он, — мне, признаюсь, более всех нравится полицеймейстер. Какой-то этакой характер прямой, открытый; в лице видно что-то простосердечное.', '.', '202.jpg', 30, '2025-11-17 21:56:49'),
(334, '— Мошенник.', '— Мошенник! — сказал Собакевич очень хладнокровно, — продаст, обманет, еще и пообедает с вами! Я их знаю всех: это всё мошенники, весь город там такой: мошенник на мошеннике сидит и мошенником погоняет. Все христопродавцы.', ' Один там только и есть порядочный человек: прокурор; да и тот, если сказать правду, свинья.', '302.jpg', 36, '2025-11-09 15:40:04'),
(335, 'После таких похвальных, хотя несколько кратких биографий Чичиков увидел.', 'После таких похвальных, хотя несколько кратких биографий Чичиков увидел, что о других чиновниках нечего упоминать и вспомнил, что Собакевич не любил ни о ком хорошо отзываться.', '.', '202.jpg', 49, '2025-11-01 10:20:16'),
(336, 'Засим, подошевши к столу, где была закуска.', 'Засим, подошевши к столу, где была закуска, гость и хозяин выпили как следует по рюмке водки, закусили, как закусывает вся пространная Россия по городам и деревням, то есть всякими соленостями и иными возбуждающими благодатями.', 'Засим, подошевши к столу, где была закуска, гость и хозяин выпили как следует по рюмке водки, закусили, как закусывает вся пространная Россия по городам и деревням, то есть всякими соленостями и иными возбуждающими благодатями, и потекли все в столовую; впереди их, как плавный гусь, понеслась хозяйка. Небольшой стол был накрыт на четыре прибора. На четвертое место явилась очень скоро, трудно сказать утвердительно, кто такая, дама или девица, родственница, домоводка или просто проживающая в доме: что-то без чепца, около тридцати лет, в пестром платке. Есть лица, которые существуют на свете не как предмет, а как посторонние крапинки или пятнышки на предмете.', '202.jpg', 47, '2025-10-27 06:58:03'),
(337, '— Щи, моя душа, сегодня очень хороши.', '— Щи, моя душа, сегодня очень хороши! — сказал Собакевич, хлебнувши щей и отваливши себе с блюда огромный кусок няни, известного блюда, которое подается к щам и состоит из бараньего желудка, начиненного гречневой кашей, мозгом и ножками.', ' — Эдакой няни, — продолжал он, обратившись к Чичикову, — вы не будете есть в городе, там вам черт знает что подадут.', '100.jpg', 1, '2025-10-17 05:43:20'),
(338, '— Не знаю, как приготовляется, об этом я не могу судить.', '— Не знаю, как приготовляется, об этом я не могу судить, но свиные котлеты и разварная рыба были превосходны.', '.', '102.jpg', 36, '2025-10-08 04:48:43'),
(339, '— Это вам так показалось. Ведь я знаю, что они на рынке покупают.', '— Это вам так показалось. Ведь я знаю, что они на рынке покупают. Купит вон тот каналья повар, что выучился у француза, кота, обдерет его, да и подает на стол вместо зайца.', '.', '100.jpg', 10, '2025-10-02 03:34:27'),
(340, '— А что ж, душенька, так у них делается, я не виноват.', '— А что ж, душенька, так у них делается, я не виноват, так у них у всех делается.', ' Все что ни есть ненужного, что Акулька у нас бросает, с позволения сказать, в помойную лохань, они его в суп! да в суп! туда его.', '101.jpg', 56, '2025-09-30 22:04:04'),
(341, '— Что ж, душа моя, — сказал Собакевич, — если б я сам это делал.', '— Что ж, душа моя, — сказал Собакевич, — если б я сам это делал, но я тебе прямо в глаза скажу, что я гадостей не стану есть. Мне лягушку хоть сахаром облепи, не возьму ее в рот, и устрицы тоже не возьму: я знаю, на что устрица похожа.', ' Возьмите барана, — продолжал он, обращаясь к Чичикову, — это бараний бок с кашей! Это не те фрикасе, что делаются на барских кухнях из баранины, какая суток по четыре на рынке валяется! Это все выдумали доктора немцы да французы, я бы их перевешал за это! Выдумали диету, лечить голодом! Что у них немецкая жидкостная натура, так они воображают, что и с русским желудком сладят! Нет, это все не то, это всё выдумки, это всё… — Здесь Собакевич даже сердито покачал головою. — Толкуют: просвещенье, просвещенье, а это просвещенье — фук! Сказал бы и другое слово, да вот только что за столом неприлично. У меня не так. У меня когда свинина — всю свинью давай на стол, баранина — всего барана тащи, гусь — всего гуся! Лучше я съем двух блюд, да съем в меру, как душа требует. — Собакевич подтвердил это делом: он опрокинул половину бараньего бока к себе на тарелку, съел все, обгрыз, обсосал до последней косточки.', '202.jpg', 12, '2025-09-28 18:49:26'),
(342, '— У меня не так, — говорил Собакевич, вытирая салфеткою руки, — у меня не так.', '— У меня не так, — говорил Собакевич, вытирая салфеткою руки, — у меня не так, как у какого-нибудь Плюшкина: восемьсот душ имеет, а живет и обедает хуже моего пастуха.', '— У меня не так, — говорил Собакевич, вытирая салфеткою руки, — у меня не так, как у какого-нибудь Плюшкина: восемьсот душ имеет, а живет и обедает хуже моего пастуха.', '201.jpg', 2, '2025-09-25 15:36:37'),
(343, '— Мошенник, — отвечал Собакевич. — Такой скряга, какого вообразитъ трудно.', '— Мошенник, — отвечал Собакевич. — Такой скряга, какого вообразитъ трудно. В тюрьме колодники лучше живут, чем он: всех людей переморил голодом.', '.', '302.jpg', 51, '2025-09-19 11:29:01'),
(344, '— Вправду! — подхватил с участием Чичиков.', '— Вправду! — подхватил с участием Чичиков.', ' — И вы говорите, что у него, точно, люди умирают в большом количестве.', '102.jpg', 13, '2025-09-11 08:19:22'),
(345, '— В пяти верстах.', '— В пяти верстах! — воскликнул Чичиков и даже почувствовал небольшое сердечное биение.', ' — Но если выехать из ваших ворот, это будет направо или налево.', '201.jpg', 47, '2025-09-06 08:12:42'),
(346, '— Я вам даже не советую дороги знать к этой собаке! — сказал Собакевич.', '— Я вам даже не советую дороги знать к этой собаке! — сказал Собакевич. — Извинительней сходить в какое-нибудь непристойное место, чем к нему.', '.', '202.jpg', 12, '2025-08-28 06:54:13'),
(347, '— Нет, я спросил не для каких-либо, а потому только.', '— Нет, я спросил не для каких-либо, а потому только, что интересуюсь познанием всякого рода мест, — отвечал на это Чичиков.', '.', '202.jpg', 39, '2025-08-23 00:38:18'),
(348, 'За бараньим боком последовали ватрушки.', 'За бараньим боком последовали ватрушки, из которых каждая была гораздо больше тарелки, потом индюк ростом в теленка, набитый всяким добром: яйцами, рисом, печенками и невесть чем, что все ложилось комом в желудке.', ' Этим обед и кончился; но когда встали из-за стола, Чичиков почувствовал в себе тяжести на целый пуд больше. Пошли в гостиную, где уже очутилось на блюдечке варенье — ни груша, ни слива, ни иная ягода, до которого, впрочем, не дотронулись ни гость, ни хозяин. Хозяйка вышла, с тем чтобы накласть его и на другие блюдечки. Воспользовавшись ее отсутствием, Чичиков обратился к Собакевичу, который, лежа в креслах, только покряхтывал после такого сытного обеда и издавал ртом какие-то невнятные звуки, крестясь и закрывая поминутно его рукою.', '101.jpg', 57, '2025-08-13 23:30:20'),
(349, '— Вот еще варенье, — сказала хозяйка, возвращаясь с блюдечком, — редька.', '— Вот еще варенье, — сказала хозяйка, возвращаясь с блюдечком, — редька, варенная в меду.', '— Вот еще варенье, — сказала хозяйка, возвращаясь с блюдечком, — редька, варенная в меду.', '203.jpg', 8, '2025-08-11 18:06:13'),
(350, '— А вот мы его после! — сказал Собакевич.', '— А вот мы его после! — сказал Собакевич.', ' — Ты ступай теперь в свою комнату, мы с Павлом Ивановичем скинем фраки, маленько приотдохнем.', '301.jpg', 5, '2025-08-05 11:59:08'),
(351, 'Хозяйка уже изъявила было готовность послать за пуховиками и подушками.', 'Хозяйка уже изъявила было готовность послать за пуховиками и подушками, но хозяин сказал: «Ничего, мы отдохнем в креслах», — и хозяйка ушла.', '.', '301.jpg', 7, '2025-07-26 07:05:51'),
(352, 'Чичиков начал как-то очень отдаленно.', 'Чичиков начал как-то очень отдаленно, коснулся вообще всего русского государства и отозвался с большою похвалою об его пространстве, сказал, что даже самая древняя римская монархия не была так велика.', 'Чичиков начал как-то очень отдаленно, коснулся вообще всего русского государства и отозвался с большою похвалою об его пространстве, сказал, что даже самая древняя римская монархия не была так велика, и иностранцы справедливо удивляются… Собакевич все слушал, наклонивши голову. И что по существующим положениям этого государства, в славе которому нет равного, ревизские души, окончивши жизненное поприще, числятся, однако ж, до подачи новой ревизской сказки наравне с живыми, чтоб таким образом не обременить присутственные места множеством мелочных и бесполезных справок и не увеличить сложность и без того уже весьма сложного государственного механизма… Собакевич все слушал, наклонивши голову, — и что, однако же, при всей справедливости этой меры она бывает отчасти тягостна для многих владельцев, обязывая их взносить подати так, как бы за живой предмет, и что он, чувствуя уважение личное к нему, готов бы даже отчасти принять на себя эту действительно тяжелую обязанность. Насчет главного предмета Чичиков выразился очень осторожно: никак не назвал души умершими, а только несуществующими.', '301.jpg', 0, '2025-07-23 02:49:55'),
(353, 'Собакевич слушал все по-прежнему, нагнувши голову.', 'Собакевич слушал все по-прежнему, нагнувши голову, и хоть бы что-нибудь похожее на выражение показалось на лице его.', ' Казалось, в этом теле совсем не было души, или она у него была, но вовсе не там, где следует, а, как у бессмертного кощея, где-то за горами и закрыта такою толстою скорлупою, что все, что ни ворочалось на дне ее, не производило решительно никакого потрясения на поверхности.', '100.jpg', 22, '2025-07-16 20:38:42'),
(354, '— Вам нужно мертвых душ.', '— Вам нужно мертвых душ? — спросил Собакевич очень просто, без малейшего удивления, как бы речь шла о хлебе.', '.', '103.jpg', 12, '2025-07-11 18:10:06'),
(355, '— Да, — отвечал Чичиков и опять смягчил выражение, прибавивши: — несуществующих.', '— Да, — отвечал Чичиков и опять смягчил выражение, прибавивши: — несуществующих.', '.', '302.jpg', 60, '2025-07-07 17:11:05'),
(356, '— Извольте, я готов продать, — сказал Собакевич.', '— Извольте, я готов продать, — сказал Собакевич, уже несколько приподнявши голову и смекнувши, что покупщик, верно, должен иметь здесь какую-нибудь выгоду.', '.', '302.jpg', 8, '2025-06-30 11:21:37'),
(357, '«Черт возьми, — подумал Чичиков про себя, — этот уж продает прежде.', '«Черт возьми, — подумал Чичиков про себя, — этот уж продает прежде, чем я заикнулся.', '«Черт возьми, — подумал Чичиков про себя, — этот уж продает прежде, чем я заикнулся.', '102.jpg', 51, '2025-06-26 09:05:15'),
(358, '— А, например, как же цена.', '— А, например, как же цена.', '— А, например, как же цена.', '101.jpg', 9, '2025-06-20 07:19:40'),
(359, '— Да чтобы не запрашивать с вас лишнего, по сту рублей за штуку.', '— Да чтобы не запрашивать с вас лишнего, по сту рублей за штуку! — сказал Собакевич.', '.', '103.jpg', 39, '2025-06-13 02:39:09'),
(360, '— По сту.', '— По сту! — вскричал Чичиков, разинув рот и поглядевши ему в самые глаза, не зная, сам ли он ослышался, или язык Собакевича по своей тяжелой натуре, не так поворотившись, брякнул вместо одного другое слово.', '.', '102.jpg', 39, '2025-06-11 21:22:55'),
(361, '— Что ж, разве это для вас дорого.', '— Что ж, разве это для вас дорого? — произнес Собакевич и потом прибавил: — А какая бы, однако ж, ваша цена.', '— Что ж, разве это для вас дорого? — произнес Собакевич и потом прибавил: — А какая бы, однако ж, ваша цена.', '202.jpg', 14, '2025-06-06 15:31:46'),
(362, '— Моя цена.', '— Моя цена! Мы, верно, как-нибудь ошиблись или не понимаем друг друга, позабыли, в чем состоит предмет.', ' Я полагаю с своей стороны, положа на руку на сердце: по восьми гривен за душу, это самая красная ценз.', '102.jpg', 10, '2025-06-03 09:17:24'),
(363, '— Так вы думаете, сыщете такого дурака.', '— Так вы думаете, сыщете такого дурака, который бы вам продал по двугривенному ревизскую душу.', '— Так вы думаете, сыщете такого дурака, который бы вам продал по двугривенному ревизскую душу.', '002.jpg', 11, '2025-05-27 08:02:00'),
(364, '— Но позвольте, зачем вы их называете ревизскими.', '— Но позвольте: зачем вы их называете ревизскими, ведь души-то самые давно уже умерли, остался один неосязаемый чувствами звук. Впрочем, чтобы не входить в дальнейшие разговоры по этой части, по полтора рубли, извольте, дам, а больше не могу.', '.', '101.jpg', 9, '2025-05-25 03:47:07'),
(365, '— Не могу, Михаил Семенович, поверьте моей совести, не могу.', '— Не могу, Михаил Семенович, поверьте моей совести, не могу: чего уж невозможно сделать, того невозможно сделать, — говорил Чичиков, однако ж по полтинке еще прибавил.', '.', '101.jpg', 18, '2025-05-17 00:29:01'),
(366, '— А Пробка Степан, плотник.', '— А Пробка Степан, плотник? я голову прозакладую, если вы где сыщете такого мужика.', ' Ведь что за силища была! Служи он в гвардии, ему бы бог знает что дали, трех аршин с вершком ростом.', '302.jpg', 47, '2026-01-19 07:22:59'),
(367, 'Чичиков опять хотел заметить, что и Пробки нет на свете, но Собакевича.', 'Чичиков опять хотел заметить, что и Пробки нет на свете, но Собакевича, как видно, пронесло, полились такие потоки речей, что только нужно было слушать.', 'Чичиков опять хотел заметить, что и Пробки нет на свете, но Собакевича, как видно, пронесло, полились такие потоки речей, что только нужно было слушать.', '203.jpg', 16, '2026-01-18 01:42:40'),
(368, '— Милушкин, кирпичник! мог поставить печь в каком угодно доме.', '— Милушкин, кирпичник! мог поставить печь в каком угодно доме. Максим Телятников, сапожник: что шилом кольнет, то и сапоги, что сапоги, то и спасибо, и хоть бы в рот хмельного.', ' А Еремей Сорокоплёхин! да этот мужик один станет за всех, в Москве торговал, одного оброку приносил по пятисот рублей. Ведь вот какой народ! Это не то, что вам продаст какой-нибудь Плюшкин.', '103.jpg', 19, '2026-01-11 23:23:35'),
(369, '— Но позвольте, — сказал наконец Чичиков.', '— Но позвольте, — сказал наконец Чичиков, изумленный таким обильным наводнением речей, которым, казалось, и конца не было, — зачем вы исчисляете все их качества, ведь в них толку теперь нет никакого, ведь это все народ мертвый.', ' Мертвым телом хоть забор подпирай, говорит пословица.', '100.jpg', 13, '2026-01-01 17:26:30'),
(370, '— Да, конечно, мертвые, — сказал Собакевич, как бы одумавшись и припомнив.', '— Да, конечно, мертвые, — сказал Собакевич, как бы одумавшись и припомнив, кто они в самом деле были уже мертвые, а потом прибавил: — Впрочем, и то сказать что из этих людей, которые числятся теперь живущими? Что это за люди? мухи, а не люди.', '.', '203.jpg', 47, '2025-12-28 14:59:56'),
(371, '— Извольте, чтоб не претендовали на меня.', '— Извольте, чтоб не претендовали на меня, что дорого запрашиваю и не хочу сделать вам никакого одолжения, извольте — по семидесяти пяти рублей за душу, только ассигнациями, право только для знакомства.', '— Извольте, чтоб не претендовали на меня, что дорого запрашиваю и не хочу сделать вам никакого одолжения, извольте — по семидесяти пяти рублей за душу, только ассигнациями, право только для знакомства.', '302.jpg', 15, '2026-01-14 03:28:00'),
(372, '«Что он в самом деле, — подумал про себя Чичиков, — за дурака, что ли.', '«Что он в самом деле, — подумал про себя Чичиков, — за дурака, что ли, принимает меня.', '«Что он в самом деле, — подумал про себя Чичиков, — за дурака, что ли, принимает меня.', '202.jpg', 60, '2026-01-04 23:25:04'),
(373, '— Мне странно, право, кажется.', '— Мне странно, право: кажется, между нами происходит какое-то театральное представление или комедия. иначе я не могу себе объяснить… Вы, кажется, человек довольно умный, владеете сведениями образованности. Ведь предмет просто фу-фу.', ' Что ж он стоит? кому нужен.', '302.jpg', 18, '2025-12-26 17:37:35'),
(374, 'Здесь Чичиков закусил губу и не нашелся, что отвечать.', 'Здесь Чичиков закусил губу и не нашелся, что отвечать.', ' Он стал было говорить про какие-то обстоятельства фамильные и семейственные, но Собакевич отвечал просто.', '302.jpg', 52, '2025-12-25 17:35:08'),
(375, '— Мне не нужно знать, какие у вас отношения, я в дела фамильные не мешаюсь.', '— Мне не нужно знать, какие у вас отношения; я в дела фамильные не мешаюсь, это ваше дело. Вам понадобились души, я и продаю вам, и будете раскаиваться, что не купили.', '.', '102.jpg', 58, '2025-12-17 13:22:55'),
(376, '— Эк, право, затвердила сорока Якова одно про всякого, как говорит пословица.', '— Эк, право, затвердила сорока Якова одно про всякого, как говорит пословица; как наладили на два, так не хотите с них и съехать.', ' Вы давайте настоящую цену.', '100.jpg', 21, '2025-12-15 10:46:43'),
(377, '«Ну, уж черт его побери, — подумал про себя Чичиков, — по полтине ему прибавлю.', '«Ну, уж черт его побери, — подумал про себя Чичиков, — по полтине ему прибавлю, собаке, на орехи.', '«Ну, уж черт его побери, — подумал про себя Чичиков, — по полтине ему прибавлю, собаке, на орехи.', '201.jpg', 33, '2025-12-06 07:27:18'),
(378, '— Ну, извольте, и я вам скажу тоже мое последнее слово: пятьдесят рублей.', '— Ну, извольте, и я вам скажу тоже мое последнее слово: пятьдесят рублей! Право, убыток себе, дешевле нигде не купите такого хорошего народа.', '— Ну, извольте, и я вам скажу тоже мое последнее слово: пятьдесят рублей! Право, убыток себе, дешевле нигде не купите такого хорошего народа.', '103.jpg', 49, '2025-11-28 03:47:23'),
(379, '«Экой кулак.', '«Экой кулак.', '«Экой кулак.', '301.jpg', 2, '2025-11-26 21:58:41'),
(380, '— Да что в самом деле… как будто точно сурьезное дело.', '— Да что в самом деле… как будто точно сурьезное дело; да я в другом месте нипочем возьму. Еще мне всякий с охотой сбудет их, чтобы только поскорей избавиться.', ' Дурак разве станет держать их при себе и платить за них подати.', '302.jpg', 29, '2025-11-23 18:03:21'),
(381, '— Но знаете ли, что такого рода покупки, я это говорю между нами, по дружбе.', '— Но знаете ли, что такого рода покупки, я это говорю между нами, по дружбе, не всегда позволительны.', '— Но знаете ли, что такого рода покупки, я это говорю между нами, по дружбе, не всегда позволительны, и расскажи я или кто иной — такому человеку не будет никакой доверенности относительно контрактов или вступления в какие-нибудь выгодные обязательства.', '203.jpg', 2, '2025-11-22 17:47:26'),
(382, '«Вишь, куды метит, подлец.', '«Вишь, куды метит, подлец.', '«Вишь, куды метит, подлец.', '201.jpg', 27, '2025-11-14 13:57:20'),
(383, '— Как вы себе хотите, я покупаю не для какой-либо надобности, как вы думаете.', '— Как вы себе хотите, я покупаю не для какой-либо надобности, как вы думаете, а так, по наклонности собственных мыслей.', ' Два с полтиною не хотите — прощайте.', '101.jpg', 51, '2025-11-10 11:14:10'),
(384, '— Позвольте, позвольте.', '— Позвольте, позвольте! — сказал Собакевич, не выпуская его руки и наступив ему на ногу, ибо герой наш позабыл поберечься, в наказанье за что должен был зашипеть и подскочить на одной ноге.', '.', '201.jpg', 16, '2025-11-03 07:08:24'),
(385, '— Прошу прощенья! я, кажется, вас побеспокоил.', '— Прошу прощенья! я, кажется, вас побеспокоил.', ' Пожалуйте, садитесь сюда! Прошу! — Здесь он усадил его в кресла с некоторою даже ловкостию, как такой медведь, который уже побывал в руках, умеет и перевертываться, и делать разные штуки на вопросы: «А покажи, Миша, как бабы парятся» или: «А как, Миша, малые ребята горох крадут.', '302.jpg', 48, '2025-10-30 07:07:10'),
(386, '— Посидите одну минуточку, я вам сейчас скажу одно приятное для вас слово.', '— Посидите одну минуточку, я вам сейчас скажу одно приятное для вас слово.', ' — Тут Собакевич подсел поближе и сказал ему тихо на ухо, как будто секрет: — Хотите угол.', '102.jpg', 46, '2025-10-29 05:19:46'),
(387, '— То есть двадцать пять рублей.', '— То есть двадцать пять рублей? Ни, ни, ни, даже четверти угла не дам, копейки не прибавлю.', '.', '101.jpg', 17, '2025-10-25 04:51:03'),
(388, 'Собакевич замолчал. Чичиков тоже замолчал. Минуты две длилось молчание.', 'Собакевич замолчал. Чичиков тоже замолчал. Минуты две длилось молчание. Багратион с орлиным носом глядел со стены чрезвычайно внимательно на эту покупку.', '.', '103.jpg', 17, '2025-10-18 23:42:11'),
(389, '— Право у вас душа человеческая все равно что пареная репа.', '— Право у вас душа человеческая все равно что пареная репа.', ' Уж хоть по три рубли дайте.', '203.jpg', 32, '2025-10-11 23:23:15'),
(390, '— Ну, нечего с вами делать, извольте.', '— Ну, нечего с вами делать, извольте! Убыток, да нрав такой собачий: не могу не доставить удовольствия ближнему. Ведь, я чай, нужно и купчую совершить, чтоб все было в порядке.', '.', '100.jpg', 19, '2025-10-09 22:01:19'),
(391, 'Так совершилось дело.', 'Так совершилось дело. Оба решили, что завтра же быть в городе и управиться с купчей крепостью. Чичиков попросил списочка крестьян.', ' Собакевич согласился охотно и тут же, подошед к бюро, собственноручно принялся выписывать всех не только поименно, но даже с означением похвальных качеств.', '301.jpg', 10, '2025-10-08 19:19:13'),
(392, 'А Чичиков от нечего делать занялся.', 'А Чичиков от нечего делать занялся, находясь позади рассматриваньем всего просторного его оклада.', ' Как взглянул он на его спину, широкую, как у вятских приземистых лошадей, и на ноги его, походившие на чугунные тумбы, которые ставят на тротуарах, не мог не воскликнуть внутренно: «Эк наградил-то тебя бог! вот уж точно, как говорят, неладно скроен, да крепко сшит!.. Родился ли ты уж так медведем, или омедведила тебя захолустная жизнь, хлебные посевы, возня с мужиками, и ты чрез них сделался то, что называют человек-кулак? Но нет: я думаю, ты все был бы тот же, хотя бы даже воспитали тебя по моде, пустили бы в ход и жил бы ты в Петербурге, а не в захолустье. Вся разница в том, что теперь ты упишешь полбараньего бока с кашей, закусивши ватрушкою в тарелку, а тогда бы ты ел какие-нибудь котлетки с трюфелями. Да вот теперь у тебя под властью мужики: ты с ними в ладу и, конечно, их не обидишь, потому что они твои, тебе же будет хуже; а тогда бы у тебя были чиновники, которых бы ты сильно пощелкивал, смекнувши, что они не твои же крепостные, или грабил бы ты казну! Нет, кто уж кулак, тому не разогнуться в ладонь! А разогни кулаку один или два пальца, выдет еще хуже. Попробуй он слегка верхушек какой-нибудь науки, даст он знать потом, занявши место повиднее всем тем, которые в самом деле узнали какую-нибудь науку. Да еще, пожалуй, скажет потом: „Дай-ка себя покажу!“ Да такое выдумает мудрое постановление, что многим придется солоно… Эх, если бы все кулаки!..', '103.jpg', 27, '2025-10-06 14:28:19'),
(393, '— Готова.', '— Готова.', '— Готова? Пожалуйте ее сюда! — Он пробежал ее глазами и подивился аккуратности и точности: не только было обстоятельно прописано ремесло, звание, лета и семейное состояние, но даже на полях находились особенные отметки насчет поведения, трезвости, — словом, любо было глядеть.', '100.jpg', 45, '2025-09-28 10:49:52'),
(394, 'Чичиков стал было отговариваться, что нет.', 'Чичиков стал было отговариваться, что нет, но Собакевич так сказал утвердительно, что у него есть деньги, что он вынул еще бумажку, сказавши.', 'Чичиков стал было отговариваться, что нет, но Собакевич так сказал утвердительно, что у него есть деньги, что он вынул еще бумажку, сказавши.', '100.jpg', 48, '2025-09-18 05:36:51'),
(395, '— На что ж деньги.', '— На что ж деньги? У меня вот они в руке! как только напишете расписку, в ту же минуту.', '.', '201.jpg', 39, '2025-09-09 05:14:31'),
(396, 'Чичиков выпустил из рук бумажки Собакевичу, который.', 'Чичиков выпустил из рук бумажки Собакевичу, который, приблизившись к столу и накрывши их пальцами левой руки, другою написал на лоскутке бумаги, что задаток двадцать пять рублей государственными ассигнациями за проданные души получил сполна.', ' Написавши записку, он пересмотрел еще раз ассигнации.', '202.jpg', 6, '2025-08-31 00:52:06'),
(397, '— Бумажка-то старенькая.', '— Бумажка-то старенькая! — произнес он, рассматривая одну из них на свете, — немножко разорвана, ну да между приятелями нечего на это глядеть.', '.', '203.jpg', 31, '2025-08-20 23:42:37'),
(398, '— Ну, когда не нуждаетесь, так нечего и говорить.', '— Ну, когда не нуждаетесь, так нечего и говорить. На вкусы нет закона: кто любит попа, а кто попадью, говорит пословица.', '.', '101.jpg', 40, '2025-08-19 20:58:51'),
(399, '— Еще я хотел вас попросить, чтобы эта сделка осталась между нами.', '— Еще я хотел вас попросить, чтобы эта сделка осталась между нами, — говорил Чичиков, прощаясь.', '.', '301.jpg', 16, '2025-08-16 14:50:20'),
(400, '— Да уж само собою разумеется.', '— Да уж само собою разумеется. Третьего сюда нечего мешать; что по искренности происходит между короткими друзьями, то должно остаться во взаимной их дружбе.', ' Прощайте! Благодарю, что посетили; прошу и впредь не забывать: коли выберется свободный часик, приезжайте пообедать, время провести. Может быть, опять случится услужить чем-нибудь друг другу.', '301.jpg', 7, '2025-08-12 13:30:44'),
(401, '«Да, как бы не так! — думал про себя Чичиков, садясь. в бричку.', '«Да, как бы не так! — думал про себя Чичиков, садясь. в бричку.', ' — По два с полтиною содрал за мертвую душу, чертов кулак.', '301.jpg', 24, '2025-08-04 09:35:55'),
(402, 'Он был недоволен поведением Собакевича.', 'Он был недоволен поведением Собакевича.', ' Все-таки, как бы то ни было, человек знакомый, и у губернатора, и у полицеймейстера видались, а поступил как бы совершенно чужой, за дрянь взял деньги! Когда бричка выехала со двора, он оглянулся назад и увидел, что Собакевич все еще стоял на крыльце и, как казалось, приглядывался, желая знать, куда гость поедет.', '100.jpg', 40, '2025-07-31 07:02:49'),
(403, '— Подлец, до сих пор еще стоит.', '— Подлец, до сих пор еще стоит! — проговорил он сквозь зубы и велел Селифану, поворотивши к крестьянским избам, отъехать таким образом, чтобы нельзя было видеть экипажа со стороны господского двора.', ' Ему хотелось заехать к Плюшкину, у которого, по словам Собакевича, люди умирали, как мухи, но не хотелось, чтобы Собакевич знал про это. Когда бричка была уже на конце деревни, он подозвал к себе первого мужика, который, попавши где-то на дороге претолстое бревно, тащил его на плече, подобно неутомимому муравью, к себе в избу.', '002.jpg', 31, '2025-07-28 04:33:05'),
(404, '— Эй, борода.', '— Эй, борода! а как проехать отсюда к Плюшкину, так чтоб не мимо господского дома.', '— Эй, борода! а как проехать отсюда к Плюшкину, так чтоб не мимо господского дома.', '201.jpg', 32, '2025-07-25 03:14:39'),
(405, '— Эх, ты! А и седым волосом еще подернуло.', '— Эх, ты! А и седым волосом еще подернуло! скрягу Плюшкина не знаешь, того, что плохо кормит людей.', '— Эх, ты! А и седым волосом еще подернуло! скрягу Плюшкина не знаешь, того, что плохо кормит людей.', '201.jpg', 23, '2025-07-18 00:10:19'),
(406, 'Было им прибавлено и существительное к слову «заплатанной», очень удачное.', 'Было им прибавлено и существительное к слову «заплатанной», очень удачное, но неупотребительное в светском разговоре, а потому мы его пропустим.', ' Впрочем, можно догадываться, что оно выражено было очень метко, потому что Чичиков, хотя мужик давно уже пропал из виду и много уехали вперед, однако ж все еще усмехался, сидя в бричке. Выражается сильно российский народ! и если наградит кого словцом, то пойдет оно ему в род и потомство, утащит он его с собою и на службу, и в отставку, и в Петербург, и на край света. И как уж потом ни хитри и ни облагораживай свое прозвище, хоть заставь пишущих людишек выводить его за наемную плату от древнекняжеского рода, ничто не поможет: каркнет само за себя прозвище во все свое воронье горло и скажет ясно, откуда вылетела птица. Произнесенное метко, все равно что писанное, не вырубливается топором.', '302.jpg', 30, '2025-07-07 18:22:10'),
(407, 'Как несметное множество церквей, монастырей с куполами, главами, крестами.', 'Как несметное множество церквей, монастырей с куполами, главами, крестами, рассыпано на святой, благочестивой Руси, так несметное множество племен, поколений, народов толпится, пестреет и мечется по лицу земли.', ' И всякий народ, носящий в себе залог сил, полный творящих способностей души, своей яркой особенности и других даров нога, своеобразно отличился каждый своим собственным словом, которым, выражая какой ни есть предмет, отражает в выраженье его часть собственного своего характера. Сердцеведением и мудрым познаньем жизни отзовется слово британца; легким щеголем блеснет и разлетится недолговечное слово француза; затейливо придумает свое, не всякому доступное, умно-худощавое слово немец; но нет слова, которое было бы так замашисто, бойко так вырвалось бы из-под самого сердца, так бы кипело и животрепетало, как метко сказанное русское слово.', '301.jpg', 35, '2025-06-30 12:38:49'),
(408, 'Прежде, давно, в лета моей юности.', 'Прежде, давно, в лета моей юности, в лета невозвратно мелькнувшего моего детства, мне было весело подъезжать в первый раз к незнакомому месту, все равно, была ли то деревушка, бедный уездный городишка, село ли, слободка.', 'Прежде, давно, в лета моей юности, в лета невозвратно мелькнувшего моего детства, мне было весело подъезжать в первый раз к незнакомому месту: все равно, была ли то деревушка, бедный уездный городишка, село ли, слободка, — любопытного много открывал в нем детский любопытный взгляд. Всякое строение, все, что носило только на себе напечатленье какой-нибудь заметной особенности, — все останавливало меня и поражало. Каменный ли казенный дом, известной архитектуры с половиною фальшивых окон, один-одинешенек торчавший среди бревенчатой тесаной кучи одноэтажных мещанских обывательских домиков, круглый ли правильный купол, весь обитый листовым белым железом, вознесенный над выбеленною, как снег, новою церковью, рынок ли, франт ли уездный, попавшийся среди города, — ничто не ускользало от свежего тонкого вниманья, и, высунувши нос из походной телеги своей, я глядел и на невиданный дотоле покрой какого-нибудь сюртука, и на деревянные ящики с гвоздями, с серой, желтевшей вдали, с изюмом и мылом, мелькавшие из дверей овощной лавки вместе с банками высохших московских конфект, глядел и на шедшего в стороне пехотного офицера, занесенного бог знает из какой губернии на уездную скуку, и на купца, мелькнувшего в сибирке на беговых дрожках, и уносился мысленно за ними в бедную жизнь их. Уездный чиновник пройди мимо — я уже и задумывался: куда он идет, на вечер ли к какому-нибудь своему брату, или прямо к себе домой, чтобы, посидевши с полчаса на крыльце, пока не совсем еще сгустились сумерки, сесть за ранний ужин с матушкой, с женой, с сестрой жены и всей семьей, и о чем будет веден разговор у них в то время, когда дворовая девка в монистах или мальчик в толстой куртке принесет уже после супа сальную свечу в долговечном домашнем подсвечнике. Подъезжая к деревне какого-нибудь помещика, я любопытно смотрел на высокую узкую деревянную колокольню или широкую темную деревянную старую церковь.', '203.jpg', 21, '2025-06-25 10:41:42'),
(409, 'Теперь равнодушно подъезжаю ко всякой незнакомый деревне и равнодушно гляжу на.', 'Теперь равнодушно подъезжаю ко всякой незнакомый деревне и равнодушно гляжу на ее пошлую наружность, моему охлажденному взору неприютно, мне не смешно, и то, что пробудило бы в прежние годы живое движенье в лице, смех и немолчные речи.', 'Теперь равнодушно подъезжаю ко всякой незнакомый деревне и равнодушно гляжу на ее пошлую наружность; моему охлажденному взору неприютно, мне не смешно, и то, что пробудило бы в прежние годы живое движенье в лице, смех и немолчные речи, то скользит теперь мимо, и безучастное молчание хранят мои недвижные уста.', '302.jpg', 15, '2025-06-23 07:45:40'),
(410, 'Покамест Чичиков думал и внутренно посмеивался над прозвищем.', 'Покамест Чичиков думал и внутренно посмеивался над прозвищем, отпущенным мужиками Плюшкину, он не заметил, как въехал в средину обширного села со множеством изб и улиц.', ' Скоро, однако же, дал заметить ему это препорядочный толчок, произведенный бревенчатою мостовою, пред которою городская каменная была ничто. Эти бревна, как фортепьянные клавиши, подымались то вверх, то вниз, и необерегшийся ездок приобретал или шишку на затылок, или синее пятно на лоб, или же случалось своими собственными зубами откусить пребольно хвостик собственного же языка. Какую-то особенную ветхость заметил он на всех деревенских строениях: бревно на избах было темно и старо; многие крыши сквозили, как решето; на иных оставался только конек вверху да жерди по сторонам в виде ребр. Кажется, сами хозяева снесли с них дранье и тес, рассуждая, и, конечно, справедливо, что в дождь избы не кроют, а в ведро и сама не каплет, бабиться же в ней незачем, когда есть простор и в кабаке, и на большой дороге, — словом, где хочешь. Окна в избенках были без стекол, иные были заткнуты тряпкой или зипуном; балкончики под крышами с перилами, неизвестно для каких причин делаемые в иных русских избах, покосились и почернели даже не живописно. Из-за изб тянулись во многих местах рядами огромные клади хлеба, застоявшиеся, как видно, долго; цветом походили они на старый, плохо выжженный кирпич, на верхушке их росла всякая дрянь, и даже прицепился сбоку кустарник. Хлеб, как видно, был господский. Из-за хлебных кладей и ветхих крыш возносились и мелькали на чистом воздухе, то справа, то слева, по мере того как бричка делала повороты, две сельские церкви, одна возле другой: опустевшая деревянная и каменная, с желтенькими стенами, испятнанная, истрескавшаяся. Частями стал выказываться господский дом и наконец глянул весь в том месте, где цепь изб прервалась и наместо их остался пустырем огород или капустник, обнесенный низкою, местами изломанною городьбою. Каким-то дряхлым инвалидом глядел сей странный замок, длинный, длинный непомерно.', '301.jpg', 15, '2025-06-19 05:08:17'),
(411, 'Старый, обширный, тянувшийся позади дома сад.', 'Старый, обширный, тянувшийся позади дома сад, выходивший за село и потом пропадавший в поле, заросший и заглохлый, казалось, один освежал эту обширную деревню и один был вполне живописен в своем картинном опустении.', ' Зелеными облаками и неправильными трепетолистными куполами лежали на небесном горизонте соединенные вершины разросшихся на свободе дерев. Белый колоссальный ствол березы, лишенный верхушки, отломленной бурею или грозою, подымался из этой зеленой гущи и круглился на воздухе, как правильная мраморная сверкающая колонна; косой остроконечный излом его, которым он оканчивался кверху вместо капители, темнел на снежной белизне его, как шапка или черная птица. Хмель, глушивший внизу кусты бузины, рябины и лесного орешника и пробежавший потом по верхушке всего частокола, взбегал наконец вверх и обвивал до половины сломленную березу. Достигнув середины ее, он оттуда свешивался вниз и начинал уже цеплять вершины других дерев или же висел на воздухе, завязавши кольцами свои тонкие цепкие крючья, легко колеблемые воздухом. Местами расходились зеленые чащи, озаренные солнцем, и показывали неосвещенное между них углубление, зиявшее, как темная пасть; оно было окинуто тенью, и чуть-чуть мелькали в черной глубине его: бежавшая узкая дорожка, обрушена нее перилы, пошатнувшаяся беседка, дуплистый дряхлый ствол ивы, седой чапыжник, густой щетиною вытыкавший из-за ивы иссохшие от страшной глушины, перепутавшиеся и скрестившиеся листья и сучья, и, наконец, молодая ветвь клена, протянувшая сбоку свои зеленые лапы-листы, под один из которых забравшись бог весть каким образом, солнце превращало его вдруг в прозрачный и огненный, чудно сиявший в этой густой темноте. В стороне, у самого края сада, несколько высокорослых, не вровень другим, осин подымали огромные вороньи гнезда на трепетные свои вершины. У иных из них отдернутые и не вполне отделенные ветви висели вниз вместе с иссохшими листьями.', '203.jpg', 41, '2025-06-16 03:48:44'),
(412, 'Сделав один или два поворота, герой наш очутился наконец перед самым домом.', 'Сделав один или два поворота, герой наш очутился наконец перед самым домом, который показался теперь еще печальнее. Зеленая плеснь уже покрыла ветхое дерево на ограде и воротах.', ' Толпа строений: людских, амбаров, погребов, видимо ветшавших, — наполняла двор; возле них направо и налево видны были ворота в другие дворы. Все говорило, что здесь когда-то хозяйство текло в обширном размере, и все глядело ныне пасмурно. Ничего не заметно было оживляющего картину: ни отворявшихся дверей, ни выходивших откуда-нибудь людей, никаких живых хлопот и забот дома! Только одни главные ворота были растворены, и то потому, что въехал мужик с нагруженною телегою, покрытою рогожею, показавшийся как бы нарочно для оживления сего вымершего места; в другое время и они были заперты наглухо, ибо в железной петле висел замок-исполин. У одного из строений Чичиков скоро заметил какую-то фигуру, которая начала вздорить с мужиком, приехавшим на телеге. Долго он не мог распознать, какого пола была фигура: баба или мужик. Платье на ней было совершенно неопределенное, похожее очень на женский капот, на голове колпак, какой носят деревенские дворовые бабы, только один голос показался ему несколько сиплым для женщины. «Ой, баба! — подумал он про себя и тут же прибавил: — Ой, нет!» — «Конечно, баба!» — наконец сказал он, рассмотрев попристальнее. Фигура с своей стороны глядела на него тоже пристально. Казалось, гость был для нее в диковинку, потому что она обсмотрела не только его, но и Селифана, и лошадей, начиная с хвоста и до морды. По висевшим у ней за поясом ключам и по тому, что она бранила мужика довольно поносными словами, Чичиков заключил, что это, верно, ключница.', '101.jpg', 21, '2025-06-13 03:30:11'),
(413, '— Нет дома, — прервала ключница, не дожидаясь окончания вопроса, и потом.', '— Нет дома, — прервала ключница, не дожидаясь окончания вопроса, и потом, спустя минуту, прибавила: — А что вам нужно.', '— Нет дома, — прервала ключница, не дожидаясь окончания вопроса, и потом, спустя минуту, прибавила: — А что вам нужно.', '301.jpg', 29, '2025-06-04 01:28:52'),
(414, '— Идите в комнаты.', '— Идите в комнаты! — сказала ключница, отворотившись и показав ему спину, запачканную мукою, с большой прорехою пониже.', '.', '101.jpg', 56, '2025-05-27 20:46:37'),
(415, 'Он вступил в темные широкие сени, от которых подуло холодом, как из погреба.', 'Он вступил в темные широкие сени, от которых подуло холодом, как из погреба. Из сеней он попал в комнату, тоже темную, чуть-чуть озаренную светом, выходившим из-под широкой щели, находившейся внизу двери.', ' Отворивши эту дверь, он наконец очутился в свету и был поражен представшим беспорядком. Казалось, как будто в доме происходило мытье полов и сюда на время нагромоздили всю мебель. На одном столе стоял даже сломанный стул, и рядом с ним часы с остановившимся маятником, к которому паук уже приладил паутину. Тут же стоял прислоненный боков к стене шкаф с старинным серебром, графинчиками и китайским фарфором. На бюре, выложенном перламутною мозаикой, которая местами уже выпала и оставила после себя одни желтенькие желобки, наполненные клеем, лежало множества всякой всячины: куча исписанных мелко бумажек, накрытых мраморным позеленевшим прессом с яичком наверху, какая-то старинная книга в кожаном переплете с красным обрезом, лимон, весь высохший, ростом не более лесного ореха, отломленная ручка кресел, рюмка с какою-то жидкостью и тремя мухами, накрытая письмом, кусочек сургучика, кусочек где-то поднятой тряпки, два пера, запачканные чернилами, высохшие, как в чахотке, зубочистка, совершенно пожелтевшая, которою хозяин, может быть, ковырял в зубах своих еще до нашествия на Москву французов.', '103.jpg', 17, '2025-05-24 15:19:58'),
(416, 'По стенам навешано было весьма тесно и бестолково несколько картин.', 'По стенам навешано было весьма тесно и бестолково несколько картин, длинный пожелтевший гравюр какого-то сражения, с огромными барабанами, кричащими солдатами в треугольных шляпах и тонущими конями, без стекла.', 'По стенам навешано было весьма тесно и бестолково несколько картин: длинный пожелтевший гравюр какого-то сражения, с огромными барабанами, кричащими солдатами в треугольных шляпах и тонущими конями, без стекла, вставленный в раму красного дерева с тоненькими бронзовыми полосками и бронзовыми же кружками по углам. В ряд с ними занимала полстены огромная почерневшая картина, писанная масляными красками, изображавшая цветы, фрукты, разрезанный арбуз, кабанью морду и висевшую головою вниз утку. С середины потолка висела люстра в холстинном мешке, от пыли сделавшаяся похожею на шелковый кокон, в котором сидит червяк. В углу комнаты была навалена на полу куча того, что погрубее и что недостойно лежать на столах. Что именно находилось в куче, решить было трудно, ибо пыли на ней было в таком изобилии, что руки всякого касавшегося становились похожими на перчатки; заметнее прочего высовывался оттуда отломленный кусок деревянной лопаты и старая подошва сапога. Никак бы нельзя было сказать, чтобы в комнате сей обитало живое существо, если бы не возвещал его пребыванье старый, поношенный колпак, лежавший на столе. Пока он рассматривал все странное убранство, отворилась боковая дверь и взошла та же самая ключница, которую встретил он на дворе. Но тут увидел он, что это был скорее ключник, чем ключница: ключница по крайней мере не бреет бороды, а этот, напротив того, брил, и, казалось, довольно редко, потому что весь подбородок с нижней частью щеки походил у него на скребницу из железной проволоки, какою чистят на конюшне лошадей. Чичиков, давши вопросительное выражение лицу своему, ожидал с нетерпеньем, что хочет сказать ему ключник. Ключник тоже с своей стороны ожидал, что хочет ему сказать Чичиков.', '302.jpg', 32, '2025-05-18 12:49:28'),
(417, '— Что, батюшка, слепы-то, что ли? — спросил ключник.', '— Что, батюшка, слепы-то, что ли? — спросил ключник.', ' — Эхва! А вить хозяин-то я.', '201.jpg', 51, '2025-05-13 09:01:34'),
(418, 'Здесь герой наш поневоле отступил назад и поглядел на него пристально.', 'Здесь герой наш поневоле отступил назад и поглядел на него пристально. Ему случалось видеть немало всякого рода людей, даже таких, какие нам с читателем, может быть, никогда не придется увидать; но такого он еще не видывал.', ' Лицо его не представляло ничего особенного; оно было почти такое же, как у многих худощавых стариков, один подбородок только выступал очень далеко вперед, так что он должен был всякий раз закрывать его платком, чтобы не заплевать; маленькие глазки еще не потухнули и бегали из-под высоко выросших бровей, как мыши, когда, высунувши из темных нор остренькие морды, насторожа уши и моргая усом, они высматривают, не затаился ли где кот или шалун мальчишка, и нюхают подозрительно самый воздух. Гораздо замечательнее был наряд его: никакими средствами и стараньями нельзя бы докопаться, из чего состряпан был его халат: рукава и верхние полы до того засалились и залоснились, что походили на юфть, какая идет на сапоги; назади вместо двух болталось четыре полы, из которых охлопьями лезла хлопчатая бумага. На шее у него тоже было повязано что-то такое, которого нельзя было разобрать: чулок ли, подвязка ли, или набрюшник, только никак не галстук. Словом, если бы Чичиков встретил его, так принаряженного, где-нибудь у церковных дверей, то, вероятно, дал бы ему медный грош. Ибо к чести героя нашего нужно сказать, что сердце у него было сострадательно и он не мог никак удержаться, чтобы не подать бедному человеку медного гроша. Но пред ним стоял не нищий, пред ним стоял помещик. У этого помещика была тысяча с лишком душ, и попробовал бы кто найти у кого другого столько хлеба зерном, мукою и просто в кладях, у кого бы кладовые, амбары и сушилы загромождены были таким множеством холстов, сукон, овчин выделанных и сыромятных, высушенными рыбами и всякой овощью, или губиной.', '103.jpg', 55, '2025-05-10 07:19:10');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(419, 'А ведь было время, когда он только был бережливым хозяином.', 'А ведь было время, когда он только был бережливым хозяином! был женат и семьянин, и сосед заезжал к нему пообедать, слушать и учиться у него хозяйству и мудрой скупости.', ' Все текло живо и совершалось размеренным ходом: двигались мельницы, валяльни, работали суконные фабрики, столярные станки, прядильни; везде во все входил зоркий взгляд хозяина и, как трудолюбивый паук, бегал хлопотливо, но расторопно, по всем концам своей хозяйственной паутины. Слишком сильные чувства не отражались в чертах лица его, но в глазах был виден ум; опытностию и познанием света была проникнута речь его, и гостю было приятно его слушать; приветливая и говорливая хозяйка славилась хлебосольством; навстречу выходили две миловидные дочки, обе белокурые и свежие, как розы; выбегал сын, разбитной мальчишка, и целовался со всеми, мало обращая внимания на то, рад ли, или не рад был этому гость. В доме были открыты все окна, антресоли были заняты квартирою учителя-француза, который славно брился и был большой стрелок: приносил всегда к обеду тетерек или уток, а иногда и одни воробьиные яйца, из которых заказывал себе яичницу, потому что больше в целом доме никто ее не ел. На антресолях жила также его компатриотка, наставница двух девиц. Сам хозяин являлся к столу в сюртуке, хотя несколько поношенном, но опрятном, локти были в порядке: нигде никакой заплаты. Но добрая хозяйка умерла; часть ключей, а с ними мелких забот, перешла к нему. Плюшкин стал беспокойнее и, как все вдовцы, подозрительнее и скупее. На старшую дочь Александру Степановну он не мог во всем положиться, да и был прав, потому что Александра Степановна скоро убежала с штабс-ротмистром, бог весть какого кавалерийского полка, и повенчалась с ним где-то наскоро в деревенской церкви, зная, что отец не любит офицеров по странному предубеждению, будто бы все военные картежники и мотишки. Отец послал ей на дорогу проклятие, а преследовать не заботился. В доме стало еще пустее.', '102.jpg', 24, '2025-05-02 07:04:56'),
(420, 'Итак, вот какого рода помещик стоял перед Чичиковым.', 'Итак, вот какого рода помещик стоял перед Чичиковым.', 'Итак, вот какого рода помещик стоял перед Чичиковым! Должно сказать, что подобное явление редко попадается на Руси, где все любит скорее развернуться, нежели съежиться, и тем поразительнее бывает оно, что тут же в соседстве подвернется помещик, кутящий во всю ширину русской удали и барства, прожигающий, как говорится, насквозь жизнь. Небывалый проезжий остановится с изумлением при виде его жилища, недоумевая, какой владетельный принц очутился внезапно среди маленьких, темных владельцев: дворцами глядят его белые каменные домы с бесчисленным множеством труб, бельведеров, флюгеров, окруженные стадом флигелей и всякими помещениями для приезжих гостей. Чего нет у него? Театры, балы; всю ночь сияет убранный огнями и плошками, оглашенный громом музыки сад. Полгубернии разодето и весело гуляет под деревьями, и никому не является дикое и грозящее в сем насильственном освещении, когда театрально выскакивает из древесной гущи озаренная поддельным светом ветвь, лишенная своей яркой зелени, а вверху темнее, и суровее, и в двадцать раз грознее является чрез то ночное небо и, далеко трепеща листьями в вышине, уходя глубже в непробудный мрак, негодуют суровые вершины дерев на сей мишурный блеск, осветивший снизу их корни.', '102.jpg', 5, '2025-04-24 05:01:50'),
(421, 'Уже несколько минут стоял Плюшкин, не говоря ни слова.', 'Уже несколько минут стоял Плюшкин, не говоря ни слова, а Чичиков все еще не мог начать разговора, развлеченный как видом самого хозяина, так и всего того, что было в его комнате.', ' Долго не мог он придумать, в каких бы словах изъяснять причину своего посещения. Он уже хотел было выразиться в таком духе, что, наслышась о добродетели и редких свойствах души его, почел долгом принести лично дань уважения, но спохватился и почувствовал, что это слишком. Искоса бросив еще один взгляд на все, что было в комнате, он почувствовал, что слово «добродетель» и «редкие свойства души» можно с успехом заменить словами «экономия» и «порядок»; и потому, преобразивши таким образом речь, он сказал, что, наслышась об экономии его и редком управлении имениями, он почел за долг познакомиться и принести лично свое почтение. Конечно, можно было бы привести иную, лучшую причину, но ничего иного не взбрело тогда на ум.', '102.jpg', 56, '2025-04-15 23:14:48'),
(422, 'На это Плюшкин что-то пробормотал сквозь губы, ибо зубов не было, что именно.', 'На это Плюшкин что-то пробормотал сквозь губы, ибо зубов не было, что именно, неизвестно, но, вероятно, смысл был таков: «А побрал бы тебя черт с твоим почтением.', 'На это Плюшкин что-то пробормотал сквозь губы, ибо зубов не было, что именно, неизвестно, но, вероятно, смысл был таков: «А побрал бы тебя черт с твоим почтением!» Но так как гостеприимство у нас в таком ходу, что и скряга не в силах преступить его законов, то он прибавил тут же несколько внятнее: «Прошу покорнейше садиться.', '302.jpg', 47, '2025-04-05 19:31:45'),
(423, '— Я давненько не вижу гостей, — сказал он, — да, признаться сказать.', '— Я давненько не вижу гостей, — сказал он, — да, признаться сказать, в них мало вижу проку.', ' Завели пренеприличный обычай ездить друг к другу, а в хозяйстве-то упущения… да и лошадей их корми сеном! Я давно уж отобедал, а кухня у меня низкая, прескверная, и труба-то совсем развалилась: начнешь топить, еще пожару наделаешь.', '101.jpg', 46, '2025-04-01 15:58:45'),
(424, '«Вон оно как! — подумал про себя Чичиков.', '«Вон оно как! — подумал про себя Чичиков. — Хорошо же, что я у Собакевича перехватил ватрушку да ломоть бараньего бока».', '.', '101.jpg', 55, '2025-03-25 11:36:05'),
(425, '— И такой скверный анекдот, что сена хоть бы клок в целом хозяйстве.', '— И такой скверный анекдот, что сена хоть бы клок в целом хозяйстве! — продолжал Плюшкин.', ' — Да и в самом деле, как приберетесь его.', '103.jpg', 6, '2025-03-20 06:31:27'),
(426, '— Мне, однако же, сказывали, — скромно заметил Чичиков.', '— Мне, однако же, сказывали, — скромно заметил Чичиков, — что у вас более тысячи душ.', '.', '002.jpg', 18, '2025-03-17 05:17:54'),
(427, '— А кто это сказывал.', '— А кто это сказывал? А вы бы, батюшка, наплевали в глаза тому, который это сказывал! Он, пересмешник видно, хотел пошутить над вами.', ' Вот, бают, тысячи душ, а поди-тка сосчитай, а и ничего не начтешь! Последние три года проклятая горячка выморила у меня здоровенный куш мужиков.', '203.jpg', 44, '2025-03-16 00:44:06'),
(428, '— Позвольте еще спросить, ведь эти души, я полагаю.', '— Позвольте еще спросить: ведь эти души, я полагаю, вы считаете со дня подачи последней ревизии.', '— Позвольте еще спросить: ведь эти души, я полагаю, вы считаете со дня подачи последней ревизии.', '002.jpg', 28, '2025-03-05 19:11:35'),
(429, '— Это бы еще слава богу, — сказал Плюшкин, — да лих-то.', '— Это бы еще слава богу, — сказал Плюшкин, — да лих-то, что с того времени до ста двадцати наберется.', '.', '201.jpg', 29, '2025-02-25 16:22:50'),
(430, '— Вправду? Целых сто двадцать.', '— Вправду? Целых сто двадцать? — воскликнул Чичиков и даже разинул несколько рот от изумления.', '.', '101.jpg', 16, '2025-02-19 13:57:51'),
(431, '— Стар я, батюшка, чтобы лгать: седьмой десяток живу! — сказал Плюшкин.', '— Стар я, батюшка, чтобы лгать: седьмой десяток живу! — сказал Плюшкин. Он, казалось, обиделся таким почти радостным восклицанием.', ' Чичиков заметил, что в самом деле неприлично подобное безучастие к чужому горю, и потому вздохнул тут же и сказал, что соболезнует.', '100.jpg', 50, '2025-02-17 08:58:00'),
(432, '— Да ведь соболезнование в карман не положишь, — сказал Плюшкин.', '— Да ведь соболезнование в карман не положишь, — сказал Плюшкин.', ' — Вот возле меня живет капитан; черт знает его, откуда взялся, говорит — родственник: «Дядюшка, дядюшка!» — и в руку целует, а как начнет соболезновать, вой такой подымет, что уши береги. С лица весь красный: пеннику, чай, насмерть придерживается.', '100.jpg', 28, '2025-02-10 06:32:54'),
(433, 'Чичиков постарался объяснить, что его соболезнование совсем не такого рода.', 'Чичиков постарался объяснить, что его соболезнование совсем не такого рода, как капитанское, и что он не пустыми словами, а делом готов доказать его и, не откладывая дела далее, без всяких обиняков.', 'Чичиков постарался объяснить, что его соболезнование совсем не такого рода, как капитанское, и что он не пустыми словами, а делом готов доказать его и, не откладывая дела далее, без всяких обиняков, тут же изъявил готовность принять на себя обязанность платить подати за всех крестьян, умерших такими несчастными случаями. Предложение, казалось, совершенно изумило Плюшкина.', '201.jpg', 29, '2025-02-06 01:51:28'),
(434, '— По статской.', '— По статской? — повторил Плюшкин и стал жевать губами, как будто что-нибудь кушал.', ' — Да ведь как же? Ведь это вам самим-то в убыток.', '203.jpg', 28, '2025-02-05 01:26:21'),
(435, '— Ах, батюшка! ах, благодетель мой.', '— Ах, батюшка! ах, благодетель мой! — вскрикнул Плюшкин, не замечая от радости, что у него из носа выглянул весьма некартинно табак, на образец густого копия, и полы халата, раскрывшись, показали платье, не весьма приличное для рассматриванья.', ' — Вот утешили старика! Ах, господи ты мой! ах, святители вы мои!.. — Далее Плюшкин и говорить не мог. Но не прошло и минуты, как эта радость, так мгновенно показавшаяся на деревянном лице его, так же мгновенно и прошла, будто ее вовсе не бывало, и лицо его вновь приняло заботливое выражение Он даже утерся платком и, свернувши его в комок, стал им возить себя по верхней губе.', '102.jpg', 0, '2025-01-31 22:53:51'),
(436, '— Как же, с позволения вашего, чтобы не рассердить вас.', '— Как же, с позволения вашего, чтобы не рассердить вас, вы за всякий год беретесь платить за них подать? и деньги будете выдавать мне или в казну.', '— Как же, с позволения вашего, чтобы не рассердить вас, вы за всякий год беретесь платить за них подать? и деньги будете выдавать мне или в казну.', '102.jpg', 14, '2025-01-22 19:17:02'),
(437, '— Да мы вот как сделаем, мы совершим на них купчую крепость.', '— Да мы вот как сделаем: мы совершим на них купчую крепость, как бы они были живые и как бы вы их мне продали.', '.', '100.jpg', 59, '2025-01-14 14:05:18'),
(438, '— Да, купчую крепость… — сказал Плюшкин, задумался и стал опять кушать губами.', '— Да, купчую крепость… — сказал Плюшкин, задумался и стал опять кушать губами. — Ведь вот купчую крепость — всё издержки.', ' Приказные такие бессовестные! Прежде, бывало, полтиной меди отделаешься да мешком муки, а теперь пошли целую подводу круп, да и красную бумажку прибавь, такое сребролюбие! Я не знаю, как священники-то не обращают на это внимание; сказал бы какое-нибудь поучение: ведь что ни говори, а против слова-то божия не устоишь.', '102.jpg', 41, '2025-01-13 09:28:11'),
(439, '«Ну, ты, я думаю, устоишь.', '«Ну, ты, я думаю, устоишь!» — подумал про себя Чичиков и произнес тут же, что, из уважения к нему, он готов принять даже издержки по купчей на свой счет.', '.', '302.jpg', 44, '2025-01-12 06:30:22'),
(440, 'Чичиков изъявил готовность совершить ее хоть сию же минуту и потребовал только.', 'Чичиков изъявил готовность совершить ее хоть сию же минуту и потребовал только списка всем крестьянам.', '.', '002.jpg', 3, '2026-01-11 19:12:18'),
(441, 'Это успокоило Плюшкина.', 'Это успокоило Плюшкина.', ' Заметно было, что он придумывал что-то сделать, и точно, взявши ключи, приблизился к шкафу и, отперши дверцу, рылся долго между стаканами и чашками и наконец произнес.', '301.jpg', 20, '2026-01-06 15:55:10'),
(442, '— Ведь вот не сыщешь, а у меня был славный ликерчик, если только не выпили.', '— Ведь вот не сыщешь, а у меня был славный ликерчик, если только не выпили! народ такие воры! А вот разве не это ли он? — Чичиков увидел в руках его графинчик, который был весь в пыли, как в фуфайке.', ' — Еще покойница делала, — продолжал Плюшкин, — мошенница ключница совсем было его забросила и даже не закупорила, каналья! Козявки и всякая дрянь было напичкались туда, но я весь сор-то повынул, и теперь вот чистенькая; я вам налью рюмочку.', '202.jpg', 39, '2026-01-04 13:12:21'),
(443, 'Но Чичиков постарался отказаться от такого ликерчика, сказавши.', 'Но Чичиков постарался отказаться от такого ликерчика, сказавши, что он уже и пил и ел.', '.', '102.jpg', 6, '2026-01-03 08:20:19'),
(444, '— Пили уже и ели! — сказал Плюшкин.', '— Пили уже и ели! — сказал Плюшкин.', ' — Да, конечно, хорошего общества человека хоть где узнаешь: он не ест, а сыт; а как эдакой какой-нибудь воришка, да его сколько ни корми… Ведь вот капитан — приедет: «Дядюшка, говорит, дайте чего-нибудь поесть!» А я ему такой же дядюшка, как он мне дедушка. У себя дома есть, верно, нечего, так вот он и шатается! Да, ведь вам нужен реестрик всех этих тунеядцев? Как же, я, как знал, всех их списал на особую бумажку, чтобы при первой подаче ревизии всех их вычеркнуть.', '201.jpg', 56, '2025-12-24 07:08:20'),
(445, 'Плюшкин надел очки и стал рыться в бумагах.', 'Плюшкин надел очки и стал рыться в бумагах. Развязывая всякие связки, он попотчевал своего гостя такою пылью, что тот чихнул. Наконец вытащил бумажку, всю исписанную кругом. Крестьянские имена усыпали ее тесно, как мошки.', ' Были там всякие: и Парамонов, и Пименов, и Пантелеймонов, и даже выглянул какой-то Григорий Доезжай-не-доедешь; всех было сто двадцать с лишком. Чичиков улыбнулся при виде такой многочисленности. Спрятав ее в карман, он заметил Плюшкину, что ему нужно будет для совершения крепости приехать в город.', '102.jpg', 27, '2025-12-16 04:22:03'),
(446, '— В город? Да как же?..', '— В город? Да как же?.. а дом-то как оставить? Ведь у меня народ или вор, или мошенник: в день так оберут, что и кафтана не на чем будет повесить.', '.', '101.jpg', 44, '2025-12-12 00:45:15'),
(447, '— Да кого же знакомого? Все мои знакомые перемерли или раззнакомились.', '— Да кого же знакомого? Все мои знакомые перемерли или раззнакомились. Ах, батюшка! как не иметь, имею! — вскричал он.', ' — Ведь знаком сам председатель, езжал даже в старые годы ко мне, как не знать! однокорытниками были, вместе по заборам лазили! как не знакомый? уж такой знакомый! так уж не к нему ли написать.', '201.jpg', 20, '2025-12-03 19:42:39'),
(448, 'И на этом деревянном лице вдруг скользнул какой-то теплый луч.', 'И на этом деревянном лице вдруг скользнул какой-то теплый луч, выразилось не чувство, а какое-то бледное отражение чувства, явление, подобное неожиданному появлению на поверхности вод утопающего, произведшему радостный крик в толпе.', 'И на этом деревянном лице вдруг скользнул какой-то теплый луч, выразилось не чувство, а какое-то бледное отражение чувства, явление, подобное неожиданному появлению на поверхности вод утопающего, произведшему радостный крик в толпе, обступившей берег. Но напрасно обрадовавшиеся братья и сестры кидают с берега веревку и ждут, не мелькнет ли вновь спина или утомленные бореньем руки, — появление было последнее. Глухо все, и еще страшнее и пустыннее становится после того затихнувшая поверхность безответной стихии. Так и лицо Плюшкина вслед за мгновенно скользнувшим на нем чувством стало еще бесчувственней и еще пошлее.', '102.jpg', 35, '2025-11-24 16:23:15'),
(449, '— Лежала на столе четвертка чистой бумаги, — сказал он, — да не знаю.', '— Лежала на столе четвертка чистой бумаги, — сказал он, — да не знаю, куда запропастилась: люди у меня такие негодные! — Тут стал он заглядывать и под стол и на стол, шарил везде и наконец закричал; — Мавра! а Мавра.', '— Лежала на столе четвертка чистой бумаги, — сказал он, — да не знаю, куда запропастилась: люди у меня такие негодные! — Тут стал он заглядывать и под стол и на стол, шарил везде и наконец закричал; — Мавра! а Мавра.', '202.jpg', 51, '2025-11-20 16:16:29'),
(450, 'На зов явилась женщина с тарелкой в руках, на которой лежал сухарь.', 'На зов явилась женщина с тарелкой в руках, на которой лежал сухарь, уже знакомый читателю.', ' И между ними произошел такой разговор.', '103.jpg', 59, '2025-11-15 14:02:16'),
(451, '— Ей-богу, барин, не видывала, опричь небольшого лоскутка.', '— Ей-богу, барин, не видывала, опричь небольшого лоскутка, которым изволили прикрыть рюмку.', '.', '201.jpg', 9, '2025-11-11 13:54:31'),
(452, '— Да на что ж бы я подтибрила? Ведь мне проку с ней никакого; я грамоте не знаю.', '— Да на что ж бы я подтибрила? Ведь мне проку с ней никакого; я грамоте не знаю.', '.', '102.jpg', 12, '2025-11-08 12:37:31'),
(453, '— Да пономаренок, если захочет, так достанет себе бумаги.', '— Да пономаренок, если захочет, так достанет себе бумаги.', ' Не видал он вашего лоскутка.', '301.jpg', 24, '2025-11-02 08:43:15'),
(454, '— Вот погоди-ка.', '— Вот погоди-ка: на страшном суде черти припекут тебя за это железными рогатками! вот посмотришь, как припекут.', '— Вот погоди-ка: на страшном суде черти припекут тебя за это железными рогатками! вот посмотришь, как припекут.', '201.jpg', 32, '2025-10-29 08:13:50'),
(455, '— Да за что же припекут, коли я не брала и в руки четвертки.', '— Да за что же припекут, коли я не брала и в руки четвертки? Уж скорее другой какой бабьей слабостью, а воровством меня еще никто не попрекал.', '.', '102.jpg', 7, '2025-10-26 05:04:11'),
(456, '— А вот черти-то тебя и припекут.', '— А вот черти-то тебя и припекут! скажут: «А вот тебе, мошенница, за то, что барина-то обманывала!», да горячими-то тебя и припекут.', '— А вот черти-то тебя и припекут! скажут: «А вот тебе, мошенница, за то, что барина-то обманывала!», да горячими-то тебя и припекут.', '202.jpg', 8, '2025-10-17 01:00:07'),
(457, '— А я скажу: «Не за что.', '— А я скажу: «Не за что! ей-богу, не за что, не брала я…» Да вон она лежит на столе.', ' Всегда понапраслиной попрекаете.', '002.jpg', 31, '2025-10-09 23:24:03'),
(458, 'Плюшкин увидел, точно, четвертку и на минуту остановился.', 'Плюшкин увидел, точно, четвертку и на минуту остановился, пожевал губами и произнес.', 'Плюшкин увидел, точно, четвертку и на минуту остановился, пожевал губами и произнес.', '102.jpg', 2, '2025-10-02 18:38:55'),
(459, '— Ну, что ж ты расходилась так.', '— Ну, что ж ты расходилась так? Экая занозистая! Ей скажи только одно слово, а она уж в ответ десяток! Поди-ка принеси огоньку запечатать письмо.', ' Да стой, ты схватишь сальную свечу, сало дело топкое: сгорит — да и нет, только убыток, а ты принеси-ка мне лучинку.', '002.jpg', 17, '2025-09-30 18:19:03'),
(460, 'Мавра ушла, а Плюшкин, севши в кресла и взявши в руку перо.', 'Мавра ушла, а Плюшкин, севши в кресла и взявши в руку перо, долго еще ворочал на все стороны четвертку, придумывая, нельзя ли отделить от нее еще осьмушку, но наконец убедился, что никак нельзя.', 'Мавра ушла, а Плюшкин, севши в кресла и взявши в руку перо, долго еще ворочал на все стороны четвертку, придумывая: нельзя ли отделить от нее еще осьмушку, но наконец убедился, что никак нельзя; всунул перо в чернильницу с какою-то заплесневшею жидкостью и множеством мух на дне и стал писать, выставляя буквы, похожие на музыкальные ноты, придерживая поминутно прыть руки, которая расскакивалась по всей бумаге, лепя скупо строка на строку и не без сожаления подумывая о том, что все еще останется много чистого пробела.', '302.jpg', 55, '2025-09-28 12:29:03'),
(461, 'И до такой ничтожности, мелочности, гадости мог снизойти человек.', 'И до такой ничтожности, мелочности, гадости мог снизойти человек! мог так измениться! И похоже это на правду? Все похоже на правду, все может статься с человеком.', ' Нынешний же пламенный юноша отскочил бы с ужасом, если бы показали ему его же портрет в старости. Забирайте же с собою в путь, выходя из мягких юношеских лет в суровое ожесточающее мужество, забирайте с собою все человеческие движения, не оставляйте их на дороге, не подымете потом! Грозна страшна грядущая впереди старость, и ничего не отдает назад и обратно! Могила милосерднее ее, на могиле напишется: «Здесь погребен человек!», но ничего не прочитаешь в хладных, бесчувственных чертах бесчеловечной старости.', '103.jpg', 47, '2025-09-24 10:03:29'),
(462, '— А не знаете ли вы какого-нибудь вашего приятеля, — сказал Плюшкин.', '— А не знаете ли вы какого-нибудь вашего приятеля, — сказал Плюшкин, складывая письмо, — которому бы понадобились беглые души.', '— А не знаете ли вы какого-нибудь вашего приятеля, — сказал Плюшкин, складывая письмо, — которому бы понадобились беглые души.', '302.jpg', 34, '2025-09-23 05:23:03'),
(463, '— В том-то и дело, что есть.', '— В том-то и дело, что есть.', ' Зять делал выправки, говорит, будто и след простыл, но ведь он человек военный, мастер притопывать шпорой.', '202.jpg', 43, '2025-09-19 23:23:51'),
(464, '— А ей-богу так! Ведь у меня что год, то бегают.', '— А ей-богу так! Ведь у меня что год, то бегают. Народ-то больно прожорлив, от праздности завел привычку трескать, а у меня есть и самому нечего… А уж я бы за них что ни дай взял бы.', ' Так посоветуйте вашему приятелю-то: отыщись ведь только десяток, так вот уж у него славная деньга. Ведь ревизская душа стоит в пятистах рублях.', '102.jpg', 25, '2025-09-17 17:22:24'),
(465, '«Нет, этого мы приятелю и понюхать не дадим».', '«Нет, этого мы приятелю и понюхать не дадим», — сказал про себя Чичиков и потом объяснил, что такого приятеля никак не найдется, что одни издержки по этому делу будут стоить более.', '«Нет, этого мы приятелю и понюхать не дадим», — сказал про себя Чичиков и потом объяснил, что такого приятеля никак не найдется, что одни издержки по этому делу будут стоить более, ибо от судов нужно отрезать полы собственного кафтана да уходить подалее; но что если он уже действительно так стиснут, то, будучи подвигнут участием, он готов дать… но что это такая безделица, о которой даже не стоит и говорить.', '201.jpg', 22, '2025-09-09 15:23:27'),
(466, '— А сколько бы вы дали.', '— А сколько бы вы дали? — спросил Плюшкин и сам ожидовел: руки его задрожали, как ртуть.', '.', '203.jpg', 35, '2025-09-01 11:17:11'),
(467, '— Почтеннейший.', '— Почтеннейший! — сказал Чичиков, — не только по сорока копеек, по пятисот рублей заплатил бы! с удовольствием заплатил бы, потому что вижу — почтенный, добрый старик терпит по причине собственного добродушия.', '.', '201.jpg', 0, '2025-08-30 06:30:12'),
(468, '— А ей-богу, так! ей-богу, правда.', '— А ей-богу, так! ей-богу, правда! — сказал Плюшкин, свесив голову вниз и сокрушительно покачав ее. — Всё от добродушия.', '.', '101.jpg', 58, '2025-08-25 02:32:00'),
(469, '— Ну, видите ли, я вдруг постигнул ваш характер.', '— Ну, видите ли, я вдруг постигнул ваш характер. Итак, почему ж не дать бы мне по пятисот рублей за душу, но… состоянья нет; по пяти копеек, извольте, готов прибавить, чтобы каждая душа обошлась, таким образом, в тридцать копеек.', '.', '202.jpg', 38, '2025-08-21 23:07:30'),
(470, '— По две копеечки пристегну, извольте.', '— По две копеечки пристегну, извольте.', ' Сколько их у вас? Вы, кажется, говорили семьдесят.', '301.jpg', 33, '2025-08-19 22:30:36'),
(471, '— Семьдесят восемь, семьдесят восемь, по тридцати копеек за душу.', '— Семьдесят восемь, семьдесят восемь, по тридцати копеек за душу, это будет… — здесь герой наш одну секунду, не более, подумал и сказал вдруг: — это будет двадцать четыре рубля девяносто шесть копеек! — он был в арифметике силен.', ' Тут же заставил он Плюшкина написать расписку и выдал ему деньги, которые тот принял в обе руки и понес их к бюро с такою же осторожностью, как будто бы нес какую-нибудь жидкость, ежеминутно боясь расхлестать ее. Подошедши к бюро, он переглядел их еще раз и уложил, тоже чрезвычайно осторожно, в один из ящиков, где, верно, им суждено быть погребенными до тех пор, покамест отец Карп и отец Поликарп, два священника его деревни, не погребут его самого, к неописанной радости зятя и дочери, а может быть, и капитана, приписавшегося ему в родню. Спрятавши деньги, Плюшкин сел в кресла и уже, казалось, больше не мог найти материи, о чем говорить.', '301.jpg', 33, '2025-08-10 22:10:42'),
(472, '— А что, вы уж собираетесь ехать.', '— А что, вы уж собираетесь ехать? — сказал он, заметив небольшое движение, которое сделал Чичиков для того только, чтобы достать из кармана платок.', '.', '202.jpg', 47, '2025-07-31 18:51:35'),
(473, '— Как же, а я приказал самовар.', '— Как же, а я приказал самовар. Я, признаться сказать, не охотник до чаю: напиток дорогой, да и цена на сахар поднялась немилосердная.', ' Прошка! не нужно самовара! Сухарь отнеси Мавре, слышишь: пусть его положит на то же место, или нет, подай его сюда, я ужо снесу его сам. Прощайте, батюшка, да благословит вас бог, а письмо-то председателю вы отдайте. Да! пусть прочтет, он мой старый знакомый.', '203.jpg', 43, '2025-07-24 14:52:43'),
(474, 'Засим это странное явление, этот съежившийся старичишка проводил его со двора.', 'Засим это странное явление, этот съежившийся старичишка проводил его со двора, после чего велел ворота тот же час запереть, потом обошел кладовые, с тем чтобы осмотреть, на своих ли местах сторожа, которые стояли на всех углах.', 'Засим это странное явление, этот съежившийся старичишка проводил его со двора, после чего велел ворота тот же час запереть, потом обошел кладовые, с тем чтобы осмотреть, на своих ли местах сторожа, которые стояли на всех углах, колотя деревянными лопатками в пустой бочонок, наместо чугунной доски; после того заглянул в кухню, где под видом того чтобы попробовать, хорошо ли едят люди, наелся препорядочно щей с кашею и, выбранивши всех до последнего за воровство и дурное поведение, возвратился в свою комнату. Оставшись один, он даже подумал о том, как бы ему возблагодарить гостя за такое в самом деле беспримерное великодушие. «Я ему подарю, — подумал он про себя, — карманные часы: они ведь хорошие, серебряные часы, а не то чтобы какие-нибудь томпаковые или бронзовые; немножко поиспорчены, да ведь он себе переправит; он человек еще молодой, так ему нужны карманные част, чтобы понравиться своей невесте! Или нет, — прибавил он после некоторого размышления, — лучше я оставлю их ему после моей смерти, в духовной, чтобы вспоминал обо мне».', '102.jpg', 47, '2025-07-14 12:57:08'),
(475, 'Но герой наш и без часов был в самом веселом расположении духа.', 'Но герой наш и без часов был в самом веселом расположении духа. Такое неожиданное приобретение было сущий подарок.', ' В самом деле, что ни говори, не только одни мертвые души, но еще и беглые, и всего двести с лишком человек! Конечно, еще подъезжая к деревне Плюшкина, он уже предчувствовал, что будет кое-какая пожива, но такой прибыточной никак не ожидал. Всю дорогу он был весел необыкновенно, посвистывал, наигрывал губами, приставивши во рту кулак, как будто играл на трубе, и наконец затянул какую-то песню, до такой степени необыкновенную, что сам Селифан слушал, слушал и потом, покачав слегка годовой, сказал: «Вишь ты, как барин поет!» Были уже густые сумерки, когда подъехали они к городу. Тень со светом перемешалась совершенно, и казалось, самые предметы перемешалися тоже. Пестрый шлагбаум принял какой-то неопределенный цвет; усы у стоявшего на часах солдата казались на лбу и гораздо выше глаз, а носа как будто не было вовсе. Гром и прыжки дали заметить, что бричка взъехала на мостовую. Фонари еще не зажигались, кое-где только начинались освещаться окна домов, а в переулках и закоулках происходили сцены и разговоры, неразлучные с этим временем во всех городах, где много солдат, извозчиков, работников и особенного рода существ, в виде дам в красных шалях и башмаках без чулок, которые, как летучие мыши, шныряют по перекресткам. Чичиков не замечал их и даже не заметил многих тоненьких чиновников с тросточками, которые, вероятно сделавши прогулку за городом, возвращались домой. Изредка доходили до слуха его какие-то, казалось, женские восклицания: «Врешь, пьяница, я никогда не позволяла ему такого грубиянства!» — или: «Ты не дерись, невежа, а ступай в часть, там я тебе докажу!..» Словом, те слова которые вдруг отдадут, как варом, какого-нибудь замечтавшегося двадцатилетнего юношу, когда, возвращаясь из театра, несет он в голове испанскую улицу, ночь, чудный женский образ с гитарой и кудрями.', '102.jpg', 47, '2025-07-04 11:56:37'),
(476, 'Наконец бричка, сделавши порядочный скачок, опустилась, как будто в яму.', 'Наконец бричка, сделавши порядочный скачок, опустилась, как будто в яму, в ворота гостиницы, и Чичиков был встречен Петрушкою, который одною рукою придерживал полу своего сюртука, ибо не любил, чтобы расходились полы.', 'Наконец бричка, сделавши порядочный скачок, опустилась, как будто в яму, в ворота гостиницы, и Чичиков был встречен Петрушкою, который одною рукою придерживал полу своего сюртука, ибо не любил, чтобы расходились полы, а другою стал помогать ему вылезать из брички. Половой тоже выбежал, со свечою в руке и салфеткою на плече. Обрадовался ли Петрушка приезду барина, неизвестно, по крайней мере они перемигнулись с Селифаном, и обыкновенно суровая его наружность на этот раз как будто несколько прояснилась.', '201.jpg', 54, '2025-06-26 05:31:43'),
(477, '— Слава богу, — отвечал половой, кланяясь.', '— Слава богу, — отвечал половой, кланяясь. — Вчера приехал поручик какой-то военный, занял шестнадцатый номер.', '.', '202.jpg', 18, '2025-06-23 01:16:30'),
(478, '— Хорошо, хорошо, веди себя и вперед хорошо.', '— Хорошо, хорошо, веди себя и вперед хорошо! — сказал Чичиков и вошел в свою комнату.', ' Проходя переднюю, он покрутил носом и сказал Петрушке: — Ты бы по крайней мере хоть окна отпер.', '203.jpg', 6, '2025-06-17 23:08:57'),
(479, '— Да я их отпирал, — сказал Петрушка, да и соврал.', '— Да я их отпирал, — сказал Петрушка, да и соврал. Впрочем, барин и сам знал, что он соврал, но уж не хотел ничего возражать. После сделанной поездки он чувствовал сильную усталость.', ' Потребовавши самый легкий ужин, состоявший только в поросенке, он тот же час разделся и, забравшись под одеяло, заснул сильно, крепко, заснул чудным образом, как спят одни только те счастливцы, которые не ведают ни геморроя, ни блох, ни слишком сильных умственных способностей.', '201.jpg', 15, '2025-06-09 21:23:09'),
(480, 'Счастлив путник, который после длинной, скучной дороги с ее холодами, слякотью.', 'Счастлив путник, который после длинной, скучной дороги с ее холодами, слякотью, грязью, невыспавшимися станционными смотрителями, бряканьями колокольчиков, починками, перебранками, ямщиками.', 'Счастлив путник, который после длинной, скучной дороги с ее холодами, слякотью, грязью, невыспавшимися станционными смотрителями, бряканьями колокольчиков, починками, перебранками, ямщиками, кузнецами и всякого рода дорожными подлецами видит наконец знакомую крышу с несущимися навстречу огоньками, и предстанут пред ним знакомые комнаты, радостный крик выбежавших навстречу людей, шум и беготня детей и успокоительные тихие речи, прерываемые пылающими лобзаниями, властными истребить все печальное из памяти.', '302.jpg', 32, '2025-06-01 19:30:51'),
(481, 'Счастлив писатель, который мимо характеров скучных, противных.', 'Счастлив писатель, который мимо характеров скучных, противных, поражающих печальною своею действительностью, приближается к характерам, являющим высокое достоинство человека.', 'Счастлив писатель, который мимо характеров скучных, противных, поражающих печальною своею действительностью, приближается к характерам, являющим высокое достоинство человека, который из великого омута ежедневно вращающихся образов избрал одни немногие исключения, который не изменял ни разу возвышенного строя своей лиры, не ниспускался с вершины своей к бедным, ничтожным своим собратьям, и, не касаясь земли, весь повергался в свои далеко отторгнутые от нее и возвеличенные образы. Вдвойне завиден прекрасный удел его: он среди их, как в родной семье; а между тем далеко и громко разносится его слава. Он окурил упоительным куревом людские очи; он чудно польстил им, сокрыв печальное в жизни, показав им прекрасного человека. Все, рукоплеща, несется за ним и мчится вслед за торжественной его колесницей. Великим всемирным поэтом именуют его, парящим высоко над всеми другими гениями мира, как парит орел над другими высоко летающими.', '301.jpg', 27, '2025-05-28 16:19:27'),
(482, 'И долго еще определено мне чудной властью идти об руку с моими странными.', 'И долго еще определено мне чудной властью идти об руку с моими странными героями, озирать всю громадно несущуюся жизнь, озирать ее сквозь видный миру смех и незримые, неведомые ему слезы.', 'И долго еще определено мне чудной властью идти об руку с моими странными героями, озирать всю громадно несущуюся жизнь, озирать ее сквозь видный миру смех и незримые, неведомые ему слезы.', '202.jpg', 58, '2025-05-24 13:26:06'),
(483, 'В дорогу! в дорогу! прочь набежавшая на чело морщина и строгий сумрак лица.', 'В дорогу! в дорогу! прочь набежавшая на чело морщина и строгий сумрак лица! Разом и вдруг окунемся в жизнь со всей ее беззвучной трескотней и бубенчиками и посмотрим, что делает Чичиков.', '.', '103.jpg', 36, '2025-05-15 12:41:05'),
(484, '— А.', '— А! — Он тут же развернул ее, пробежал глазами и подивился чистоте и красоте почерка. — Славно написано, — сказал он, — не нужно и переписывать.', ' Еще и каемка вокруг! кто это так искусно сделал каемку.', '202.jpg', 57, '2026-01-06 12:05:23'),
(485, 'Чичиков поклонился с признательностью.', 'Чичиков поклонился с признательностью. Узнавши, что он шел в палату за совершением купчей, Манилов изъявил готовность ему сопутствовать. Приятели взялись под руку и пошли вместе.', ' При всяком небольшом возвышении, или горке, или ступеньке, Манилов поддерживал Чичикова и почти приподнимал его рукою, присовокупляя с приятной улыбкою, что он не допустит никак Павла Ивановича зашибить свои ножки. Чичиков совестился, не зная, как благодарить, ибо чувствовал, что несколько был тяжеленек. Во взаимных услугах они дошли наконец до площади, где находились присутственные места: большой трехэтажный каменный дом, весь белый, как мел, вероятно для изображения чистоты душ помещавшихся в нем должностей; прочие здания на площади не отвечали огромностию каменному дому. Это были: караульная будка, у которой стоял солдат с ружьем, две-три извозчичьи биржи и, наконец, длинные заборы с известными заборными надписями и рисунками, нацарапанными углем и мелом; более не находилось ничего на сей уединенной, или, как у нас выражаются, красивой площади. Из окон второго и третьего этажа высовывались неподкупные головы жрецов Фемиды и в ту ж минуту прятались опять: вероятно, в то время входил в комнату начальник. Приятели не взошли, а взбежали по лестнице, потому что Чичиков, стараясь избегнуть поддерживанья под руки со стороны Манилова, ускорял шаг, а Манилов тоже с своей стороны летел вперед, стараясь не позволить Чичикову устать, и потому оба запыхались весьма сильно, когда вступили в темный коридор. Ни в коридорах, ни в комнатах взор их не был поражен чистотою. Тогда еще не заботились о ней, и то, что было грязно, так и оставалось грязным, не принимая привлекательной наружности. Фемида просто, какова есть, в неглиже и халате принимала гостей. Следовало бы описать канцелярские комнаты, которыми проходили наши герои, но автор питает сильную робость ко всем присутственным местам. Если и случалось ему проходить их даже в блистательном и облагорожонном виде, с лакированными полами и столами, он старался пробежать как можно скорее, смиренно опустив и потупив глаза в землю, а потому совершенно не знает, как там все благоденствует и процветает.', '101.jpg', 14, '2026-01-04 06:14:07'),
(486, 'Чичиков и Манилов подошли к первому столу.', 'Чичиков и Манилов подошли к первому столу, где сидели два чиновника еще юных лет, и спросили.', 'Чичиков и Манилов подошли к первому столу, где сидели два чиновника еще юных лет, и спросили.', '002.jpg', 50, '2025-12-30 01:14:48'),
(487, '— Да скажите прежде, что купили и в какую цену, так мы вам тогда и скажем где.', '— Да скажите прежде, что купили и в какую цену, так мы вам тогда и скажем где, а так нельзя знать.', '.', '102.jpg', 44, '2025-12-19 22:57:19'),
(488, 'Чичиков тотчас увидел, что чиновники были просто любопытны.', 'Чичиков тотчас увидел, что чиновники были просто любопытны, подобно всем молодым чиновникам, и хотели придать более весу и значения себе и своим занятиям.', '.', '201.jpg', 41, '2025-12-17 20:25:20'),
(489, '— Послушайте, любезные, — сказал он, — я очень хорошо знаю.', '— Послушайте, любезные, — сказал он, — я очень хорошо знаю, что все дела по крепостям, в какую бы ни было цену, находятся в одном месте, а потому прошу вас показать нам стол, а если вы не знаете, что у вас делается, так мы спросим у других.', '.', '103.jpg', 4, '2025-12-09 16:38:37'),
(490, 'Чиновники на это ничего не отвечали.', 'Чиновники на это ничего не отвечали, один из них только ткнул пальцем в угол комнаты, где сидел за столом какой-то старик, перемечавший какие-то бумаги. Чичиков и Манилов прошли промеж столами прямо к нему. Старик занимался очень внимательно.', '.', '101.jpg', 42, '2025-12-08 10:48:33'),
(491, 'Старик тыкнул пальцем в другой угол комнаты.', 'Старик тыкнул пальцем в другой угол комнаты. Чичиков и Манилов отправились к Ивану Антоновичу. Иван Антонович уже запустил один глаз назад и оглянул их искоса, но в ту же минуту погрузился еще внимательнее в писание.', '.', '103.jpg', 40, '2025-11-29 09:39:53'),
(492, 'Иван Антонович как будто бы и не слыхал и углубился совершенно в бумаги.', 'Иван Антонович как будто бы и не слыхал и углубился совершенно в бумаги, не отвечая ничего. Видно было вдруг, что это был уже человек благоразумных лет, не то что молодой болтун и вертопляс.', ' Иван Антонович, казалось, имел уже далеко за сорок лет; волос на нем был черный, густой; вся середина лица выступала у него вперед и пошла в нос, — словом, это было то лицо, которое называют в общежитье кувшинным рылом.', '002.jpg', 44, '2025-11-24 09:11:33'),
(493, '— Здесь, — сказал Иван Антонович.', '— Здесь, — сказал Иван Антонович, поворотил свое кувшинное рыло и приложился опять писать.', '.', '203.jpg', 10, '2025-11-22 07:16:22'),
(494, '— А у меня дело вот какое.', '— А у меня дело вот какое: куплены мною у разных владельцев здешнего уезда крестьяне на вывод: купчая есть, остается совершить.', '.', '103.jpg', 15, '2025-11-13 00:54:39'),
(495, '— Принес и просьбу.', '— Принес и просьбу.', ' Я бы хотел… мне нужно поторопиться… так нельзя ли, например, кончить дело сегодня.', '203.jpg', 43, '2025-11-03 20:53:19'),
(496, '— Да, сегодня! сегодня нельзя, — сказал Иван Антонович.', '— Да, сегодня! сегодня нельзя, — сказал Иван Антонович. — Нужно навести еще справки, нет ли еще запрещений.', '.', '002.jpg', 52, '2025-10-25 16:58:33'),
(497, '— Впрочем, что до того, чтоб ускорить дело, так Иван Григорьевич, председатель.', '— Впрочем, что до того, чтоб ускорить дело, так Иван Григорьевич, председатель.', '— Впрочем, что до того, чтоб ускорить дело, так Иван Григорьевич, председатель.', '202.jpg', 43, '2025-10-20 16:26:05'),
(498, '— Да ведь Иван Григорьевич не один, бывают и другие.', '— Да ведь Иван Григорьевич не один; бывают и другие, — сказал сурово Иван Антонович.', '.', '301.jpg', 6, '2025-10-17 11:58:46'),
(499, '— Вот он вас проведет в присутствие.', '— Вот он вас проведет в присутствие.', '— Вот он вас проведет в присутствие! — сказал Иван Антонович, кивнув головою, и один из священнодействующих, тут же находившихся, приносивший с таким усердием жертвы Фемиде, что оба рукава лопнули на локтях и давно лезла оттуда подкладка, за что и получил в свое время коллежского регистратора, прислужился нашим приятелям, как некогда Виргилий прислужился Данту, и провел их в комнату присутствия, где стояли одни только широкие кресла и в них перед столом, за зерцалом и двумя толстыми книгами, сидел один, как солнце, председатель. В этом месте новый Вергилий почувствовал такое благоговение, что никак не осмелился занести туда ногу и поворотил назад, показав свою спину, вытертую, как рогожка, с прилипнувшим где-то куриным пером. Вошедши в залу присутствия, они увидели, что председатель был не один, подле него сидел Собакевич, совершенно заслоненный зерцалом. Приход гостей произвел восклицание, правительственные кресла были отодвинуты с шумом. Собакевич тоже привстал со стула и стал виден со всех сторон с длинными своими рукавами. Председатель принял Чичикова в объятия, и комната присутствия огласилась поцелуями; спросили друг друга о здоровье; оказалось, что у обоих побаливает поясница, что тут же было отнесено к сидячей жизни. Председатель, казалось, уже был уведомлен Собакевичем о покупке, потому что принялся поздравлять, что сначала несколько смешало нашего героя, особливо когда он увидел, что и Собакевич и Манилов, оба продавцы, с которыми дело было улажено келейно, теперь стояли вместе лицом друг к другу.', '102.jpg', 12, '2025-12-30 07:45:43'),
(500, 'И точно, не на что было жаловаться, скорее железо могло простудиться и кашлять.', 'И точно, не на что было жаловаться: скорее железо могло простудиться и кашлять, чем этот на диво сформованный помещик.', '.', '002.jpg', 48, '2025-12-21 01:30:19'),
(501, '— Да вы всегда славились здоровьем, — сказал председатель.', '— Да вы всегда славились здоровьем, — сказал председатель, — и покойный ваш батюшка был также крепкий человек.', '.', '203.jpg', 55, '2025-12-16 21:52:12'),
(502, '— Мне кажется, однако ж, — сказал председатель.', '— Мне кажется, однако ж, — сказал председатель. — вы бы тоже повалили медведя, если бы захотели выйти против него.', '.', '002.jpg', 1, '2025-12-08 16:21:08'),
(503, '— Нет, не повалю, — отвечал Собакевич, — покойник был меня покрепче, — и.', '— Нет, не повалю, — отвечал Собакевич, — покойник был меня покрепче, — и, вздохнувши, продолжал: — Нет, теперь не те люди: вот хоть и моя жизнь, что за жизнь.', '— Нет, не повалю, — отвечал Собакевич, — покойник был меня покрепче, — и, вздохнувши, продолжал: — Нет, теперь не те люди: вот хоть и моя жизнь, что за жизнь.', '202.jpg', 29, '2025-12-07 09:57:11'),
(504, '— Нехорошо, нехорошо, — сказал Собакевич, покачав головою.', '— Нехорошо, нехорошо, — сказал Собакевич, покачав головою. — Вы посудите, Иван Григорьевич: пятый десяток живу, ни разу не был болен; хоть бы горло заболело, веред или чирей выскочил… Нет, не к добру! когда-нибудь придется поплатиться за это.', ' — Тут Собакевич погрузился в меланхолию.', '202.jpg', 42, '2025-12-02 08:55:48'),
(505, '«Эк его, — подумали в одно время и Чичиков и председатель.', '«Эк его, — подумали в одно время и Чичиков и председатель, — на что вздумал пенять.', '«Эк его, — подумали в одно время и Чичиков и председатель, — на что вздумал пенять.', '101.jpg', 29, '2025-11-26 05:11:33'),
(506, '— К вам у меня есть письмецо, — сказал Чичиков.', '— К вам у меня есть письмецо, — сказал Чичиков, вынув из кармана письмо Плюшкина.', '.', '203.jpg', 0, '2025-11-24 01:07:25'),
(507, '— От кого? — сказал председатель и, распечатавши, воскликнул: — А! от Плюшкина.', '— От кого? — сказал председатель и, распечатавши, воскликнул: — А! от Плюшкина. Он еще до сих пор прозябает на свете.', ' Вот судьба, ведь какой был умнейший, богатейший человек.', '101.jpg', 39, '2025-11-16 20:50:51'),
(508, '— Извольте, извольте, — сказал председатель, прочитав письмо.', '— Извольте, извольте, — сказал председатель, прочитав письмо, — я готов быть поверенным.', ' Когда вы хотите совершить купчую, теперь или после.', '202.jpg', 12, '2025-11-06 16:41:01'),
(509, '— Теперь, — сказал Чичиков, — я буду просить даже вас, если можно, сегодня.', '— Теперь, — сказал Чичиков, — я буду просить даже вас, если можно, сегодня, потому что мне завтра хотелось бы выехать из города; я принес и крепости и просьбу.', '.', '202.jpg', 26, '2025-10-28 16:01:35'),
(510, '— Все это хорошо, только, уж как хотите, мы вас не выпустим так рано.', '— Все это хорошо, только, уж как хотите, мы вас не выпустим так рано. Крепости будут совершены сегодня, а вы все-таки с нами поживите.', ' Вот я сейчас отдам приказ, — сказал он и отворил дверь в канцелярскую комнату, всю наполненную чиновниками, которые уподобились трудолюбивым пчелам, рассыпавшимся по сотам, если только соты можно уподобить канцелярским делам: — Иван Антонович здесь.', '301.jpg', 5, '2025-10-26 12:35:00'),
(511, 'Уже известный читателям Иван Антонович кувшинное рыло показался в зале.', 'Уже известный читателям Иван Антонович кувшинное рыло показался в зале присутствия и почтительно поклонился.', '.', '302.jpg', 55, '2025-10-23 12:31:57'),
(512, '— Да не позабудьте, Иван Григорьевич, — подхватил Собакевич.', '— Да не позабудьте, Иван Григорьевич, — подхватил Собакевич, — нужно будет свидетелей, хотя по два с каждой стороны.', ' Пошлите теперь же к прокурору, он человек праздный и, верно, сидит дома, за него все делает стряпчий Золотуха, первейший хапуга в мире.', '202.jpg', 46, '2025-10-21 08:07:50'),
(513, '— Именно, именно.', '— Именно, именно! — сказал председатель и тот же час отрядил за ними всеми канцелярского.', '.', '202.jpg', 58, '2025-10-13 06:03:43'),
(514, '— Еще я попрошу вас, — сказал Чичиков, — пошлите за поверенным одной помещицы.', '— Еще я попрошу вас, — сказал Чичиков, — пошлите за поверенным одной помещицы, с которой я тоже совершил сделку, сыном протопопа отца Кирилла; он служит у вас же.', '.', '301.jpg', 13, '2025-10-02 23:56:36'),
(515, '— Как же, пошлем и за ним! — сказал председатель.', '— Как же, пошлем и за ним! — сказал председатель. — Все будет сделано, а чиновным вы никому не давайте ничего, об этом я вас прошу. Приятели мои не должны платить.', ' — Сказавши это, он тут же дал какое-то приказанье Ивану Антоновичу, как видно ему не понравившееся. Крепости произвели, кажется, хорошее действие на председателя, особливо когда он увидел, что всех покупок было почти на сто тысяч рублей.', '002.jpg', 55, '2025-09-28 19:29:41'),
(516, '— Да я вижу сам, что более благого дела не мог бы предпринять.', '— Да я вижу сам, что более благого дела не мог бы предпринять. Как бы то ни было, цель человека все еще не определена, если он не стал наконец твердой стопою на прочное основание, а не на какую-нибудь вольнодумную химеру юности.', ' — Тут он весьма кстати выбранил за либерализм, и поделом, всех молодых людей. Но замечательно, что в словах его была все какая-то нетвердость, как будто бы тут же сказал он сам себе: «Эх, брат, врешь ты, да еще и сильно!» Он даже не взглянул на Собакевича и Манилова из боязни встретить что-нибудь на их лицах. Но напрасно боялся он: лицо Собакевича не шевельнулось, а Манилов, обвороженный фразою, от удовольствия только потряхивал одобрительно головою, погрузясь в такое положение, в каком находится любитель музыки, когда певица перещеголяла самую скрыпку и пискнула такую тонкую ноту, какая невмочь и птичьему горлу.', '201.jpg', 4, '2025-09-26 16:51:55'),
(517, '— Да, что ж вы не скажете Ивану Григорьевичу, — отозвался Собакевич.', '— Да, что ж вы не скажете Ивану Григорьевичу, — отозвался Собакевич, — что такое именно вы приобрели; а вы, Иван Григорьевич, что вы не спросите, какое приобретение они сделали? Ведь какой народ! просто золото. Ведь я им продал и каретника Михеева.', '.', '202.jpg', 46, '2025-09-22 12:29:26'),
(518, '— Нет, будто и Михеева продали? — сказал председатель.', '— Нет, будто и Михеева продали? — сказал председатель. — Я знаю каретника Михеева: славный мастер; он мне дрожки переделал.', ' Только позвольте, как же… Ведь вы мне сказывали.', '100.jpg', 50, '2025-09-12 06:18:44'),
(519, '— Кто, Михеев умер? — сказал Собакевич, ничуть не смешавшись.', '— Кто, Михеев умер? — сказал Собакевич, ничуть не смешавшись. — Это его брат умер, а он преживехонький и стал здоровее прежнего. На днях такую бричку наладил, что и в Москве не сделать. Ему, по-настоящему, только на одного государя и работать.', '.', '103.jpg', 20, '2025-09-04 06:05:14'),
(520, '— Да, Михеев славный мастер, — сказал председатель, — и я дивлюсь даже.', '— Да, Михеев славный мастер, — сказал председатель, — и я дивлюсь даже, как вы могли с ним расстаться.', '.', '302.jpg', 50, '2025-08-30 04:05:42'),
(521, '— Да будто один Михеев.', '— Да будто один Михеев! А Пробка Степан, плотник, Милушкин, кирпичник, Телятников Максим, сапожник, — ведь все пошли, всех продал.', '— Да будто один Михеев! А Пробка Степан, плотник, Милушкин, кирпичник, Телятников Максим, сапожник, — ведь все пошли, всех продал! — А когда председатель спросил, зачем же они пошли, будучи людьми необходимыми для дому и мастеровыми, Собакевич отвечал, махнувши рукой: — А! так просто, нашла дурь: дай, говорю, продам, да и продал сдуру! — Засим он повесил голову так, как будто сам раскаивался в этом деле, и прибавил: — Вот и седой человек, а до сих пор не набрался ума.', '203.jpg', 53, '2025-08-22 02:13:06'),
(522, '— Но позвольте, Павел Иванович, — сказал председатель.', '— Но позвольте, Павел Иванович, — сказал председатель, — как же вы покупаете крестьян без земли? разве на вывод.', '— Но позвольте, Павел Иванович, — сказал председатель, — как же вы покупаете крестьян без земли? разве на вывод.', '102.jpg', 15, '2025-08-19 22:18:16'),
(523, '— О, там отличные земли.', '— О, там отличные земли! — сказал председатель и отозвался с большою похвалою насчет рослости тамошних трав.', ' — А земли в достаточном количестве.', '202.jpg', 23, '2025-08-18 18:07:24'),
(524, '— Река. Впрочем, и пруд есть.', '— Река. Впрочем, и пруд есть.', ' — Сказав это, Чичиков взглянул ненароком на Собакевича, и хотя Собакевич был по-прежнему неподвижен, но ему казалось, будто бы было написано на лице его: «Ой, врешь ты! вряд ли есть река, и пруд, да и вся земля.', '203.jpg', 9, '2025-08-11 17:51:09');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(525, 'Пока продолжались разговоры, начали мало-помалу появляться свидетели.', 'Пока продолжались разговоры, начали мало-помалу появляться свидетели: знакомый читателю прокурор-моргун, инспектор врачебной управы, Трухачевский, Бегушкин и прочие, по словам Собакевича, даром бременящие землю.', ' Многие из них были совсем незнакомы Чичикову: недостававшие и лишние набраны были тут же, из палатских чиновников. Привели также не только сына протопопа отца Кирила, но даже и самого протопопа. Каждый из свидетелей поместил себя со всеми своими достоинствами и чинами, кто оборотным шрифтом, кто косяками, кто просто чуть не вверх ногами, помещая такие буквы, каких даже и не видано было в русском алфавите. Известный Иван Антонович управился весьма проворно: крепости были записаны, помечены, занесены в книгу и куда следует, с принятием полупроцентовых и за припечатку в «Ведомостях», и Чичикову пришлось заплатить самую малость. Даже председатель дал приказание из пошлинных денег взять с него только половину, а другая, неизвестно каким образом, отнесена была на счет какого-то другого просителя.', '302.jpg', 21, '2025-08-07 17:42:45'),
(526, '— Итак, — сказал председатель, когда все было кончено.', '— Итак, — сказал председатель, когда все было кончено, — остается теперь только вспрыснуть покупочку.', '.', '302.jpg', 51, '2025-08-02 14:23:41'),
(527, '— Я готов, — сказал Чичиков. — От вас зависит только назначить время.', '— Я готов, — сказал Чичиков. — От вас зависит только назначить время. Был бы грех с моей стороны, если бы для эдакого приятного общества да не раскупорить другую-третью бутылочку шипучего.', '.', '103.jpg', 19, '2025-07-27 08:08:03'),
(528, '— Нет, вы не так приняли дело, шипучего мы сами поставим, — сказал председатель.', '— Нет, вы не так приняли дело: шипучего мы сами поставим, — сказал председатель, — это наша обязанность, наш долг. Вы у нас гость: нам должно угощать.', ' Знаете ли что, господа! Покамест что, а мы вот как сделаем: отправимтесь-ка все, так как есть, к полицеймейстеру; он у нас чудотворец: ему стоит только мигнуть, проходя мимо рыбного ряда или погреба, так мы, знаете ли, так закусим! да при этой оказии и в вистишку.', '301.jpg', 58, '2025-07-22 03:26:33'),
(529, 'От такого предложения никто не мог отказаться… Свидетели уже при одном.', 'От такого предложения никто не мог отказаться… Свидетели уже при одном наименованье рыбного ряда почувствовали аппетит; взялись все тот же час за картузы и шапки, и присутствие кончилось.', ' Когда проходили они канцелярию, Иван Антонович кувшинное рыло, учтиво поклонившись, сказал потихоньку Чичикову.', '203.jpg', 7, '2025-07-13 22:35:02'),
(530, '— Да ведь какие крестьяне, — отвечал ему на это тоже шепотом Чичиков.', '— Да ведь какие крестьяне, — отвечал ему на это тоже шепотом Чичиков, — препустой и преничтожный народ, и половины не стоят.', '.', '100.jpg', 33, '2025-07-11 16:21:04'),
(531, '— Нет, никакого Воробья я не приписывал.', '— Нет, никакого Воробья я не приписывал, — сказал Собакевич и отошел к другим гостям.', '.', '202.jpg', 55, '2025-07-08 14:08:53'),
(532, 'Гости добрались наконец гурьбой к дому полицеймейстера.', 'Гости добрались наконец гурьбой к дому полицеймейстера.', ' Полицеймейстер, точно, был чудотворец: как только услышал он, в чем дело, в ту ж минуту кликнул квартального, бойкого малого в лакированных ботфортах, и, кажется, всего два слова шепнул ему на ухо да прибавил только: «Понимаешь!» — а уж там, в другой комнате, в продолжение того времени, как гости резалися в вист, появилась на столе белуга, осетры, семга, икра паюсная, икра свежепросольная, селедки, севрюжки, сыры, копченые языки и балыки, — это все было со стороны рыбного ряда. Потом появились прибавления с хозяйской стороны, изделия кухни: пирог с головизною, куда вошли хрящ и щеки девятипудового осетра, другой пирог — с груздями, пряженцы, маслянцы, взваренцы. Полицеймейстер был некоторым образом отец и благотворитель в городе. Он был среди граждан совершенно как в родной семье, а в лавки и в гостиный двор наведывался, как в собственную кладовую. Вообще он сидел, как говорится, на своем месте и должность свою постигнул в совершенстве. Трудно было даже и решить, он ли был создан для места, или место для него. Дело было так поведено умно, что он получал вдвое больше доходов противу всех своих предшественников, а между тем заслужил любовь всего города. Купцы первые его очень любили, именно за то, что не горд; и точно, он крестил у них детей, кумился с ними и хоть драл подчас с них сильно, но как-то чрезвычайно ловко: и по плечу потреплет, и засмеется, и чаем напоит, пообещается и сам прийти поиграть в шашки, расспросит обо всем: как делишки, что и как. Если узнает, что детеныш как-нибудь прихворнул, и лекарство присоветует, — словом, молодец! Поедет на дрожках, даст порядок, а между тем и словцо промолвит тому-другому: «Что, Михеич нужно бы нам с тобою доиграть когда-нибудь в горку». — «Да, Алексей Иванович, — отвечал тот, снимая шапку, — нужно бы». — «Ну, брат, Илья Парамоныч, приходи ко мне поглядеть рысака: в обгон с твоим пойдет, да и своего заложи в беговые; попробуем».', '301.jpg', 11, '2025-07-05 09:20:43'),
(533, 'Заметив, что закуска была готова.', 'Заметив, что закуска была готова, полицеймейстер предложил гостям окончить вист после завтрака, и все пошли в ту комнату, откуда несшийся запах давно начинал приятным образом щекотать ноздри гостей и куда уже Собакевич давно заглядывал в дверь.', 'Заметив, что закуска была готова, полицеймейстер предложил гостям окончить вист после завтрака, и все пошли в ту комнату, откуда несшийся запах давно начинал приятным образом щекотать ноздри гостей и куда уже Собакевич давно заглядывал в дверь, наметив издали осетра, лежавшего в стороне на большом блюде. Гости, выпивши по рюмке водки темного оливкового цвета, какой бывает только на сибирских прозрачных камнях, из которых режут на Руси печати, приступили со всех сторон с вилками к столу и стали обнаруживать, как говорится, каждый свой характер и склонности, налегая кто на икру, кто на семгу, кто на сыр. Собакевич, оставив без всякого внимания все эти мелочи, пристроился к осетру, и, покамест те пили, разговаривали и ели, он в четверть часа с небольшим доехал его всего, так что когда полицеймейстер вспомнил было о нем и, сказавши: «А каково вам, господа покажется вот это произведенье природы?» — подошел было к нему с вилкою вместе с другими, то увидел, что от произведенья природы оставался всего один хвост; а Собакевич пришипился так, как будто и не он, и, подошедши к тарелке, которая была подальше прочих, тыкал вилкою в какую-то сушеную маленькую рыбку. Отделавши осетра, Собакевич сел в кресла и уж более не ел, не пил, а только жмурил и хлопал глазами. Полицеймейстер, кажется, не любил жалеть вина; тостам не было числа. Первый тост был выпит, как читатели, может быть, и сами догадаются, за здоровье нового херсонского помещика, потом за благоденствие крестьян его и счастливое их переселение, потом за здоровье будущей жены его, красавицы, что сорвало приятную улыбку с уст нашего героя.', '101.jpg', 1, '2025-06-30 04:28:35'),
(534, '— Нет, Павел Иванович.', '— Нет, Павел Иванович! как вы себе хотите, это выходит избу только выхолаживать: на порог, да и назад! нет, вы проведите время с нами! Вот мы вас женим: не правда ли, Иван Григорьевич, женим его.', '— Нет, Павел Иванович! как вы себе хотите, это выходит избу только выхолаживать: на порог, да и назад! нет, вы проведите время с нами! Вот мы вас женим: не правда ли, Иван Григорьевич, женим его.', '203.jpg', 59, '2025-06-22 01:36:40'),
(535, '— Женим, женим! — подхватил председатель.', '— Женим, женим! — подхватил председатель. — Уж как ни упирайтесь руками и ногами, мы вас женим! Нет, батюшка, попали сюда, так не жалуйтесь. Мы шутить не любим.', '.', '002.jpg', 5, '2025-06-15 19:25:35'),
(536, '— Что ж.', '— Что ж? зачем упираться руками и ногами, — сказал, усмехнувшись, Чичиков, — женитьба еще не такая вещь, чтобы того, была бы невеста.', '.', '201.jpg', 41, '2025-06-07 18:17:38'),
(537, '— Браво, остается! — закричали все.', '— Браво, остается! — закричали все. — Виват, ура, Павел Иванович! ура! — И все подошли к нему чокаться с бокалами в руках.', '.', '301.jpg', 54, '2025-06-06 18:05:09'),
(538, 'Чичиков перечокался со всеми.', 'Чичиков перечокался со всеми. «Нет, нет, еще!» — говорили те, которые были позадорнее, и вновь перечокались; потом полезли в третий раз чокаться, перечокались и в третий раз. В непродолжительное время всем сделалось весело необыкновенно.', ' Председатель, который был премилый человек, когда развеселялся, обнимал несколько раз Чичикова, произнеся в излиянии сердечном: «Душа ты моя! маменька моя!» — и даже, щелкнув пальцами, пошел приплясывать вокруг него, припевая известную песню: «Ах ты такой и этакой камаринский мужик». После шампанского раскупорили венгерское, которое придало еще более духу и развеселило общество. Об висте решительно позабыли; спорили, кричали, говорили обо всем: об политике, об военном даже деле, излагали вольные мысли, за которые в другое время сами бы высекли своих детей. Решили тут же множество самых затруднительных вопросов. Чичиков никогда не чувствовал себя в таком веселом расположении, воображал себя уже настоящим херсонским помещиком, говорил об разных улучшениях: о трехпольном хозяйстве, о счастии и блаженстве двух душ, и стал читать Собакевичу послание в стихах Вертера к Шарлотте, на которое тот хлопал только глазами, сидя в креслах, ибо после осетра чувствовал большой позыв ко сну. Чичиков смекнул и сам, что начал уже слишком развязываться, попросил экипажа и воспользовался прокурорскими дрожками. Прокурорский кучер, как оказалось в дороге, был малый опытный, потому что правил одной только рукой, а другую засунув назад, придерживал ею барина. Таким образом, уже на прокурорских дрожках доехал он к себе в гостиницу, где долго еще у него вертелся на языке всякий вздор: белокурая невеста с румянцем и ямочкой на правой щеке, херсонские деревни, капиталы. Селифану даже были даны кое-какие хозяйственные приказания: собрать всех вновь переселившихся мужиков, чтобы сделать всем лично поголовную перекличку. Селифан молча слушал очень долго и потом вышел из комнаты, сказавши Петрушке: «Ступай раздевать барина!» Петрушка принялся снимать с него сапоги и чуть не стащил вместе с ними на пол и самого барина. Но наконец сапоги были сняты, барин разделся как следует и, поворочавшись несколько времени на постеле, которая скрыпела немилосердно, заснул решительно херсонским помещиком.', '203.jpg', 33, '2025-06-02 15:00:54'),
(539, 'Покупки Чичикова сделались предметом разговоров.', 'Покупки Чичикова сделались предметом разговоров. В городе пошли толки, мнения, рассуждения о том, выгодно ли покупать на вывод крестьян. Из прений многие отзывались совершенным познанием предмета.', ' «Конечно, — говорили иные, — это так, против этого и спору нет: земли в южных губерниях, точно, хороши и плодородны; но каково будет крестьянам Чичикова без воды? реки ведь нет никакой». — «Это бы еще ничего, что нет воды, это бы ничего, Степан Дмитриевич, но переселение-то ненадежная вещь. Дело известное, что мужик: на новой земле, да заняться еще хлебопашеством, да ничего у него нет, ни избы, ни двора, — убежит, как дважды два, навострит так лыжи, что и следа не отыщешь». — «Нет, Алексей Иванович, позвольте, позвольте, я не согласен с тем, что вы говорите, что мужик Чичикова убежит. Русский человек способен во всему и привыкает ко всякому климату. Пошли его хоть в Камчатку, да дай только теплые рукавицы, он похлопает руками, топор в руки, и пошел рубить себе новую избу». — «Но, Иван Григорьевич, ты упустил из виду важное дело: ты не спросил еще, каков мужик у Чичикова. Позабыл то, что ведь хорошего человека не продаст помещик; я готов голову положить, если мужик Чичикова не вор и не пьяница в последней степени, праздношатайка и буйного поведения». — «Так, так, на это я согласен, это правда, никто не продаст хороших людей, и мужики Чичикова пьяницы, но нужно принять во внимание, что вот тут-то и есть мораль, тут-то и заключена мораль: они теперь негодяи, а, переселившись на новую землю, вдруг могут сделаться отличными подданными. Уж было немало таких примеров: просто в мире, да и по истории тоже». — «Никогда, никогда, — говорил управляющий казенными фабриками, — поверьте, никогда это не может быть. Ибо у крестьян Чичикова будут теперь два сильные врага. Первый враг есть близость губерний малороссийских, где, как известно, свободная продажа вина. Я вас уверяю: в две недели они изопьются и будут стельки. Другой враг есть уже самая привычка к бродяжнической жизни, которая необходимо приобретется крестьянами во время переселения.', '100.jpg', 28, '2025-05-30 11:11:56'),
(540, 'Таким образом рассуждали и говорили в городе, и многие, побуждаемые участием.', 'Таким образом рассуждали и говорили в городе, и многие, побуждаемые участием, сообщили даже Чичикову лично некоторые из сих советов, предлагали даже конвой для безопасного препровожденья крестьян до места жительства За советы Чичиков благодарил.', 'Таким образом рассуждали и говорили в городе, и многие, побуждаемые участием, сообщили даже Чичикову лично некоторые из сих советов, предлагали даже конвой для безопасного препровожденья крестьян до места жительства За советы Чичиков благодарил, говоря, что при случае не преминет ими воспользоваться, а от конвоя отказался решительно, говоря, что он совершенно не нужен, что купленные им крестьяне отменно смирного характера, чувствуют сами добровольное расположение к переселению и что бунта ни в каком случае между ними быть не может.', '302.jpg', 9, '2025-05-25 08:42:03'),
(541, 'Все эти толки и рассуждения произвели, однако ж, самые благоприятные следствия.', 'Все эти толки и рассуждения произвели, однако ж, самые благоприятные следствия, какие только мог ожидать Чичиков. Именно, пронесли слухи, что он не более, не менее как миллионщик.', ' Жители города и без того, как уже мы видели в первой главе, душевно полюбили Чичикова, а теперь, после таких слухов, полюбили еще душевнее. Впрочем, если сказать правду, они все были народ добрый, живя между собою в ладу, обращались совершенно по-приятельски, и беседы их носили печать какого-то особенного простодушия и короткости: «Любезный друг Илья Ильич», «Послушай, брат, Антипатор Захарьевич!», «Ты заврался, мамочка, Иван Григорьевич». К почтмейстеру, которого звали Иван Андреевич, всегда прибавляли: «Шпрехен за дейч, Иван Андрейч?» — словом, все было очень семейственно. Многие были не без образования: председатель палаты знал наизусть «Людмилу» Жуковского, которая еще была тогда непростывшею новостию, и мастерски читал многие места, особенно: «Бор заснул, долина спит», и слово «чу!» так, что в самом деле виделось, как будто долина спит; для большего сходства он даже в это время зажмуривал глаза. Почтмейстер вдался более в философию и читал весьма прилежно, даже по ночам, Юнговы «Ночи» и «Ключ к таинствам натуры» Эккартсгаузена, из которых делал весьма длинные выписки, но какого рода они были, это никому не было известно; впрочем, он был остряк, цветист в словах и любил, как сам выражался, уснастить речь. А уснащивал он речь множеством разных частиц, как-то: «судырь ты мой, эдакой какой-нибудь, знаете, понимаете, можете себе представить, относительно так сказать, некоторым образом», и прочими, которые сыпал он мешками; уснащивал он речь тоже довольно удачно подмаргиванием, прищуриванием одного глаза, что все придавало весьма едкое выражение многим его сатирическим намекам. Прочие тоже были более или менее люди просвещенные: кто читал Карамзина, кто «Московские ведомости», кто даже и совсем ничего не читал. Кто был то, что называют тюрюк, то есть человек, которого нужно было подымать пинком на что-нибудь; кто был просто байбак, лежавший, как говорится, весь век на боку, которого даже напрасно было подымать: не встанет ни в каком случае.', '201.jpg', 40, '2025-05-22 06:43:34'),
(542, 'В последней строке не было размера, но это, впрочем, ничего.', 'В последней строке не было размера, но это, впрочем, ничего: письмо было написано в духе тогдашнего времени. Никакой подписи тоже не было: ни имени, ни фамилии, ни даже месяца и числа.', ' В postscriptum было только прибавлено, что его собственное сердце должно отгадать писавшую и что на бале у губернатора, имеющем быть завтра, будет присутствовать сам оригинал.', '101.jpg', 6, '2025-05-16 04:11:16'),
(543, 'Это очень его заинтересовало.', 'Это очень его заинтересовало.', ' В анониме было так много заманчивого и подстрекающего любопытство, что он перечел и в другой и в третий раз письмо и наконец сказал: «Любопытно бы, однако ж, знать, кто бы такая была писавшая!» Словом, дело, как видно, сделалось сурьезно; более часу он все думал об этом, наконец, расставив руки и наклоня голову, сказал: «А письмо очень, очень кудряво написано!» Потом, само собой разумеется, письмо было свернуто и уложено в шкатулку, в соседстве с какою-то афишею и пригласительным свадебным билетом, семь лет сохранявшимся в том же положении и на том же месте. Немного спустя принесли к нему, точно, приглашенье на бал к губернатору, — дело весьма обыкновенное в губернских городах: где губернатор, там и бал, иначе никак не будет надлежащей любви и уважения со стороны дворянства.', '002.jpg', 37, '2025-05-10 02:24:23'),
(544, '— Вона! пошла писать губерния.', '— Вона! пошла писать губерния.', '— Вона! пошла писать губерния! — проговорил Чичиков, попятившись назад, и как только дамы расселись по местам, он вновь начал выглядывать: нельзя ли по выражению в лице и в глазах узнать, которая была сочинительница; но никак нельзя было узнать ни по выражению в лице, ни по выражению в глазах, которая была сочинительница. Везде было заметно такое чуть-чуть обнаруженное, такое неуловимо-тонкое, у! какое тонкое!.. «Нет, — сказал сам в себе Чичиков, — женщины, это такой предмет… — Здесь он и рукой махнул: — просто и говорить нечего! Поди-ка попробуй рассказать или передать все то, что бегает на их лицах, все те излучинки, намеки, — а вот просто ничего не передашь. Одни глаза их такое бесконечное государство, в которое заехал человек — и поминай как звали! Уж его оттуда ни крючком, ничем не вытащишь. Ну попробуй, например, рассказать один блеск их: влажный, бархатный, сахарный. Бог их знает какого нет еще! и жесткий, и мягкий, и даже совсем томный, или, как иные говорят, в неге, или без неги, но пуще, нежели в неге — так вот зацепит за сердце, да и поведет по всей душе, как будто смычком.', '302.jpg', 46, '2025-12-19 05:08:04'),
(545, 'Виноват! Кажется, из уст нашего героя излетело словцо, подмеченное на улице.', 'Виноват! Кажется, из уст нашего героя излетело словцо, подмеченное на улице.', ' Что ж делать? Таково на Руси положение писателя! Впрочем, если слово из улицы попало в книгу, не писатель виноват, виноваты читатели, и прежде всего читатели высшего общества: от них первых не услышишь ни одного порядочного русского слова, а французскими, немецкими и английскими они, пожалуй, наделят в таком количестве, что и не захочешь, и наделят даже с сохранением всех возможных произношений: по-французски в нос картавя, по-английски произнесут как следует птице, и даже физиономию сделают птичью, и даже посмеются над тем, кто не сумеет сделать птичьей физиономии; а вот только русским ничем не наделят, разве из патриотизма выстроят себе на даче избу в русском вкусе. Вот каковы читатели высшего сословия, а за ними и все причитающие себя к высшему сословию! А между тем какая взыскательность! Хотят непременно, чтобы все было написано языком самым строгим, очищенным и благородным, — словом, хотят, чтобы русский язык сам собою опустился вдруг с облаков, обработанный как следует, и сел бы им прямо на язык, а им бы больше ничего, как только разинуть рты да выставить его. Конечно, мудрена женская половина человеческого рода; но почтенные читатели, надо признаться, бывают еще мудренее.', '101.jpg', 48, '2025-12-18 00:58:36'),
(546, 'А Чичиков приходил между тем в совершенное недоумение решить.', 'А Чичиков приходил между тем в совершенное недоумение решить, которая из дам была сочинительница письма.', ' Попробовавши устремить внимательнее взор, он увидел, что с дамской стороны тоже выражалось что-то такое, ниспосылающее вместе и надежду, и сладкие муки в сердце бедного смертного, что он наконец сказал: «Нет, никак нельзя угадать!» Это, однако же, никак не уменьшило веселого расположения духа, в котором он находился. Он непринужденно и ловко разменялся с некоторыми из дам приятными словами, подходил к той и другой дробным мелким шагом, или, как говорят, семенил ножками, как обыкновенно делают маленькие старички щеголи на высоких каблуках, называемые мышиными жеребчиками, забегающие весьма проворно около дам. Посеменивши с довольно ловкими поворотами направо и налево, он подшаркнул тут же ножкой в виде коротенького хвостика или наподобие запятой. Дамы были очень довольны и не только отыскали в нем кучу приятностей и любезностей, но даже стали находить величественное выражение в лице, что-то даже марсовское и военное, что, как известно, очень нравится женщинам. Даже из-за него уже начинали несколько ссориться: заметивши, что он становился обыкновенно около дверей, некоторые наперерыв спешили занять стул поближе к дверям, и когда одной посчастливилось сделать это прежде, то едва не произошла пренеприятная история, и многим, желавшим себе сделать то же, показалась уже чересчур отвратительною подобная наглость.', '201.jpg', 15, '2025-12-13 21:11:20'),
(547, 'Чичиков так занялся разговорами с дамами, или, лучше.', 'Чичиков так занялся разговорами с дамами, или, лучше, дамы так заняли и закружили его своими разговорами, подсыпая кучу самых замысловатых и тонких аллегорий, которые все нужно было разгадывать, отчего даже выступил у него на лбу пот.', 'Чичиков так занялся разговорами с дамами, или, лучше, дамы так заняли и закружили его своими разговорами, подсыпая кучу самых замысловатых и тонких аллегорий, которые все нужно было разгадывать, отчего даже выступил у него на лбу пот, — что он позабыл исполнить долг приличия и подойти прежде всего к хозяйке. Вспомнил он об этом уже тогда, когда услышал голос самой губернаторши, стоявшей перед ним уже несколько минут. Губернаторша произнесла несколько ласковым и лукавым голосом с приятным потряхиванием головы: «А, Павел Иванович, так вот как вы!..» В точности не могу передать слов губернаторши, но было сказано что-то исполненное большой любезности, в том духе, в котором изъясняются дамы и кавалеры в повестях наших светских писателей, охотников описывать гостиные и похвалиться знанием высшего тона, в духе того, что «неужели овладели так вашим сердцем, что в нем нет более ни места, ни самого тесного уголка для безжалостно позабытых вами». Герой наш поворотился в ту ж минуту к губернаторше и уже готов был отпустить ей ответ, вероятно ничем не хуже тех, какие отпускают в модных повестях Звонские, Линские, Лидипы, Гремины и всякие ловкие военные люди, как, невзначай поднявши глаза, остановился вдруг, будто оглушенный ударом.', '302.jpg', 18, '2025-12-07 20:11:18'),
(548, 'Перед ним стояла не одна губернаторша.', 'Перед ним стояла не одна губернаторша, она держала под руку молоденькую шестнадцатилетнюю девушку, свеженькую блондинку с тоненькими и стройными чертами лица, с остреньким подбородком, с очаровательно круглившимся овалом лица.', 'Перед ним стояла не одна губернаторша: она держала под руку молоденькую шестнадцатилетнюю девушку, свеженькую блондинку с тоненькими и стройными чертами лица, с остреньким подбородком, с очаровательно круглившимся овалом лица, какое художник взял бы в образец для мадонны и какое только редким случаем попадается на Руси, где любит все оказаться в широком размере, всё что ни есть: и горы и леса и степи, и лица и губы и ноги; ту самую блондинку, которую он встретил на дороге, ехавши от Ноздрева, когда, по глупости кучеров или лошадей, их экипажи так странно столкнулись, перепутавшись упряжью, и дядя Митяй с дядею Миняем взялись распутывать дело. Чичиков так смешался, что не мог произнести ни одного толкового слова, и пробормотал черт знает что такое, чего бы уж никак не сказал ни Гремин, ни Зяонский, ни Лидин.', '201.jpg', 10, '2025-11-28 15:14:21'),
(549, 'Вовсе это никак не произвело предполагаемого действия на Чичикова.', 'Вовсе это никак не произвело предполагаемого действия на Чичикова.', ' Он даже не смотрел на круги, производимые дамами, но беспрестанно подымался на цыпочки выглядывать поверх голов, куда бы могла забраться занимательная блондинка; приседал и вниз тоже, высматривая промеж плечей и спин, наконец доискался и увидел ее, сидящую вместе с матерью, над которою величаво колебалась какая-то восточная чалма с пером. Казалось, как будто он хотел взять их приступом; весеннее ли расположение подействовало на него, или толкал его кто сзади, только он протеснялся решительно вперед, несмотря ни на что; откупщик получил от него такой толчок, что пошатнулся и чуть-чуть удержался на одной ноге, не то бы, конечно, повалил за собою целый ряд; почтмейстер тоже отступился и посмотрел на него с изумлением, смешанным с довольно тонкой иронией, но он на них не поглядел; он видел только вдали блондинку, надевавшую длинную перчатку и, без сомнения, сгоравшую желанием пуститься летать по паркету. А уж там в стороне четыре пары откалывали мазурку; каблуки ломали пол, и армейский штабс-капитан работал и душою и телом, и руками и ногами, отвертывая такие па, какие и во сне никому не случалось отвертывать. Чичиков прошмыгнул мимо мазурки почти по самым каблукам и прямо к тому месту, где сидела губернаторша с дочкой. Однако ж он подступил к ним очень робко, не семенил так бойко и франтовски ногами, даже несколько замялся, и во всех движениях оказалась какая-то неловкость.', '100.jpg', 2, '2025-12-14 22:46:41'),
(550, 'Нельзя сказать наверно, точно ли пробудилось в нашем герое чувство любви.', 'Нельзя сказать наверно, точно ли пробудилось в нашем герое чувство любви, — даже сомнительно, чтобы господа такого рода, то есть не так чтобы толстые, однако ж и не то чтобы тонкие, способны были к любви.', 'Нельзя сказать наверно, точно ли пробудилось в нашем герое чувство любви, — даже сомнительно, чтобы господа такого рода, то есть не так чтобы толстые, однако ж и не то чтобы тонкие, способны были к любви; но при всем том здесь было что-то такое странное, что-то в таком роде, чего он сам не мог себе объяснить: ему показалось, как сам он потом сознавался, что весь бал, со всем своим говором и шумом, стал на несколько минут как будто где-то вдали; скрыпки и трубы нарезывали где-то за горами, и всё подернулось туманом, похожим на небрежно замалеванное поле на картине. И из этого мглистого, кое-как набросанного поля выходили ясно и оконченно только одни тонкие черты увлекательной блондинки: ее овально круглившееся личико, ее тоненький, тоненький стан, какой бывает у институтки в первые месяцы после выпуска, ее белое, почти простое платьице, легко и ловко обхватившее во всех местах молоденькие стройные члены, которые означались в какие-то чистых линиях. Казалось, она вся походила на какую-то игрушку, отчетливо выточенную из слоновой кости; она только одна белела и выходила прозрачною и светлою из мутной и непрозрачной толпы.', '100.jpg', 54, '2025-12-10 16:22:43'),
(551, 'Видно, так уж бывает на свете, видно.', 'Видно, так уж бывает на свете; видно, и Чичиковы на несколько минут в жизни обращаются в поэтов; но слово «поэт» будет уже слишком. По крайней мере он почувствовал себя совершенно чем-то вроде молодого человека, чуть-чуть не гусаром.', ' Увидевши возле них пустой стул, он тотчас его занял. Разговор сначала не клеился, но после дело пошло, и он начал даже получать форс, но… здесь, к величайшему прискорбию, надобно заметить, что люди степенные и занимающие важные должности как-то немного тяжеловаты в разговорах с дамами; на это мастера господа поручики и никак не далее капитанских чинов. Как они делают, бог их ведает: кажется, и не очень мудреные вещи говорят, а девица то и дело качается на стуле от смеха; статский же советник бог знает что расскажет: или поведет речь о том, что Россия очень пространное государство, или отпустит комплимент, который, конечно выдуман не без остроумия, но от него ужасно пахнет книгою; если же скажет что-нибудь смешное, то сам несравненно больше смеется, чем та, которая его слушает. Здесь это замечено для того, чтобы читатели видели, почему блондинка стала зевать во время рассказов нашего героя. Герой, однако же, совсем этого не замечал, рассказывая множество приятных вещей, которые уже случалось ему произносить в подобных случаях в разных местах: именно в Симбирской губернии у Софрона Ивановича Беспечного, где были тогда дочь его Аделаида Софроновна с тремя золовками: Марьей Гавриловной, Александрой Гавриловной и Адельгейдой Гавриловной; у Федора Федоровича Перекроева в Рязанской губернии; у Фрола Васильевича Победоносного в Пензенской губернии и у брата его Петра Васильевича, где были свояченица его Катерина Михайловна и внучатные сестры ее Роза Федоровна и Эмилия Федоровна; в Вятской губернии у Петра Варсонофьевича, где была сестра невестки его Пелагея Егоровна с племянницей Софьей Ростиславной и двумя сводными сестрами — Софией Александровной и Маклатурой Александровной.', '203.jpg', 26, '2025-12-05 14:59:04'),
(552, 'Всем дамам совершенно не понравилось такое обхождение Чичикова.', 'Всем дамам совершенно не понравилось такое обхождение Чичикова.', ' Одна из них нарочно прошла мимо его, чтобы дать ему это заметить, и даже задела блондинку довольно небрежно толстым руло своего платья, а шарфом, который порхал вокруг плеч ее, распорядилась так, что он махнул концом своим ее по самому лицу; в то же самое время позади его из одних дамских уст изнеслось вместе с запахом фиалок довольно колкое и язвительное замечание. Но, или он не услышал в самом деле, или прикинулся, что не услышал, только это было нехорошо, ибо мнением дам нужно дорожить: в этом он и раскаялся, но уже после, стало быть поздно.', '002.jpg', 10, '2025-11-26 13:25:46'),
(553, 'Негодование, во всех отношениях справедливое, изобразилось во многих лицах.', 'Негодование, во всех отношениях справедливое, изобразилось во многих лицах.', ' Как ни велик был в обществе вес Чичикова, хотя он и миллионщик и в лице его выражалось величие и даже что-то марсовское и военное, но есть вещи, которых дамы не простят никому, будь он кто бы ни было, и тогда прямо пиши пропало! Есть случаи, где женщина, как ни слаба и бессильна характером в сравнении с мужчиною, но становится вдруг тверже не только мужчины, но и всего что ни есть на свете. Пренебрежение, оказанное Чичиковым почти неумышленное, восстановило между дамами даже согласие, бывшее было на краю погибели по случаю завладения стулом. В произнесенных им невзначай каких-то сухих и обыкновенных словах нашли колкие намеки. В довершение бед какой-то из молодых людей сочинил тут же сатирические стихи на танцевавшее общество, без чего, как известно, никогда почти не обходится на губернских балах. Эти стихи были приписаны тут же Чичикову. Негодованье росло, и дамы стали говорить о нем в разных углах самым неблагоприятным образом; а бедная институтка была уничтожена совершенно, и приговор ее уже был подписан.', '201.jpg', 6, '2025-11-20 08:00:21'),
(554, 'А между тем герою нашему готовилась пренеприятнейшая неожиданность.', 'А между тем герою нашему готовилась пренеприятнейшая неожиданность, в то время когда блондинка зевала, а он рассказывал ей кое-какие в разные времена случившиеся историйки, и даже коснулся было греческого философа Диогена.', 'А между тем герою нашему готовилась пренеприятнейшая неожиданность: в то время когда блондинка зевала, а он рассказывал ей кое-какие в разные времена случившиеся историйки, и даже коснулся было греческого философа Диогена, показался из последней комнаты Ноздрев. Из буфета ли он вырвался, или из небольшой зеленой гостиной, где производилась игра посильнее, чем в обыкновенный вист, своей ли волею, или вытолкали его, только он явился веселый, радостный, ухвативши под руку прокурора, которого, вероятно, уже таскал несколько времени, потому что бедный прокурор поворачивал на все стороны густые брови, как бы придумывая средство выбраться из этого дружеского подручного путешествия. В самом деле, оно было невыносимо. Ноздрев, захлебнув куражу в двух чашках чаю, конечно не без рома, врал немилосердно. Завидев еще издали его, Чичиков решился даже на пожертвование, то есть оставить свое завидное место и сколько можно поспешнее удалиться: ничего хорошего не предвещала ему эта встреча. Но, на беду в это время подвернулся губернатор, изъявивший необыкновенную радость, что нашел Павла Ивановича, и остановил его, прося быть судиею в споре его с двумя дамами насчет того, продолжительна ли женская любовь, или нет; а между тем Ноздрев уже увидал его и шел прямо навстречу.', '101.jpg', 19, '2025-11-15 02:10:10'),
(555, '— А, херсонский помещик, херсонский помещик.', '— А, херсонский помещик, херсонский помещик! — кричал он, подходя и заливаясь смехом, от которого дрожали его свежие, румяные, как весенняя роза, щеки.', ' — Что? много наторговал мертвых.', '301.jpg', 7, '2025-11-14 01:43:36'),
(556, '— Уж ты, брат, ты, ты… я не отойду от тебя, пока не узнаю.', '— Уж ты, брат, ты, ты… я не отойду от тебя, пока не узнаю, зачем ты покупал мертвые души. Послушай, Чичиков, ведь тебе, право, стыдно, у тебя, ты сам знаешь, нет лучшего друга, как я.', ' Вот и его превосходительство здесь, не правда ли, прокурор? Вы не верите, ваше превосходительство, как мы друг к другу привязаны, то есть, просто если бы вы сказали, вот, я тут стою, а вы бы сказали: «Ноздрев! скажи по совести, кто тебе дороже, отец родной или Чичиков?» — скажу: «Чичиков», ей-богу… Позволь, душа, я тебе влеплю один безе. Уж вы позвольте, ваше превосходительство, поцеловать мне его.', '201.jpg', 28, '2025-12-11 22:19:09'),
(557, 'Ноздрев был так оттолкнут с своими безе, что чуть не полетел на землю.', 'Ноздрев был так оттолкнут с своими безе, что чуть не полетел на землю, от него все отступились и не слушали больше, но все же слова его о покупке мертвых душ были произнесены во всю глотку и сопровождены таким громким смехом.', 'Ноздрев был так оттолкнут с своими безе, что чуть не полетел на землю: от него все отступились и не слушали больше; но все же слова его о покупке мертвых душ были произнесены во всю глотку и сопровождены таким громким смехом, что привлекли внимание даже тех, которые находились в самых дальних углах комнаты. Эта новость так показалась странною, что все остановились с каким-то деревянным, глупо-вопросительным выражением. Чичиков заметил, что многие дамы перемигнулись между собою с какою-то злобною, едкою усмешкою и в выражении некоторых лиц показалось что-то такое двусмысленное, которое еще более увеличило это смущение. Что Ноздрев лгун отъявленный, это было известно всем, и вовсе не было в диковинку слышать от него решительную бессмыслицу; но смертный, право, трудно даже понять, как устроен этот смертный: как бы ни была пошла новость, но лишь бы она была новость, он непременно сообщит ее другому смертному, хотя бы именно для того только, чтобы сказать: «Посмотрите, какую ложь распустили!» — а другой смертный с удовольствием преклонит ухо, хотя после скажет сам: «Да это совершенно пошлая ложь, не стоящая никакого внимания!» — и вслед за тем сей же час отправится искать третьего смертного, чтобы, рассказавши ему, после вместе с ним воскликнуть с благородным негодованием: «Какая пошлая ложь!» И это непременно обойдет весь город, и все смертные, сколько их ни есть, наговорятся непременно досыта и потом признают, что это не стоит внимания и не достойно, чтобы о нем говорить.', '101.jpg', 43, '2025-12-03 19:48:18'),
(558, 'Это вздорное, по-видимому, происшествие заметно расстроило нашего героя.', 'Это вздорное, по-видимому, происшествие заметно расстроило нашего героя. Как ни глупы слова дурака, а иногда бывают они достаточны, чтобы смутить умного человека.', ' Он стал чувствовать себя неловко, неладно: точь-точь как будто прекрасно вычищенным сапогом вступил вдруг в грязную, вонючую лужу; словом, нехорошо, совсем нехорошо! Он пробовал об этом не думать, старался рассеяться, развлечься, присел в вист, но все пошло как кривое колесо: два раза сходил он в чужую масть и, позабыв, что по третьей не бьют, размахнулся со всей руки и хватил сдуру свою же. Председатель никак не мог понять, как Павел Иванович, так хорошо и, можно сказать, тонко разумевший игру, мог сделать подобные ошибки и подвел даже под обух его пикового короля, на которого он, по собственному выражению, надеялся, как на бога. Конечно, почтмейстер и председатель и даже сам полицеймейстер, как водится, подшучивали над нашим героем, что уж не влюблен ли он и что мы знаем, дескать, что у Павла Ивановича сердечишко прихрамывает, знаем, кем и подстрелено; но все это никак не утешало, как он ни пробовал усмехаться и отшучиваться. За ужином тоже он никак не был в состоянии развернуться, несмотря на то что общество за столом было приятное и что Ноздрева давно уже вывели; ибо сами даже дамы наконец заметили, что поведение его чересчур становилось скандалезно. Посреди котильона он сел на пол и стал хватать за полы танцующих, что было уже ни на что не похоже, по выражению дам. Ужин был очень весел, все лица, мелькавшие перед тройными подсвечниками, цветами, конфектами и бутылками, были озарены самым непринужденным довольством. Офицеры, дамы, фраки — все сделалось любезно, даже до приторности. Мужчины вскакивали со стульев и бежали отнимать у слуг блюда, чтобы с необыкновенною ловкостию предложить их дамам. Один полковник подал даме тарелку с соусом на конце обнаженной шпаги.', '202.jpg', 53, '2025-12-01 17:41:32'),
(559, 'Там, в этой комнатке, так знакомой читателю, с дверью, заставленной комодом.', 'Там, в этой комнатке, так знакомой читателю, с дверью, заставленной комодом, и выглядывавшими иногда из углов тараканами, положение мыслей и духа его было так же неспокойно, как неспокойны те кресла, в которых он сидел.', ' Неприятно, смутно было у него на сердце, какая-то тягостная пустота оставалась там. «Чтоб вас черт побрал всех, кто выдумал эти балы! — говорил он в сердцах. — Ну, чему сдуру обрадовались? В губернии неурожаи, дороговизна, так вот они за балы! Эк штука: разрядились в бабьи тряпки! Невидаль, что иная навертела на себя тысячу рублей! А ведь на счет же крестьянских оброков или, что еще хуже, на счет совести нашего брата. Ведь известно, зачем берешь взятку и покривишь душой: для того чтобы жене достать на шаль или на разные роброны, провал их возьми, как их называют. А из чего? чтобы не сказала какая-нибудь подстёга Сидоровна, что на почтмейстерше лучше было платье, да из-за нее бух тысячу рублей. Кричат: „Бал, бал, веселость!“ — просто дрянь бал, не в русском духе, не в русской натуре; черт знает что такое: взрослый, совершеннолетний вдруг выскочит весь в черном, общипанный, обтянутый, как чертик, и давай месить ногами. Иной даже, стоя в паре, переговаривает с другим об важном деле, а ногами в то же время, как козленок, вензеля направо и налево… Всё из обезьянства, всё из обезьянства! Что француз в сорок лет такой же ребенок, каким был и в пятнадцать, так вот давай же и мы! Нет, право… после всякого бала точно как будто какой грех сделал; и вспоминать даже о нем не хочется. В голове просто ничего, как после разговора с светским человеком: всего он наговорит, всего слегка коснется, все скажет, что понадергал из книжек, пестро, красно, а в голове хоть бы что-нибудь из того вынес, и видишь потом, как даже, разговор с простым купцом, знающим одно свое дело, но знающим его твердо и опытно, лучше всех этих побрякушек. Ну что из него выжмешь, из этого бала? Ну если бы, положим, какой-нибудь писатель вздумал описывать всю эту сцену так, как она есть? Ну и в книге, и там была бы она также бестолкова, как в натуре. Что она такое: нравственная ли, безнравственная ли? просто черт знает что такое! Плюнешь, да и книгу потом закроешь».', '302.jpg', 35, '2025-11-30 15:29:49'),
(560, 'Но в продолжение того, как он сидел в жестких своих креслах.', 'Но в продолжение того, как он сидел в жестких своих креслах, тревожимый мыслями и бессонницей, угощая усердно Ноздрева и всю родню его, и перед ним теплилась сальная свечка, которой светильня давно уже накрылась нагоревшею черною шапкою.', 'Но в продолжение того, как он сидел в жестких своих креслах, тревожимый мыслями и бессонницей, угощая усердно Ноздрева и всю родню его, и перед ним теплилась сальная свечка, которой светильня давно уже накрылась нагоревшею черною шапкою, ежеминутно грозя погаснуть, и глядела ему в окна слепая, темная ночь, готовая посинеть от приближавшегося рассвета, и пересвистывались вдали отдаленные петухи, и в совершенно заснувшем городе, может быть, плелась где-нибудь фризовая шинель, горемыка неизвестно какого класса и чина, знающая одну только (увы!) слишком протертую русским забубенным народом дорогу, — в это время на другом конце города происходило событие, которое готовилось увеличить неприятность положения нашего героя. Именно, в отдаленных улицах и закоулках города дребезжал весьма странный экипаж, наводивший недоумение насчет своего названия. Он не был похож ни на тарантас, ни на коляску, ни на бричку, а был скорее похож на толстощекий выпуклый арбуз, поставленный на колеса. Щеки этого арбуза, то есть дверцы, носившие следы желтой краски, затворялись очень плохо по причине плохого состояния ручек и замков, кое-как связанных веревками. Арбуз был наполнен ситцевыми подушками в виде кисетов, валиков и просто подушек, напичкан мешками с хлебами, калачами, кокурками, скородумками и кренделями из заварного теста. Пирог-курник и пирог-рассольник выглядывали даже наверх. Запятки были заняты лицом лакейского происхожденья, в куртке из домашней пеструшки, с небритой бородою, подернутою легкой проседью, — лицо, известное под именем «малого». Шум и визг от железных скобок и ржавых винтов разбудили на другом конце города булочника, который, подняв свою алебарду, закричал спросонья что стало мочи: «Кто идет?» — но, увидев, что никто не шел, а слышалось только издали дребезжанье, поймал у себя на воротнике какого-то зверя и, подошед к фонарю, казнил его тут же у себя на ногте. После чего, отставивши алебарду, опять заснул по уставам своего рыцарства.', '301.jpg', 56, '2025-11-22 12:17:07'),
(561, '— Какой веселенький ситец.', '— Какой веселенький ситец! — воскликнула во всех отношениях приятная дама, глядя на платье просто приятной дамы.', '.', '102.jpg', 59, '2025-12-01 20:58:05'),
(562, '— Да, очень веселенький.', '— Да, очень веселенький. Прасковья Федоровна, однако же, находит, что лучше, если бы клеточки были помельче, и чтобы не коричневые были крапинки, а голубые.', ' Сестре ее прислали материйку: это такое очарованье, которого просто нельзя выразить словами; вообразите себе: полосочки узенькие-узенькие, какие только может представить воображение человеческое, фон голубой и через полоску всё глазки и лапки, глазки и лапки, глазки и лапки… Словом, бесподобно! Можно сказать решительно, что ничего еще не было подобного на свете.', '302.jpg', 45, '2025-11-22 18:35:33'),
(563, 'Нужно заметить, что во всех отношениях приятная дама была отчасти материалистка.', 'Нужно заметить, что во всех отношениях приятная дама была отчасти материалистка, склонна к отрицанию и сомнению и отвергала весьма многое в жизни.', '.', '201.jpg', 18, '2025-11-15 13:50:33'),
(564, '— Фестончики, всё фестончики, пелеринка из фестончиков, на рукавах фестончики.', '— Фестончики, всё фестончики: пелеринка из фестончиков, на рукавах фестончики, эполетцы из фестончиков, внизу фестончики, везде фестончики.', '.', '103.jpg', 38, '2025-11-12 09:45:49'),
(565, '— Мило, Анна Григорьевна, до невероятности, шьется в два рубчика.', '— Мило, Анна Григорьевна, до невероятности, шьется в два рубчика, широкие проймы и сверху… Но вот, вот когда вы изумитесь, вот уж когда скажете, что… Ну, изумляйтесь, вообразите, лифчики пошли еще длиннее, впереди мыском.', '— Мило, Анна Григорьевна, до невероятности; шьется в два рубчика: широкие проймы и сверху… Но вот, вот когда вы изумитесь, вот уж когда скажете, что… Ну, изумляйтесь: вообразите, лифчики пошли еще длиннее, впереди мыском, и передняя косточка совсем выходит из границ; юбка вся собирается вокруг, как, бывало, в старину фижмы, даже сзади немножко подкладывают ваты, чтобы была совершенная бель-фам.', '302.jpg', 38, '2025-11-06 07:36:41'),
(566, '— Ну уж это просто: признаюсь.', '— Ну уж это просто: признаюсь! — сказала дама приятная во всех отношениях, сделавши движенье головою с чувством достоинства.', '.', '202.jpg', 55, '2025-10-28 05:07:34'),
(567, '— Я сама тоже… Право, как вообразишь.', '— Я сама тоже… Право, как вообразишь, до чего иногда доходит мода… ни на что не похоже! Я выпросила у сестры выкройку нарочно для смеху; Меланья моя принялась шить.', '.', '302.jpg', 29, '2025-10-24 03:11:01'),
(568, '— Так у вас разве есть выкройка.', '— Так у вас разве есть выкройка? — вскрикнула во всех отношениях приятная дама не без заметного сердечного движенья.', '.', '202.jpg', 24, '2025-10-23 02:26:53'),
(569, '— Кто ж станет носить после Прасковьи Федоровны.', '— Кто ж станет носить после Прасковьи Федоровны? Это уже слишком странно будет с вашей стороны, если вы чужих предпочтете своим.', '.', '102.jpg', 15, '2025-10-15 20:58:19'),
(570, '— Она вам тетка еще бог знает какая, с мужниной стороны… Нет, Софья Ивановна.', '— Она вам тетка еще бог знает какая: с мужниной стороны… Нет, Софья Ивановна, я и слышать не хочу, это выходит: вы мне хотите нанесть такое оскорбленье… Видно, я вам наскучила уже, видно, вы хотите прекратить со мною всякое знакомство.', '.', '202.jpg', 0, '2025-10-05 17:01:15'),
(571, 'Бедная Софья Ивановна не знала совершенно, что ей делать.', 'Бедная Софья Ивановна не знала совершенно, что ей делать. Она чувствовала сама, между каких сильных огней себя поставила. Вот тебе и похвасталась! Она бы готова была исколоть за это иголками глупый язык.', '.', '002.jpg', 37, '2025-09-29 10:41:56'),
(572, '— Ну что ж наш прелестник? — сказала между тем дама приятная во всех отношениях.', '— Ну что ж наш прелестник? — сказала между тем дама приятная во всех отношениях.', '.', '002.jpg', 16, '2025-09-20 08:35:36'),
(573, '— Ах, боже мой! что ж я так сижу перед вами! вот хорошо.', '— Ах, боже мой! что ж я так сижу перед вами! вот хорошо! Ведь вы знаете, Анна Григорьевна, с чем я приехала к вам.', '— Ах, боже мой! что ж я так сижу перед вами! вот хорошо! Ведь вы знаете, Анна Григорьевна, с чем я приехала к вам? — Тут дыхание гостьи сперлось, слова, как ястребы, готовы были пуститься в погоню одно за другим, и только нужно было до такой степени быть бесчеловечной, какова была искренняя приятельница, чтобы решиться остановить ее.', '302.jpg', 7, '2025-09-11 07:09:45'),
(574, '— Как вы ни выхваляйте и ни превозносите его, — говорила она с живостью.', '— Как вы ни выхваляйте и ни превозносите его, — говорила она с живостью, более нежели обыкновенною, — а я скажу прямо, и ему в глаза скажу, что он негодный человек, негодный, негодный, негодный.', '.', '202.jpg', 13, '2025-09-03 00:49:50'),
(575, '— Распустили слухи, что он хорош, а он совсем не хорош, совсем не хорош.', '— Распустили слухи, что он хорош, а он совсем не хорош, совсем не хорош, и нос у него… самый неприятный нос.', '.', '102.jpg', 22, '2025-08-26 22:06:58'),
(576, '— Позвольте же, позвольте же только рассказать вам… душенька, Анна Григорьевна.', '— Позвольте же, позвольте же только рассказать вам… душенька, Анна Григорьевна, позвольте рассказать! Ведь это история, понимаете ли: история, сконапель истоар, — говорила гостья с выражением почти отчаяния и совершенно умоляющим голосом.', ' Не мешает заметить, что в разговор обеих дам вмешивалось очень много иностранных слов и целиком иногда длинные французские фразы. Но как ни исполнен автор благоговения к тем спасительным пользам, которые приносит французский язык России, как ни исполнен благоговения к похвальному обычаю нашего высшего общества, изъясняющегося на нем во все часы дня, конечно, из глубокого чувства любви к отчизне, но при всем том никак не решается внести фразу какого бы ни было чуждого языка в сию русскую свою поэму. Итак, станем продолжать по-русски.', '301.jpg', 39, '2025-08-23 18:33:33'),
(577, '— Ах, жизнь моя, Анна Григорьевна.', '— Ах, жизнь моя, Анна Григорьевна, если бы вы могли только представить то положение, в котором я находилась, вообразите, приходит ко мне сегодня протопопша — протопопша, отца Кирилы жена — и что бы вы думали, наш-то смиренник, приезжий-то наш, каков.', '— Ах, жизнь моя, Анна Григорьевна, если бы вы могли только представить то положение, в котором я находилась, вообразите: приходит ко мне сегодня протопопша — протопопша, отца Кирилы жена — и что бы вы думали: наш-то смиренник, приезжий-то наш, каков, а.', '202.jpg', 5, '2025-08-17 17:09:09'),
(578, '— Ах, Анна Григорьевна, пусть бы еще куры, это бы еще ничего, слушайте только.', '— Ах, Анна Григорьевна, пусть бы еще куры, это бы еще ничего, слушайте только, что рассказала протопопша, приехала, говорит, к ней помещица Коробочка, перепуганная и бледная как смерть, и рассказывает, и как рассказывает, послушайте только.', '— Ах, Анна Григорьевна, пусть бы еще куры, это бы еще ничего; слушайте только, что рассказала протопопша: приехала, говорит, к ней помещица Коробочка, перепуганная и бледная как смерть, и рассказывает, и как рассказывает, послушайте только, совершенный роман: вдруг в глухую полночь, когда все уже спало в доме, раздается в ворота стук, опаснейший, какой только можно себе представить; кричат: «Отворите, отворите, не то будут выломаны ворота!» Каково вам это покажется? Каков же после этого прелестник.', '203.jpg', 37, '2025-08-14 12:59:56'),
(579, '— Ах, прелести! Так он за старуху принялся.', '— Ах, прелести! Так он за старуху принялся. Ну, хорош же после этого вкус наших дам, нашли в кого влюбиться.', '.', '002.jpg', 30, '2025-08-10 11:57:05');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(580, '— Да ведь нет, Анна Григорьевна, совсем не то, что вы полагаете.', '— Да ведь нет, Анна Григорьевна, совсем не то, что вы полагаете. Вообразите себе только то, что является вооруженный с ног до головы, вроде Ринальда Ринальдина, и требует: «Продайте, говорит, все души, которые умерли».', ' Коробочка отвечает очень резонно, говорит: «Я не могу продать, потому что они мертвые». — «Нет, говорит, они не мертвые, это мое, говорит, дело знать, мертвые ли они, или нет, они не мертвые, не мертвые, кричит, не мертвые». Словом, скандальозу наделал ужасного: вся деревня сбежалась, ребенки плачут, все кричит, никто никого не понимает, ну просто оррёр, оррёр, оррёр!.. Но вы себе представить не можете, Анна Григорьевна, как я перетревожилась, когда услышала все это. «Голубушка барыня, — говорит мне Машка. — посмотрите в зеркало: вы бледны». — «Не до зеркала, говорю, мне, я должна ехать рассказать Анне Григорьевне». В ту ж минуту приказываю заложить коляску: кучер Андрюшка спрашивает меня, куда ехать, а я ничего не могу и говорить, гляжу просто ему в глаза, как дура; я думаю, что он подумал, что я сумасшедшая.', '202.jpg', 49, '2025-08-01 07:10:00'),
(581, '— Это, однако ж, странно, — сказала во всех отношениях приятная дама.', '— Это, однако ж, странно, — сказала во всех отношениях приятная дама, — что бы такое могли значить эти мертвые души? Я, признаюсь, тут ровно ничего не понимаю.', ' Вот уже во второй раз я все слышу про эти мертвые души; а муж мой еще говорит, что Ноздрев врет; что-нибудь, верно же, есть.', '302.jpg', 19, '2025-07-28 05:19:16'),
(582, '— Но представьте же, Анна Григорьевна, каково мое было положение.', '— Но представьте же, Анна Григорьевна, каково мое было положение, когда я услышала это. «И теперь, — говорит Коробочка, — я не знаю, говорит, что мне делать.', ' Заставил, говорит, подписать меня какую-то фальшивую бумагу, бросил пятнадцать рублей ассигнациями; я, говорит, неопытная беспомощная вдова, я ничего не знаю…» Так вот происшествия! Но только если бы вы могли сколько-нибудь себе представить, как я вся перетревожилась.', '203.jpg', 37, '2025-07-22 00:13:33'),
(583, '— Я, признаюсь, тоже.', '— Я, признаюсь, тоже, — произнесла не без удивления просто приятная дама и почувствовала тут же сильное желание узнать, что бы такое могло здесь скрываться.', ' Она даже произнесла с расстановкой: — А что ж, вы полагаете, здесь скрывается.', '102.jpg', 26, '2025-07-19 18:50:02'),
(584, 'Но приятная дама ничего не нашлась сказать.', 'Но приятная дама ничего не нашлась сказать. Она умела только тревожиться, но чтобы составить какое-нибудь сметливое предположение, для этого никак ее не ставало, и оттого, более нежели всякая другая, она имела потребность в нежной дружбе и советах.', '.', '002.jpg', 7, '2025-07-16 14:52:35'),
(585, '— Ну, слушайте же, что такое эти мертвые души.', '— Ну, слушайте же, что такое эти мертвые души, — сказала дама приятная во всех отношениях, и гостья при таких словах вся обратилась в слух, ушки ее вытянулись сами собою, она приподнялась, почти не сидя и не держась на диване, и.', '— Ну, слушайте же, что такое эти мертвые души, — сказала дама приятная во всех отношениях, и гостья при таких словах вся обратилась в слух: ушки ее вытянулись сами собою, она приподнялась, почти не сидя и не держась на диване, и, несмотря на то что была отчасти тяжеловата, сделалась вдруг тонее, стала похожа на легкий пух, который вот так и полетит на воздух от дуновенья.', '102.jpg', 29, '2025-07-13 09:12:53'),
(586, 'Так русский барин, собачей и иора-охотник, подъезжая к лесу.', 'Так русский барин, собачей и иора-охотник, подъезжая к лесу, из которого вот-вот выскочит оттопанный доезжачими заяц, превращается весь с своим конем и поднятым арапником в один застывший миг, в порох, к которому вот-вот поднесут огонь.', ' Весь впился он очами в мутный воздух и уж настигнет зверя, уж допечет его неотбойный, как ни воздымайся против него вся мятущая снеговая степь, пускающая серебряные звезды ему в уста, в усы, в очи, в брови и в бобровую его шапку.', '101.jpg', 45, '2025-07-11 06:25:43'),
(587, '— Это просто выдумано только для прикрытья, а дело вот в чем.', '— Это просто выдумано только для прикрытья, а дело вот в чем: он хочет увезти губернаторскую дочку.', '.', '302.jpg', 25, '2025-07-02 03:31:58'),
(588, 'Это заключение, точно, было никак неожиданно и во всех отношениях необыкновенно.', 'Это заключение, точно, было никак неожиданно и во всех отношениях необыкновенно. Приятная дама, услышав это, так и окаменела на месте, побледнела, побледнела, как смерть и, точно, перетревожилась не на шутку.', '.', '101.jpg', 55, '2025-06-27 02:11:49'),
(589, '— Ах, боже мой.', '— Ах, боже мой! — вскрикнула она, всплеснув руками, — уж этого я бы никак не могла предполагать.', '.', '301.jpg', 8, '2025-06-24 00:05:59'),
(590, '— А я, признаюсь, как только вы открыли рот, я уже смекнула, в чем дело.', '— А я, признаюсь, как только вы открыли рот, я уже смекнула, в чем дело, — отвечала дама приятная во всех отношениях.', '.', '302.jpg', 20, '2025-06-14 19:57:18'),
(591, '— Но каково же после этого, Анна Григорьевна, институтское воспитание.', '— Но каково же после этого, Анна Григорьевна, институтское воспитание! ведь вот невинность.', '— Но каково же после этого, Анна Григорьевна, институтское воспитание! ведь вот невинность.', '302.jpg', 28, '2025-06-04 14:05:14'),
(592, '— Какая невинность.', '— Какая невинность! Я слыхала, как она говорила такие речи, что, признаюсь, у меня не станет духа произнести их.', '.', '201.jpg', 36, '2025-05-28 10:29:56'),
(593, '— Знаете, Анна Григорьевна, ведь это просто раздирает сердце, когда видишь.', '— Знаете, Анна Григорьевна, ведь это просто раздирает сердце, когда видишь, до чего достигла наконец безнравственность.', '.', '301.jpg', 33, '2025-05-21 05:23:17'),
(594, '— А мужчины от нее без ума.', '— А мужчины от нее без ума. А по мне, так я, признаюсь, ничего не нахожу в ней… Манерна нестерпимо.', '.', '302.jpg', 25, '2025-05-11 03:24:17'),
(595, '— Ах, жизнь моя, Анна Григорьевна, она статуя.', '— Ах, жизнь моя, Анна Григорьевна, она статуя, и хоть бы какое-нибудь выраженье в лице.', '.', '203.jpg', 8, '2025-05-03 02:35:48'),
(596, '— Ах, как манерна! ах, как манерна! Боже, как манерна.', '— Ах, как манерна! ах, как манерна! Боже, как манерна! Кто выучил ее, я не знаю, но я еще не видывала женщины, в которой бы было столько жеманства.', '.', '302.jpg', 27, '2025-04-28 22:08:32'),
(597, '— Милая, я сидела возле нее, румянец в палец толщиной и отваливается.', '— Милая, я сидела возле нее: румянец в палец толщиной и отваливается, как штукатурка, кусками. Мать выучила, сама кокетка, а дочка еще превзойдет матушку.', '.', '202.jpg', 59, '2025-04-26 18:58:39'),
(598, '— Ну позвольте, ну положите сами клятву, какую хотите.', '— Ну позвольте, ну положите сами клятву, какую хотите, я готова сей же час лишиться детей, мужа, всего именья, если у ней есть хоть одна капелька, хоть частица, хоть тень какого-нибудь румянца.', '— Ну позвольте, ну положите сами клятву, какую хотите, я готова сей же час лишиться детей, мужа, всего именья, если у ней есть хоть одна капелька, хоть частица, хоть тень какого-нибудь румянца.', '202.jpg', 20, '2025-04-17 16:56:45'),
(599, '— Ах, что вы это говорите, Софья Ивановна.', '— Ах, что вы это говорите, Софья Ивановна! — сказала дама приятная во всех отношениях и всплеснула руками.', '.', '302.jpg', 8, '2025-04-13 16:14:22'),
(600, '— Ах, какие же вы, право, Анна Григорьевна! я с изумленьем на вас гляжу.', '— Ах, какие же вы, право, Анна Григорьевна! я с изумленьем на вас гляжу! — сказала приятная дама и всплеснула тоже руками.', '.', '202.jpg', 38, '2025-04-10 13:46:48'),
(601, 'Да не покажется читателю странным.', 'Да не покажется читателю странным, что обе дамы были не согласны между собою в том, что видели почти в одно и то же время.', ' Есть, точно, на свете много таких вещей, которые имеют уже такое свойство: если на них взглянет одна дама, они выйдут совершенно белые, а взглянет другая, выйдут красные, красные, как брусника.', '301.jpg', 20, '2025-04-09 11:51:49'),
(602, '— Ну, вот вам еще доказательство, что она бледна, — продолжала приятная дама.', '— Ну, вот вам еще доказательство, что она бледна, — продолжала приятная дама, — я помню, как теперь, что я сижу возле Манилова и говорю ему: «Посмотрите, какая она бледная.', '— Ну, вот вам еще доказательство, что она бледна, — продолжала приятная дама, — я помню, как теперь, что я сижу возле Манилова и говорю ему: «Посмотрите, какая она бледная!» Право, нужно быть до такой степени бестолковыми, как наши мужчины, чтобы восхищаться ею. А наш-то прелестник… Ах, как он мне показался противным! Вы не можете себе представить, Анна Григорьевна, до какой степени он мне показался противным.', '202.jpg', 15, '2025-04-01 06:46:36'),
(603, '— Я, Анна Григорьевна.', '— Я, Анна Григорьевна.', '— Я, Анна Григорьевна.', '301.jpg', 52, '2025-03-29 00:23:37'),
(604, '— Никогда, никогда, Анна Григорьевна.', '— Никогда, никогда, Анна Григорьевна! Позвольте мне вам заметить, что я очень хорошо себя знаю; а разве со стороны каких-нибудь иных дам, которые играют роль недоступных.', '.', '203.jpg', 4, '2025-03-27 22:45:25'),
(605, '— Уж извините, Софья Ивановна.', '— Уж извините, Софья Ивановна! Уж позвольте вам сказать, что за мной подобных скандальозностей никогда еще не водилось. За кем другим разве, а уж за мной нет, уж позвольте мне вам это заметить.', '.', '203.jpg', 46, '2025-03-26 19:18:00'),
(606, '— Отчего же вы обиделись.', '— Отчего же вы обиделись? ведь там были и другие дамы, были даже такие, которые первые захватили стул у дверей, чтобы сидеть к нему поближе.', '.', '002.jpg', 23, '2025-03-24 13:49:54'),
(607, 'Ну, уж после таких слов, произнесенных приятною дамою.', 'Ну, уж после таких слов, произнесенных приятною дамою, должна была неминуемо последовать буря, но, к величайшему изумлению, обе дамы вдруг приутихли, и совершенно ничего не последовало.', ' Во всех отношениях приятная дама вспомнила, что выкройка для модного платья еще не находится в ее руках, а просто приятная дама смекнула, что она еще не успела выведать никаких подробностей насчет открытия, сделанного ее искреннею приятельницею, и потому мир последовал очень скоро. Впрочем, обе дамы нельзя сказать чтобы имели в своей натуре потребность наносить неприятность, и вообще в характерах их ничего не было злого, а так, нечувствительно, в разговоре рождалось само собою маленькое желание кольнуть друг друга; просто одна другой из небольшого наслаждения при случае всунет иное живое словцо: вот, мол, тебе! на, возьми, съешь! Разного рода бывают потребности в сердцах как мужеского, так и женского пола.', '202.jpg', 47, '2025-03-19 10:53:53'),
(608, '— Я не могу, однако же, понять только того, — сказала просто приятная дама.', '— Я не могу, однако же, понять только того, — сказала просто приятная дама, — как Чичиков, будучи человек заезжий, мог решиться на такой отважный пассаж. Не может быть, чтобы тут не было участников.', '.', '202.jpg', 10, '2025-03-12 09:38:29'),
(609, '— А что ж? ведь его на это станет.', '— А что ж? ведь его на это станет. Вы знаете, он родного отца хотел продать или, еще лучше, проиграть в карты.', '.', '101.jpg', 48, '2025-03-04 08:25:15'),
(610, '— Ах, боже мой, какие интересные новости я узнаю от вас.', '— Ах, боже мой, какие интересные новости я узнаю от вас! Я бы никак не могла предполагать, чтобы и Ноздрев был замешан в эту историю.', '— Ах, боже мой, какие интересные новости я узнаю от вас! Я бы никак не могла предполагать, чтобы и Ноздрев был замешан в эту историю.', '002.jpg', 5, '2025-02-24 04:51:12'),
(611, '— Как подумаешь, право, чего не происходит на свете.', '— Как подумаешь, право, чего не происходит на свете! Ну можно ли было предполагать, когда, помните, Чичиков только что приехал к нам в город, что он произведет такой странный марш в свете.', '— Как подумаешь, право, чего не происходит на свете! Ну можно ли было предполагать, когда, помните, Чичиков только что приехал к нам в город, что он произведет такой странный марш в свете? Ах, Анна Григорьевна, если бы вы знали, как я перетревожилась! Если бы не ваша благосклонность и дружба… вот уже, точно, на краю погибели… куда ж? Машка моя видит, что я бледна как смерть. «Душечка барыня, — говорит мне, — вы бледны как смерть». — «Машка, говорю, мне не до того теперь».', '302.jpg', 57, '2025-02-17 01:39:19'),
(612, 'Приятной даме очень хотелось выведать дальнейшие подробности насчет похищения.', 'Приятной даме очень хотелось выведать дальнейшие подробности насчет похищения, то есть в котором часу и прочее, но многого захотела. Во всех отношениях приятная дама прямо отозвалась незнанием.', ' Она не умела лгать: предположить что-нибудь — это другое дело, но и то в таком случае, когда предположение основывалось на внутреннем убеждении; если ж было почувствовано внутреннее убеждение, тогда умела она постоять за себя, и попробовал бы какой-нибудь дока-адвокат, славящийся даром побеждать чужие мнения, попробовал бы он состязаться здесь, — увидел бы он, что значит внутреннее убеждение.', '101.jpg', 30, '2025-02-14 23:16:18'),
(613, 'Сделавши свое дело относительно губернаторши.', 'Сделавши свое дело относительно губернаторши, дамы насели было на мужскую партию, пытаясь склонить их на свою сторону и утверждая, что мертвые души выдумка и употреблена только для того.', 'Сделавши свое дело относительно губернаторши, дамы насели было на мужскую партию, пытаясь склонить их на свою сторону и утверждая, что мертвые души выдумка и употреблена только для того, чтобы отвлечь всякое подозрение и успешнее произвесть похищение. Многие даже из мужчин были совращены и пристали к их партии, несмотря на то что подвергнулись сильным нареканиям от своих же товарищей, обругавших их бабами и юбками — именами, как известном, очень обидными для мужского пола.', '102.jpg', 57, '2025-11-21 20:23:25'),
(614, 'Но как ни вооружались и ни противились мужчины.', 'Но как ни вооружались и ни противились мужчины, а в их партии совсем не было такого порядка, как в женской.', ' Все у них было как-то черство, неотесанно, неладно, негоже, нестройно, нехорошо, в голове кутерьма, сутолока, сбивчивость, неопрятность в мыслях, — одним словом, так и вызначилась во всем пустая природа мужчины, природа грубая, тяжелая, не способная ни к домостроительству, ни к сердечным убеждениям, маловерная, ленивая, исполненная беспрерывных сомнений и вечной боязни. Они говорили, что все это вздор, что похищенье губернаторской дочки более дело гусарское, нежели гражданское, что Чичиков не сделает этого, что бабы врут, что баба что мешок: что положат, то несет, что главный предмет, на который нужно обратить внимание, есть мертвые души, которые, впрочем, черт его знает, что значат, но в них заключено, однако ж, весьма скверное, нехорошее. Почему казалось мужчинам, что в них заключалось скверное и нехорошее, сию минуту узнаем: в губернию назначен был новый генерал-губернатор — событие, как известно, приводящее чиновников в тревожное состояние: пойдут переборки, распеканья, взбутетениванья и всякие должностные похлебки, которыми угощает начальник своих подчиненных. «Ну что, — думали чиновники, — если он узнает только просто, что в городе их вот-де какие глупые слухи, да за это одно может вскипятить не на жизнь, а на самую смерть». Инспектор врачебной управы вдруг побледнел; ему представилось бог знает что: не разумеются ли под словом «мертвые души» больные, умершие в значительном количестве в лазаретах и в других местах от повальной горячки, против которой не было взято надлежащих мер, и что Чичиков не есть ли подосланный чиновник из канцелярии генерал-губернатора для произведения тайного следствия. Он сообщил об этом председателю.', '203.jpg', 45, '2025-11-18 16:35:14'),
(615, 'Собравшись у полицеймейстера.', 'Собравшись у полицеймейстера, уже известного читателям отца и благодетеля города, чиновники имели случай заметить друг другу, что они даже похудели от этих забот и тревог.', ' В самом деле, назначение нового генерал-губернатора, и эти полученные бумаги такого сурьезного содержания, и эти бог знает какие слухи — все это оставило заметные следы в их лицах, и фраки на многих сделались заметно просторней. Все подалось: и председатель похудел, и инспектор врачебной управы похудел, и прокурор похудел, и какой-то Семен Иванович, никогда не называвшийся по фамилии, носивший на указательном пальце перстень, который давал рассматривать дамам, даже и тот похудел. Конечно, нашлись, как и везде бывает, кое-кто неробкого десятка, которые не теряли присутствия духа, но их было весьма немного. Почтмейстер один только. Он один не изменялся в постоянно ровном характере и всегда в подобных случаях имел обыкновение говорить: «Знаем мы вас, генерал-губернаторов! Вас, может быть, три-четыре переменится, а я вот уже тридцать лет, судырь мой, сижу на одном месте». На это обыкновенно замечали другие чиновники: «Хорошо тебе, шпрехен за дейч Иван Андрейч, у тебя дело почтовое: принять да отправить экспедицию; разве только надуешь, заперши присутствие часом раньше, да возьмешь с опоздавшего купца за прием письма в неуказанное время или перешлешь иную посылку, которую не следует пересылать, — тут, конечно, всякий будет святой. А вот пусть к тебе повадится черт подвертываться всякий день под руку, так что вот и не хочешь брать, а он сам сует. Тебе, разумеется, сполагоря, у тебя один сынишка, а тут, брат, Прасковью Федоровну наделил бог такою благодатию, что год, то несет: либо Праскушку, либо Петрушку: тут, брат, другое запоешь». Так говорили чиновники, а можно ли в самом деле устоять против черта, об этом судить не авторское дело. В собравшемся на сей раз совете очень заметно было отсутствие той необходимой вещи, которую в простонародье называют толком. Вообще мы как-то не создались для представительных заседаний. Во всех наших собраниях, начиная от крестьянской мирской сходки до всяких возможных ученых и прочих комитетов, если в них нет одной главы, управляющей всем, присутствует препорядочная путаница.', '202.jpg', 33, '2025-11-14 11:33:18'),
(616, 'Голос, которым он произнес это, заключал в себе что-то потрясающее.', 'Голос, которым он произнес это, заключал в себе что-то потрясающее, так что заставил вскрикнуть всех в одно время.', 'Голос, которым он произнес это, заключал в себе что-то потрясающее, так что заставил вскрикнуть всех в одно время.', '202.jpg', 2, '2025-11-09 05:50:46'),
(617, 'А когда все тут же в один голос спросили: «Кто таков этот капитан Копейкин.', 'А когда все тут же в один голос спросили: «Кто таков этот капитан Копейкин.', 'А когда все тут же в один голос спросили: «Кто таков этот капитан Копейкин.', '203.jpg', 0, '2025-11-03 05:03:13'),
(618, '— Капитан Копейкин, — сказал почтмейстер.', '— Капитан Копейкин, — сказал почтмейстер, открывший свою табакерку только вполовину, из боязни, чтобы кто-нибудь из соседей не запустил туда своих пальцев, в чистоту которых он плохо верил и даже имел обыкновение приговаривать, «Знаем, батюшка.', '— Капитан Копейкин, — сказал почтмейстер, открывший свою табакерку только вполовину, из боязни, чтобы кто-нибудь из соседей не запустил туда своих пальцев, в чистоту которых он плохо верил и даже имел обыкновение приговаривать: «Знаем, батюшка: вы пальцами своими, может быть, невесть в какие места наведываетесь, а табак вещь, требующая чистоты». — Капитан Копейкин, — сказал почтмейстер, уже понюхавши табаку, — да ведь это, впрочем, если рассказать, выйдет презанимательная для какого-нибудь писателя в некотором роде целая поэма.', '302.jpg', 40, '2025-10-27 02:19:57'),
(619, 'Все присутствующие изъявили желание узнать эту историю, или.', 'Все присутствующие изъявили желание узнать эту историю, или, как выразился почтмейстер, презанимательную для писателя в некотором роде целую поэму, и он начал так.', 'Все присутствующие изъявили желание узнать эту историю, или, как выразился почтмейстер, презанимательную для писателя в некотором роде целую поэму, и он начал так.', '102.jpg', 25, '2025-10-18 01:01:26'),
(620, 'Здесь почтмейстер вскрикнул и хлопнул со всего размаха рукой по своему лбу.', 'Здесь почтмейстер вскрикнул и хлопнул со всего размаха рукой по своему лбу, назвавши себя публично при всех телятиной.', ' Он не мог понять, как подобное обстоятельство не пришло ему в самом начале рассказа, и сознался, что совершенно справедлива поговорка: «Русский человек задним умом крепок». Однако ж минуту спустя он тут же стал хитрить и попробовал было вывернуться, говоря, что, впрочем, в Англии очень усовершенствована механика, что видно по газетам, как один изобрел деревянные ноги таким образом, что при одном прикосновении к незаметной пружинке уносили эти ноги человека бог знает в какие места, так что после нигде и отыскать его нельзя было.', '202.jpg', 17, '2025-11-24 18:07:07'),
(621, 'Но все очень усомнились, чтобы Чичиков был капитан Копейкин, и нашли.', 'Но все очень усомнились, чтобы Чичиков был капитан Копейкин, и нашли, что почтмейстер хватил уже слишком далеко. Впрочем, они, с своей стороны, тоже не ударили лицом в грязь и, наведенные остроумной догадкой почтмейстера, забрели едва ли не далее.', ' Из числа многих в своем роде сметливых предположений было наконец одно — странно даже и сказать: что не есть ли Чичиков переодетый Наполеон, что англичанин издавна завидует, что, дескать, Россия так велика и обширна, что даже несколько раз выходили и карикатуры, где русский изображен разговаривающим с англичанином. Англичанин стоит и сзади держит на веревке собаку, и под собакой разумеется Наполеон: «Смотри, мол, говорит, если что не так, так я на тебя сейчас выпущу эту собаку!» — и вот теперь они, может быть, и выпустили его с острова Елены, и вот он теперь и пробирается в Россию, будто бы Чичиков, а в самом деле вовсе не Чичиков.', '302.jpg', 44, '2025-11-17 12:40:49'),
(622, 'Конечно, поверить этому чиновники не поверили, а, впрочем, призадумались и.', 'Конечно, поверить этому чиновники не поверили, а, впрочем, призадумались и, рассматривая это дело каждый про себя, нашли, что лицо Чичикова, если он поворотится и станет боком, очень сдает на портрет Наполеона.', ' Полицеймейстер, который служил в кампанию двенадцатого года и лично видел Наполеона, не мог тоже не сознаться, что ростом он никак не будет выше Чичикова и что складом своей фигуры Наполеон тоже нельзя сказать чтобы слишком толст, однако ж и не так чтобы тонок. Может быть, некоторые читатели назовут все это невероятным; автор тоже в угоду им готов бы назвать все это невероятным; но, как на беду, все именно произошло так, как рассказывается, и тем еще изумительнее, что город был не в глуши, а, напротив, недалеко от обеих столиц. Впрочем, нужно помнить, что все это происходило вскоре после достославного изгнания французов. В это время все наши помещики, чиновники, купцы, сидельцы и всякий грамотный и даже неграмотный народ сделались по крайней мере на целые восемь лет заклятыми политиками. «Московские ведомости» и «Сын отечества» зачитывались немилосердо и доходили к последнему чтецу в кусочках, не годных ни на какое употребление. Вместо вопросов: «Почем, батюшка, продали меру овса? как воспользовались вчерашней порошей?» — говорили: «А что пишут в газетах, не выпустили ли опять Наполеона из острова?» Купцы этого сильно опасались, ибо совершенно верили предсказанию одного пророка, уже три года сидевшего в остроге; пророк пришел неизвестно откуда в лаптях и нагольном тулупе, страшно отзывавшемся тухлой рыбой, и возвестил, что Наполеон есть антихрист и держится на каменной цепи, за шестью стенами и семью морями, но после разорвет цепь и овладеет всем миром. Пророк за предсказание попал, как следует, в острог, но тем не менее дело свое сделал и смутил совершенно купцов. Долго еще, во время даже самых прибыточных сделок, купцы, отправляясь в трактир запивать их чаем, поговаривали об антихристе. Многие из чиновников и благородного дворянства тоже невольно подумывали об этом и, зараженные мистицизмом, который, как известно, был тогда в большой моде, видели в каждой букве, из которых было составлено слово «Наполеон», какое-то особенное значение; многие даже открыли в нем апокалипсические цифры.', '302.jpg', 26, '2025-11-07 09:33:19'),
(623, 'Странные люди эти господа чиновники, а за ними и все прочие звания.', 'Странные люди эти господа чиновники, а за ними и все прочие звания: ведь очень хорошо знали, что Ноздрев лгун, что ему нельзя верить ни в одном слове, ни в самой безделице, а между тем именно прибегнули к нему.', ' Поди ты сладь с человеком! не верит в бога, а верит, что если почешется переносье, то непременно умрет; пропустит мимо создание поэта, ясное как день, все проникнутое согласием и высокою мудростью простоты, а бросится именно на то, где какой-нибудь удалец напутает, наплетет, изломает, выворотит природу, и ему оно понравится, и он станет кричать: «Вот оно, вот настоящее знание тайн сердца!» Всю жизнь не ставит в грош докторов, а кончится тем, что обратится наконец к бабе, которая лечит зашептываньями и заплевками, или, еще лучше, выдумает сам какой-нибудь декохт из невесть какой дряни, которая, бог знает почему, вообразится ему именно средством против его болезни. Конечно, можно отчасти извинить господ чиновников действительно затруднительным их положением. Утопающий, говорят, хватается и за маленькую щепку, и у него нет в это время рассудка подумать, что на щепке может разве прокатиться верхом муха, а в нем весу чуть не четыре пуда, если даже не целых пять; но не приходит ему в то время соображение в голову, и он хватается за щепку. Так и господа наши ухватились наконец и за Ноздрева. Полицеймейстер в ту же минуту написал к нему записочку пожаловать на вечер, и квартальный, в ботфортах, с привлекательным румянцем на щеках, побежал в ту же минуту, придерживая шпагу, вприскочку на квартиру Ноздрева. Ноздрев был занят важным делом; целые четыре дня уже не выходил он из комнаты, не впускал никого и получал обед в окошко, — словом, даже исхудал и позеленел. Дело требовало большой внимательности: оно состояло в подбирании из нескольких десятков дюжин карт одной талии, но самой меткой, на которую можно было бы понадеяться, как на вернейшего друга. Работы оставалось еще по крайней мере на две недели; во все продолжение этого времени Порфирий должен был чистить меделянскому щенку пуп особенной щеточкой и мыть его три раза на день в мыле.', '203.jpg', 45, '2025-11-01 08:19:30'),
(624, 'Все эти толки, мнения и слухи, неизвестно по какой причине.', 'Все эти толки, мнения и слухи, неизвестно по какой причине, больше всего подействовали на бедного прокурора. Они подействовали на него до такой степени, что он, пришедши домой, стал думать, думать и вдруг, как говорится, ни с того ни с другого умер.', ' Параличом ли его, или чем другим прихватило, только он как сидел, так и хлопнулся со стула навзничь. Вскрикнули, как водится, всплеснув руками: «Ах, боже мой!» — послали за доктором, чтобы пустить кровь, но увидели, что прокурор был уже одно бездушное тело. Тогда только с соболезнованием узнали, что у покойника была, точно, душа, хотя он по скромности своей никогда ее не показывал. А между тем появленье смерти так же было страшно в малом, как страшно оно и в великом человеке: тот, кто еще не так давно ходил, двигался, играл в вист, подписывал разные бумаги и был так часто виден между чиновников с своими густыми бровями и мигающим глазом, теперь лежал на столе, левый глаз уже не мигал вовсе, но бровь одна все еще была приподнята с каким-то вопросительным выражением. О чем покойник спрашивал, зачем он умер или зачем жил, об этом один бог ведает.', '203.jpg', 26, '2025-10-28 02:47:24'),
(625, 'Но это, однако ж, несообразно! это несогласно ни с чем.', 'Но это, однако ж, несообразно! это несогласно ни с чем! это невозможно, чтобы чиновники так могли сами напугать себя; создать такой вздор, так отдалиться от истины, когда даже ребенку видно, в чем дело.', 'Но это, однако ж, несообразно! это несогласно ни с чем! это невозможно, чтобы чиновники так могли сами напугать себя; создать такой вздор, так отдалиться от истины, когда даже ребенку видно, в чем дело! Так скажут многие читатели и уморят автора в несообразностях или назовут бедных чиновников дураками, потому что щедр человек на слово «дурак» и готов прислужиться им двадцать раз на день своему ближнему. Довольно из десяти сторон иметь одну глупую, чтобы быть признану дураком мимо девяти хороших. Читателям легко судить, глядя из своего покойного угла и верхушки, откуда открыт весь горизонт на все, что делается внизу, где человеку виден только близкий предмет. И во всемирной летописи человечества много есть целых столетий, которые, казалось бы, вычеркнул и уничтожил как ненужные. Много совершилось в мире заблуждений, которых бы, казалось, теперь не сделал и ребенок. Какие искривленные, глухие, узкие, непроходимые, заносящие далеко в сторону дороги избирало человечество, стремясь достигнуть вечной истины, тогда как перед ним весь был открыт прямой путь, подобный пути, ведущему к великолепной храмине, назначенной царю в чертоги! Всех других путей шире и роскошнее он, озаренный солнцем и освещенный всю ночь огнями, но мимо его в глухой темноте текли люди. И сколько раз уже наведенные нисходившим с небес смыслом, они и тут умели отшатнуться и сбиться в сторону, умели среди бела дня попасть вновь в непроходимые захолустья, умели напустить вновь слепой туман друг другу в очи и, влачась вслед за болотными огнями, умели-таки добраться до пропасти, чтобы потом с ужасом спросить друг друга: где выход, где дорога? Видит теперь все ясно текущее поколение, дивится заблужденьям, смеется над неразумием своих предков, не зря, что небесным огнем исчерчена сия летопись, что кричит в ней каждая буква, что отвсюду устремлен пронзительный перст на него же, на него, на текущее поколение; но смеется текущее поколение и самонадеянно, гордо начинает ряд новых заблуждений, над которыми также потом посмеются потомки.', '202.jpg', 15, '2025-10-24 23:44:49'),
(626, 'Чичиков ничего обо всем этом не знал совершенно.', 'Чичиков ничего обо всем этом не знал совершенно. Как нарочно, в то время он получил легкую простуду — флюс и небольшое воспаление в горле, в раздаче которых чрезвычайно щедр климат многих наших губернских городов.', ' Чтобы не прекратилась, боже сохрани, как-нибудь жизнь без потомков, он решился лучше посидеть денька три в комнате. В продолжение сих дней он полоскал беспрестанно горло молоком с фигой, которую потом съедал, и носил привязанную к щеке подушечку из ромашки и камфары. Желая чем-нибудь занять время, он сделал несколько новых и подробных списков всем накупленным крестьянам, прочитал даже какой-то том герцогини Лавальер, отыскавшийся в чемодане, пересмотрел в ларце разные находившиеся там предметы и записочки, кое-что перечел и в другой раз, и все это прискучило ему сильно. Никак не мог он понять, что бы значило, что ни один из городских чиновников не приехал к нему хоть бы раз наведаться о здоровье, тогда как еще недавно то и дело стояли перед гостиницей дрожки — то почтмейстерские, то прокурорские, то председательские. Он пожимал только плечами, ходя по комнате. Наконец почувствовал он себя лучше и обрадовался бог знает как, когда увидел возможность выйти на свежий воздух. Не откладывая, принялся он немедленно за туалет, отпер свою шкатулку, налил в стакан горячей воды, вынул щетку и мыло и расположился бриться, чему, впрочем, давно была пора и время, потому что, пощупав бороду рукою и взглянув в зеркало, он уже произнес: «Эк какие пошли писать леса!» И в самом деле, леса не леса, а по всей щеке и подбородку высыпал довольно густой посев. Выбрившись, принялся он за одеванье живо и скоро, так что чуть не выпрыгнул из панталон. Наконец он был одет, вспрыснут одеколоном и, закутанный потеплее, выбрался на улицу, завязавши из предосторожности щеку. Выход его, как всякого выздоровевшего человека, был точно праздничный. Все, что ни попадалось ему, приняло вид смеющийся: и домы, и проходившие мужики, довольно, впрочем, сурьезные, из которых иной уже успел съездить своего брата в ухо. Первый визит он намерен был сделать губернатору. Дорогою много приходило ему всяких мыслей на ум; вертелась в голове блондинка, воображенье начало даже слегка шалить, и он уже сам стал немного шутить и подсмеиваться над собою.', '102.jpg', 40, '2025-10-19 21:37:09'),
(627, '— Как, что ты, ты, видно, не узнал меня.', '— Как, что ты, ты, видно, не узнал меня? Ты всмотрись хорошенько в лицо! — говорил ему Чичиков.', '.', '102.jpg', 21, '2025-10-10 17:14:58'),
(628, '— Как не узнать, ведь я вас не впервой вижу, — сказал швейцар.', '— Как не узнать, ведь я вас не впервой вижу, — сказал швейцар. — Да вас-то именно одних и не велено пускать, других всех можно.', '.', '101.jpg', 35, '2025-10-05 13:52:53'),
(629, '— Такой приказ, так уж, видно, следует.', '— Такой приказ, так уж, видно, следует, — сказал швейцар и прибавил к тому слово: «да». После чего стал перед ним совершенно непринужденно, не сохраняя того ласкового вида, с каким прежде торопился снимать с него шинель.', ' Казалось, он думал, глядя на него: «Эге! уж коли тебя бары гоняют с крыльца, так ты, видно, так себе, шушера какой-нибудь.', '102.jpg', 10, '2025-09-30 12:29:50'),
(630, '«Непонятно.', '«Непонятно!» — подумал про себя Чичиков и отправился тут же к председателю палаты, но председатель палаты так смутился, увидя его, что не мог связать двух слов, и наговорил такую дрянь, что даже им обоим сделалось совестно.', ' Уходя от него, как ни старался Чичиков изъяснить дорогою и добраться, что такое разумел председатель и насчет чего могли относиться слова его, но ничего не мог понять. Потом зашел в другим: к полицеймейстеру, к вице-губернатору, к почтмейстеру, но все или не приняли его, или приняли так странно, такой принужденный и непонятный вели разговор, так растерялись, и такая вышла бестолковщина изо всего, что он усомнился в здоровье их мозга. Попробовал было еще зайти кое к кому, чтобы узнать по крайней мере причину, и не добрался никакой причины. Как полусонный, бродил он без цели по городу, не будучи в состоянии решить, он ли сошел с ума, чиновники ли потеряли голову, во сне ли все это делается, или наяву заварилась дурь почище сна. Поздно уже, почти в сумерки, возвратился он к себе в гостиницу, из которой было вышел в таком хорошем расположении духа, и от скуки велел подать себе чаю. В задумчивости и в каком-то бессмысленном рассуждении о странности положения своего стал он разливать чай, как вдруг отворилась дверь его комнаты и предстал Ноздрев никак неожиданным образом.', '103.jpg', 37, '2025-09-20 06:37:02'),
(631, '— Вот говорит пословица: «Для друга семь верст не околица.', '— Вот говорит пословица: «Для друга семь верст не околица!» — говорил он, снимая картуз. — Прохожу мимо, вижу свет в окне, дай, думаю, зайду, верно, не спит.', ' А! вот хорошо, что у тебя на столе чай, выпью в удовольствием чашечку: сегодня за обедом объелся всякой дряни, чувствую, что уж начинается в желудке возня.', '101.jpg', 4, '2025-09-13 05:03:29'),
(632, '— Пустое, будто я не знаю, что ты куряка.', '— Пустое, будто я не знаю, что ты куряка.', ' Эй! как, бишь, зовут твоего человека.', '101.jpg', 24, '2025-09-11 01:44:22'),
(633, '— Да, точно, это у Деребина Вахрамей.', '— Да, точно, это у Деребина Вахрамей. Вообрази, Деребину какое счастье: тетка его поссорилась с сыном за то, что женился на крепостной, и теперь записала ему все именье.', ' Я думаю себе, вот если бы эдакую тетку иметь для дальнейших! Да что ты, брат, так отдалился от всех, нигде не бываешь? Конечно, я знаю, что ты занят иногда учеными предметами, любишь читать (уж почему Ноздрев заключил, что герой наш занимается учеными предметами и любит почитать, этого, признаемся, мы никак не можем сказать, а Чичиков и того менее). Ах, брат Чичиков, если бы ты только увидал… вот уж, точно, была бы пища твоему сатирическому уму (почему у Чичикова был сатирический ум, это тоже неизвестно). Вообрази, брат, у купца Лихачева играли в горку, вот уж где смех был! Перепендев, который был со мною: «Вот, говорит, если бы теперь Чичиков, уж вот бы ему точно!..» (между тем Чичиков отроду не знал никакого Перепендева). А ведь признайся, брат, ведь ты, право, преподло поступил тогда со мною, помнишь, как играли в шашки, ведь я выиграл… Да, брат, ты просто поддедюлил меня. Но ведь я, черт меня знает, никак не могу сердиться. Намедни с председателем… Ах, да! я ведь тебе должен сказать, что в городе все против тебя; они думают, что ты делаешь фальшивые бумажки, пристали ко мне, да я за тебя горой, наговорил им, что с тобой учился и отца знал; ну и, уж нечего говорить, слил им пулю порядочную.', '101.jpg', 32, '2025-09-07 19:27:51'),
(634, '— Зачем ты, однако ж, так напугал их? — продолжал Ноздрев.', '— Зачем ты, однако ж, так напугал их? — продолжал Ноздрев. — Они, черт знает, с ума сошли со страху: нарядили тебя в разбойники и в шпионы… А прокурор с испугу умер, завтра будет погребение.', ' Ты не будешь? Они, сказать правду, боятся нового генерал-губернатора, чтобы из-за тебя чего-нибудь не вышло; а я насчет генерал-губернатора такого мнения, что если он подымет нос и заважничает, то с дворянством решительно ничего не сделает. Дворянство требует радушия, не правда ли? Конечно, можно запрятаться к себе в кабинет и не дать ни одного бала, да ведь этим что ж? Ведь этим ничего не выиграешь. А ведь ты, однако ж, Чичиков, рискованное дело затеял.', '302.jpg', 49, '2025-08-31 18:23:57'),
(635, '— Да увезти губернаторскую дочку.', '— Да увезти губернаторскую дочку. Я, признаюсь, ждал этого, ей-богу, ждал! В первый раз, как только увидел вас вместе на бале, ну уж, думаю себе, Чичиков, верно, недаром… Впрочем, напрасно ты сделал такой выбор, я ничего в ней не наложу хорошего.', ' А есть одна, родственница Бикусова, сестры его дочь, так вот уж девушка! можно сказать: чудо коленкор.', '203.jpg', 11, '2025-08-26 13:51:35'),
(636, '— Да что ты, что ты путаешь? Как увезти губернаторскую дочку, что ты.', '— Да что ты, что ты путаешь? Как увезти губернаторскую дочку, что ты? — говорил Чичиков, выпуча глаза.', '.', '203.jpg', 24, '2025-08-21 10:55:49'),
(637, '— Ну, полно, брат, экой скрытный человек.', '— Ну, полно, брат, экой скрытный человек! Я, признаюсь, к тебе с тем пришел: изволь, я готов тебе помогать. Так и быть: подержу венец тебе, коляска и переменные лошади будут мои, только с уговором: ты должен мне дать три тысячи взаймы.', ' Нужны, брат, хоть зарежь.', '100.jpg', 16, '2025-08-13 10:17:32'),
(638, 'В продолжение всей болтовни Ноздрева Чичиков протирал несколько раз себе глаза.', 'В продолжение всей болтовни Ноздрева Чичиков протирал несколько раз себе глаза, желая увериться, не во сне ли он все это слышит.', ' Делатель фальшивых ассигнаций, увоз губернаторской дочки, смерть прокурора, которой причиною будто бы он, приезд генерал-губернатора — все это навело на него порядочный испуг. «Ну, уж коли пошло на то, — подумал он сам в себе, — так мешкать более нечего, нужно отсюда убираться поскорей».', '203.jpg', 9, '2025-08-04 08:34:35'),
(639, 'Он постарался сбыть поскорее Ноздрева.', 'Он постарался сбыть поскорее Ноздрева, призвал к себе тот же час Селифана и велел ему быть готовым на заре, с тем чтобы завтра же в шесть часов утра выехать из города непременно, чтобы все было пересмотрено, бричка подмазана и прочее, и прочее.', ' Селифан произнес: «Слушаю, Павел Иванович!» — и остановился, однако ж, несколько времени у дверей, не двигаясь с места. Барин тут же велел Петрушке выдвинуть из-под кровати чемодан, покрывшийся уже порядочно пылью, и принялся укладывать вместе с ним, без большого разбора, чулки, рубашки, белье мытое и немытое, сапожные колодки, календарь… Все это укладывалось как попало; он хотел непременно быть готовым с вечера, чтобы назавтра не могло случиться никакой задержки. Селифан, постоявши минуты две у дверей, наконец очень медленно вышел из комнаты. Медленно, как только можно вообразить себе медленно, спускался он с лестницы, отпечатывая своими мокрыми сапогами следы по сходившим вниз избитым ступеням, и долго почесывал у себя рукою в затылке. Что означало это почесыванье? и что вообще оно значит? Досада ли на то, что вот не удалась задуманная назавтра сходка с своим братом в неприглядном тулупе, опоясанном кушаком, где-нибудь во царевом кабаке, или уже завязалась в новом месте какая зазнобушка сердечная и приходится оставлять вечернее стоянье у ворот и политичное держанье за белы ручки в тот час, как нахлобучиваются на город сумерки, детина в красной рубахе бренчит на балалайке перед дворовой челядью и плетет тихие речи разночинный отработавшийся народ? Или просто жаль оставлять отогретое уже место на людской кухне под тулупом, близ печи, да щей с городским мягким пирогом, с тем чтобы вновь тащиться под дождь, и слякоть, и всякую дорожную невзгоду? Бог весть, не угадаешь. Многое разное значит у русского народа почесыванье в затылке.', '103.jpg', 10, '2025-07-26 04:25:25'),
(640, 'Ничто, однако же, не случилось так, как предполагал Чичиков.', 'Ничто, однако же, не случилось так, как предполагал Чичиков. Во-первых, проснулся он позже, нежели думал, — это была первая неприятность.', ' Вставши, он послал тот же час узнать, заложена ли бричка и все ли готово; но донесли, что бричка еще была не заложена и ничего не было готово. Это была вторая неприятность. Он рассердился, приготовился даже задать что-то вроде потасовки приятелю нашему Селифану и ожидал только с нетерпением, какую тот с своей стороны приведет причину в оправдание. Скоро Селифан показался в дверях, и барин имел удовольствие услышать те же самые речи, какие обыкновенно слышатся от прислуги в таком случае, когда нужно скоро ехать.', '102.jpg', 42, '2025-07-16 02:01:31'),
(641, '— Ах ты чушка! чурбан! а прежде зачем об этом не сказал? Не было разве времени.', '— Ах ты чушка! чурбан! а прежде зачем об этом не сказал? Не было разве времени.', '— Ах ты чушка! чурбан! а прежде зачем об этом не сказал? Не было разве времени.', '100.jpg', 55, '2025-07-13 19:43:48'),
(642, '— Да время-то было… Да вот и колесо тоже, Павел Иванович.', '— Да время-то было… Да вот и колесо тоже, Павел Иванович, шину нужно будет совсем перетянуть, потому что теперь дорога ухабиста, шибень такой везде пошел… Да если позволите доложить, перед у брички совсем расшатался, так что она, может быть.', '— Да время-то было… Да вот и колесо тоже, Павел Иванович, шину нужно будет совсем перетянуть, потому что теперь дорога ухабиста, шибень такой везде пошел… Да если позволите доложить: перед у брички совсем расшатался, так что она, может быть, и двух станций не сделает.', '302.jpg', 38, '2025-07-03 17:28:40'),
(643, '— Подлец ты.', '— Подлец ты! — вскрикнул Чичиков, всплеснув руками, и подошел к нему так близко, что Селифан из боязни, чтобы не получить от барина подарка, попятился несколько назад и посторонился.', ' — Убить ты меня собрался? а? зарезать меня хочешь? На большой дороге меня собрался зарезать, разбойник, чушка ты проклятый, страшилище морское! а? а? Три недели сидели на месте, а? Хоть бы заикнулся, беспутный, — а вот теперь к последнему часу и пригнал! когда уж почти начеку: сесть бы да и ехать, а? а ты вот тут-то и напакостил, а? а? Ведь ты знал это прежде? ведь ты знал это, а? а? Отвечай.', '203.jpg', 30, '2025-07-01 17:13:31'),
(644, 'На этот вопрос Селифан ничего не отвечал, но, потупивши голову, казалось.', 'На этот вопрос Селифан ничего не отвечал, но, потупивши голову, казалось, говорил сам себе: «Вишь ты, как оно мудрено случилось; и знал ведь, да не сказал.', 'На этот вопрос Селифан ничего не отвечал, но, потупивши голову, казалось, говорил сам себе: «Вишь ты, как оно мудрено случилось; и знал ведь, да не сказал.', '002.jpg', 37, '2025-06-29 16:56:42'),
(645, '— А вот теперь ступай приведи кузнеца, да чтоб в два часа все было сделано.', '— А вот теперь ступай приведи кузнеца, да чтоб в два часа все было сделано. Слышишь? непременно в два часа, а если не будет, так я тебя, я тебя… в рог согну и узлом завяжу! — Герой наш был сильно рассержен.', '.', '203.jpg', 48, '2025-06-28 12:28:33'),
(646, 'Селифан оборотился было к дверям, с тем чтоб идти выполнить приказание.', 'Селифан оборотился было к дверям, с тем чтоб идти выполнить приказание, но остановился и сказал.', 'Селифан оборотился было к дверям, с тем чтоб идти выполнить приказание, но остановился и сказал.', '203.jpg', 17, '2025-06-27 10:51:58'),
(647, '— Да еще, сударь, чубарого коня, право, хоть бы продать, потому что он.', '— Да еще, сударь, чубарого коня, право, хоть бы продать, потому что он, Павел Иванович, совсем подлец; он такой конь, просто не приведи бог, только помеха.', '.', '100.jpg', 47, '2025-06-23 08:01:03'),
(648, '— Ей-богу, Павел Иванович, он только что на вид казистый.', '— Ей-богу, Павел Иванович, он только что на вид казистый, а на деле самый лукавый конь; такого коня нигде..', '.', '203.jpg', 11, '2025-06-16 01:50:46'),
(649, '— Дурак! когда захочу продать, так продам.', '— Дурак! когда захочу продать, так продам.', ' Еще пустился в рассужденья! Вот посмотрю я: если ты мне не приведешь сейчас кузнецов да в два часа не будет все готово, так я тебе такую дам потасовку… сам на себе лица не увидишь! Пошел! ступай.', '302.jpg', 45, '2025-06-13 20:55:25'),
(650, 'Чичиков сделался совершенно не в духе и швырнул на пол саблю.', 'Чичиков сделался совершенно не в духе и швырнул на пол саблю, которая ездила с ним в дороге для внушения надлежащего страха кому следует.', ' Около четверти часа с лишком провозился он с кузнецами, покамест сладил, потому что кузнецы, как водится, были отъявленные подлецы и, смекнув, что работа нужна к спеху, заломили ровно вшестеро. Как он ни горячился, называл их мошенниками, разбойниками, грабителями проезжающих, намекнул даже на страшный суд, но кузнецов ничем не пронял: они совершенно выдержали характер — не только не отступились от цены, но даже провозились за работой вместо двух часов целых пять с половиною. В продолжение этого времени он имел удовольствие испытать приятные минуты, известные всякому путешественнику, когда в чемодане все уложено и в комнате валяются только веревочки, бумажки да разный сор, когда человек не принадлежит ни к дороге, ни к сиденью на месте, видит из окна проходящих плетущихся людей, толкующих об своих гривнах и с каким-то глупым любопытством поднимающих глаза, чтобы, взглянув на него, опять продолжать свою дорогу, что еще более растравляет нерасположение духа бедного неедущего путешественника. Все, что ни есть, все, что ни видит он: и лавчонка против его окон, и голова старухи, живущей в супротивном доме, подходящей к окну с коротенькими занавесками, — все ему гадко, однако же он не отходит от окна. Стоит, то позабываясь, то обращая вновь какое-то притупленное внимание на все, что перед ним движется и не движется, и душит с досады какую-нибудь муху, которая в это время жужжит и бьется об стекло под его пальцем. Но всему бывает конец, и желанная минута настала: все было готово, перед у брички как следует был налажен, колесо было обтянуто новою шиною, кони приведены с водопоя, и разбойники кузнецы отправились, пересчитав полученные целковые и пожелав благополучия.', '103.jpg', 13, '2025-06-11 15:16:42'),
(651, 'Бричка между тем поворотила в более пустынные улицы.', 'Бричка между тем поворотила в более пустынные улицы; скоро потянулись одни длинные деревянные заборы, предвещавшие конец города. Вот уже и мостовая кончилась, и шлагбаум, и город назади, и ничего нет, и опять в дороге.', ' И опять по обеим сторонам столбового пути пошли вновь писать версты, станционные смотрители, колодцы, обозы, серые деревни с самоварами, бабами и бойким бородатым хозяином, бегущим из постоялого двора с овсом в руке, пешеход в протертых лаптях, плетущийся за восемьсот верст, городишки, выстроенные живьем, с деревянными лавчонками, мучными бочками, лаптями, калачами и прочей мелюзгой, рябые шлагбаумы, чинимые мосты, поля неоглядные и по ту сторону и по другую, помещичьи рыдваны, солдат верхом на лошади, везущий зеленый ящик с свинцовым горохом и подписью: такой-то артиллерийской батареи, зеленые, желтые и свежеразрытые черные полосы, мелькающие по степям, затянутая вдали песня, сосновые верхушки в тумане, пропадающий далече колокольный звон, вороны как мухи и горизонт без конца… Русь! Русь! вижу тебя, из моего чудного, прекрасного далека тебя вижу: бедно, разбросанно и неприютно в тебе; не развеселят, не испугают взоров дерзкие дива природы, венчанные дерзкими дивами искусства, города с многооконными высокими дворцами, вросшими в утесы, картинные дерева и плющи, вросшие в домы, в шуме и в вечной пыли водопадов; не опрокинется назад голова посмотреть на громоздящиеся без конца над нею и в вышине каменные глыбы; не блеснут сквозь наброшенные одна на другую темные арки, опутанные виноградными сучьями, плющами и несметными миллионами диких роз, не блеснут сквозь них вдали вечные линии сияющих гор, несущихся в серебряные ясные небеса. Открыто-пустынно и ровно все в тебе; как точки, как значки, неприметно торчат среди равнин невысокие твои города; ничто не обольстит и не очарует взора.', '201.jpg', 19, '2025-06-05 09:17:24'),
(652, '— Вот я тебя палашом! — кричал скакавший навстречу фельдъегерь с усами в аршин.', '— Вот я тебя палашом! — кричал скакавший навстречу фельдъегерь с усами в аршин. — Не видишь, леший дери твою душу: казенный экипаж! — И, как призрак, исчезнула с громом и пылью тройка.', '.', '203.jpg', 28, '2025-06-03 04:36:25');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(653, 'Какое странное, и манящее, и несущее, и чудесное в слове: дорога.', 'Какое странное, и манящее, и несущее, и чудесное в слове: дорога! и как чудна она сама, эта дорога: ясный день, осенние листья, холодный воздух… покрепче в дорожную шинель, шапку на уши, тесней и уютней прижмемся к углу.', 'Какое странное, и манящее, и несущее, и чудесное в слове: дорога! и как чудна она сама, эта дорога: ясный день, осенние листья, холодный воздух… покрепче в дорожную шинель, шапку на уши, тесней и уютней прижмемся к углу! В последний раз пробежавшая дрожь прохватила члены, и уже сменила ее приятная теплота. Кони мчатся… как соблазнительно крадется дремота и смежаются очи, и уже сквозь сон слышатся и «Не белы снеги», и сап лошадей, и шум колес, и уже храпишь, прижавши к углу своего соседа. Проснулся: пять станций убежало назад; луна, неведомый город, церкви с старинными деревянными куполами и чернеющими остроконечьями, темные бревенчатые и белые каменные дома. Сияние месяца там и там: будто белые полотняные платки развешались по стенам, по мостовой, по улицам; косяками пересекают их черные, как уголь, тени; подобно сверкающему металлу блистают вкось озаренные деревянные крыши, и нигде ни души — все спит. Один-одинешенек, разве где-нибудь в окошке брезжит огонек: мещанин ли городской тачает свою пару сапогов, пекарь ли возится в печурке — что до них? А ночь! небесные силы! какая ночь совершается в вышине! А воздух, а небо, далекое, высокое, там, в недоступной глубине своей, так необъятно, звучно и ясно раскинувшееся!.. Но дышит свежо в самые очи холодное ночное дыхание и убаюкивает тебя, и вот уже дремлешь и забываешься, и храпишь, и ворочается сердито, почувствовав на себе тяжесть, бедный, притиснутый в углу сосед. Проснулся — и уже опять перед тобою поля и степи, нигде ничего — везде пустырь, все открыто. Верста с цифрой летит тебе в очи; занимается утро; на побелевшем холодном небосклоне золотая бледная полоса; свежее и жестче становится ветер: покрепче в теплую шинель!.. какой славный холод! какой чудный, вновь обнимающий тебя сон! Толчок — и опять проснулся. На вершине неба солнце.', '102.jpg', 4, '2025-05-28 02:49:45'),
(654, 'Очень сомнительно, чтобы избранный нами герой понравился читателям.', 'Очень сомнительно, чтобы избранный нами герой понравился читателям.', ' Дамам он не понравится, это можно сказать утвердительно, ибо дамы требуют, чтоб герой был решительное совершенство, и если какое-нибудь душевное или телесное пятнышко, тогда беда! Как глубоко ни загляни автор ему в душу, хоть отрази чище зеркала его образ, ему не дадут никакой цены. Самая полнота и средние лета Чичикова много повредят ему: полноты ни в каком случае не простят герою, и весьма многие дамы, отворотившись, скажут: «Фи, такой гадкий!» Увы! все это известно автору, и при всем том он не может взять в герои добродетельного человека, но… может быть, в сей же самой повести почуются иные, еще доселе не бранные струны, предстанет несметное богатство русского духа, пройдет муж, одаренный божескими доблестями, или чудная русская девица, какой не сыскать нигде в мире, со всей дивной красотой женской души, вся из великодушного стремления и самоотвержения. И мертвыми покажутся пред ними все добродетельные люди других племен, как мертва книга пред живым словом! Подымутся русские движения… и увидят, как глубоко заронилось в славянскую природу то, что скользнуло только по природе других народов… Но к чему и зачем говорить о том, что впереди? Неприлично автору, будучи давно уже мужем, воспитанному суровой внутренней жизнью и свежительной трезвостью уединения, забываться подобно юноше. Всему свой черед, и место, и время! А добродетельный человек все-таки не взят в герои. И можно даже сказать, почему не взят. Потому что пора наконец дать отдых бедному добродетельному человеку, потому что праздно вращается на устах слово «добродетельный человек»; потому что обратили в лошадь добродетельного человека, и нет писателя, который бы не ездил на нем, понукая и кнутом и всем чем ни попало; потому что изморили добродетельного человека до того, что теперь нет на нем и тени добродетели, а остались только ребра да кожа вместо тела; потому что лицемерно призывают добродетельного человека; потому что не уважают добродетельного человека. Нет, пора наконец припрячь и подлеца.', '201.jpg', 1, '2025-05-26 20:55:23'),
(655, 'Темно и скромно происхождение нашего героя.', 'Темно и скромно происхождение нашего героя.', ' Родители были дворяне, но столбовые или личные — бог ведает; лицом он на них не походил: по крайней мере родственница, бывшая при его рождении, низенькая, коротенькая женщина, которых обыкновенно называют пигалицами, взявши в руки ребенка, вскрикнула: «Совсем вышел не такой, как я думала! Ему бы следовало пойти в бабку с матерней стороны, что было бы и лучше, а он родился просто, как говорит пословица: ни в мать, ни в отца, а в проезжего молодца». Жизнь при начале взглянула на него как-то кисло-неприютно, сквозь какое-то мутное, занесенное снегом окошко: ни друга, ни товарища в детстве! Маленькая горенка с маленькими окнами, не отворявшимися ни в зиму, ни в лето, отец, больной человек, в длинном сюртуке на мерлушках и в вязаных хлопанцах, надетых на босую ногу, беспрестанно вздыхавший, ходя по комнате, и плевавший в стоявшую в углу песочницу, вечное сиденье на лавке, с пером в руках, чернилами на пальцах и даже на губах, вечная пропись перед глазами: «не лги, послушествуй старшим и носи добродетель в сердце»; вечный шарк и шлепанье по комнате хлопанцев, знакомый, но всегда суровый голос: «опять задурил!», отзывавшийся в то время, когда ребенок, наскуча однообразием труда, приделывал к букве какую-нибудь кавыку или хвост; и вечно знакомое, всегда неприятное чувство, когда вслед за сими словами краюшка уха его скручивалась очень больно ногтями длинных протянувшихся сзади пальцев: вот бедная картина первоначального его детства, о котором едва сохранил он бледную память. Но в жизни все меняется быстро и живо: и в один день, с первым весенним солнцем и разлившимися потоками, отец, взявши сына, выехал с ним на тележке, которую потащила мухортая пегая лошадка, известная у лошадиных барышников под именем соро&#769;ки; ею правил кучер, маленький горбунок, родоначальник единственной крепостной семьи, принадлежавшей отцу Чичикова, занимавший почти все должности в доме.', '302.jpg', 4, '2025-05-24 15:23:18'),
(656, 'Павлуша с другого же дни принялся ходить в классы.', 'Павлуша с другого же дни принялся ходить в классы. Особенных способностей к какой-нибудь науке в нем не оказалось; отличился он больше прилежанием и опрятностию; но зато оказался в нем большой ум с другой стороны, со стороны практической.', ' Он вдруг смекнул и понял дело и повел себя в отношении к товарищам точно таким образом, что они его угощали, а он их не только никогда, но даже иногда, припрятав полученное угощенье, потом продавал им же. Еще ребенком он умел уже отказать себе во всем. Из данной отцом полтины не издержал ни копейки, напротив — в тот же год уже сделал к ней приращения, показав оборотливость почти необыкновенную: слепил из воску снегиря, выкрасил его и продал очень выгодно. Потом в продолжение некоторого времени пустился на другие спекуляции, именно вот какие: накупивши на рынке съестного, садился в классе возле тех, которые были побогаче, и как только замечал, что товарища начинало тошнить, — признак подступающего голода, — он высовывал ему из-под скамьи будто невзначай угол пряника или булки и, раззадоривши его, брал деньги, соображаяся с аппетитом. Два месяца он провозился у себя на квартире без отдыха около мыши, которую засадил в маленькую деревянную клеточку, и добился наконец до того, что мышь становилась на задние лапки, ложилась и вставала по приказу, и продал потом ее тоже очень выгодно. Когда набралось денег до пяти рублей, он мешочек зашил и стал копить в другой. В отношении к начальству он повел себя еще умнее. Сидеть на лавке никто не умел так смирно. Надобно заметить, что учитель был большой любитель тишины и хорошего поведения и терпеть не мог умных и острых мальчиков; ему казалось, что они непременно должны над ним смеяться. Достаточно было тому, который попал на замечание со стороны остроумия, достаточно было ему только пошевелиться или как-нибудь ненароком мигнуть бровью, чтобы подпасть вдруг под гнев. Он его гнал и наказывал немилосердно. «Я, брат, из тебя выгоню заносчивость и непокорность! — говорил он. — Я тебя знаю насквозь, как ты сам себя не знаешь. Вот ты у меня постоишь на коленях! ты у меня поголодаешь!» И бедный мальчишка, сам не зная за что, натирал себе колени и голодал по суткам. «Способности и дарования? это все вздор, — говаривал он, — я смотрю только на поведенье.', '301.jpg', 59, '2025-05-22 14:34:33'),
(657, 'Нельзя, однако же, сказать.', 'Нельзя, однако же, сказать, чтобы природа героя нашего была так сурова и черства и чувства его были да того притуплены, чтобы он не знал ни жалости, ни сострадания, он чувствовал и то и другое, он бы даже хотел помочь, но только.', 'Нельзя, однако же, сказать, чтобы природа героя нашего была так сурова и черства и чувства его были да того притуплены, чтобы он не знал ни жалости, ни сострадания; он чувствовал и то и другое, он бы даже хотел помочь, но только, чтобы не заключалось это в значительной сумме, чтобы не трогать уже тех денег, которых положено было не трогать; словом, отцовское наставление: береги и копи копейку — пошло впрок. Но в нем не было привязанности собственно к деньгам для денег; им не владели скряжничество и скупость. Нет, не они двигали им: ему мерещилась впереди жизнь во всех довольствах, со всякими достатками; экипажи, дом, отлично устроенный, вкусные обеды — вот что беспрерывно носилось в голове его. Чтобы наконец потом, со временем, вкусить непременно все это, вот для чего береглась копейка, скупо отказываемая до времени и себе и другому. Когда проносился мимо его богач на пролетных красивых дрожках, на рысаках в богатой упряжи, он как вкопанный останавливался на месте и потом, очнувшись, как после долгого сна, говорил: «А ведь был конторщик, волосы носил в кружок!» И все, что ни отзывалось богатством и довольством, производило на него впечатление, непостижимое им самим. Вышед из училища, он не хотел даже отдохнуть: так сильно было у него желанье скорее приняться за дело и службу. Однако же, несмотря на похвальные аттестаты, с большим трудом определился он в казенную палату. И в дальних захолустьях нужна протекция! Местечко досталось ему ничтожное, жалованья тридцать или сорок рублей в год. Но решился он жарко заняться службою, все победить и преодолеть. И точно, самоотвержение, терпенье и ограничение нужд показал он неслыханное. С раннего утра до позднего вечера, не уставая ни душевными, ни телесными силами, писал он, погрязнув весь в канцелярские бумаги, не ходил домой, спал в канцелярских комнатах на столах, обедал подчас с сторожами и при всем том умел сохранить опрятность, порядочно одеться, сообщить лицу приятное выражение и даже что-то благородное в движениях.', '201.jpg', 45, '2025-05-17 12:20:47'),
(658, 'Это был самый трудный порог, через который перешагнул он.', 'Это был самый трудный порог, через который перешагнул он. С этих пор пошло легче и успешнее. Он стал человеком заметным. Все оказалось в нем, что нужно для этого мира: и приятность в оборотах и поступках, и бойкость в деловых делах.', ' С такими средствами добыл он в непродолжительное время то, что называют хлебное местечко, и воспользовался им отличным образом. Нужно знать, что в то же самое время начались строжайшие преследования всяких взяток; преследований он не испугался и обратил их тот же час в свою пользу, показав таким образом прямо русскую изобретательность, являющуюся только во время прижимок. Дело устроено было вот как: как только приходил проситель и засовывал руку в карман, с тем чтобы вытащить оттуда известные рекомендательные письма за подписью князя Хованского, как выражаются у нас на Руси: «Нет, нет, — говорил он с улыбкой, удерживая его руки, — вы думаете, что я… нет, нет. Это наш долг, наша обязанность без всяких возмездий мы должны сделать! С этой стороны уж будьте покойны: завтра же все будет сделано. Позвольте узнать вашу квартиру, вам и заботиться не нужно самим, все будет принесено к вам на дом». Очарованный проситель возвращался домой чуть не в восторге, думая: «Вот наконец человек, каких нужно побольше, это просто драгоценный алмаз!» Но ждет проситель день, другой, не приносят дела на дом, на третий тоже. Он в канцелярию, дело и не начиналось; он к драгоценному алмазу. «Ах, извините! — говорил Чичиков очень учтиво, схвативши его за обе руки, — у нас было столько дел; но завтра же все будет сделано завтра непременно, право, мне даже совестно!» И все это сопровождалось движениями обворожительными. Если при этом распахивалась как-нибудь пола халата, то рука в ту же минуту старалась дело поправить и придержать полу. Но ни завтра, ни послезавтра, ни на третий день не несут дела на дом. Проситель берется за ум: да полно, нет ли чего? Выведывает; говорят, нужно дать писарям. «Почему ж не дать? я готов четвертак, другой». — «Нет, не четвертак, а по беленькой». — «По беленькой писарям!» — вскрикивает проситель. «Да чего вы так горячитесь? — отвечают ему, — оно так и выйдет, писарям и достанется по четвертаку, а остальное пойдет к начальству».', '302.jpg', 19, '2025-05-12 10:08:34'),
(659, 'Но вдруг на место прежнего тюфяка был прислан новый начальник, человек военный.', 'Но вдруг на место прежнего тюфяка был прислан новый начальник, человек военный, строгий, враг взяточников и всего, что зовется неправдой.', ' На другой же день пугнул он всех до одного, потребовал отчеты, увидел недочеты, на каждом шагу недостающие суммы, заметил в ту же минуту дома красивой гражданской архитектуры, и пошла переборка. Чиновники были отставлены от должности; дома гражданской архитектуры поступили в казну и обращены были на разные богоугодные заведения и школы для кантонистов, все распушено было в пух, и Чичиков более других. Лицо его вдруг, несмотря на приятность, не понравилось начальнику, почему именно, бог ведает, — иногда даже просто не бывает на это причин, — и он возненавидел его насмерть. И грозен был сильно для всех неумолимый начальник. Но так как все же он был человек военный, стало быть, не знал всех тонкостей гражданских проделок, то чрез несколько времени, посредством правдивой наружности и уменья подделаться во всему, втерлись к нему в милость другие чиновники, и генерал скоро очутился в руках еще больших мошенников, которых он вовсе не почитал такими; даже был доволен, что выбрал наконец людей как следует, и хвастался не в шутку тонким уменьем различать способности. Чиновники вдруг постигнули дух его и характер. Все, что ни было под начальством его, сделалось страшными гонителями неправды; везде, во всех делах они преследовали ее, как рыбак острогой преследует какую-нибудь мясистую белугу, и преследовали ее с таким успехом, что в скором времени у каждого очутилось по нескольку тысяч капиталу. В это время обратились на путь истины многие из прежних чиновников и были вновь приняты на службу. Но Чичиков уж никаким образом не мог втереться, как ни старался и как стоял за него подстрекнутый письмами князя Хованского первый генеральский секретарь, постигнувший совершенно управленье генеральским носом, но тут он ничего решительно не мог сделать. Генерал был такого рода человек, которого хотя и водили за нос (впрочем, без его ведома), но зато уже, если в голову ему западала какая-нибудь мысль, то она там была все равно что железный гвоздь: ничем нельзя было ее оттуда вытеребить.', '302.jpg', 26, '2025-05-03 06:55:50'),
(660, '«Ну, что ж! — сказал Чичиков, — зацепил — поволок, сорвалось — не спрашивай.', '«Ну, что ж! — сказал Чичиков, — зацепил — поволок, сорвалось — не спрашивай. Плачем горю не пособить, нужно дело делать».', ' И вот решился он сызнова начать карьер, вновь вооружиться терпением, вновь ограничиться во всем, как ни привольно и ни хорошо было развернулся прежде. Нужно было переехать в другой город, там еще приводить себя в известность. Все как-то не клеилось. Две, три должности должен он был переменить в самое короткое время. Должности как-то были грязны, низменны. Нужно знать, что Чичиков был самый благопристойный человек какой когда-либо существовал в свете. Хотя он и должен был вначале протираться в грязном обществе, но в душе всегда сохранял чистоту, любил, чтобы в канцеляриях были столы из лакированного дерева и все бы было благородно. Никогда не позволял он себе в речи неблагопристойного слова и оскорблялся всегда, если в словах других видел отсутствие должного уважения к чину или званию. Читателю, я думаю, приятно будет узнать, что он всякие два дни переменял на себе белье, а летом во время жаров даже и всякий день: всякий сколько-нибудь неприятный запах уже оскорблял его. По этой причине он всякий раз, когда Петрушка приходил раздевать его и скидавать сапоги, клал себе в нос гвоздичку, и во многих случаях нервы у него были щекотливые, как у девушки; и потому тяжело ему было очутиться вновь в тех рядах, где все отзывалось пенником и неприличьем в поступках. Как ни крепился он духом, однако же похудел и даже позеленел во время таких невзгод. Уже начинал было он полнеть и приходить в те круглые и приличные формы, в каких читатель застал его при заключении с ним знакомства, и уже не раз, поглядывая в зеркало, подумывал он о многом приятном: о бабенке, о детской, и улыбка следовала за такими мыслями; но теперь, когда он взглянул на себя как-то ненароком в зеркало, не мог не вскрикнуть: «Мать ты моя пресвятая! какой же я стал гадкий!» И после долго не хотел смотреться. Но переносил все герой наш, переносил сильно, терпеливо переносил, и — перешел наконец в службу по таможне. Надобно сказать, что эта служба давно составляла тайный предмет его помышлений.', '203.jpg', 29, '2025-04-23 05:54:49'),
(661, 'Получив же в свое распоряжение все, в ту же минуту дал знать обществу, сказавши.', 'Получив же в свое распоряжение все, в ту же минуту дал знать обществу, сказавши: «Теперь пора». Расчет был слишком верен. Тут в один год он мог получить то, чего не выиграл бы в двадцать лет самой ревностной службы.', ' Прежде он не хотел вступать ни в какие сношения с ними, потому что был не более как простой пешкой, стало быть, немного получил бы; но теперь… теперь совсем другое дело: он мог предложить какие угодно условия. Чтобы дело шло беспрепятственней, он склонил и другого чиновника, своего товарища, который не устоял против соблазна, несмотря на то что волосом был сед. Условия были заключены, и общество приступило к действиям. Действия начались блистательно: читатель, без сомнения, слышал так часто повторяемую историю об остроумном путешествии испанских баранов, которые, совершив переход через границу в двойных тулупчиках, пронесли под тулупчиками на миллион брабантских кружев. Это происшествие случилось именно тогда, когда Чичиков служил при таможне. Не участвуй он сам в этом предприятии, никаким жидам в мире не удалось бы привести в исполнение подобного дела. После трех или четырех бараньих походов через границу у обоих чиновников очутилось по четыреста тысяч капиталу. У Чичикова, говорят, даже перевалило и за пятьсот, потому что был побойчее. Бог знает до какой бы громадной цифры не возросли благодатные суммы, если бы какой-то нелегкий зверь не перебежал поперек всему. Черт сбил с толку обоих чиновников; чиновники, говоря попросту, перебесились и поссорились ни за что. Как-то в жарком разговоре, а может быть, несколько и выпивши, Чичиков назвал другого чиновника поповичем, а тот, хотя действительно был попович, неизвестно почему обиделся жестоко и ответил ему тут же сильно и необыкновенно резко, именно вот как: «Нет, врешь, я статский советник, а не попович, а вот ты так попович!» И потом еще прибавил ему в пику для большей досады: «Да вот, мол, что!» Хотя он отбрил таким образом его кругом, обратив на него им же приданное название, и хотя выражение «вот, мол, что!» могло быть сильно, но, недовольный сим, он послал еще на него тайный донос.', '302.jpg', 49, '2025-04-13 02:32:00'),
(662, 'Уже известно, что Чичиков сильно заботился о своих потомках.', 'Уже известно, что Чичиков сильно заботился о своих потомках.', ' Такой чувствительный предмет! Иной, может быть, и не так бы глубоко запустил руку, если бы не вопрос, который, неизвестно почему, приходит сам собою: а что скажут дети? И вот будущий родоначальник, как осторожный кот, покося только одним глазом вбок, не глядит ли откуда хозяин, хватает поспешно все, что к нему поближе: мыло ли стоит, свечи ли, сало, канарейка ли попалась под лапу — словом, не пропускает ничего. Так жаловался и плакал герой наш, а между тем деятельность никак не умирала в голове его; там все хотело что-то строиться и ждало только плана. Вновь съежился он, вновь принялся вести трудную жизнь, вновь ограничил себя во всем, вновь из чистоты и приличного положения опустился в грязь и низменную жизнь. И в ожидании лучшего принужден был даже заняться званием поверенного, званием, еще не приобретшим у нас гражданства, толкаемым со всех сторон, плоха уважаемым мелкою приказною тварью и даже самими доверителями, осужденным на пресмыканье в передних, грубости и прочее, но нужда заставила решиться на все. Из поручений досталось ему, между прочим, одно: похлопотать о заложении в опекунский совет нескольких сот крестьян. Имение было расстроено в последней степени. Расстроено оно было скотскими падежами, плутами приказчиками, неурожаями, повальными болезнями, истребившими лучших работников, и, наконец, бестолковьем самого помещика, убиравшего себе в Москве дом в последнем вкусе и убившего на эту уборку все состояние свое до последней копейки, так что уж не на что было есть. По этой-то причине понадобилось наконец заложить последнее оставшееся имение. Заклад в казну был тогда еще дело новое, на которое решались не без страха.', '301.jpg', 20, '2025-04-11 00:31:18'),
(663, '— Ну, так чего же вы оробели.', '— Ну, так чего же вы оробели? — сказал секретарь, — один умер, другой родится, а все в дело годится.', '.', '302.jpg', 46, '2025-04-01 21:04:52'),
(664, 'Секретарь, как видно, умел говорить и в рифму.', 'Секретарь, как видно, умел говорить и в рифму. А между тем героя нашего осенила вдохновеннейшая мысль, какая когда-либо приходила в человеческую голову.', ' «Эх я Аким-простота, — сказал он сам в себе, — ищу рукавиц, а обе за поясом! Да накупи я всех этих, которые вымерли, пока еще не подавали новых ревизских сказок, приобрети их, положим, тысячу, да, положим, опекунский совет даст по двести рублей на душу: вот уж двести тысяч капиталу! А теперь же время удобное, недавно была эпидемия, народу вымерло, слава богу, немало. Помещики попроигрывались в карты, закутили и промотались как следует; все полезло в Петербург служить; имения брошены, управляются как ни попало, подати уплачиваются с каждым годом труднее, так мне с робостью уступит их каждый уже потому только, чтобы не платить за них подушных денег; может, в другой раз так случится, что с иного и я еще зашибу за это копейку. Конечно, трудно, хлопотливо, страшно, чтобы как-нибудь еще не досталось, чтобы не вывести из этого истории. Ну да ведь дан же человеку на что-нибудь ум. А главное то хорошо, что предмет то покажется всем невероятным, никто не поверит. Правда, без земли нельзя ни купить, ни заложить. Да ведь я куплю на вывод, на вывод; теперь земли в Таврической и Херсонской губерниях отдаются даром, только заселяй. Туда я их всех и переселю! в Херсонскую их! пусть их там живут! А переселение можно сделать законным образом, как следует по судам. Если захотят освидетельствовать крестьян: пожалуй, я и тут не прочь, почему же нет? я представлю и свидетельство за собственноручным подписанием капитана-исправника. Деревню можно назвать Чичикова слободка или по имени, данному при крещении: сельцо Павловское». И вот таким образом составился в голове нашего героя сей странный сюжет, за который, не знаю, будут ли благодарны ему читатели, а уж как благодарен автор, так и выразить трудно. Ибо, что ни говори, не приди в голову Чичикову эта мысль, не явилась бы на свет сия поэма.', '102.jpg', 20, '2025-03-28 19:26:48'),
(665, 'Перекрестясь по русскому обычаю, приступил он к исполнению.', 'Перекрестясь по русскому обычаю, приступил он к исполнению.', ' Под видом избрания места для жительства и под другими предлогами предпринял он заглянуть в те и другие углы нашего государства, и преимущественно в те, которые более других пострадали от несчастных случаев, неурожаев, смертностей и прочего и прочего, — словом, где бы можно удобнее и дешевле накупить потребного народа. Он не обращался наобум ко всякому помещику, но избирал людей более по своему вкусу или таких, с которыми бы можно было с меньшими затруднениями делать подобные сделки, стараясь прежде познакомиться, расположить к себе, чтобы, если можно, более дружбою, а не покупкою приобрести мужиков. Итак, читатели не должны негодовать на автора, если лица, доныне являвшиеся, не пришлись по его вкусу; это вина Чичикова, здесь он полный хозяин, и куда ему вздумается, туда и мы должны тащиться. С нашей стороны, если, точно, падет обвинение за бледность и невзрачность лиц и характеров, скажем только то, что никогда вначале не видно всего широкого теченья и объема дела. Въезд в какой бы ни было город, хоть даже в столицу, всегда как-то бледен; сначала все серо и однообразно: тянутся бесконечные заводы да фабрики, закопченные дымом, а потом уже выглянут углы шестиэтажных домов, магазины, вывески, громадные перспективы улиц, все в колокольнях, колоннах, статуях, башнях, с городским блеском, шумом и громом и всем, что на диво произвела рука и мысль человека. Как произвелись первые покупки, читатель уже видел; как пойдет дело далее, какие будут удачи и неудачи герою, как придется разрешить и преодолеть ему более трудные препятствия, как предстанут колоссальные образы, как двигнутся сокровенные рычаги широкой повести, раздастся далече ее горизонт и вся она примет величавое лирическое течение, то увидит потом. Еще много пути предстоит совершить всему походному экипажу, состоящему из господина средних лет, брички, в которой ездят холостяки, лакея Петрушки, кучера Селифана и тройки коней, уже известных поименно от Заседателя до подлеца чубарого.', '002.jpg', 16, '2025-03-27 19:25:35'),
(666, 'Но не то тяжело, что будут недовольны героем, тяжело то.', 'Но не то тяжело, что будут недовольны героем, тяжело то, что живет в душе неотразимая уверенность, что тем же самым героем, тем же самым Чичиковым были бы довольны читатели.', ' Не загляни автор поглубже ему в душу, не шевельни на дне ее того, что ускользает и прячется от света, не обнаружь сокровеннейших мыслей, которых никому другому не вверяет человек, а покажи его таким, каким он показался всему городу, Манилову и другим людям, и все были бы радешеньки и приняли бы его за интересного человека. Нет нужды, что ни лицо, ни весь образ его не метался бы как живой пред глазами; зато по окончании чтения душа не встревожена ничем, и можно обратиться вновь к карточному столу, тешащему всю Россию. Да, мои добрые читатели, вам бы не хотелось видеть обнаруженную человеческую бедность. Зачем, говорите вы, к чему это? Разве мы не знаем сами, что есть много презренного и глупого в жизни? И без того случается нам часто видеть то, что вовсе не утешительно. Лучше же представляйте нам прекрасное, увлекательное. Пусть лучше позабудемся мы! «Зачем ты, брат, говоришь мне, что дела в хозяйстве идут скверно? — говорит помещик приказчику. — Я, брат, это знаю без тебя, да у тебя речей разве нет других, что ли? Ты дай мне позабыть это, не знать этого, я тогда счастлив». И вот те деньги, которые бы поправили сколько-нибудь дело, идут на разные средства для приведения себя в забвенье. Спит ум, может быть обретший бы внезапный родник великих средств; а там имение бух с аукциона, и пошел помещик забываться по миру с душою, от крайности готовою на низости, которых бы сам ужаснулся прежде.', '103.jpg', 16, '2025-03-24 15:22:10'),
(667, 'Еще падет обвинение на автора со стороны так называемых патриотов.', 'Еще падет обвинение на автора со стороны так называемых патриотов, которые спокойно сидят себе по углам и занимаются совершенно посторонними делами, накопляют себе капитальцы, устроивая судьбу свою на счет других, но как только случится что-нибудь.', 'Еще падет обвинение на автора со стороны так называемых патриотов, которые спокойно сидят себе по углам и занимаются совершенно посторонними делами, накопляют себе капитальцы, устроивая судьбу свою на счет других; но как только случится что-нибудь, по мненью их, оскорбительное для отечества, появится какая-нибудь книга, в которой скажется иногда горькая правда, они выбегут со всех углов, как пауки, увидевшие, что запуталась в паутину муха, и подымут вдруг клики: «Да хорошо ли выводить это на свет, провозглашать об этом? Ведь это все, что ни описано здесь, это все наше — хорошо ли это? А что скажут иностранцы? Разве весело слышать дурное мнение о себе. Думают, разве это не больно? Думают, разве мы не патриоты?» Да такие мудрые замечания, особенно насчет мнения иностранцев, признаюсь, ничего нельзя прибрать в ответ. А разве вот что: жили в одном отдаленном уголке России два обитателя. Один был отец семейства, по имени Кифа Мокиевич, человек нрава кроткого, проводивший жизнь халатным образом. Семейством своим он не занимался; существованье его было обращено более в умозрительную сторону и занято следующим. как он называл, философическим вопросом: «Вот, например, зверь, — говорил он, ходя по комнате, — зверь родится нагишом. Почему же именно нагишом? Почему не так, как птица, почему не вылупливается из яйца? Как, право, того: совсем не поймешь натуры, как побольше в нее углубишься!» Так мыслил обитатель Кифа Мокиевич. Но не в этом еще главное дело. Другой обитатель был Мокий Кифович, родной сын его. Был он то, что называют на Руси богатырь, и в то время, когда отец занимался рожденьем зверя, двадцатилетняя плечистая натура его так и порывалась развернуться. Ни за что не умел он взяться слегка: все или рука у кого-нибудь затрещит, или волдырь вскочит на чьем-нибудь носу. В доме и в соседстве все, от дворовой девки до дворовой собаки, бежало прочь, его завидя; даже собственную кровать в спальне изломал он в куски. Таков был Мокий Кифович, а впрочем, был он доброй души. Но не в этом еще главное дело.', '301.jpg', 7, '2025-03-19 13:58:17'),
(668, 'Но мы стали говорить довольно громко, позабыв, что герой наш.', 'Но мы стали говорить довольно громко, позабыв, что герой наш, спавший во все время рассказа его повести, уже проснулся и легко может услышать так часто повторяемую свою фамилию.', ' Он же человек обидчивый и недоволен, если о нем изъясняются неуважительно. Читателю сполагоря, рассердится ли на него Чичиков, или нет, но что до автора, то он ни в коком случае не должен ссориться с своим героем: еще не мало пути и дороги придется им пройти вдвоем рука в руку; две большие части впереди — это не безделица.', '100.jpg', 48, '2025-03-18 10:52:25'),
(669, 'И в самом деле, Селифан давно уже ехал зажмуря глаза.', 'И в самом деле, Селифан давно уже ехал зажмуря глаза, изредка только потряхивая впросонках вожжами по бокам дремавших тоже лошадей, а с Петрушки уже давно невесть в каком месте слетел картуз, и он сам, опрокинувшись назад.', 'И в самом деле, Селифан давно уже ехал зажмуря глаза, изредка только потряхивая впросонках вожжами по бокам дремавших тоже лошадей; а с Петрушки уже давно невесть в каком месте слетел картуз, и он сам, опрокинувшись назад, уткнул свою голову в колено Чичикову, так что тот должен был дать ей щелчка. Селифан приободрился и, отшлепавши несколько раз по спине чубарого, после чего тот пустился рысцой, да помахнувши сверху кнутом на всех, примолвил тонким певучим голоском: «Не бойся!» Лошадки расшевелились и понесли, как пух, легонькую бричку. Селифан только помахивал да покрикивал: «Эх! эх! эх!» — плавно подскакивая на козлах, по мере того как тройка то взлетала на пригорок, то неслась духом с пригорка, которыми была усеяна вся столбовая дорога, стремившаяся чуть заметным накатом вниз. Чичиков только улыбался, слегка подлетывая на своей кожаной подушке, ибо любил быструю езду. И какой же русский не любит быстрой езды? Его ли душе, стремящейся закружиться, загуляться, сказать иногда: «черт побери все!» — его ли душе не любить ее? Ее ли не любить, когда в ней слышится что-то восторженно-чудное? Кажись, неведомая сила подхватила тебя на крыло к себе, и сам летишь, и все летит: летят версты, летят навстречу купцы на облучках своих кибиток, летит с обеих сторон лес с темными строями елей и сосен, с топорным стуком и вороньим криком, летит вся дорога невесть куда в пропадающую даль, и что-то страшное заключено в сем быстром мельканье, где не успевает означиться пропадающий предмет, — только небо над головою, да легкие тучи, да продирающийся месяц одни кажутся недвижны. Эх, тройка! птица тройка, кто тебя выдумал? знать, у бойкого народа ты могла только родиться, в той земле, что не любит шутить, а ровнем-гладнем разметнулась на полсвета, да и ступай считать версты, пока не зарябит тебе в очи. И не хитрый, кажись, дорожный снаряд, не железным схвачен винтом, а наскоро живьем с одним топором да молотом снарядил и собрал тебя ярославский расторопный мужик.', '201.jpg', 29, '2025-03-09 08:10:26'),
(670, 'Не так ли и ты, Русь, что бойкая необгонимая тройка несешься.', 'Не так ли и ты, Русь, что бойкая необгонимая тройка несешься? Дымом дымится под тобою дорога, гремят мосты, все отстает и остается позади.', ' Остановился пораженный божьим чудом созерцатель: не молния ли это, сброшенная с неба? что значит это наводящее ужас движение? и что за неведомая сила заключена в сих неведомых светом конях? Эх, кони, кони, что за кони! Вихри ли сидят в ваших гривах? Чуткое ли ухо горит во всякой вашей жилке? Заслышали с вышины знакомую песню, дружно и разом напрягли медные груди и, почти не тронув копытами земли, превратились в одни вытянутые линии, летящие по воздуху, и мчится вся вдохновенная богом!.. Русь, куда ж несешься ты? дай ответ. Не дает ответа. Чудным звоном заливается колокольчик; гремит и становится ветром разорванный в куски воздух; летит мимо все, что ни есть на земли, и, косясь, постораниваются и дают ей дорогу другие народы и государства.', '101.jpg', 38, '2025-03-06 06:06:00'),
(671, 'Зачем же выставлять напоказ бедность нашей жизни и наше грустное несовершенство.', 'Зачем же выставлять напоказ бедность нашей жизни и наше грустное несовершенство, выкапывая людей из глуши, из отдаленных закоулков государства.', 'Зачем же выставлять напоказ бедность нашей жизни и наше грустное несовершенство, выкапывая людей из глуши, из отдаленных закоулков государства? Что ж делать, если такого свойства сочинитель, и так уже заболел он сам собственным несовершенством, и так уже устроен талант его, чтобы изображать ему бедность нашей жизни, выкапывая людей из глуши, из отдаленных закоулков государства! И вот опять попали мы в глушь, опять наткнулись на закоулок.', '302.jpg', 17, '2025-02-27 05:27:35'),
(672, 'На тысячу с лишком верст неслись, извиваясь, горные возвышения.', 'На тысячу с лишком верст неслись, извиваясь, горные возвышения.', ' Точно как бы исполинский вал какой-то бесконечной крепости, возвышались они над равнинами то желтоватым отломом, в виде стены, с промоинами и рытвинами, то зеленой кругловидной выпуклиной, покрытой, как мерлушками, молодым кустарником, подымавшимся от срубленных дерев, то наконец темным лесом, еще уцелевшим от топора. Река то, верная своим высоким берегам, давала вместе с ними углы и колена по всему пространству, то иногда уходила от них прочь, в луга, затем, чтобы, извившись там в несколько извивов, блеснуть, как огонь, перед солнцем, скрыться в рощи берез, осин и ольх и выбежать оттуда в торжестве, в сопро-вожденье мостов, мельниц и плотин, как бы гонявшихся за нею на всяком повороте.', '102.jpg', 44, '2025-02-19 00:48:53'),
(673, 'В одном месте крутой бок возвышений воздымался выше прочих и весь от низу до.', 'В одном месте крутой бок возвышений воздымался выше прочих и весь от низу до верху убирался в зелень столпившихся густо дерев.', ' Тут было все вместе: и клен, и груша, и низкорослый ракитник, и чилига, и березка, и ель, и рябина, опутанная хмелем; тут… мелькали красные крыши господских строении, коньки и гребни сзади скрывшихся изб и верхняя надстройка господского дома, а над всей этой кучей дерев и крыш старинная церковь возносила свои пять играющих верхушек. На всех их были золотые прорезные кресты, золотыми прорезными цепями прикрепленные к куполам, так что издали сверкало, как бы на воздухе, ни к чему не прикрепленное, висевшее золото. И вся эта куча дерев, крыш, вместе с церковью, опрокинувшись верхушками вниз, отдавалась в реке, где картинно-безобразные старые ивы, одни стоя у берегов, другие совсем в воде, опустивши туда и ветви и листья, точно как бы рассматривали это изображение, которым не могли налюбоваться во все продолженье своей многолетней жизни.', '302.jpg', 25, '2025-02-12 19:09:24'),
(674, 'Вид был очень недурен, но вид сверху вниз.', 'Вид был очень недурен, но вид сверху вниз, с надстройки дома на равнины и отдаленья, был еще лучше. Равнодушно не мог выстоять на балконе никакой гость и посетитель.', ' У него захватывало в груди, и он мог только произнесть: «Господи, как здесь просторно!» Пространства открывались без конца. За лугами, усеянными рощами и водяными мельницами, зеленели и синели густые леса, как моря или туман, далеко разливавшийся. За лесами, сквозь мглистый воздух, желтели пески. За песками лежали гребнем на отдаленном небосклоне меловые горы, блиставшие ослепительной белизной даже и в ненастное время, как бы освещало их вечное солнце. Кое-где дымились по ним легкие туманно-сизые пятна. Это были отдаленные деревни, но их уже не мог рассмотреть человеческий глаз. Только вспыхивавшая, подобно искре, золотая церковная маковка давала знать, что это было людное, большое селенье. Все это облечено было в тишину невозмущаемую, которую не пробуждали даже чуть долетавшие до слуха отголоски воздушных певцов, наполнявших воздух.', '002.jpg', 10, '2025-02-11 17:44:20'),
(675, 'Кто ж был жилец этой деревни, к которой, как к неприступной крепости.', 'Кто ж был жилец этой деревни, к которой, как к неприступной крепости, нельзя было и подъехать отсюда, а нужно было подъезжать с другой стороны — полями, хлебами и, наконец, редкой дубровой, раскинутой картинно по зелени.', 'Кто ж был жилец этой деревни, к которой, как к неприступной крепости, нельзя было и подъехать отсюда, а нужно было подъезжать с другой стороны — полями, хлебами и, наконец, редкой дубровой, раскинутой картинно по зелени, вплоть до самых изб и господского дома.', '201.jpg', 27, '2025-02-03 14:59:44'),
(676, 'Кто был жилец, господин и владетель этой деревни.', 'Кто был жилец, господин и владетель этой деревни? Какому счастливцу принадлежал этот закоулок.', 'Кто был жилец, господин и владетель этой деревни? Какому счастливцу принадлежал этот закоулок.', '002.jpg', 18, '2025-01-27 10:11:31'),
(677, 'А помещику Тремалаханского уезда Андрею Ивановичу Тентетникову.', 'А помещику Тремалаханского уезда Андрею Ивановичу Тентетникову, молодому тридцатитрехлетнему господину, коллежскому секретарю, неженатому человеку.', '.', '100.jpg', 23, '2025-01-17 04:21:39'),
(678, 'Что же за человек такой, какого нрава.', 'Что же за человек такой, какого нрава, каких свойств и какого характера был помещик Андрей Иванович Тентетников.', 'Что же за человек такой, какого нрава, каких свойств и какого характера был помещик Андрей Иванович Тентетников.', '102.jpg', 23, '2025-01-10 22:40:18'),
(679, 'Разумеется, следует расспросить у соседей.', 'Разумеется, следует расспросить у соседей.', ' Сосед, принадлежавший к фамилии отставных штаб-офицеров, брандеров, выражался о нем лаконическим выраженьем: «Естественнейший скотина!» Генерал, проживавший в десяти верстах, говорил: «Молодой человек, неглупый, но много забрал себе в голову. Я бы мог быть ему полезным, потому что у меня и в Петербурге, и даже при…» Генерал речи не оканчивал. Капитан-исправник замечал: «Да ведь чинишка на нем — дрянь; а вот я завтра же к нему за недоимкой!» Мужик его деревни, на вопрос о том, какой у них барин, ничего не отвечал. Словом, общественное мненье о нем было скорее неблагоприятное, чем благоприятное.', '301.jpg', 4, '2025-01-05 20:32:49'),
(680, 'А между тем в существе своем Андрей Иванович был не то доброе.', 'А между тем в существе своем Андрей Иванович был не то доброе, не то дурное существо, а просто — коптитель неба.', ' Так как уже немало есть на белом свете людей, коптящих небо, то почему же и Тентетникову не коптить его? Впрочем, вот в немногих словах весь журнал его дня, и пусть из него судит читатель сам, какой у него был характер.', '202.jpg', 58, '2024-12-26 18:37:04'),
(681, 'Поутру просыпался он очень поздно и, приподнявшись.', 'Поутру просыпался он очень поздно и, приподнявшись, долго еще сидел на своей кровати, протирая глаза. Глаза же, как на беду, были маленькие, и потому протиранье их производилось необыкновенно долго.', ' Во все это время стоял у дверей человек Михайло с рукомойником и полотенцем. Стоял этот бедный Михайло час, другой, отправлялся потом на кухню, потом вновь приходил, — барин все еще протирал глаза и сидел па кровати. Наконец подымался он с постели, умывался, надевал халат и выходил в гостиную затем, чтобы пить чай, кофий, какао и даже парное молоко, всего прихлебывая понемногу, накрошивая хлеба безжалостно и насоривая повсюду трубочной золы бессовестно. Два часа просиживал он за чаем; этого мало: он брал еще холодную чашку и с ней подвигался к окну, обращенному на двор. У окна же происходила всякий раз следующая сцена.', '202.jpg', 33, '2024-12-16 15:55:04'),
(682, 'Прежде всего ревел небритый буфетчик Григорий, относившийся к Перфильевне.', 'Прежде всего ревел небритый буфетчик Григорий, относившийся к Перфильевне, ключнице, в сих выражениях.', 'Прежде всего ревел небритый буфетчик Григорий, относившийся к Перфильевне, ключнице, в сих выражениях.', '002.jpg', 21, '2024-12-11 12:34:05'),
(683, '— Душонка ты мелкопоместная, ничтожность этакая.', '— Душонка ты мелкопоместная, ничтожность этакая! Тебе бы, гнусной бабе, молчать, да и только.', '.', '203.jpg', 8, '2024-12-03 09:28:20'),
(684, '— Уж тебя-то не послушаюсь, ненасытное горло.', '— Уж тебя-то не послушаюсь, ненасытное горло! — выкрикивала ничтожность, или Перфильевна.', '.', '100.jpg', 56, '2024-11-25 06:58:29'),
(685, '— Да ведь с тобой никто не уживется, ведь ты и с приказчиком сцепишься.', '— Да ведь с тобой никто не уживется, ведь ты и с приказчиком сцепишься, мелочь ты анбарная! — ревел Григорий.', '.', '201.jpg', 19, '2024-11-15 05:35:37'),
(686, '— Да и приказчик — вор такой же, как и ты.', '— Да и приказчик — вор такой же, как и ты! — выкрикивала ничтожность так, что было на деревне слышно. — Вы оба пиющие, губители господского, бездонные бочки! Ты думаешь, барин не знает вас? Ведь он здесь, ведь он вас слышит.', '.', '201.jpg', 8, '2024-11-13 05:15:35'),
(687, 'К довершению этого, кричал кричмя дворовый ребятишка.', 'К довершению этого, кричал кричмя дворовый ребятишка, получивший от матери затрещину; визжал борзой кобель, присев задом к земле, по поводу горячего кипятка, которым обкатил его, выглянувши из кухни, повар. Словом, все голосило и верещало невыносимо.', ' Барин все видел и слышал. И только тогда, когда это делалось до такой степени несносно, что даже мешало барину ничем не заниматься, высылал он сказать, чтоб шумели потише.', '201.jpg', 22, '2024-11-12 04:00:30'),
(688, 'За два часа до обеда Андрей Иванович уходил к себе в кабинет затем.', 'За два часа до обеда Андрей Иванович уходил к себе в кабинет затем, чтобы заняться сурьезно и действительно. Занятие было, точно, сурьезное. Оно состояло в обдумыванье сочинения, которое уже издавна и постоянно обдумывалось.', ' Сочинение это долженствовало обнять всю Россию со всех точек — с гражданской, политической, религиозной, философической, разрешить затруднительные задачи и вопросы, заданные ей временем, и определить ясно ее великую будущность — словом, большого объема. Но покуда все оканчивалось одним обдумыванием; изгрызалось перо, являлись на бумаге рисунки, и потом все это отодвигалось на сторону, бралась наместо того в руки книга и уже не выпускалась до самого обеда. Книга эта читалась вместе с супом, соусом, жарким и даже с пирожным, так что иные блюда оттого стыли, а другие принимались вовсе нетронутыми. Потом следовала прихлебка чашки кофию с трубкой, потом игра в шахматы с самим собой. Что же делалось потом до самого ужина — право, уже и сказать трудно. Кажется, просто ничего не делалось.', '103.jpg', 56, '2024-11-11 00:50:42'),
(689, 'И этак проводил время, один-одинешенек в целом мире.', 'И этак проводил время, один-одинешенек в целом мире, молодой тридцатидвухлетний человек, сидень сиднем, в халате, без галстука.', ' Ему не гулялось, не ходилось, не хотелось даже подняться вверх взглянуть на отдаленности и виды, не хотелось даже растворять окна затем, чтобы забрать свежего воздуха в комнату, и прекрасный вид деревни, которым не мог равнодушно любоваться никакой посетитель, точно не существовал для самого хозяина.', '002.jpg', 34, '2024-11-02 21:35:19'),
(690, 'Из этого журнала читатель может видеть.', 'Из этого журнала читатель может видеть, что Андрей Иванович Тентетников принадлежал к семейству тек людей, которых на Руси много, которым имена — увальни, лежебоки, байбаки и тому подобные.', '.', '201.jpg', 35, '2024-10-27 18:49:28'),
(691, 'Родятся ли уже сами собою такие характеры или создаются потом.', 'Родятся ли уже сами собою такие характеры или создаются потом, как отвечать на это? Я думаю, что лучше вместо ответа рассказать историю детства и воспитания Андрея Ивановича.', '.', '102.jpg', 60, '2024-10-17 15:54:33'),
(692, 'В детстве был он остроумный, талантливый мальчик, то живой, то задумчивый.', 'В детстве был он остроумный, талантливый мальчик, то живой, то задумчивый. Счастливым или несчастливым случаем попал он в такое училище, где был директором человек, в своем роде необыкновенный, несмотря на некоторые причуды.', ' Александр Петрович имел дар слышать природу русского человека и знал язык, которым нужно говорить с ним. Никто из детей не уходил от него с повиснувшим носом; напротив, даже после строжайшего выговора чувствовал он какую-то бодрость и желанье загладить сделанную пакость и проступок. Толпа воспитанников его с виду казалась так шаловлива, развязна и жива, что иной принял бы ее за беспорядочную, необузданную вольницу. Но он обманулся бы: власть одного слишком была слышна в этой вольнице. Не было проказника и шалуна, который бы не пришел к нему сам и не рассказал всего, что ни напроказил. Малейшее движенье их помышлений было ему известно. Во всем поступал он необыкновенно. Он говорил, что прежде всего следует пробудить в человеке честолюбье, — честолюбье называл он силою, толкающею вперед человека, — без которого не подвигнешь его на деятельность. Многих резвостей и шалостей он не удерживал вовсе: в первоначальных резвостях видел он начало развитья свойств душевных. Они были ему нужны затем, чтобы видеть, что такое именно таится в ребенке. Так умный врач глядит спокойно на появляющиеся временные припадки и сыпи, показывающиеся на теле, не истребляет их, но всматривается внимательно, дабы узнать достоверно, что именно заключено внутри человека.', '101.jpg', 37, '2024-10-16 14:03:39'),
(693, 'Учителей у него было немного: большую часть наук читал он сам.', 'Учителей у него было немного: большую часть наук читал он сам.', ' И надо сказать правду, что, без всяких педантских терминов, огромных воззрений и взглядов, которыми любят пощеголять молодые профессора, он умел в немногих словах передать самую душу науки, так что и малолетнему было очевидно, на что именно она ему нужна, наука. Он утверждал, что всего нужнее человеку наука жизни, что, узнав ее, он узнает тогда сам, чем он должен заняться преимущественнее.', '201.jpg', 46, '2024-10-07 09:12:11');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(694, 'Эту-то науку жизни сделал он предметом отдельного курса воспитания.', 'Эту-то науку жизни сделал он предметом отдельного курса воспитания, в который поступали только одни самые отличные.', ' Малоспособных выпускал он на службу из первого курса, утверждая, что их не нужно много мучить: довольно с них, если приучились быть терпеливыми, работящими исполнителями, не приобретая заносчивости и всяких видов вдаль. «Но с умниками, но с даровитыми мне нужно долго повозиться», — обыкновенно говорил он. И становился в этом курсе совершенно другой Александр Петрович и с первых же раз возвещал, что доселе он требовал от них простого ума, теперь потребует ума высшего. Не того ума, который умеет подтрунить над дураком и посмеяться, но умеющего вынесть всякое оскорбление, спустить дураку — и не раздражиться. Здесь-то стал он требовать того, что другие требуют от детей. Это-то называл он высшей степенью ума. Сохранить посреди каких бы то ни было огорчений высокий покой, в котором вечно должен пребывать человек, — вот что называл он умом! В этом-то курсе Александр Петрович показал, что знает, точно, науку жизни. Из наук были избраны только те, которые способны образовать из человека гражданина земли своей. Большая часть лекций состояла в рассказах о том, что ожидает впереди человека на всех поприщах и ступенях государственной службы и частных занятий. Все огорченья и преграды, какие только воздвигаются человеку на пути его, все искушенья и соблазны, ему предстоящие, собирал он перед ними во всей наготе, не скрывая ничего. Все было ему известно, точно как бы перебыл он сам во всех званьях и должностях. Словом, чертил он перед ними вовсе не радужную будущность. Странное дело! оттого ли, что честолюбие уже так сильно было в них возбуждено; оттого ли, что в самых глазах необыкновенного наставника было что-то говорящее юноше: вперед! — это слово, производящее такие чудеса над русским человеком, — то ли, другое ли, но юноша с самого начала искал только трудностей, алча действовать только там, где трудно, где нужно было показать большую силу души. Было что-то трезвое в их жизни.', '302.jpg', 37, '2024-10-02 07:04:34'),
(695, 'Но этого ученья не удалось попробовать бедному Андрею Ивановичу.', 'Но этого ученья не удалось попробовать бедному Андрею Ивановичу.', ' Только что он был удостоен перевода в этот высший курс, как один из самых лучших, — вдруг несчастие: необыкновенный наставник, которого одно одобрительное слово уже бросало его в сладкий трепет, скоропостижно умер. Все переменилось в училище: на место Александра Петровича поступил какой-то Федор Иванович, человек добрый и старательный, но совершенно другого взгляда на вещи. В свободной развязности детей первого курса почудилось ему что-то необузданное. Начал он заводить между ними какие-то внешние порядки, требовал, чтобы молодой народ пребывал в какой-то безмолвной тишине, чтобы ни в каком случае иначе все не ходили, как попарно. Начал даже сам аршином размерять расстоянье от пары до пары. За столом, для лучшего вида, рассадил всех по росту, а не по уму, так что ослам доставались лучшие куски, умным — оглодки. Все это произвело ропот, особенно когда новый начальник, точно как наперекор своему предместнику, объявил, что для него ум и хорошие успехи в науках ничего не значат, что он смотрит только на поведенье, что если человек и плохо учится, но хорошо ведет себя, он предпочтет его умнику. Но именно того-то и не получил Федор Иванович, чего добивался. Завелись шалости потаенные, которые, как известно, хуже открытых. Все было в струнку днем, а по ночам — кутежи.', '203.jpg', 2, '2024-09-23 02:43:54'),
(696, 'В образе преподавания наук он все переворотил вверх дном.', 'В образе преподавания наук он все переворотил вверх дном. С самыми благими намерениями завел он всякие нововведения — и все невпопад. Выписал новых преподавателей, с новыми взглядами и новыми точками воззрений.', ' Читали они учено, забросали слушателей множеством новых терминов и слов. Видна была и логическая связь, и следованье за новыми открытиями, но увы! не было только, жизни в самой науке. Мертвечиной стало все это казаться в глазах уж начинавших понимать слушателей. Все пошло навыворот. Но хуже всего было то, что потерялось уваженье к начальству и власти: стали насмехаться и над наставниками и над преподавателями, директора стали называть Федькой, Булкой и другими разными именами; завелись такие дела, что нужно было многих выключить и выгнать.', '100.jpg', 16, '2024-09-16 23:02:46'),
(697, 'Андрей Иванович был нрава тихого.', 'Андрей Иванович был нрава тихого.', ' Он не участвовал в ночных оргиях с товарищами, которые, несмотря на строжайший присмотр, завели на стороне любовницу — одну на восемь человек, — ни также в других шалостях, доходивших до кощунства и насмешек над самою религиею из-за того только, что директор требовал частого хождения в церковь и попался плохой священник. Но он повесил нос. Честолюбье было возбуждено в нем сильно, а деятельности и поприща ему не было. Лучше б было и не возбуждать его! Он слушал горячившихся на кафедре профессоров, а вспоминал прежнего наставника, который, не горячась, умел говорить понятно. Он слушал и химию, и философию прав, и профессорские углубления во все тонкости политических наук, и всеобщую историю человечества в таком огромном виде, что профессор в три года успел только прочесть введение да развитие общин каких-то немецких городов; но все это оставалось в голове его какими-то безобразными клочками. Благодаря природному уму он чувствовал только, что не так должно преподаваться, а как — не знал. И вспоминал он часто об Александре Петровиче, и так ему бывало грустно, что не знал он, куда деться от тоски.', '002.jpg', 33, '2024-09-10 22:59:53'),
(698, 'Но у молодости есть будущее.', 'Но у молодости есть будущее. По мере того как приближалось время к выпуску, сердце у него билось. Он говорил себе: «Ведь это еще не жизнь, это только приготовленье к жизни: настоящая жизнь на службе. Там подвиги».', ' И, не взглянувши на прекрасный уголок, так поражавший всякого гостя-посетителя, не поклонившись праху своих родителей, по обычаю всех честолюбцев понесся он в Петербург, куда, как известно, стремится ото всех сторон России наша пылкая молодежь — служить, блистать, выслуживаться или же просто схватывать вершки бесцветного, холодного как лед, общественного обманчивого образованья. Честолюбивое стремление Андрея Ивановича осадил, однако же, с самого начала его дядя, действительный статский советник Онуфрий Иванович. Он объявил, что главное дело — в хорошем почерке, а не в чем-либо другом, что без этого не попадешь ни в министры, ни в государственные советники, а Тентетников писал тем самым письмом, о котором говорят: «Писала сорока лапой, а не человек».', '201.jpg', 49, '2024-09-04 19:14:01'),
(699, 'С большим трудом и с помощью дядиных протекций.', 'С большим трудом и с помощью дядиных протекций, проведя два месяца в каллиграфических уроках, достал он наконец место списывателя бумаг в каком-то департаменте.', ' Когда взошел он в светлый зал, где повсюду за письменными лакированными столами сидели пишущие господа, шумя перьями и наклоня голову набок, и когда посадили его самого, предложа ему тут же переписать какую-то бумагу, — необыкновенно странное чувство его проникнуло. Ему на время показалось, как бы он очутился в какой-то малолетней школе, затем, чтобы сызнова учиться азбуке, как бы за проступок перевели его из верхнего класса в нижний. Сидевшие вокруг его господа показались ему так похожими на учеников. Иные из них читали роман, засунув его в большие листы разбираемого дела, как бы занимались они самым делом, и в то же время вздрагивая при всяком появленье начальника. Ему вдруг представилось, как невозвратно-потерянный рай, школьное время его. Так высокими сделались вдруг занятья ученьем перед этим мелким письменным занятьем. Как это учебное приготовленье к службе казалось ему теперь выше самой службы. И вдруг предстал в его мыслях, как живой, его ни с кем не сравненный, чудесный воспитатель, никем не заменимый Александр Петрович, — и в три ручья потекли вдруг слезы из глаз его. Закружилась комната, задвигались столы, перемешались чиновники, и чуть не упал он от мгновенного потемненья. «Нет, — сказал он в себе, очнувшись, — примусь за дело, как бы оно ни казалось вначале мелким!» Скрепясь духом и сердцем, решился он служить по примеру прочих.', '201.jpg', 37, '2024-08-26 16:16:56'),
(700, 'Где не бывает наслаждений.', 'Где не бывает наслаждений? Живут они и в Петербурге, несмотря на суровую, сумрачную его наружность.', ' Трещит по улицам сердитый тридцатиградусный мороз, визжит отчаянным бесом ведьма-вьюга, нахлобучивая на голову воротники шуб и шинелей, пудря усы людей и морды скотов, но приветливо светит вверху окошко где-нибудь, даже и в четвертом этаже: в уютной комнатке, при скромных стеариновых свечках, под шумок самовара, ведется согревающий и сердце и душу разговор, читается светлая страница вдохновенного русского поэта, какими наградил бог свою Россию, и так возвышенно-пылко трепещет молодое сердце юноши, как не случается нигде в других землях и под полуденным роскошным небом.', '203.jpg', 51, '2024-08-22 16:11:32'),
(701, 'Скоро Тентетников свыкнулся с службою.', 'Скоро Тентетников свыкнулся с службою, но только она сделалась у него не первым делом и целью, как он полагал было вначале, но чем-то вторым. Она служила ему распределеньем времени, заставив его более дорожить оставшимися минутами.', ' Дядя, действительный статский советник, уже начинал было думать, что в племяннике будет прок, как вдруг племянник подгадил. Надобно сказать, что в числе друзей Андрея Ивановича попалось два человека, которые были то, что называется огорченные люди. Это были те беспокойно-странные характеры, которые не могут переносить равнодушно не только несправедливостей, но даже и всего того, что кажется в их глазах несправедливостью. Добрые поначалу, но беспорядочные сами в своих действиях, они исполнены нетерпимости к другим. Пылкая речь их и благородный обра:: негодованья подействовали на него сильно. Разбудивши в нем нервы и дух раздражительности, они заставили замечать все те мелочи, на которые он прежде и не думал обращать внимание. Федор Федорович Леницын, начальник того отделения, в котором он числился, человек наиприятнейшей наружности, вдруг ему не понравился. Он стал отыскивать в нем бездну недостатков и возненавидел его за то, будто бы он выражал в лице своем чересчур много сахару, когда говорил с высшим, и тут же, оборотившись к низшему, становился весь уксус. «Я бы ему простил, — говорил Тентетников, — если бы эта перемена происходила не так скоро в его лице; но как тут же, при моих глазах, и сахар и уксус в одно и то же время!» С этих пор он стал замечать всякий шаг. Ему казалось, что и важничал Федор Федорович уже чересчур, что имел он все замашки мелких начальников, как-то: брать на замечанье тех, которые не являлись к нему с поздравленьем в праздники, даже мстить всем тем, которых имена не находились у швейцара на листе, и множество разных тех грешных принадлежностей, без которых не обходится ни добрый, ни злой человек. Он почувствовал к нему отвращенье нервическое. Какой-то злой дух толкал его сделать что-нибудь неприятное Федору Федоровичу. Он наискивался на это с каким-то особым наслаждением и в том успел. Раз поговорил он с ним до того крупно, что ему объявлено было от начальства — или просить извинения, или выходить в отставку. Он подал в отставку.', '101.jpg', 22, '2024-08-12 13:11:52'),
(702, '— Ради самого Христа! помилуй, Андрей Иванович, что это ты делаешь.', '— Ради самого Христа! помилуй, Андрей Иванович, что это ты делаешь! Оставлять так выгодно начатый карьер из-за того только, что попался начальник не того… Что ж это? Ведь если на это глядеть, тогда и в службе никто бы не остался.', ' Образумься, образумься.', '101.jpg', 1, '2024-08-08 12:08:17'),
(703, '— Не в том дело, дядюшка, — сказал племянник.', '— Не в том дело, дядюшка, — сказал племянник. — Мне не трудно попросить у него извиненья, тем более, что я, точно, виноват. Он мне начальник, и мне ни в каком случае не следовало так говорить с ним.', ' Но дело вот в чем: вы позабыли, что у меня есть другая служба; у меня триста душ крестьян, именье в расстройстве, а управляющий — дурак. Государству утраты немного, если вместо меня сядет в канцелярию другой переписывать бумагу, но большая утрата, если триста человек не заплатят податей. Я помещик: званье это также не бездельно.', '002.jpg', 28, '2024-08-05 09:14:53'),
(704, 'Действительный статский советник остался с открытым ртом от изумленья.', 'Действительный статский советник остался с открытым ртом от изумленья. Такого потока слов он не ожидал.', ' Немного подумавши, начал он было в таком роде.', '101.jpg', 29, '2024-07-26 05:47:07'),
(705, '— Но все же таки… но как же таки… как же запропастить себя в деревне.', '— Но все же таки… но как же таки… как же запропастить себя в деревне? Какое же общество может быть между мужичьем? Здесь все-таки на улице попадется навстречу генерал или князь.', ' Захочешь — и сам пройдешь каких-нибудь публичных красивых зданий, на Неву пойдешь взглянуть, а ведь там, что ни попадется, все это или мужик, или баба.', '101.jpg', 30, '2024-07-17 03:03:53'),
(706, 'Так говорил дядя, действительный статский советник.', 'Так говорил дядя, действительный статский советник.', ' Сам же он во всю жизнь свою не ходил по другой улице, кроме той, которая вела к месту его службы, где не было никаких публичных красивых зданий; не замечал никого из встречных, был ли он генерал или князь; в глаза не знал прихотей, какие дразнят в столицах людей, падких на невоздержанье, и даже отроду не был в театре. Все это он говорил единственно затем, чтобы затеребить честолюбье и подействовать на воображенье молодого человека. В этом, однако же, не успел: Тентетников стоял на своем упрямо. Департаменты и столица стали ему надоедать. Деревня начинала представляться каким-то привольным приютом, воспоительницею дум и помышлений, единственным поприщем полезной деятельности. Через недели две после этого разговора был он уже в окрестности мест, где пронеслось его детство. Как стало все припоминаться, как забилось в нем сердце, когда почувствовал, что он уже вблизи отцовской деревни! Он уже многие места позабыл вовсе и смотрел любопытно, как новичок, на прекрасные виды.', '103.jpg', 54, '2024-07-14 22:03:44'),
(707, 'А между тем его ожидало другое зрелище.', 'А между тем его ожидало другое зрелище. Узнавши о приезде барина, населенье всей деревни собралося к крыльцу.', ' Пестрые платки, повязки, повойники, зипуны, бороды всех родов: заступом, лопатой и клином, рыжие, русые и белые, как серебро, покрыли всю площадь. Мужики загремели: «Кормилец, дождались мы тебя!» Бабы заголосили: «Золото, серебро ты сердечное!» Стоявшие подале даже подрались от усердья продраться. Дряблая старушонка, похожая на сушеную грушу, прошмыгнула промеж ног других, подступила к нему, всплеснула руками и взвизгнула: «Соплюнчик ты наш, да какой же ты жиденький! изморила тебя окаянная немчура!» — «Пошла ты, баба! — закричали ей тут же бороды заступом, лопатой и клином. — Ишь куды полезла, корявая!» Кто-то приворотил к этому такое словцо, от которого один только русский мужик мог не засмеяться. Барин не выдержал и рассмеялся, но тем не менее он тронут был глубоко в душе своей. «Столько любви! и за что? — думал он в себе.', '302.jpg', 26, '2024-07-08 15:51:04'),
(708, 'И действительно, Тентетников не шутя принялся хозяйничать и распоряжаться.', 'И действительно, Тентетников не шутя принялся хозяйничать и распоряжаться.', ' Он увидел на месте, что приказчик был баба и дурак со всеми качествами дрянного приказчика, то есть вел аккуратно счет кур и яиц, пряжи и полотна, приносимых бабами, но не знал ни бельмеса в уборке хлеба и посевах, а в прибавленье ко всему подозревал мужиков в покушенье на жизнь свою. Дурака приказчика он выгнал, наместо его выбрал другого, бойкого. Оставил мелочи, обратил вниманье на главные части, уменьшил барщину, убавил дни работы на себя, прибавил времени мужикам работать на них самих и думал, что теперь дела пойдут наиотличнейшим порядком. Сам стал входить во все, показываться на полях, па гумне, в овинах, на мельницах, у пристани, при грузке и сплавке барок и плоскодонов.', '302.jpg', 3, '2024-07-03 14:29:46'),
(709, '«Да он, вишь ты, востроногий.', '«Да он, вишь ты, востроногий!» — стали говорить мужики и даже почесывать в затылках, потому что от долговременного бабьего управления они все изрядно поизленились. Но это продолжалось не долго.', ' Русский мужик сметлив и умен: он понял скоро, что барин хоть и прыток и есть в нем охота взяться за многое, но как именно, каким образом взяться, — этого еще не смыслит, говорит как-то чересчур грамотно и затейливо, мужику невдолбеж и не в науку. Вышло то, что барин и мужик как-то не то чтобы совершенно не поняли друг друга, но просто не спелись вместе, не приспособились выводить одну и ту же ноту. Тентетников стал замечать, что на господской земле все выходило как-то хуже, чем на мужичьей: сеялось раньше, всходило позже. А работали, казалось, хорошо: он сам присутствовал и приказал выдать даже по чапорухе водки за усердные труды. У мужиков уже давно колосилась рожь, высыпался овес и кустилось просо, а у него едва начинал только идти хлеб в трубку, пятка колоса еще не завязывалась. Словом, стал замечать барин, что мужик просто плутует, несмотря на все льготы. Попробовал было укорить, но получил такой ответ: «Как можно, барин, чтобы мы о господской, то есть, выгоде не радели? Сами изволили видеть, как старались, когда пахали и сеяли: по чапорухе водки приказали подать». Что было на это возражать? «Да отчего ж теперь вышло скверно?» — допрашивал барин. «Кто его знает! Видно, червь подъел снизу, да и лето, вишь ты, какое: совсем дождей не было». Но барин видел, что у мужиков червь не подъедал снизу, да и дождь шел как-то странно, полосою: мужику угодил, а на барскую ниву хоть бы каплю выронил. Еще трудней ему было ладить с бабами. То и дело отпрашивались они от работ, жалуясь на тягость барщины. Странное дело! Он уничтожил вовсе всякие приносы холста, ягод, грибов и орехов, наполовину сбавил с них других работ, думая, что бабы обратят это время на домашнее хозяйство, обошьют, оденут своих мужей, умножат огороды. Не тут-то было! Праздность, драка, сплетни и всякие ссоры завелись между прекрасным полом такие, что мужья то и дело приходили к нему с такими словами: «Барин, уйми беса-бабу! Точно черт какой! житья нет от ней!» Несколько раз, скрепя свое сердце, хотел он приняться за строгость.', '301.jpg', 34, '2024-06-27 08:12:41'),
(710, 'Временами из соседей завернет к нему, бывало, отставной гусар-поручик.', 'Временами из соседей завернет к нему, бывало, отставной гусар-поручик, прокуренный насквозь трубочный куряка, или брандер-полковник, мастер и охотник на разговоры обо всем. Но и это стало ему надоедать.', ' Разговоры их начали ему казаться как-то поверхностными; живое, ловкое обращенье, потрепки по колену и прочие развязности начали ему казаться уже чересчур прямыми и открытыми. Он решился с ними раззнакомиться и произвел это даже довольно резко. Именно, когда представитель всех полковников-брандеров, наиприятнейший во всех поверхностных разговорах обо всем, Варвар Николаич Вишнепокромов приехал к нему затем именно, чтобы наговориться вдоволь, коснувшись и политики, и философии, и литературы, и морали, и даже состоянья финансов в Англии, он выслал сказать, что его нет дома, и в то же время имел неосторожность показаться перед окошком. Гость и хозяин встретились взорами. Один, разумеется, проворчал сквозь зубы: «Скотина!», другой послал ему тоже что-то вроде свиньи. Так и кончилось знакомство. С тех пор не заезжал к нему никто. Уединенье полное водворилось в доме. Хозяин залез в халат безвыходно, предавши тело бездействию, а мысль — обдумыванью большого сочиненья о России. Как обдумывалось это сочинение, читатель уже видел. День приходил и уходил, однообразный и бесцветный. Нельзя сказать, однако же, чтобы не было минут, в которые как будто пробуждался он ото сна. Когда привозила почта газеты, новые книги и журналы и попадалось ему в печати знакомое имя прежнего товарища, уже преуспевавшего на видном поприще государственной службы или приносившего посильную дань наукам и образованью всемирному, тайная тихая грусть подступала ему под сердце, и скорбная, безмолвно-грустная, тихая жалоба на бездействие свое прорывалась невольно. Тогда противной и гадкой казалась ему жизнь его. С необыкновенной силой воскресало пред ним школьное минувшее время и представал вдруг, как живой, Александр Петрович… Градом лились из глаз его слезы, и рыданья продолжались почти весь день.', '103.jpg', 27, '2024-06-19 02:50:36'),
(711, 'Что значили эти рыданья.', 'Что значили эти рыданья.', 'Что значили эти рыданья? Обнаруживала ли ими болеющая душа скорбную тайну своей болезни, что не успел образоваться и окрепнуть начинавший в нем строиться высокий внутренний человек; что, не испытанный измлада в борьбе с неудачами, не достигнул он до высокого состоянья возвышаться и крепнуть от преград и препятствий; что, растопившись, подобно разогретому металлу, богатый запас великих ощущений не принял последней закалки, и теперь, без упругости, бессильна его воля; что слишком для него рано умер необыкновенный наставник и нет теперь никого во всем свете, кто бы был в силах воздвигнуть и поднять шатаемые вечными колебаньями силы и лишенную упругости немощную волю, — кто бы крикнул живым, пробуждающим голосом, — крикнул душе пробуждающее слово: вперед! — которого жаждет повсюду, на всех ступенях стоящий, всех сословий, званий и промыслов, русский человек.', '302.jpg', 50, '2024-06-16 23:44:58'),
(712, 'Где же тот.', 'Где же тот, кто бы на родном языке русской души нашей умел бы нам сказать это всемогущее слово вперед? кто, зная все силы, и свойства, и всю глубину нашей природы, одним чародейным мановеньем мог бы устремить на высокую жизнь русского человека.', 'Где же тот, кто бы на родном языке русской души нашей умел бы нам сказать это всемогущее слово вперед? кто, зная все силы, и свойства, и всю глубину нашей природы, одним чародейным мановеньем мог бы устремить на высокую жизнь русского человека? Какими словами, какой любовью заплатил бы ему благодарный русский человек. Но веки проходят за веками; полмиллиона сидней, увальней и байбаков дремлют непробудно, и редко рождается на Руси муж, умеющий произносить его, это всемогущее слово.', '103.jpg', 46, '2024-06-12 18:11:57'),
(713, 'Одно обстоятельство чуть было, однако же.', 'Одно обстоятельство чуть было, однако же, не разбудило Тентетникова и чуть было не произвело переворота в его характере. Случилось что-то вроде любви, но и тут дело как-то свелось на ничего.', ' В соседстве, в десяти верстах от его деревни, проживал генерал, отзывавшийся, как мы уже видели, не совсем благосклонно о Тентетникове. Генерал жил генералом, хлебосольствовал, любил, чтобы соседи приезжали изъявлять ему почтенье; сам, разумеется, визитов не платил, говорил хрипло, читал книги и имел дочь, существо невиданное, странное, которую скорей можно было почесть каким-то фантастическим видением, чем женщиной. Иногда случается человеку во сне увидеть что-то подобное, и с тех пор он уже во всю жизнь свою грезит этим сновиденьем, действительность для него пропадает навсегда, и он решительно ни на что не годится. Имя ей было Улинька. Воспиталась она как-то странно. Ее воспитывала англичанка-гувернантка, не знавшая ни слова по-русски. Матери лишилась она еще в детстве. Отцу было некогда. Впрочем, любя дочь до безумия, он мог только избаловать ее. Необыкновенно трудно изобразить портрет ее. Это было что-то живое, как сама жизнь. Она была миловидней, чем красавица; лучше, чем умна; стройней, воздушней классической женщины. Никак бы нельзя было сказать, какая страна положила на нее свой отпечаток, потому что подобного профиля и очертанья лица трудно было где-нибудь отыскать, разве только на античных камеях. Как в ребенке, воспитанном на свободе, в ней было все своенравно. Если бы кто увидал, как внезапный гнев собирал вдруг строгие морщины на прекрасном челе ее и как оно спорила пылко с отцом своим, он бы подумал, что это было капризнейшее созданье. Но гнев бывал у нее только тогда, когда она слышала о какой бы то ни было несправедливости или жестоком поступке с кем бы то ни было. Но как вдруг исчезнул бы этот гнев, если бы она увидела в несчастии того самого, на кого гневалась, как бы вдруг бросила она ему свой кошелек, не размышляя, умно ли это или глупо, и разорвала на себе платье для перевязки, если б он был ранен! Было в ней что-то стремительное.', '002.jpg', 50, '2024-06-07 15:17:38'),
(714, 'Андрей Иванович Тентетников не мог бы никак рассказать, как это случилось.', 'Андрей Иванович Тентетников не мог бы никак рассказать, как это случилось, что с первого же дни он стал с ней так, как бы знаком был вечно. Неизъяснимое, новое чувство вошло к нему в душу. Скучная жизнь его на мгновенье озарилась.', ' Халат на время был оставлен. Не так долго копался он на кровати, не так долго стоял Михайло с рукомойником в руках. Растворялись окна в комнатах, и часто владетель картинного поместья долго ходил по темным излучинам своего сада и останавливался по часам перед пленительными видами на отдаленья.', '101.jpg', 32, '2024-05-31 10:30:56'),
(715, 'Генерал принимал сначала Тентетннкова довольно хорошо и радушно.', 'Генерал принимал сначала Тентетннкова довольно хорошо и радушно; но совершенно сойтись между собою они не могли. Разговоры у них всегда оканчивались спором и каким-то неприятным ощущеньем с обеих сторон.', ' Генерал не любил противуречья и возраженья, хотя в то же время любил поговорить даже и о том, чего не знал вовсе. Тентетников, со своей стороны, тоже был человек щекотливый. Впрочем, ради дочери прощалось многое отцу, и мир у них держался до тех пор, покуда не приехали гостить к генералу родственницы, графиня Болдырева и княжна Юзякииа: одна — вдова, другая — старая девка, обе фрейлины прежних времен, обе болтуньи, обе сплетницы, не весьма обворожительные любезностью своей, но, однако же, имевшие значительные связи в Петербурге, и перед которыми генерал немножко даже подличал. Тентетникову показалось, что с самого дня приезда их генерал стал к нему как-то холоднее, почти не замечал его и обращался как с лицом бессловесным или с чиновником, употребляемым для переписки, самым мелким. Он говорил ему то братец, то любезнейший, и один раз сказал ему даже ты. Андрея Ивановича взорвало; кровь бросилась ему в голову.', '201.jpg', 32, '2024-05-29 07:35:57'),
(716, '— Я должен благодарить вас, генерал, за ваше расположение.', '— Я должен благодарить вас, генерал, за ваше расположение. Вы приглашаете и вызываете меня словом ты на самую тесную дружбу, обязывая меня также говорить вам ты.', ' Но позвольте вам заметить, что я помню различие наше в летах, совершенно препятствующее такому фамильярному между нами обращению.', '101.jpg', 47, '2024-05-26 03:20:52'),
(717, 'Генерал смутился.', 'Генерал смутился. Собирая слова и мысли, стал он говорить, хотя несколько несвязно, что слово ты было им сказано не в том смысле, что старику иной раз позволительно сказать молодому человеку ты (о чине своем он не упомянул ни слова).', '.', '201.jpg', 54, '2024-05-18 23:48:31'),
(718, 'Разумеется, с этих пор знакомство между ними прекратилось.', 'Разумеется, с этих пор знакомство между ними прекратилось, и любовь кончилась при самом начале. Потухнул свет, на минуту было перед ним блеснувший, и последовавшие за ним сумерки стали еще сумрачней. Байбак сызнова залез в халат свой.', ' Все поворотило сызнова на лежанье и бездействие. В доме завелись гадость и беспорядок. Половая щетка оставалась по целому дню посреди комнаты вместе с сором. Панталоны заходили даже в гостиную. На щеголеватом столе перед диваном лежали засаленные подтяжки, точно какое угощенье гостю, и до того стала ничтожной и сонной его жизнь, что не только перестали уважать его дворовые люди, но даже чуть не клевали домашние куры. Бессильно чертил он на бумаге по целым часам рогульки, домики, избы, телеги, тройки или же выписывал «Милостивый государь!» с восклицательным знаком всеми почерками и характерами. А иногда же, все позабывши, перо чертило само собой, без ведома хозяина, маленькую головку с тонкими, острыми чертами, с приподнятой легкой прядью волос, упадавшей из-под гребня длинными тонкими кудрями, молодыми обнаженными руками, как бы летевшую, — и в изумленье видел хозяин, как выходил портрет той, с которой портрета не мог бы написать никакой живописец. И еще грустнее становилось ему потом, и, веря тому, что нет на земле счастья, оставался он на целый день скучным и безответным.', '203.jpg', 41, '2024-05-10 20:31:22'),
(719, 'Таковы были обстоятельства Андрея Ивановича Тентетникова.', 'Таковы были обстоятельства Андрея Ивановича Тентетникова. Вдруг в один день, подходя к окну обычным порядком, с трубкой и чашкой в руках, заметил он во дворе движенье и некоторую суету.', ' Поварчонок и поломойка бежали отворять вороты, и в воротах показались кони, точь-в-точь как лепят иль рисуют их на триумфальных воротах: морда направо, морда налево, морда посередине. Свыше их, на козлах — кучер и лакей в широком сюртуке, опоясавший себя носовым платком. За ними господин в картузе и шинели, закутанный в косынку радужных цветов. Когда экипаж изворотился перед крыльцом, оказалось, что был он не что другое, как рессорная легкая бричка. Господин необыкновенно приличной наружности соскочил на крыльцо с быстротой и ловкостью почти военного человека.', '202.jpg', 6, '2024-04-30 16:25:06'),
(720, 'Андрей Иванович струсил. Он принял его за чиновника от правительства.', 'Андрей Иванович струсил. Он принял его за чиновника от правительства. Надобно сказать, что в молодости своей он было замешался в одно неразумное дело.', ' Какие-то философы из гусар, да недоучившийся студент, да промотавшийся игрок затеяли какое-то филантропическое общество, под верховным распоряжением старого плута, и масона, и карточного игрока, пьяницы и красноречивейшего человека. Общество было устроено с целью доставить прочное счастье всему человечеству от берегов Темзы до Камчатки. Касса денег потребовалась огромная, пожертвованья собирались с великодушных членов неимоверные. Куда это все пошло — знал об этом только один верховный распорядитель. В общество это затянули его два приятеля, принадлежавшие к классу огорченных людей, добрые люди, но которые от частых тостов во имя науки, просвещения и прогресса сделались потом формальными пьяницами. Тентетников скоро спохватился и выбыл из этого круга. Но общество успело уже запутаться в каких-то других действиях, даже не совсем приличных дворянину, так что потом завязались дела и с полицией… А потому не мудрено, что хотя и вышедши, и разорвавши всякие сношения с благодетелем человечества, Тентетников не мог, однако же, оставаться покоен. На совести у него было не совсем ловко. Не без страха глядел он и теперь на растворявшуюся дверь.', '201.jpg', 13, '2024-04-21 14:59:50'),
(721, 'Страх его, однако же, прошел вдруг.', 'Страх его, однако же, прошел вдруг, когда гость раскланялся с ловкостью неимоверной, сохраняя почтительное положение головы несколько набок.', ' В коротких, но определительных словах изъяснил, что уже издавна ездит он по России, побуждаемый и потребностями, и любознательностью; что государство наше преизобилует предметами замечательными, не говоря уже о красоте мест, обилии промыслов и разнообразии почв; что он увлекся картинностью местоположенья его деревни; что, несмотря, однако же, на картинность местоположенья, он не дерзнул бы никак обеспокоить его неуместным заездом своим, если бы не случилось что-то в бричке его, требующее руки помощи со стороны кузнецов и мастеров; что при всем том, однако же, если бы даже и ничего не случилось в его бричке, он бы не мог отказать себе в удовольствии засвидетельствовать ему лично свое почтенье.', '301.jpg', 18, '2024-04-17 08:35:10'),
(722, 'Окончив речь, гость с обворожительной приятностью подшаркнул ножкой и.', 'Окончив речь, гость с обворожительной приятностью подшаркнул ножкой и, несмотря на полноту корпуса, отпрыгнул тут же несколько назад с легкостью резинного мячика.', '.', '002.jpg', 7, '2024-04-11 07:15:28'),
(723, 'Андрей Иванович подумал.', 'Андрей Иванович подумал, что это должен быть какой-нибудь любознательный ученый-профессор, который ездит по России затем, чтобы собирать какие-нибудь растения или даже предметы ископаемые.', ' Он изъявил ему всякую готовность споспешествовать: предложил своих мастеров, колесников и кузнецов для поправки брички; просил расположиться у него как в собственном доме; усадил обходительного гостя в большие вольтеровские кресла и приготовился слушать его рассказ, без сомнения, об ученых предметах и естественных.', '302.jpg', 23, '2024-04-03 05:13:15'),
(724, 'Гость, однако же, коснулся больше событий внутреннего мира.', 'Гость, однако же, коснулся больше событий внутреннего мира.', ' Заговорил о превратностях судьбы; уподобил жизнь свою судну посреди морей, гонимому отовсюду ветрами; упомянул о том, что должен был переменить много мест и должностей, что много потерпел за правду, что даже самая жизнь его была не раз в опасности со стороны врагов, и много еще рассказал он такого, из чего Тентетников мог видеть, что гость его был скорее практический человек. В заключенье всего, он высморкался в белый батистовый платок так громко, как Андрей Иванович еще и не слыхивал. Подчас попадается в оркестре такая пройдоха-труба, которая когда хватит, покажется, что крякнуло не в оркестре, но в собственном ухе. Точно такой же звук раздался в пробужденных покоях дремавшего дома, и немедленно вослед за ним воспоследовало благоуханье одеколона, невидимо распространенное ловким встряхнутьем носового батистового платка.', '101.jpg', 15, '2024-03-26 02:13:23'),
(725, 'Читатель, может быть, уже догадался, что гость был не другой кто.', 'Читатель, может быть, уже догадался, что гость был не другой кто, как наш почтенный, давно нами оставленный Павел Иванович Чичиков. Он немножко постарел: как видно, не без бурь и тревог было для него это время.', ' Казалось, как бы и самый фрак на нем немножко поустарел, и бричка, и кучер, и слуга, и лошади, и упряжь как бы поистерлись и поизносились. Казалось, как бы и самые финансы не были в завидном состоянии. Но выраженье лица, приличье, обхожденье остались те же. Даже как бы еще приятнее стал он в поступках и оборотах, еще ловче подвертывал под ножку ножку, когда садился в кресла; еще более было мягкости в выговоре речей, осторожной умеренности в словах и выраженьях, более уменья держать себя и более такту во всем. Белей и чище снегов были на нем воротнички и манишка, и, несмотря на то что был он с дороги, ни пушинки не село к нему на фрак, — хоть на именинный обед! Щеки и подбородок выбриты были так, что один разве только слепой мог не полюбоваться приятной выпуклостью и круглотой их.', '002.jpg', 5, '2024-03-19 20:20:09'),
(726, 'В доме произошло преобразование.', 'В доме произошло преобразование. Половина его, дотоле пребывавшая в слепоте, с заколоченными ставнями, вдруг прозрела и озарилась. Из брички стали выносить поклажу.', ' Все начало размещаться в осветившихся комнатах, и скоро все приняло такой вид: комната, определенная быть спальней, вместила в себе вещи, необходимые для ночного туалета; комната, определенная быть кабинетом… Но прежде необходимо знать, что в этой комнате было три стола: один письменный — перед диваном, другой ломберный — между окнами у стены, третий угольный — в углу, между дверью в спальню и дверью в необитаемый зал с инвалидною мебелью. На этом угольном столе поместилось вынутое из чемодана платье, а именно: панталоны под фрак, панталоны под сюртук, панталоны серенькие, два бархатных жилета и два атласных, сюртук и два фрака. (Жилеты же белого пике и летние брюки отошли к белью в комод). Все это разместилось один на другом пирамидкой и прикрылось сверху носовым шелковым платком. В другом углу, между дверью и окном, выстроились рядком сапоги: сапоги не совсем новые, сапоги совсем новые, сапоги с новыми головками и лакированные полусапожки. Они также стыдливо занавесились шелковым носовым платком — так, как бы их там вовсе не было. На столе перед двумя окнами поместилася шкатулка. На письменном столе перед диваном — портфель, банка с одеколоном, сургуч, зубные щетки, новый календарь и два какие-то романа, оба вторые тома. Чистое белье поместилось в комоде, уже находившемся в спальне; белье же, которое следовало прачке, завязано было в узел и подсунуто под кровать. Чемодан, по опростанье его, был тоже подсунут под кровать. Сабля поместилась также в спальне, повиснувши на гвозде невдалеке от кровати. Та и другая комната приняли вид чистоты и опрятности необыкновенной. Нигде ни бумажки, ни перышка, ни соринки. Самый воздух как-то облагородился. В нем утвердился приятный запах здорового, свежего мужчины, который белья не занашивает, в баню ходит и вытирает себя мокрой губкой по воскресным дням. В вестибульной комнате покушался было утвердиться на время запах служителя Петрушки, но Петрушка скоро перемещен был на кухню, как оно и следовало.', '002.jpg', 56, '2024-03-14 17:10:44'),
(727, 'В первые дни Андрей Иванович опасался за свою независимость.', 'В первые дни Андрей Иванович опасался за свою независимость, чтобы как-нибудь гость не связал его, не стеснил какими-нибудь измененьями в образе жизни, и не разрушился бы порядок дня его, так удачно заведенный, — но опасенья были напрасны.', ' Павел Иванович наш показал необыкновенно гибкую способность приспособиться ко всему. Одобрил философическую неторопливость хозяина, сказавши, что она обещает столетнюю жизнь. Об уединении выразился весьма счастливо — именно, что оно питает великие мысли в человеке. Взглянув на библиотеку и отозвавшись с похвалой о книгах вообще, заметил, что они спасают от праздности человека. Словом, выронил слов не много, но значительных. В поступках же своих поступал еще более кстати. Вовремя являлся, вовремя уходил; не затруднял хозяина запросами в часы неразговорчивости его; с удовольствием играл с ним в шахматы, с удовольствием молчал. В то время, когда один пускал кудреватыми облаками трубочный дым, другой, не куря трубки, придумывал, однако же, соответствовавшее тому занятие: вынимал, например, из кармана серебряную с чернью табакерку и, утвердив ее между двух пальцев левой руки, оборачивал ее быстро пальцем правой, в подобье того как земная сфера обращается около своей оси, или же просто барабанил по табакерке пальцами, насвистывая какое-нибудь ни то ни се. Словом, он не мешал хозяину никак. «Я в первый раз вижу человека, с которым можно жить, — говорил про себя Тентетников. — Вообще этого искусства у нас мало. Между нами есть довольно людей и умных, и образованных, и добрых, но людей постоянно приятных, людей постоянно ровного характера, людей, с которыми можно прожить век и не поссориться, — я не знаю, много ли у нас можно отыскать таких людей! Вот первый, единственный человек, которого я вижу!» Так отзывался Тентетников о своем госте.', '102.jpg', 46, '2024-03-05 13:07:49'),
(728, 'Чичиков, со своей стороны, был очень рад.', 'Чичиков, со своей стороны, был очень рад, что поселился на время у такого мирного и смирного хозяина. Цыганская жизнь ему надоела.', ' Приотдохнуть, хотя на месяц, в прекрасной деревне, в виду полей и начинавшейся весны, полезно было даже и в геморроидальном отношении. Трудно было найти лучший уголок для отдохновения. Весна убрала его красотой несказанной. Что яркости в зелени! Что свежести в воздухе! Что птичьего крику в садах! Рай, радость и ликованье всего! Деревня звучала и пела, как будто новорожденная.', '301.jpg', 45, '2024-03-02 12:02:59'),
(729, 'Чичиков ходил много.', 'Чичиков ходил много.', ' То направлял он прогулку свою по плоской вершине возвышений, в виду расстилавшихся внизу долин, по которым повсюду оставались еще большие озера от разлития воды; или же вступал в овраги, где едва начинавшие убираться листьями дерева отягчены птичьими гнездами, — оглушенный карканьем ворон, разговорами галок и граньями грачей, перекрестными летаньями, помрачавшими небо; или же спускался вниз к поемным местам и разорванным плотинам — глядеть, как с оглушительным шумом неслась повергаться вода на мельничные колеса; или же пробирался дале к пристани, откуда неслись, вместе с течью воды, первые суда, нагруженные горохом, овсом, ячменем и пшеницей; или отправлялся в поля на первые весенние работы глядеть, как свежая орань черной полосою проходила по зелени, или же как ловкий сеятель бросал из горсти семена ровно, метко, ни зернышка не передавши на ту или другую сторону. Толковал и говорил и с приказчиком, и с мужиком, и мельником — и что, и как, и каковых урожаев можно ожидать, и на какой лад идет у них запашка, и по сколько хлеба продается, и что выбирают весной и осенью за умол муки, и как зовут каждого мужика, и кто с кем в родстве, и где купил корову, и чем кормит свинью — словом, все. Узнал и то, сколько перемерло мужиков. Оказалось, немного. Как умный человек, заметил он вдруг, что незавидно идет хозяйство у Андрея Ивановича. Повсюду упущенья, нераденье, воровство, немало и пьянства. И мысленно говорил он сам в себе: «Какая, однако же, скотина Тентетников! Запустить так имение, которое могло бы приносить по малой мере пятьдесят тысяч годового доходу!» И, не будучи в силах удержать справедливого негодования, повторял он: «Решительно скотина!» Не раз посреди таких прогулок приходило ему на мысль сделаться когда-нибудь самому, — то есть, разумеется, не теперь, но после, когда обделается главное дело и будут средства в руках, — сделаться самому мирным владельцем подобного поместья.', '103.jpg', 39, '2024-02-24 10:31:51'),
(730, 'Людям Павла Ивановича деревня тоже понравилась.', 'Людям Павла Ивановича деревня тоже понравилась. Они так же, как и он, обжились в ней. Петрушка сошелся очень скоро с буфетчиком Григорием, хотя сначала они оба важничали и дулись друг перед другом нестерпимо.', ' Петрушка пустил Григорию пыль в глаза тем, что он бывал в Костроме, Ярославле, Нижнем и даже в Москве; Григорий же осадил его сразу Петербургом, в котором Петрушка не был. Последний хотел было подняться и выехать на дальности расстояний тех мест, в которых он бывал; но Григорий назвал ему такое место, какого ни на какой карте нельзя было отыскать, и насчитал тридцать тысяч с лишком верст, так что Петрушка осовел, разинул рот и был поднят на смех тут же всею дворней. Впрочем, дело кончилось между ними самой тесной дружбой: дядя лысый Пимен держал в конце деревни знаменитый кабак, которому имя было «Акулька»; в этом заведенье видели их все часы дня. Там стали они свои други, или то, что называют в народе — кабацкие завсегдатели.', '203.jpg', 45, '2024-02-18 04:44:27'),
(731, 'У Селифана была другого рода приманка.', 'У Селифана была другого рода приманка. На деревне, что ни вечер, пелись песни, заплетались и расплетались весенние хороводы. Породистые, стройные девки, каких трудно было найти в другом месте, заставляли его по нескольким часам стоять вороной.', ' Трудно было сказать, которая лучше: все белогрудые, белошейные, у всех глаза репой, у всех глаза с поволокой, походка павлином и коса до пояса. Когда, взявшись обеими руками за белые руки, медленно двигался он с ними в хороводе или же выходил на них стеной, в ряду других парней, и погасал горячо рдеющий вечер, и тихо померкала вокруг окольность, и далече за рекой отдавался верный отголосок неизменно грустного напева, — не знал он и сам тогда, что с ним делалось. Долго потом во сне и наяву, утром и в сумерки все мерещилось ему, что в обеих руках его белые руки и движется он с ними в хороводе.', '202.jpg', 16, '2024-02-17 01:28:07'),
(732, 'Коням Чичикова понравилось тоже новое жилище.', 'Коням Чичикова понравилось тоже новое жилище.', ' И коренной, и пристяжной каурой масти, называемый Заседателем, и самый чубарый, о котором выражался Селифан: «подлец-лошадь», нашли пребыванье у Тентетникова совсем нескучным, овес отличным, а расположенье конюшен необыкновенно удобным. У всякого стойло, хотя и отгороженное, но через перегородки можно было видеть и других лошадей, так что, если бы пришла кому-нибудь из них, даже самому дальнему, фантазия здруг заржать, то можно было ему ответствовать тем же тот же час.', '301.jpg', 33, '2024-02-09 21:23:38'),
(733, 'Словом, все обжились, как дома.', 'Словом, все обжились, как дома. Читатель, может быть, изумляется, что Чичиков доселе не заикнулся по части известных душ. Как бы не так! Павел Иванович стал очень осторожен насчет этого предмета.', ' Если бы даже пришлось вести дело с дураками круглыми, он бы и тут не вдруг начал. Тентетников же, как бы то ни было, читает книги, философствует, старается изъяснить себе всякие причины всего — и отчего, и почему… «Нет, черт его возьми! разве начать с другого конца?» — Так думал Чичиков. Раздобаривая почасту с дворовыми людьми, он, между прочим, от них разведал, что барин ездил прежде довольно нередко к соседу генералу, что у генерала барышня, что барин было к барышне, да и барышня тоже к барину… но потом вдруг за что-то не поладили и разошлись. Он заметил и сам, что Андрей Иванович карандашом и пером все рисовал какие-то головки, одна на другую похожие.', '101.jpg', 36, '2024-02-08 16:31:21'),
(734, 'Чичиков не смутился, выбрал другое время, уже перед ужином, и.', 'Чичиков не смутился, выбрал другое время, уже перед ужином, и, разговаривая о том и о сем, сказал вдруг.', 'Чичиков не смутился, выбрал другое время, уже перед ужином, и, разговаривая о том и о сем, сказал вдруг.', '302.jpg', 17, '2024-02-04 11:19:26'),
(735, 'Хоть бы слово сказал на это Тентетников.', 'Хоть бы слово сказал на это Тентетников, точно как бы и самая речь об этом была ему неприятна.', '.', '203.jpg', 25, '2024-01-29 11:03:47'),
(736, 'Чичиков не смутился.', 'Чичиков не смутился.', ' В третий раз выбрал он время, уже после ужина, и сказал так.', '201.jpg', 22, '2024-01-23 05:59:28'),
(737, '— А все-таки, как ни переворочу обстоятельства ваши, вижу.', '— А все-таки, как ни переворочу обстоятельства ваши, вижу, что нужно вам жениться: впадете в ипохондрию.', '.', '202.jpg', 14, '2024-01-20 02:33:12'),
(738, 'Слова ли Чичикова были на этот раз так убедительны или же расположение духа у.', 'Слова ли Чичикова были на этот раз так убедительны или же расположение духа у Андрея Ивановича было как-то особенно настроено к откровенности, — он вздохнул и сказал, пустивши кверху трубочный дым, «На все нужно родиться счастливцем, Павел Иванович».', 'Слова ли Чичикова были на этот раз так убедительны или же расположение духа у Андрея Ивановича было как-то особенно настроено к откровенности, — он вздохнул и сказал, пустивши кверху трубочный дым: «На все нужно родиться счастливцем, Павел Иванович», — и рассказал все, как было, всю историю знакомства с генералом и разрыв.', '102.jpg', 47, '2024-01-11 01:16:24'),
(739, 'Когда услышал Чичиков, от слова до слова, все дело и увидел.', 'Когда услышал Чичиков, от слова до слова, все дело и увидел, что из-за одного слова ты произошла такая история, он оторопел.', ' Несколько минут смотрел пристально в глаза Тентетникова и заключил: «Да он просто круглый дурак.', '002.jpg', 39, '2024-01-07 23:16:57'),
(740, '— Андрей Иванович, помилуйте! — сказал он, взявши его за обе руки.', '— Андрей Иванович, помилуйте! — сказал он, взявши его за обе руки.', ' — Какое ж оскорбление? что ж тут оскорбительного в слове ты.', '102.jpg', 2, '2024-01-01 18:48:56'),
(741, '— В самом слове нет ничего оскорбительного, — сказал Тентетников.', '— В самом слове нет ничего оскорбительного, — сказал Тентетников, — но в смысле слова, но в голосе, с которым сказано оно, заключается оскорбление.', ' Ты — это значит: «Помни, что ты дрянь; я принимаю тебя потому только, что нет никого лучше, а приехала какая-нибудь княжна Юзякина, — ты знай свое место, стой у порога».', '301.jpg', 48, '2023-12-29 14:13:21'),
(742, 'Говоря это, смирный и кроткий Андрей Иванович засверкал глазами.', 'Говоря это, смирный и кроткий Андрей Иванович засверкал глазами; в голосе его послышалось раздражение оскорбленного чувства.', '.', '002.jpg', 41, '2023-12-25 14:02:57'),
(743, '— Как? — сказал Тентетников, смотря пристально в глаза Чичикову.', '— Как? — сказал Тентетников, смотря пристально в глаза Чичикову.', ' — Вы хотите, чтобы я продолжал бывать у него после такого поступка.', '203.jpg', 11, '2023-12-19 11:53:46'),
(744, '— Это не поступок, Андрей Иванович.', '— Это не поступок, Андрей Иванович. Это просто генеральская привычка: они всем говорят ты.', ' Да, впрочем, уж почему этого и не позволить заслуженному, почтенному человеку.', '002.jpg', 8, '2023-12-14 06:00:43'),
(745, '— Это другое дело, — сказал Тентетников.', '— Это другое дело, — сказал Тентетников. — Если бы он был старик, бедняк, не горд, не чванлив, не генерал, я бы тогда позволил ему говорить мне ты и принял бы даже почтительно.', '.', '100.jpg', 2, '2023-12-07 05:31:43'),
(746, '«Он совсем дурак! — подумал про себя Чичиков.', '«Он совсем дурак! — подумал про себя Чичиков.', ' — Оборвышу позволить, а генералу не позволить.', '203.jpg', 19, '2023-12-03 03:42:15'),
(747, '— Хорошо, положим, он вас оскорбил, зато вы и поквитались с ним, он вам.', '— Хорошо; положим, он вас оскорбил, зато вы и поквитались с ним: он вам, и вы ему.', ' Но расставаться навсегда из пустяка, — помилуйте, на что же это похоже? Как же оставлять дело, которое только что началось? Если уже избрана цель, так тут уже нужно идти напролом. Что глядеть на то, что человек плюется! Человек всегда плюется; да вы не отыщете теперь во всем свете такого, который бы не плевался.', '101.jpg', 37, '2023-11-27 01:16:59');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(748, 'Тентетников совершенно озадачился этими словами, оторопел.', 'Тентетников совершенно озадачился этими словами, оторопел, глядел в глаза Павлу Ивановичу и думал про себя: «Престранный, однако ж, человек этот Чичиков.', 'Тентетников совершенно озадачился этими словами, оторопел, глядел в глаза Павлу Ивановичу и думал про себя: «Престранный, однако ж, человек этот Чичиков.', '103.jpg', 41, '2023-11-25 19:19:53'),
(749, '— Позвольте мне как-нибудь обделать это дело, — сказал он вслух.', '— Позвольте мне как-нибудь обделать это дело, — сказал он вслух. — Я могу съездить к его превосходительству и объясню, что случилось это с вашей стороны по недоразумению, по молодости и незнанью людей и света.', '.', '302.jpg', 1, '2023-11-21 15:54:44'),
(750, '— Сохрани бог подличать! — сказал Чичиков и перекрестился.', '— Сохрани бог подличать! — сказал Чичиков и перекрестился.', ' — Подействовать словом увещания, как благоразумный посредник, но подличать… Извините, Андрей Иванович, за мое доброе желанье и преданность, я даже не ожидал, чтобы слова мои принимали вы в таком обидном смысле.', '302.jpg', 26, '2023-11-16 12:49:20'),
(751, '— Простите, Павел Иванович, я виноват.', '— Простите, Павел Иванович, я виноват! — сказал тронутый Тентетников, схвативши признательно обе его руки. — Ваше доброе участие мне дорого, клянусь! Но оставим этот разговор, не будем больше никогда об этом говорить.', '.', '202.jpg', 3, '2023-11-10 12:08:53'),
(752, '— Так как моя бричка, — сказал Чичиков, — не пришла еще в надлежащее состояние.', '— Так как моя бричка, — сказал Чичиков, — не пришла еще в надлежащее состояние, то позвольте мне взять у вас коляску. Я бы завтра же, эдак около десяти часов, к нему съездил.', '.', '202.jpg', 9, '2023-11-08 07:13:33'),
(753, '— Помилуйте, что за просьба.', '— Помилуйте, что за просьба! Вы — полный господин, выбирайте какой хотите экипаж: всё в вашем распоряжении.', '.', '100.jpg', 29, '2023-10-30 02:11:42'),
(754, 'Чудная, однако же, вещь, на другой день.', 'Чудная, однако же, вещь, на другой день, когда подали Чичикову лошадей и вскочил он в коляску с легкостью почти военного человека, одетый в новый фрак, белый галстук и жилет, и покатился свидетельствовать почтение генералу.', 'Чудная, однако же, вещь: на другой день, когда подали Чичикову лошадей и вскочил он в коляску с легкостью почти военного человека, одетый в новый фрак, белый галстук и жилет, и покатился свидетельствовать почтение генералу, Тентетников пришел в такое волненье духа, какого давно не испытывал. Весь этот ржавый и дремлющий ход его мыслей превратился в деятельно-беспокойный. Возмущенье нервическое обуяло вдруг всеми чувствами доселе погруженного в беспечную лень байбака. То садился он на диван, то подходил к окну, то принимался за книгу, то хотел мыслить, — безуспешное хотенье! — мысль не лезла к нему в голову. То старался ни о чем не мыслить, — безуспешное старание! — отрывки чего-то похожего на мысли, концы и хвостики мыслен лезли и отовсюду наклевывались к нему в голову. «Странное состоянье!» — сказал он и придвинулся к окну глядеть на дорогу, прорезавшую дуброву, в конце которой еше курилась не успевшая улечься пыль, поднятая уехавшей коляской. Но оставим Тентетникова и последуем за Чичиковым.', '101.jpg', 58, '2023-10-22 22:02:58'),
(755, 'В полчаса с небольшим кони пронесли Чичикова чрез десятиверстное пространство —.', 'В полчаса с небольшим кони пронесли Чичикова чрез десятиверстное пространство — сначала дубровою, потом хлебами, начинавшими зеленеть посреди свежей орани, потом горной окраиной, с которой поминутно открывались виды на отдаленья.', 'В полчаса с небольшим кони пронесли Чичикова чрез десятиверстное пространство — сначала дубровою, потом хлебами, начинавшими зеленеть посреди свежей орани, потом горной окраиной, с которой поминутно открывались виды на отдаленья, — и широкою аллеею раскидистых лип внесли его в генеральскую деревню. Аллея лип превратилась в аллею тополей, огороженных снизу плетеными коробками, и уперлась в чугунные сквозные ворота, сквозь которые глядел кудряво-великолепный резной фронтон генеральского дома, опиравшийся на восемь колонн с коринфскими капителями. Пахнуло повсюду масляной краской, которою беспрерывно обновлялося все, ничему не давая состареться. Двор чистотой подобен был паркету. Подкативши к подъезду, Чичиков с почтеньем соскочил на крыльцо, приказал о себе доложить и был введен прямо в кабинет к генералу.', '203.jpg', 47, '2023-10-12 18:52:52'),
(756, 'Генерал поразил его величественной наружностью.', 'Генерал поразил его величественной наружностью. Он был на ту пору в атласном малиновом халате.', ' Открытый взгляд, лицо мужественное, бакенбарды и большие усы с проседью, стрижка низкая, а на затылке даже под гребенку, шея толстая, широкая, так называемая в три этажа или в три складки с трещиной поперек, голос — бас с некоторою охрипью, движения генеральские. Генерал Бетрищев, как и все мы грешные, был одарен многими достоинствами и многими недостатками. То и другое, как случается в русском человеке, было набросано в нем в каком-то картинном беспорядке. Самопожертвованье, великодушье в решительные минуты, храбрость, ум и — ко всему зтому — изрядная подмесь себялюбья, честолюбья, самолюбия, мелочной щекотливости личной и многого того, без чего уже не обходится человек. Всех, которые ушли вперед его по службе, он не любил, выражался о них едко, в сардонических, колких эпиграммах. Всего больше доставалось от него его прежнему сотоварищу, которого считал он ниже себя и умом и способностями, и который, однако же, обогнал его и был уже генерал-губернатором двух губерний, и как нарочно тех, в которых находились его поместья, так что он очутился как бы в зависимости от него. В отместку язвил он его при всяком случае, критиковал всякое распоряженье и видел во всех мерах и действиях его верх неразумия. Несмотря на доброе сердце, генерал был насмешлив. Вообще говоря, он любил первенствовать, любил фимиам, любил блеснуть и похвастаться умом, любил знать то, чего другие не знают, и не любил тех людей, которые знают что-нибудь такое, чего он не знает. Воспитанный полуиностранным воспитаньем, он хотел сыграть в то же время роль русского барина. С такой неровностью в характере, с такими крупными, яркими противуположностями, он должен был неминуемо встретить по службе кучу неприятностей, вследствие которых и вышел в отставку, обвиняя во всем какую-то враждебную партию и не имея великодушии обвинить в чем-либо себя самого. В отставке сохранил он ту же картинную, величавую осанку. В сертуке ли, во фраке ли, в халате — он был все тот же.', '100.jpg', 12, '2023-10-03 16:40:17'),
(757, 'Чичиков почувствовал то и другое: и уваженье и робость.', 'Чичиков почувствовал то и другое: и уваженье и робость.', ' Наклоня почтительно голову набок, начал он так.', '102.jpg', 33, '2023-09-25 11:08:51'),
(758, '— Счел долгом представиться вашему превосходительству.', '— Счел долгом представиться вашему превосходительству. Питая уваженье к доблестям мужей, спасавших отечество на бранном поле, счел долгом представиться лично вашему превосходительству.', '.', '102.jpg', 57, '2023-09-17 08:15:53'),
(759, 'Генералу, как видно, не не понравился такой приступ.', 'Генералу, как видно, не не понравился такой приступ.', ' Сделавши весьма милостивое движенье головою, он сказал.', '302.jpg', 60, '2023-09-16 02:44:26'),
(760, '— Поприще службы моей, — сказал Чичиков, садясь в кресла не в середине.', '— Поприще службы моей, — сказал Чичиков, садясь в кресла не в середине, но наискось, и ухватившись рукою за ручку кресел, — началось в казенной палате, ваше превосходительство, дальнейшее же теченье оной продолжал в разных местах.', '— Поприще службы моей, — сказал Чичиков, садясь в кресла не в середине, но наискось, и ухватившись рукою за ручку кресел, — началось в казенной палате, ваше превосходительство; дальнейшее же теченье оной продолжал в разных местах: был и в надворном суде, и в комиссии построения, и в таможне. Жизнь мою можно уподобить судну среди волн, ваше превосходительство. На терпенье, можно сказать, вырос, терпеньем воспоен, терпеньем спеленат, и сам, так сказать, не что другое, как одно терпенье. А уж сколько претерпел от врагов, так ни слова, ни краски не сумеют передать. Теперь же, на вечере, так сказать, жизни своей, ищу уголка, где бы провесть остаток дней.', '202.jpg', 45, '2023-09-14 02:33:00'),
(761, '— Он, ваше превосходительство, весьма раскаивается в том.', '— Он, ваше превосходительство, весьма раскаивается в том.', '— Он, ваше превосходительство, весьма раскаивается в том.', '002.jpg', 15, '2023-09-11 01:57:32'),
(762, '— К заслугам вашего превосходительства. Не находит слов.', '— К заслугам вашего превосходительства. Не находит слов. Говорит: «Если бы я только мог чему-нибудь… потому что, точно, говорит, умею ценить мужей, спасавших отечество», — говорит.', '.', '101.jpg', 40, '2023-09-10 01:12:17'),
(763, '— Помилуйте, что ж он?.. Да ведь я не сержусь! — сказал смягчившийся генерал.', '— Помилуйте, что ж он?.. Да ведь я не сержусь! — сказал смягчившийся генерал. — В душе моей я искренно полюбил его и уверен, что со временем он будет преполезный человек.', '.', '102.jpg', 13, '2023-09-08 23:26:08'),
(764, '— Совершенно справедливо изволите выразиться, ваше превосходительство.', '— Совершенно справедливо изволите выразиться, ваше превосходительство, преполезный человек, обладает даром слова и владеет пером.', '.', '201.jpg', 4, '2023-08-31 17:07:10'),
(765, '— Историю… — тут Чичиков остановился и, оттого ли, что перед ним сидел генерал.', '— Историю… — тут Чичиков остановился и, оттого ли, что перед ним сидел генерал, или просто чтобы придать более важности предмету, прибавил: — историю о генералах, ваше превосходительство.', '.', '201.jpg', 37, '2023-08-22 15:04:17'),
(766, '— Вообще о генералах, ваше превосходительство, в общности… то есть.', '— Вообще о генералах, ваше превосходительство, в общности… то есть, говоря собственно, об отечественных генералах, — сказал Чичиков, а сам подумал: «Чтой-то я за вздор такой несу.', '— Вообще о генералах, ваше превосходительство, в общности… то есть, говоря собственно, об отечественных генералах, — сказал Чичиков, а сам подумал: «Чтой-то я за вздор такой несу.', '202.jpg', 45, '2023-08-18 10:39:12'),
(767, '— Извините, я не очень понимаю… что ж это выходит.', '— Извините, я не очень понимаю… что ж это выходит, историю какого-нибудь времени или отдельные биографии, и притом всех ли или только участвовавших в Двенадцатом году.', '— Извините, я не очень понимаю… что ж это выходит, историю какого-нибудь времени или отдельные биографии, и притом всех ли или только участвовавших в Двенадцатом году.', '203.jpg', 15, '2023-08-15 05:03:19'),
(768, '— Точно так, ваше превосходительство, участвовавших в двенадцатом году.', '— Точно так, ваше превосходительство, участвовавших в двенадцатом году! — Проговоривши это, он подумал в себе: «Хоть убей, не понимаю».', '.', '201.jpg', 60, '2023-08-12 22:44:55'),
(769, '— Так что же он ко мне не приедет.', '— Так что же он ко мне не приедет? Я бы мог собрать ему весьма много любопытных материалов.', '.', '102.jpg', 31, '2023-08-02 20:57:09'),
(770, '— Какой вздор! Из какого-нибудь пустого слова… Да я совсем не такой человек.', '— Какой вздор! Из какого-нибудь пустого слова… Да я совсем не такой человек. Я, пожалуй, к нему сам готов приехать.', '.', '002.jpg', 46, '2023-07-28 19:43:20'),
(771, '— Он к тому не допустит, он сам приедет, — сказал Чичиков.', '— Он к тому не допустит, он сам приедет, — сказал Чичиков, и в то же время подумал в себе: «Генералы пришлись, однако же, кстати; между тем ведь язык совершенно взболтнул сдуру».', '.', '301.jpg', 33, '2023-07-22 15:08:34'),
(772, 'В кабинете послышался шорох. Ореховая дверь резного шкафа отворилась сама собою.', 'В кабинете послышался шорох. Ореховая дверь резного шкафа отворилась сама собою. На обратной половине растворенной двери, ухватившись чудесной рукой за ручку двери, явилась живая фигурка.', ' Если бы в темной комнате вдруг вспыхнула прозрачная картина, освещенная сзади лампою, она бы не поразила так, как эта сиявшая жизнью фигурка, которая точно предстала затем, чтобы осветить комнату. Казалось, как бы вместе с нею влетел солнечный луч в комнату, озаривши вдруг потолок, карниз и темные углы ее. Она казалась блистающего роста. Это было обольщенье: происходило это от необыкновенной стройности и гармонического соотношения между собой всех частей тела, от головы до пальчиков. Одноцветное платье, на ней наброшенное, было наброшено с таким вкусом, что казалось, швеи столиц делали совещанье между собой, как бы получше убрать ее. Это был обман. Оделась она кое-как, сама собой: в двух, трех местах схватила неизрезанный кусок ткани, и он прильнул и расположился вокруг нее в таких складках, что ваятель перенес бы их тотчас же на мрамор, и барышни, одетые по моде, все казались перед ней какими-то пеструшками. Несмотря на то что Чичикову почти знакомо было лицо ее по рисункам Андрея Ивановича, он смотрел на нее как оторопелый и после, ужо очнувшись, заметил, что у ней был существенный недостаток, именно — недостаток толщины.', '002.jpg', 7, '2023-07-21 13:59:42'),
(773, '— Рекомендую вам мою баловницу! — сказал генерал, обратись к Чичикову.', '— Рекомендую вам мою баловницу! — сказал генерал, обратись к Чичикову. — Однако ж я вашего имени и отчества до сих пор не знаю.', '.', '202.jpg', 16, '2023-07-15 11:22:57'),
(774, '— Впрочем, должно ли быть знаемо имя и отчество человека.', '— Впрочем, должно ли быть знаемо имя и отчество человека, не ознаменовавшего себя доблестями? — сказал Чичиков.', '.', '203.jpg', 44, '2023-07-09 10:15:14'),
(775, '— Павел Иванович, ваше превосходительство, — проговорил Чичиков.', '— Павел Иванович, ваше превосходительство, — проговорил Чичиков, с легким наклоном головы набок.', '.', '100.jpg', 28, '2023-06-29 05:58:32'),
(776, '— Улинька! Павел Иванович сейчас сказал преинтересную новость.', '— Улинька! Павел Иванович сейчас сказал преинтересную новость. Сосед наш Тентетников совсем не такой глупый человек, как мы полагали. Он занимается довольно важным делом: историей генералов двенадцатого года.', '.', '103.jpg', 27, '2023-06-23 05:29:40'),
(777, '— Да кто же думал, что он глупый человек? — проговорила она быстро.', '— Да кто же думал, что он глупый человек? — проговорила она быстро.', ' — Это мог думать разве один только Вишнепокромов, которому ты веришь, папа, который и пустой и низкий человек.', '203.jpg', 50, '2023-06-16 04:05:13'),
(778, '— Он подловат и гадковат, не только что пустоват, — подхватила живо Улинька.', '— Он подловат и гадковат, не только что пустоват, — подхватила живо Улинька.', ' — Кто так обидел своих братьев и выгнал из дому родную сестру.', '100.jpg', 38, '2023-06-10 01:04:29'),
(779, '— Рассказывать не будут напрасно.', '— Рассказывать не будут напрасно. У тебя, отец, добрейшая душа и редкое сердце, но ты поступаешь так, что иной подумает о тебе совсем другое.', ' Ты будешь принимать человека, о котором сам знаешь, что он дурен, потому что он только краснобай и мастер перед тобой увиваться.', '103.jpg', 38, '2023-05-30 22:30:15'),
(780, '— А вот и нет, ваше превосходительство, — сказал Чичиков Улиньке.', '— А вот и нет, ваше превосходительство, — сказал Чичиков Улиньке, с легким наклоном головы, с приятной улыбкой. — По христианству именно таких мы должны любить.', '.', '201.jpg', 34, '2023-05-20 17:16:01'),
(781, '— Изволили ли, ваше превосходительство, слышать когда-нибудь о том.', '— Изволили ли, ваше превосходительство, слышать когда-нибудь о том, что такое — «полюби нас черненькими, а беленькими нас всякий полюбит».', '— Изволили ли, ваше превосходительство, слышать когда-нибудь о том, что такое — «полюби нас черненькими, а беленькими нас всякий полюбит».', '202.jpg', 15, '2023-05-11 14:06:11'),
(782, '— А это преказусный анекдот, — сказал Чичиков с плутоватой улыбкой.', '— А это преказусный анекдот, — сказал Чичиков с плутоватой улыбкой.', ' — В имении, ваше превосходительство, у князя Гукзовского, которого, без сомнения, ваше превосходительство.', '301.jpg', 33, '2023-05-02 08:11:28'),
(783, '— Был управитель, ваше превосходительство, из немцев, молодой человек.', '— Был управитель, ваше превосходительство, из немцев, молодой человек. По случаю поставки рекрут и прочего имел он надобность приезжать в город и, разумеется, подмазывать судейских.', ' — Тут Чичиков, прищуря глаз, выразил в лице своем, как подмазываются судейские. — Впрочем, и они тоже полюбили, угощали его. Вот как-то один раз у них на обеде говорит он: «Что ж, господа, когда-нибудь и ко мне, в имение к князю». Говорят: «Приедем». Скоро после того случилось выехать суду на следствие, по делу, случившемуся во владениях графа Трехметьева, которого, ваше превосходительство, без сомнения, тоже изволите знать.', '202.jpg', 21, '2023-04-26 03:27:02'),
(784, '— Самого-то следствия они не делали.', '— Самого-то следствия они не делали, а всем судом заворотили на экономический двор, к старику, графскому эконому, да три дни и три ночи без просыпу — в карты. Самовар и пунш, разумеется, со стола не сходят. Старику-то они уж и надоели.', ' Чтобы как-нибудь от них отделаться, он и говорит: «Вы бы, господа, заехали к княжому управителю немцу: он недалеко отсюда и вас ждет». — «А и в самом деле», — говорят, и сполупьяна, небритые и заспанные, как были, на телеги да к немцу… А немец, ваше превосходительство, надобно знать, в это время только что женился. Женился на институтке, молоденькой, субтильной (Чичиков выразил в лице своем субтильность). Сидят они двое за чаем, ни о чем не думая, вдруг отворяются двери — и ввалилось сонмище.', '101.jpg', 38, '2023-04-15 23:45:06'),
(785, '— Управитель так и оторопел, говорит: «Что вам угодно.', '— Управитель так и оторопел, говорит: «Что вам угодно?» — «А! говорят, так вот ты как!» И вдруг, с этим словом, перемена лиц и физиогномии… «За делом! Сколько вина выкуривается по именью? Покажите книги!» Тот сюды-туды.', ' «Эй, понятых!» Взяли, связали, да в город, да полтора года и просидел немец в тюрьме.', '101.jpg', 19, '2023-04-10 22:08:57'),
(786, '— Жена — хлопотать! — продолжал Чичиков.', '— Жена — хлопотать! — продолжал Чичиков. — Ну, что ж может какая-нибудь неопытная молодая женщина? Спасибо, что случились добрые люди, которые посоветовали пойти на мировую. Отделался он двумя тысячами да угостительным обедом.', ' И на обеде, когда все уже развеселились, и он также, вот и говорят они ему: «Не стыдно ли тебе так поступить с нами? Ты все бы хотел нас видеть прибранными, да выбритыми, да во фраках. Нет, ты полюби нас черненькими, а беленькими нас всякий полюбит».', '102.jpg', 1, '2023-04-08 21:01:49'),
(787, '— Я не понимаю, папа, как ты можешь смеяться! — сказала она быстро.', '— Я не понимаю, папа, как ты можешь смеяться! — сказала она быстро.', ' Гнев отемнил прекрасный лоб ее… — Бесчестнейший поступок, за который я не знаю.', '002.jpg', 15, '2023-03-31 20:30:20'),
(788, '— Друг мой, я их ничуть не оправдываю, — сказал генерал, — но что ж делать.', '— Друг мой, я их ничуть не оправдываю, — сказал генерал, — но что ж делать, если смешно? Как бишь: «полюби нас беленькими»?..', '.', '002.jpg', 34, '2023-03-23 20:05:16'),
(789, 'И туловище генерала стало колебаться от смеха.', 'И туловище генерала стало колебаться от смеха. Плечи, носившие некогда густые эполеты, тряслись, точно как бы носили и поныне густые эполеты.', '.', '102.jpg', 6, '2023-03-20 18:51:58'),
(790, 'Чичиков разрешился тоже междуиметием смеха, но, из уважения к генералу.', 'Чичиков разрешился тоже междуиметием смеха, но, из уважения к генералу, пустил его на букву э: хе, хе, хе, хе, хе! И туловище его также стало колебаться от смеха, хотя плечи и не тряслись, потому что не носили густых эполет.', '.', '201.jpg', 53, '2023-03-11 16:00:27'),
(791, '— Да, ваше превосходительство.', '— Да, ваше превосходительство, как бы то ни было… без просыпу… трехдневное бдение — тот же пост; поизнурились, поизнурились! — говорил Чичиков, продолжая смеяться.', '.', '101.jpg', 30, '2023-03-05 15:48:31'),
(792, 'Улинька опустилась в кресла и закрыла рукой прекрасные глаза.', 'Улинька опустилась в кресла и закрыла рукой прекрасные глаза, как бы досадуя на то, что не с кем было поделиться негодованием, сказала ока.', 'Улинька опустилась в кресла и закрыла рукой прекрасные глаза, как бы досадуя на то, что не с кем было поделиться негодованием, сказала ока.', '102.jpg', 11, '2023-02-24 15:04:04'),
(793, 'В самом деле, необыкновенно странны были своею противуположностью те чувства.', 'В самом деле, необыкновенно странны были своею противуположностью те чувства, которые родились в сердцах троих беседовавших людей. Одному была смешна неповоротливая ненаходчивость немца. Другому смешно было оттого, что смешно изворотились плуты.', ' Третьему было грустно, что безнаказанно совершился несправедливый поступок. Не было только четвертого, который бы задумался именно над этими словами, произведшими смех в одном и грусть з другом. Что значит, однако же, что и в паденье своем гибнущий грязный человек требует любви к себе? Животный ли инстинкт это? или слабый крик души, заглушённой тяжелым гнетом подлых страстей, еще пробивающийся сквозь деревенеющую кору мерзостей, еще вопиющий: «Брат, спаси!» Не было четвертого, которому бы тяжелей всего была погибающая душа его брата.', '102.jpg', 54, '2023-02-20 10:12:38'),
(794, '— Я не знаю, — говорила Улипька, отнимая от лица руку.', '— Я не знаю, — говорила Улипька, отнимая от лица руку, — меня одна только досада берет.', '.', '301.jpg', 34, '2023-02-12 09:30:03'),
(795, '— Только, пожалуйста, не гневайся на нас, — сказал генерал.', '— Только, пожалуйста, не гневайся на нас, — сказал генерал. — Мы тут ни в чем не виноваты. Поцелуй меня и уходи к себе, потому что я сейчас буду одеваться к обеду.', ' Ведь ты, — сказал генерал, вдруг обратись к Чичикову, — обедаешь у меня.', '201.jpg', 4, '2023-02-11 08:20:48'),
(796, 'Чичиков приятно наклонил голову, и, когда приподнял потом ее вверх.', 'Чичиков приятно наклонил голову, и, когда приподнял потом ее вверх, он уже не увидал Улиньки. Она исчезнула. Наместо ее предстал, в густых усах и бакенбардах, великан-камердинер, с серебряной лоханкой и рукомойником в руках.', '.', '100.jpg', 49, '2023-02-04 03:25:16'),
(797, '— Ты мне позволишь одеваться при себе.', '— Ты мне позволишь одеваться при себе? — сказал генерал, скидая халат и засучивая рукава рубашки на богатырских руках.', '.', '102.jpg', 52, '2023-01-26 02:53:39'),
(798, '— Помилуйте, не только одеваться, ко можете совершать при мне все.', '— Помилуйте, не только одеваться, ко можете совершать при мне все, что угодно вашему превосходительству, — сказал Чичиков.', '.', '201.jpg', 24, '2023-01-23 01:07:57'),
(799, 'Генерал стал умываться, брызгаясь и фыркая, как утка.', 'Генерал стал умываться, брызгаясь и фыркая, как утка. Вода с мылом летела во все стороны.', '.', '302.jpg', 25, '2023-01-18 20:07:43'),
(800, '— Как бишь.', '— Как бишь? — сказал он, вытирая со всех сторон свою толстую шею, — полюби нас беленькими?..', '.', '201.jpg', 44, '2023-01-12 17:45:15'),
(801, '— Полюби нас черненькими, а беленькими нас всякий полюбит.', '— Полюби нас черненькими, а беленькими нас всякий полюбит.', ' Очень, очень хорошо.', '103.jpg', 59, '2023-01-04 16:01:32'),
(802, '— История тоже смешная, но мне-то от ней не смешно.', '— История тоже смешная, но мне-то от ней не смешно.', ' Даже так.', '203.jpg', 16, '2022-12-31 14:42:59'),
(803, '— Да вот, ваше превосходительство, как!..', '— Да вот, ваше превосходительство, как!.. — Тут Чичиков осмотрелся и, увидя, что камердинер с лоханкою вышел, начал так: — Есть у меня дядя, дряхлый старик. У него триста душ и, кроме меня, наследников никого.', ' Сам управлять именьем, по дряхлости, не может, а мне не передает тоже.', '203.jpg', 3, '2022-12-22 09:53:43'),
(804, '«Я, говорит, племянника не знаю; может быть, он мот.', '«Я, говорит, племянника не знаю; может быть, он мот. Пусть он докажет мне, что он надежный человек, пусть приобретет прежде сам собой триста душ, тогда я ему отдам и свои триста душ».', '.', '102.jpg', 52, '2022-12-20 08:30:20'),
(805, '— Справедливо изволили заметить, ваше превосходительство.', '— Справедливо изволили заметить, ваше превосходительство. Но представьте же теперь мое положение… — Тут Чичиков, понизивши голос, стал говорить как бы по секрету: — У него в доме, ваше превосходительство, есть ключница, а у ключницы дети.', ' Того и смотри, все перейдет им.', '302.jpg', 11, '2022-12-13 03:41:12'),
(806, '— Выжил глупый старик из ума, и больше ничего, — сказал генерал.', '— Выжил глупый старик из ума, и больше ничего, — сказал генерал. — Только я не вижу, чем тут я могу пособить.', '.', '002.jpg', 9, '2022-12-09 21:43:37'),
(807, '— Я придумал вот что.', '— Я придумал вот что.', ' Теперь, покуда новые ревижские сказки не поданы, у помещиков больших имений наберется немало, наряду с душами живыми, отбывших и умерших… Так, если, например, ваше превосходительство передадите мне их в таком виде, как бы они были живые, с совершением купчей крепости, я бы тогда эту крепость представил старику, и он, как ни вертись, а наследство бы мне отдал.', '302.jpg', 57, '2022-12-06 20:41:27'),
(808, 'Тут генерал разразился таким смехом, каким вряд ли когда смеялся человек.', 'Тут генерал разразился таким смехом, каким вряд ли когда смеялся человек: как был, так и повалился он в кресла; голову забросил назад и чуть не захлебнулся. Весь дом встревожился. Предстал камердинер. Дочь прибежала в испуге.', '.', '203.jpg', 36, '2022-12-02 15:27:14'),
(809, '— Ничего, мой друг. Ха, ха, ха! Ступай к себе, мы сейчас явимся обедать.', '— Ничего, мой друг. Ха, ха, ха! Ступай к себе, мы сейчас явимся обедать.', ' Ха, ха, ха.', '102.jpg', 57, '2022-11-23 12:51:51'),
(810, 'И несколько раз задохнувшись, вырывался с новою силою генеральский хохот.', 'И несколько раз задохнувшись, вырывался с новою силою генеральский хохот, раздаваясь от передней до последней комнаты в высоких, звонких генеральских покоях.', '.', '201.jpg', 33, '2022-11-19 07:01:22'),
(811, '— Ну, брат, извини: тебя сам черт угораздил на такую штуку.', '— Ну, брат, извини: тебя сам черт угораздил на такую штуку.', ' Ха, ха, ха! Попотчевать старика, подсунуть ему мертвых! Ха, ха, ха, ха! Дядя-то, дядя! В каких дураках дядя! Ха, ха, ха, ха.', '202.jpg', 3, '2022-11-10 00:54:39'),
(812, 'Положение Чичикова было конфузное, тут же стоял камердинер.', 'Положение Чичикова было конфузное: тут же стоял камердинер, разинувши рот и выпуча глаза.', '.', '201.jpg', 0, '2022-11-02 00:26:36'),
(813, '— Извини, брат! Ну, уморил.', '— Извини, брат! Ну, уморил. Да я бы пятьсот тысяч дал за то только, чтобы посмотреть на твоего дядю в то время, как ты поднесешь ему купчую на мертвые души.', ' Да что, он слишком стар! Сколько ему лет.', '203.jpg', 51, '2022-10-27 23:21:02'),
(814, '— Восемьдесят лет, ваше превосходительство.', '— Восемьдесят лет, ваше превосходительство. Но это келейное, я бы… чтобы… — Чичиков посмотрел значительно в лицо генерала и в то же время искоса на камердинера.', '.', '101.jpg', 15, '2022-10-24 20:22:30'),
(815, '— Поди вон, братец. Придешь после, — сказал генерал камердинеру. Усач удалился.', '— Поди вон, братец. Придешь после, — сказал генерал камердинеру. Усач удалился.', '.', '301.jpg', 54, '2022-10-18 15:43:40'),
(816, '— Да, ваше превосходительство… Это, ваше превосходительство, дело такое.', '— Да, ваше превосходительство… Это, ваше превосходительство, дело такое.', '— Да, ваше превосходительство… Это, ваше превосходительство, дело такое.', '103.jpg', 8, '2022-10-09 09:57:28'),
(817, '— Разумеется, я это очень понимаю.', '— Разумеется, я это очень понимаю.', ' Экой дурак старик! Ведь придет же в восемьдесят лет этакая дурь в голову! Да что, он с виду как? бодр? держится еще на ногах.', '101.jpg', 34, '2022-10-02 07:15:01'),
(818, '— Точно так, ваше превосходительство.', '— Точно так, ваше превосходительство. Хоть он мне и родственник, и тяжело сознаваться в этом, но действительно — осел.', '.', '203.jpg', 28, '2022-09-26 02:54:13'),
(819, 'Впрочем, как читатель может смекнуть и сам.', 'Впрочем, как читатель может смекнуть и сам, Чичикову не тяжело было в этом сознаться, тем более что вряд ли у него был когда-либо какой дядя.', '.', '302.jpg', 52, '2022-09-20 23:43:41'),
(820, '— Чтобы отдать тебе мертвых душ.', '— Чтобы отдать тебе мертвых душ.', '— Чтобы отдать тебе мертвых душ.', '100.jpg', 29, '2022-09-13 19:56:51'),
(821, '«Нет, я не так, — говорил Чичиков.', '«Нет, я не так, — говорил Чичиков, очутившись опять посреди открытых полей и пространств, — нет, я не так распоряжусь.', ' Как только, даст бог, все покончу благополучно и сделаюсь действительно состоятельным, зажиточным человеком, я поступлю тогда совсем иначе: будет у меня и повар, и дом, как полная чаша, но будет и хозяйственная часть в порядке.', '202.jpg', 30, '2022-09-08 16:10:05'),
(822, '— Да так изволили приказывать, Павел Иванович, — к полковнику Кошкареву.', '— Да так изволили приказывать, Павел Иванович, — к полковнику Кошкареву, — сказал Селифан.', '.', '103.jpg', 50, '2022-08-29 10:47:03'),
(823, '— Я, Павел Иванович, изволите видеть, так как все хлопотал около коляски.', '— Я, Павел Иванович, изволите видеть, так как все хлопотал около коляски, так оно-с… генеральского конюха только видел… А Петрушка расспрашивал у кучера.', '.', '202.jpg', 39, '2022-08-26 09:48:22'),
(824, '— Ведь тут не мудрость какая, — сказал Петрушка, глядя искоса, — окроме того.', '— Ведь тут не мудрость какая, — сказал Петрушка, глядя искоса, — окроме того, что, спустись с горы, взять попрямей, ничего больше и нет.', '.', '301.jpg', 18, '2022-08-24 09:03:16'),
(825, '— А ты, окроме сивухи, ничего больше, чай, и в рот не брал.', '— А ты, окроме сивухи, ничего больше, чай, и в рот не брал? Чай, и теперь налимонился.', '— А ты, окроме сивухи, ничего больше, чай, и в рот не брал? Чай, и теперь налимонился.', '302.jpg', 35, '2022-08-21 02:41:47'),
(826, 'Увидя, что речь повернула вона в какую сторону, Петрушка закрутил только носом.', 'Увидя, что речь повернула вона в какую сторону, Петрушка закрутил только носом. Хотел он было сказать, что даже и не пробовал, да уж как-то и самому стало стыдно.', '.', '203.jpg', 43, '2022-08-17 23:49:43'),
(827, '— Говорю, Павел Иванович, что в коляске-де вашей милости хорошо-с ехать.', '— Говорю, Павел Иванович, что в коляске-де вашей милости хорошо-с ехать, получше-с, как в бричке — не трясет.', '.', '103.jpg', 49, '2022-08-13 18:39:14'),
(828, 'Селифан хлыснул слегка бичом по крутым бокам лошадей и поворотил речь к.', 'Селифан хлыснул слегка бичом по крутым бокам лошадей и поворотил речь к Петрушке.', 'Селифан хлыснул слегка бичом по крутым бокам лошадей и поворотил речь к Петрушке.', '100.jpg', 23, '2022-08-07 13:44:23'),
(829, '— Слышь, мужика Кошкарев барин одел, говорит, сак немца.', '— Слышь, мужика Кошкарев барин одел, говорит, сак немца; поодаль и не распознаешь, — выступает по-журавлиному, как немец.', ' И на бабе не то чтобы платок, как бывает, пирогом или кокошник на голове, а немецкий капор такой, как немки ходят, знашь, в капорах, — так капор называется, знашь, капор. Немецкий такой капор.', '101.jpg', 9, '2022-07-29 08:58:05'),
(830, '— А тебя как бы нарядить немцем да в капор.', '— А тебя как бы нарядить немцем да в капор! — сказал Петрушка, острясь над Селифаном и ухмыльнувшись.', ' Но что за рожа вышла из этой усмешки! И подобья не было на усмешку, а точно как бы человек, доставши себе В нос насморк и силясь при насморке чихнуть, не чихнул, но так и остался в положенье человека, собирающегося чихнуть.', '100.jpg', 14, '2022-07-27 04:11:46'),
(831, 'Чичиков заглянул из-под низа ему в рожу, желая знать, что там делается.', 'Чичиков заглянул из-под низа ему в рожу, желая знать, что там делается, и сказал: «Хорош! а еще воображает, что красавец.', 'Чичиков заглянул из-под низа ему в рожу, желая знать, что там делается, и сказал: «Хорош! а еще воображает, что красавец!» Надобно сказать, что Павел Иванович был сурьезно уверен в том, что Петрушка влюблен в красоту свою, тогда как последний временами позабывал, есть ли у него даже вовсе рожа.', '101.jpg', 1, '2022-07-19 23:06:50'),
(832, '— Вот как бы догадались было, Павел Иванович, — сказал Селифан.', '— Вот как бы догадались было, Павел Иванович, — сказал Селифан, оборотившись с козел, — чтобы выпросить у Андрея Ивановича другого коня, в обмен на чубарого, он бы, по дружественному расположению к вам, не отказал бы, а это конь-с, право.', '— Вот как бы догадались было, Павел Иванович, — сказал Селифан, оборотившись с козел, — чтобы выпросить у Андрея Ивановича другого коня, в обмен на чубарого; он бы, по дружественному расположению к вам, не отказал бы, а это конь-с, право, подлец-лошадь и помеха.', '103.jpg', 34, '2022-07-16 16:58:07'),
(833, '— Пошел, пошел, не болтай.', '— Пошел, пошел, не болтай! — сказал Чичиков и про себя подумал: «В самом деле, напрасно я не догадался».', '.', '100.jpg', 57, '2022-07-14 14:14:25'),
(834, 'Легким ходом неслась тем временем легкая на ходу коляска.', 'Легким ходом неслась тем временем легкая на ходу коляска. Легко подымалась и вверх, хотя подчас и неровна была дорога; легко опускалась и под гору, хотя и беспокойны были спуски проселочных дорог. С горы спустились.', ' Дорога шла лугами через извивы реки, мимо мельниц. Вдали мелькали пески, выступали картинно одна из-за другой осиновые рощи; быстро пролетали мимо их кусты лоз, тонкие ольхи и серебристые тополи, ударявшие ветвями сидевших на козлах Селифана и Петрушку. С последнего ежеминутно сбрасывали они картуз. Суровый служитель соскакивал с козел, бранил глупое дерево и хозяина, который насадил его, но привязать картуза или даже придержать рукою не догадался, все надеясь на то, что авось дальше не случится. Деревья же становились гуще: к осинам и ольхам начала присоединяться береза, и скоро образовалась вокруг лесная гущина. Свет солнца сокрылся. Затемнели сосны и ели. Непробудный мрак бесконечного леса сгущался и, казалось, готовился превратиться в ночь. И вдруг промеж дерев — свет, там и там промеж ветвей и пней, точно живое серебро или зеркала. Лес стал освещаться, деревья редеть, послышались крики — и вдруг перед ними озеро. Водная равнина версты четыре в поперечнике, вокруг дерева, позади их избы. Человек двадцать, по пояс, по плеча и по горло в воде, тянули к супротивному берегу невод. Посреди их плавал проворно, кричал и хлопотал за всех человек, почти такой же меры в вышину, как и в толщину, круглый кругом, точный арбуз. По причине толщины, он уже не мог ни в каком случае потонуть и как бы ни кувыркался, желая нырнуть, вода бы его все выносила наверх; и если бы село к нему на спину еще двое человек, он бы, как упрямый пузырь, остался с ними на верхушке воды, слегка только под ними покряхтывал да пускал носом и ртом пузыри.', '100.jpg', 21, '2022-07-06 10:27:36'),
(835, '— Этот, Павел Иванович, — сказал Селифан, оборотись с козел.', '— Этот, Павел Иванович, — сказал Селифан, оборотись с козел, — должен быть барин, полковник Кошкарев.', '— Этот, Павел Иванович, — сказал Селифан, оборотись с козел, — должен быть барин, полковник Кошкарев.', '201.jpg', 16, '2022-06-29 08:18:20'),
(836, '— Оттого, что тело у него, изволите видеть, побелей, чем у других.', '— Оттого, что тело у него, изволите видеть, побелей, чем у других, и дородство почтительное, как у барина.', '.', '201.jpg', 13, '2022-06-24 05:44:37'),
(837, 'Крики между тем становились явственней.', 'Крики между тем становились явственней.', ' Скороговоркой и звонко выкрикивал барин-арбуз.', '202.jpg', 51, '2022-06-16 03:01:24'),
(838, '— Передавай, передавай, Денис, Козьме! Козьма, бери хвост у Дениса.', '— Передавай, передавай, Денис, Козьме! Козьма, бери хвост у Дениса! Фома Большой, напирай туды же, где и Фома Меньшой! Заходи справа, справа заходи! Стой, стой, черт вас побери обоих! Запутали меня самого в невод.', '— Передавай, передавай, Денис, Козьме! Козьма, бери хвост у Дениса! Фома Большой, напирай туды же, где и Фома Меньшой! Заходи справа, справа заходи! Стой, стой, черт вас побери обоих! Запутали меня самого в невод! Зацепили, говорю, проклятые, зацепили за пуп.', '103.jpg', 54, '2022-06-06 00:32:13'),
(839, 'Влачители правого крыла остановились, увидя.', 'Влачители правого крыла остановились, увидя, что действительно случилась непредвиденная оказия: барин запутался в сети.', '.', '203.jpg', 23, '2022-05-29 19:04:58'),
(840, 'Барин барахтался и, желая выпутаться, перевернулся на спину, брюхом вверх.', 'Барин барахтался и, желая выпутаться, перевернулся на спину, брюхом вверх, запутавшись еще в сетку. Боясь оборвать сеть, плыл он вместе с пойманною рыбою, приказавши себя перехватить только впоперек веревкой.', ' Перевязавши его веревкой, бросили конец ее на берег. Человек с двадцать рыбаков, стоявших на берегу, подхватили конец и стали бережно тащить его. Добравшись до мелкого места, барин стал на ноги, покрытый клетками сети, как в летнее время дамская ручка под сквозной перчаткой, — взглянул вверх и увидел гостя, в коляске взъезжавшего на плотину. Увидя гостя, кивнул он головой. Чичиков снял картуз и учтиво раскланялся с коляски.', '202.jpg', 11, '2022-05-19 14:01:17'),
(841, '— Обедали.', '— Обедали? — закричал барин, подходя с пойманною рыбою на берег, держа одну руку над глазами козырьком в защиту от солнца, другую же пониже — на манер Венеры Медицейской, выходящей из бани.', '.', '202.jpg', 3, '2022-05-17 10:59:07'),
(842, '— А вот что.', '— А вот что! — сказал барин, очутившийся на берегу вместе с коропами и карасями, которые бились у ног его и прыгали на аршин от земли. — Это ничего, на это не глядите; а вот штука, вон где!.. А покажите-ка, Фома Большой, осетра.', ' — Два здоровых мужика вытащили из кадушки какое-то чудовище.', '101.jpg', 47, '2022-05-08 04:47:38'),
(843, '— Вот то-то же. Поезжайте-ка вы теперь вперед, а я за вами.', '— Вот то-то же. Поезжайте-ка вы теперь вперед, а я за вами. Кучер, ты, братец, возьми дорогу пониже, через огород. Побеги, телепень Фома Меньшой, снять перегородку. А я за вами — как тут, прежде чем успеете оглянуться.', '.', '202.jpg', 33, '2022-05-04 01:22:44'),
(844, '«Полковник чудаковат», — подумал Чичиков.', '«Полковник чудаковат», — подумал Чичиков, проехавши наконец бесконечную плотину и подъезжая к избам, из которых одни, подобно стаду уток, рассыпались по косогору возвышенья, а другие стояли внизу на сваях, как цапли.', ' Сети, невода, бредни развешены были повсюду. Фома Меньшой снял перегородку, коляска проехала огородом и очутилась на площади возле устаревшей деревянной церкви. За церковью, подальше, видны были крыши господских строений.', '301.jpg', 35, '2022-04-24 20:24:07'),
(845, '— А вот я и здесь! — раздался голос сбоку. Чичиков оглянулся.', '— А вот я и здесь! — раздался голос сбоку. Чичиков оглянулся. Барин уже ехал возле него, одетый, на дрожках — травяно-зеленый нанковый сюртук, желтые штаны и шея без галстука, на манер купидона! Боком сидел он на дрожках, занявши собою все дрожки.', ' Чичиков хотел было что-то сказать ему, но толстяк уже исчез. Дрожки показались на другой стороне, и только слышался голос: «Щуку и семь карасей отнесите повару-телепню, а осетра подавай сюда: я его свезу сам на дрожках». Раздались снова голоса: «Фома Большой да Фома Меньшой! Козьма да Денис!» Когда же подъехал он к крыльцу дома, к величайшему изумленью его, толстый барин был уже на крыльце и принял его в свои объятья. Как он успел слетать, было непостижимо. Они поцеловались троекратно навкрест.', '203.jpg', 40, '2022-04-15 19:53:19'),
(846, '— Как же это?..', '— Как же это?..', ' Я надеюсь, по крайней мере, что имею удовольствие говорить с полковником Кошкаревым.', '201.jpg', 7, '2022-04-11 18:17:27'),
(847, '— Вот тебе на.', '— Вот тебе на! Как же вы, дураки, — сказал он, оборотившись к Селифану и Петрушке, которые оба разинули рты и выпучили глаза, один сидя на козлах, другой стоя у дверец коляски, — как же вы, дураки.', '— Вот тебе на! Как же вы, дураки, — сказал он, оборотившись к Селифану и Петрушке, которые оба разинули рты и выпучили глаза, один сидя на козлах, другой стоя у дверец коляски, — как же вы, дураки.', '201.jpg', 43, '2022-04-08 12:32:23'),
(848, '— Ребята сделали отлично! — сказал Петр Петрович.', '— Ребята сделали отлично! — сказал Петр Петрович. — За это вам по чапорухе водки и кулебяка в придачу.', ' Откладывайте коней и ступайте сей же час в людскую.', '201.jpg', 29, '2022-03-29 12:20:22'),
(849, '— Не ошибка, — живо проговорил Петр Петрович Петух, — не ошибка.', '— Не ошибка, — живо проговорил Петр Петрович Петух, — не ошибка. Вы прежде попробуйте, каков обед, да потом скажете: ошибка ли это? Покорнейше прошу, — сказал он, взявши Чичикова под руку и вводя его вэ внутренние покои.', '.', '203.jpg', 8, '2022-03-23 12:04:46'),
(850, 'Чичиков, чинясь, проходил в дверь боком.', 'Чичиков, чинясь, проходил в дверь боком, чтоб дать и хозяину пройти с ним вместе; но это было напрасно: хозяин бы не прошел, да его уж и не было.', ' Слышно было только, как раздавались его речи по двору: «Да что ж Фома Большой? Зачем он до сих пор не здесь? Ротозей Емельян, беги к повару-телепню, чтобы потрошил поскорей осетра. Молоки, икру, потроха и лещей в уху, а карасей — в соус. Да раки, раки! Ротозей Фома Меньшой, где же раки? раки, говорю, раки?!» И долго раздавалися всё — раки да раки.', '002.jpg', 48, '2022-03-15 09:38:45'),
(851, '— Ну, хозяин захлопотался, — сказал Чичиков.', '— Ну, хозяин захлопотался, — сказал Чичиков, садясь в кресла и осматривая углы и стены.', '.', '102.jpg', 36, '2022-03-14 07:36:08'),
(852, '— А вот я и здесь, — сказал, входя, хозяин и ведя за собой двух юношей.', '— А вот я и здесь, — сказал, входя, хозяин и ведя за собой двух юношей, в летних сюртуках. Тонкие, точно ивовые хлысты, выгнало их вверх почти на целый аршин выше Петра Петровича.', '.', '302.jpg', 35, '2022-03-06 06:53:54'),
(853, '— Сыны мои, гимназисты. Приехали на праздники.', '— Сыны мои, гимназисты. Приехали на праздники. Николаша, ты побудь с гостем, а ты, Алексаша, ступай за мной.', '.', '100.jpg', 54, '2022-02-27 05:30:09'),
(854, 'Чичиков занялся с Николашей. Николаша был говорлив.', 'Чичиков занялся с Николашей. Николаша был говорлив.', ' Он рассказал, что у них в гимназии не очень хорошо учат, что больше благоволят к тем, которых маменьки шлют побогаче подарки, что в городе стоит Ингерманландский гусарский полк; что у ротмистра Ветвицкого лучше лошадь, нежели у самого полковника, хотя поручик Взъемцев ездит гораздо его почище.', '100.jpg', 16, '2022-02-25 23:48:29'),
(855, '— Заложено, — сказал на это сам батюшка, снова очутившийся в гостиной.', '— Заложено, — сказал на это сам батюшка, снова очутившийся в гостиной, — заложено.', '.', '103.jpg', 47, '2022-02-24 22:33:47'),
(856, 'Чичикову осталось сделать то же самое движенье губами, которое делает человек.', 'Чичикову осталось сделать то же самое движенье губами, которое делает человек, как дело идет на нуль и оканчивается ничем.', '.', '202.jpg', 1, '2022-02-14 22:29:17'),
(857, '— Да так.', '— Да так. Все пошли закладывать, так зачем же отставать от других? Говорят, выгодно. Притом же все жил здесь, дай-ка еще попробую прожить в Москве.', '.', '203.jpg', 29, '2022-02-10 20:59:21'),
(858, '«Дурак, дурак! — думал Чичиков, — промотает все, да и детей сделает мотишками.', '«Дурак, дурак! — думал Чичиков, — промотает все, да и детей сделает мотишками. Оставался бы себе, кулебяка, в деревне».', '.', '201.jpg', 2, '2022-01-31 18:26:15'),
(859, '— Вы думаете: «Дурак, дурак этот Петух! зазвал обедать, а обеда до сих пор нет».', '— Вы думаете: «Дурак, дурак этот Петух! зазвал обедать, а обеда до сих пор нет». Будет готов, почтеннейший. Не успеет стриженая девка косы заплесть, как он поспеет.', '.', '203.jpg', 55, '2022-01-27 17:02:29'),
(860, '— Верхом на гнедой лошади! — подхватил Николаша, нагибаясь к окну.', '— Верхом на гнедой лошади! — подхватил Николаша, нагибаясь к окну.', ' — Ты думаешь, Алексаша, наш чагравый хуже его.', '102.jpg', 58, '2022-01-18 12:00:59'),
(861, 'Между тем вошел в комнату красавец — стройного роста, светло-русые.', 'Между тем вошел в комнату красавец — стройного роста, светло-русые, блестящие кудри и темные глаза. Гремя медным ошейником, мордатый пес, собака-страшилище, вошел вослед за ним.', '.', '100.jpg', 49, '2022-01-16 11:23:23'),
(862, '— Что ж вы, смеяться, что ли, надо мной приехали? — сказал, сердясь, Петух.', '— Что ж вы, смеяться, что ли, надо мной приехали? — сказал, сердясь, Петух.', ' — Что мне в вас после обеда.', '101.jpg', 49, '2022-01-13 11:16:28'),
(863, '— Впрочем, Петр Петрович, — сказал гость, усмехнувшись, — могу вас утешить тем.', '— Впрочем, Петр Петрович, — сказал гость, усмехнувшись, — могу вас утешить тем, что ничего не ел за обедом: совсем нет аппетита.', '.', '103.jpg', 0, '2022-01-06 06:50:10'),
(864, '— А каков был улов, если б вы видели! Какой осетрище пожаловал.', '— А каков был улов, если б вы видели! Какой осетрище пожаловал! Карасей и не считали.', '.', '302.jpg', 38, '2022-01-05 05:31:24'),
(865, '— Даже завидно вас слушать, — сказал гость.', '— Даже завидно вас слушать, — сказал гость. — Научите меня быть так же веселым, как вы.', '.', '101.jpg', 42, '2021-12-28 03:24:41'),
(866, '— Мало едите, вот и все. Попробуйте-ка хорошенько пообедать.', '— Мало едите, вот и все. Попробуйте-ка хорошенько пообедать. Ведь это в последнее время выдумали скуку. Прежде никто не скучал.', '.', '101.jpg', 4, '2021-12-24 01:13:06'),
(867, '— Никогда! Да и не знаю, даже и времени нет для скучанья.', '— Никогда! Да и не знаю, даже и времени нет для скучанья. Поутру проснешься — ведь нужно пить чай, и тут ведь приказчик, а тут и на рыбную ловлю, а тут и обед.', ' После обеда не успеешь всхрапнуть, а тут и ужин, а после пришел повар — заказывать нужно на завтра обед.', '201.jpg', 33, '2021-12-14 00:17:10'),
(868, 'Платон Михалыч Платонов был Ахиллес и Парид вместе, стройное сложенье.', 'Платон Михалыч Платонов был Ахиллес и Парид вместе: стройное сложенье, картинный рост, свежесть — все было собрано в нем. Приятная усмешка с легким выраженьем иронии как бы еще усиливала его красоту.', ' Но, несмотря на все это, было в нем что-то неоживленное и сонное. Страсти, печали и потрясения не навели морщины на девственное, свежее его лицо, но с тем вместе и не оживили его.', '201.jpg', 56, '2021-12-05 23:51:50'),
(869, '— Признаюсь, я тоже, — произнес Чичиков, — не могу понять.', '— Признаюсь, я тоже, — произнес Чичиков, — не могу понять, если позволите так заметить, не могу понять, как при такой наружности, как ваша, скучать.', ' Конечно, могут быть причины другие: недостача денег, притеснения от каких-нибудь злоумышленников, как есть иногда такие, которые готовы покуситься даже на самую жизнь.', '103.jpg', 39, '2021-11-29 23:26:18'),
(870, '— В том-то и дело, что ничего этого нет, — сказал Платонов.', '— В том-то и дело, что ничего этого нет, — сказал Платонов. — Поверите ли, что иной раз я бы хотел, чтобы это было, чтобы была какая-нибудь тревога и волненья. Ну, хоть бы просто рассердил меня кто-нибудь. Но нет! Скучно — да и только.', '.', '103.jpg', 58, '2021-11-20 19:34:38'),
(871, '— Не понимаю.', '— Не понимаю.', ' Но, может быть, именье у вас недостаточное, малое количество душ.', '100.jpg', 58, '2021-11-19 13:47:41'),
(872, '— Ничуть.', '— Ничуть, у нас с братом земли на десять тысяч десятин и при них тысяча душ крестьян.', '.', '201.jpg', 60, '2021-11-17 12:20:12'),
(873, '— И при этом скучать.', '— И при этом скучать.', ' Непонятно! Но, может быть, именье в беспорядке? были неурожаи, много людей вымерло.', '302.jpg', 36, '2021-11-16 06:21:05'),
(874, '— А вот мы скуку сейчас прогоним, — сказал хозяин.', '— А вот мы скуку сейчас прогоним, — сказал хозяин. — Бежи, Алексаша, проворней на кухню и скажи повару, чтобы поскорей прислал нам расстегайчиков.', ' Да где ж ротозей Емельян и вор Антошка? Зачем не дают закуски.', '301.jpg', 18, '2021-11-13 03:47:32'),
(875, 'Но дверь растворилась.', 'Но дверь растворилась. Ротозей Емельян и вор Антошка явились с салфетками, накрыли стол, поставили поднос с шестью графинами разноцветных настоек.', ' Скоро вокруг подносов и графинов обстановилось ожерелье тарелок — икра, сыры, соленые грузди, опенки, да новые приносы из кухни чего-то в закрытых тарелках, сквозь которые слышно было ворчавшее масло. Ротозей Емельян и вор Антошка были народ хороший и расторопный. Названья эти хозяин давал только потому, что без прозвищ все как-то выходило пресно, а он пресного не любил: сам был добр душой, но словцо любил пряное. Впрочем, и люди за это не сердились.', '203.jpg', 7, '2021-11-02 21:50:41'),
(876, 'Закуске последовал обед.', 'Закуске последовал обед. Здесь добродушный хозяин сделался совершенным разбойником. Чуть замечал у кого один кусок, подкладывал ему тут же другой, приговаривая: «Без пары ни человек, ни птица не могут жить на свете».', ' Съедал гость два — подваливал ему третий, приговаривая: «Что ж за число два? Бог любит троицу». Съедал гость три — он ему: «Где ж бывает телега о трех колесах? Кто ж строит избу о трех углах?» На четыре у него была опять поговорка, на пять — тоже. Чичиков съел чего-то чуть ли не двенадцать ломтей и думал: «Ну, теперь ничего не приберет больше хозяин».', '002.jpg', 54, '2021-10-26 20:37:41'),
(877, '— Да ведь и в церкви не было места. Взошел городничий — нашлось.', '— Да ведь и в церкви не было места. Взошел городничий — нашлось. А ведь была такая давка, что и яблоку; негде было упасть. Вы только попробуйте: этот кусок — тот же городничий.', '.', '202.jpg', 29, '2021-10-22 18:44:16'),
(878, 'Попробовал Чичиков — действительно, кусок был вроде городничего.', 'Попробовал Чичиков — действительно, кусок был вроде городничего. Нашлось ему место, а казалось, ничего нельзя было поместить.', '.', '202.jpg', 26, '2021-10-18 15:12:27');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(879, 'С винами была тоже история.', 'С винами была тоже история. Получивши деньги из ломбарда, Петр Петрович запасся провизией на десять лет вперед.', ' Он то и дело подливал да подливал; чего ж не допивали гости, давал допить Алексаше и Николаше, которые так и хлопали рюмка за рюмкой, а встали из-за стола — как бы ни в чем не бывали, точно выпили по стакану воды. С гостьми было не то: в силу, в силу перетащились они на балкон и в силу поместились в креслах. Хозяин, как сел в свое, какое-то четырехместное, так тут же и заснул. Тучная собственность его превратилась в кузнецкий мех. Через открытый рот и носовые ноздри начала она издавать какие-то звуки, какие не бывают и в новой музыке. Тут было все — и барабан, и флейта, и какой-то отрывистый звук, точно собачий лай.', '101.jpg', 10, '2021-10-14 12:16:24'),
(880, '— Разумеется, если этак пообедать, — заговорил Платонов, — как тут прийти скуке.', '— Разумеется, если этак пообедать, — заговорил Платонов, — как тут прийти скуке! тут сон придет.', '.', '302.jpg', 28, '2021-10-13 11:29:58'),
(881, '— Да, — говорил Чичиков лениво. Глазки стали у него необыкновенно маленькие.', '— Да, — говорил Чичиков лениво. Глазки стали у него необыкновенно маленькие. — А все-таки, однако ж, извините, не могу понять, как можно скучать. Против скуки есть так много средств.', '.', '202.jpg', 39, '2021-10-08 08:46:00'),
(882, '— Да мало ли для молодого человека.', '— Да мало ли для молодого человека! Можно танцевать, играть на каком-нибудь инструменте… а не то — жениться.', '.', '100.jpg', 39, '2021-10-05 04:29:49'),
(883, '— Ну, поискать в других местах, поездить.', '— Ну, поискать в других местах, поездить. — Тут богатая мысль сверкнула в голове Чичикова, глаза его стали побольше. — Да вот прекрасное средство! — сказал он, глядя в глаза Платонову.', '.', '201.jpg', 11, '2021-09-26 23:01:44'),
(884, '— Да если вам свободно, так поедем со мной, — сказал Чичиков и подумал про себя.', '— Да если вам свободно, так поедем со мной, — сказал Чичиков и подумал про себя, глядя на Платонова: «А это было бы хорошо: тогда бы можно издержки пополам, а подчинку коляски отнести вовсе на его счет».', '.', '100.jpg', 20, '2021-09-17 19:49:26'),
(885, '— Да как сказать — куда.', '— Да как сказать — куда? Еду я покуда не столько по своей надобности, сколько по надобности другого.', ' Генерал Бетрищев, близкий приятель и, можно сказать, благотворитель, просил навестить родственников… Конечно, родственники родственниками, но отчасти, так сказать, и для самого себя; ибо видеть свет, коловращенье людей — кто что ни говори, есть как бы живая книга, вторая наука.', '101.jpg', 16, '2021-09-14 14:23:22'),
(886, 'Чичиков между тем так помышлял: «Право, было бы хорошо.', 'Чичиков между тем так помышлял: «Право, было бы хорошо! Можно даже и так, что все издержки будут на его счет. Можно даже сделать и так, чтобы отправиться на его лошадях, а мои покормятся у него в деревне.', ' Для сбереженья можно и коляску оставить у него в деревне, а в дорогу взять его коляску».', '002.jpg', 32, '2021-09-06 13:48:47'),
(887, '«Что ж? почему ж не проездиться? — думал между тем Платонов.', '«Что ж? почему ж не проездиться? — думал между тем Платонов. — Авось-либо будет повеселее. Дома же мне делать нечего, хозяйство и без того на руках у брата; стало быть, расстройства никакого.', ' Почему ж, в самом деле, не проездиться.', '202.jpg', 15, '2021-09-05 11:00:51'),
(888, '— А согласны ли вы, — сказал он вслух, — погостить у брата денька два.', '— А согласны ли вы, — сказал он вслух, — погостить у брата денька два? Иначе он меня не отпустит.', '.', '301.jpg', 49, '2021-08-31 07:27:32'),
(889, '— Куда? куда? — воскликнул хозяин, проснувшись и выпуча на них глаза.', '— Куда? куда? — воскликнул хозяин, проснувшись и выпуча на них глаза. — Нет, государи, и колеса приказано снять с вашей коляски, а ваш жеребец, Платон Михайлыч, отсюда теперь за пятнадцать верст.', ' Нет, вот вы сегодня переночуйте, а завтра после раннего обеда и поезжайте себе.', '102.jpg', 40, '2021-08-30 04:49:38'),
(890, '«Вот тебе на!» — подумал Чичиков.', '«Вот тебе на!» — подумал Чичиков. Платонов ничего на это не сказал, зная, что Петух держался обычаев своих крепко. Нужно было остаться.', '.', '302.jpg', 3, '2021-08-25 04:32:16'),
(891, 'Зато награждены они были удивительным весенним вечером.', 'Зато награждены они были удивительным весенним вечером. Хозяин устроил гулянье на реке. Двенадцать гребцов, в двадцать четыре весла, с песнями, понесли их по гладкому хребту зеркального озера.', ' Из озера они пронеслись в реку, беспредельную, с пологими берегами по обе стороны. Хоть бы струйкой шевельнулись воды. На катере они пили с калачами чай, подходя ежеминутно под протянутые впоперек реки канаты для ловли рыбы снастью. Еще до чаю хозяин успел раздеться и выпрыгнуть в реку, где барахтался и шумел с полчаса с рыбаками, покрикивая на Фому Большого и Кузьму, и, накричавшись, нахлопотавшись, намерзнувшись в зоде, очутился на катере с аппетитом и так пил чай, что было завидно. Тем временем солнце зашло. Осталась небесная ясность. Крики отдавались звонче. Наместо рыбаков показались повсюду у берегов группы купающихся ребятишек: хлопанье по воде, смех отдавались далече. Гребцы, хвативши разом в двадцать четыре весла, подымали вдруг все весла вверх, и катер сам собой, как легкая птица, стремился по недвижной зеркальной поверхности. Здоровый, свежий, как девка, детина, третий от руля, запевал звонко один, вырабатывая чистым голосом; пятеро подхватывало, шестеро выносило — и разливалась беспредельная, как Русь, песня; и, заслонивши ухо рукой, как бы терялись сами певцы в ее беспредельности. Становилося как-то льготно, и думал Чичиков: «Эх, право, заведу себе когда-нибудь деревеньку!» — «Ну, что тут хорошего, — думал Платонов, — в этой заунывной песне? от ней еще большая тоска находит на душу».', '002.jpg', 1, '2021-08-15 02:41:12'),
(892, 'Возвращались назад уже сумерками.', 'Возвращались назад уже сумерками. Весла ударяли впотьмах по водам, уже не отражавшим неба. Едва видны были по берегам озера огоньки. Месяц подымался, когда они пристали к берегу.', ' Повсюду на треногах варили рыбаки уху, все из ершей да из животрепещущей рыбы. Все уже было дома. Гуси, коровы, козы давно уже были пригнаны, и самая пыль от них уже давно улеглась, и пастухи, пригнавшие их, стояли у ворот, ожидая крынки молока и приглашенья к ухе. Там и там слышались говор и гомон людской, громкое лаянье собак своей деревни и отдаленное — чужих деревень. Месяц подымался, стали озаряться потемки; и все наконец озарилось — и озеро и избы; побледнели огни; стал виден дым из труб, осеребренный лучами. Николаша и Алексаша пронеслись в это время перед ними на двух лихих жеребцах, в обгонку друг друга; пыль за ними поднялась, как от стада баранов. «Эх, право, заведу себе когда-нибудь деревеньку!» — думал Чичиков. Бабенка и маленькие Чичонки начали ему снова представляться.', '103.jpg', 32, '2021-08-12 01:30:08'),
(893, 'А за ужином опять объелись.', 'А за ужином опять объелись.', ' Когда вошел Павел Иванович в отведенную комнату для спанья и, ложась в постель, пощупал животик свой: «Барабан! — сказал, — никакой городничий не взойдет!» Надобно же было такому стеченыо обстоятельств: за стеной был кабинет хозяина. Стена была тонкая, и слышалось все, что там ни говорилось. Хозяин заказывал повару, под видом раннего завтрака, на завтрашний день, решительный обед. И как заказывал! У мертвого родился бы аппетит. И губами подсасывал, и причмокивал. Раздавалось только: «Да поджарь, да дай взопреть хорошенько!» А повар приговаривал тоненькой фистулой: «Слушаю-с. Можно-с. Можно-с и такой».', '201.jpg', 3, '2021-08-03 21:13:21'),
(894, '— Да кулебяку сделай на четыре угла.', '— Да кулебяку сделай на четыре угла.', ' В один угол положи ты мне щеки осетра да вязигу, в другой запусти гречневой кашицы, да грибочков с лучком, да молок сладких, да мозгов.', '101.jpg', 20, '2021-07-30 16:18:29'),
(895, '— Да чтобы с одного боку она, понимаешь, — зарумянилась бы.', '— Да чтобы с одного боку она, понимаешь, — зарумянилась бы, а с другого пусти ее полегче.', ' Да исподку-то, исподку-то, понимаешь, пропеки ее так, чтобы рассыпалась, чтобы всю ее проняло, знаешь, соком, чтобы и не услышал ее во рту — как снег бы растаяла.', '301.jpg', 34, '2021-07-20 16:03:38'),
(896, '— Да сделай ты мне свиной сычуг.', '— Да сделай ты мне свиной сычуг. Положи в середку кусочек льду, чтобы он взбухнул хорошенько.', ' Да чтобы к осетру обкладка, гарнир-то, гарнир-то чтобы был побогаче! Обложи его раками, да поджаренной маленькой рыбкой, да проложи фаршецом из снеточков, да подбавь мелкой сечки, хренку, да груздочков, да репушки, да морковки, да бобков, да нет ли еще там какого коренья.', '100.jpg', 18, '2021-07-18 11:44:36'),
(897, '— Пропал совершенно сон.', '— Пропал совершенно сон! — сказал Чичиков, переворачиваясь на другую сторону, закутал голову в подушки и закрыл себя всего одеялом, чтобы не слышать ничего.', ' Но сквозь одеяло слышалось беспрестанно: «Да поджарь, да подпеки, да дай взопреть хорошенько». Заснул он уже на каком-то индюке.', '002.jpg', 18, '2021-07-09 09:00:15'),
(898, 'На другой день до того объелись гости, что Платонов уже не мог ехать верхом.', 'На другой день до того объелись гости, что Платонов уже не мог ехать верхом; жеребец был отправлен с конюхом Петуха. Они сели в коляску. Мордатый пес лениво пошел за коляской: он тоже объелся.', '.', '203.jpg', 26, '2021-07-06 04:59:45'),
(899, '— Нет, это уже слишком, — сказал Чичиков, когда выехали они со двора.', '— Нет, это уже слишком, — сказал Чичиков, когда выехали они со двора. — Это даже по-свински. Не беспокойно ли вам, Платон Михалыч? Препокойная была коляска, и вдруг стало беспокойно.', ' Петрушка, ты, верно, по-глупости, стал перекладывать.', '101.jpg', 23, '2021-06-29 01:47:40'),
(900, '— Точно так, — сказал Петрушка, оборотясь с козел.', '— Точно так, — сказал Петрушка, оборотясь с козел, — приказано было все поставить в коляску — пашкеты и пироги.', '.', '103.jpg', 6, '2021-06-20 23:05:30'),
(901, '— Точно-с, Павел Иванович, — сказал Селифан, оборотясь с козел, веселый.', '— Точно-с, Павел Иванович, — сказал Селифан, оборотясь с козел, веселый, — очень почтенный барин. Угостительный помещик! По рюмке шампанского выслал. Точно-с, и приказал от стола отпустить блюда — оченно хорошего блюда, деликатного скусу.', ' Такого почтительного господина еще и не было.', '302.jpg', 0, '2021-06-18 19:04:33'),
(902, '— Видите ли? он всех удовлетворил, — сказал Платонов.', '— Видите ли? он всех удовлетворил, — сказал Платонов. — Однако же, скажите просто: есть ли у вас время, что бы заехать в одну деревню, отсюда верст десять? Мне бы хотелось проститься с сестрой и зятем.', '.', '100.jpg', 44, '2021-06-10 13:25:44'),
(903, '— Это первый хозяин, какой когда-либо бывал на Руси.', '— Это первый хозяин, какой когда-либо бывал на Руси. Он в десять лет с небольшим, купивши расстроенное имение, едва дававшее двадцать тысяч, возвел его до того, что теперь он получает двести тысяч.', '.', '002.jpg', 21, '2021-06-03 13:13:37'),
(904, '— А, почтенный человек.', '— А, почтенный человек! Вот этакого человека жизнь стоит того, чтобы быть переданной в поученье людям! Очень, очень будет приятно познакомиться, А как по фамилии.', '— А, почтенный человек! Вот этакого человека жизнь стоит того, чтобы быть переданной в поученье людям! Очень, очень будет приятно познакомиться, А как по фамилии.', '302.jpg', 42, '2021-05-31 12:30:11'),
(905, '— Константин Федорович Костанжогло. Очень приятно познакомиться.', '— Константин Федорович Костанжогло. Очень приятно познакомиться. Поучительно знать этакого человека. — И Чичиков пустился в расспросы о Костанжогле, и все, что он узнал о нем от Платонова, было, точно, изумительно.', '.', '002.jpg', 15, '2021-05-26 11:56:01'),
(906, '— Вот смотрите, в этом месте уже начинаются его земли, — говорил Платонов.', '— Вот смотрите, в этом месте уже начинаются его земли, — говорил Платонов, указывая на поля. — Вы увидите тотчас отличье от других. Кучер, здесь возьмешь дорогу налево. Видите ли этот молодник-лес? Это — сеяный.', ' У другого в пятнадцать лет не поднялся бы так, а у него в восемь вырос. Смотрите, вот лес и кончился. Начались уже хлеба; а через пятьдесят десятин опять будет лес, тоже сеяный, а там опять. Смотрите на хлеба, во сколько раз они гуще, чем у другого.', '101.jpg', 44, '2021-05-22 08:44:36'),
(907, '— Ну, расспросите у него, вы увидите, что… Это всезнай, такой всезнай.', '— Ну, расспросите у него, вы увидите, что… Это всезнай, такой всезнай, какого вы нигде не найдете. Он мало того что знает, какую почву что любит, знает, какое соседство для кого нужно, поблизости какого леса нужно сеять какой хлеб.', ' У нас у всех земля трескается от засух, а у него нет. Он рассчитает, насколько нужно влажности, столько и дерева разведет; у него все играет две-три роли: лес лесом, а полю удобренье от листьев да от тени. И это во всем так.', '302.jpg', 47, '2021-05-12 04:26:46'),
(908, 'Все было в порядке необыкновенном.', 'Все было в порядке необыкновенном. Леса были загороженные; повсюду попадались скотные дворы, тоже не без причины обстроенные, завидно содержимые; хлебные клади росту великанского. Обильно и хлебно было повсюду. Видно было вдруг, что живет туз-хозяин.', ' Поднявшись на небольшую возвышенность, увидели на супротивной стороне большую деревню, рассыпавшуюся на трех горных возвышениях. Все тут было богато: торные улицы, крепкие избы; стояла ли где телега — телега была крепкая и новешенькая; попадался ли конь — конь был откормленный и добрый; рогатый скот — как на отбор. Даже мужичья свинья глядела дворянином. Так и видно, что здесь именно живут те мужики, которые гребут, как поется в песне, серебро лопатой. Не было тут аглицких парков, беседок и мостов с затеями и разных проспектов перед домом. От изб до господского двора потянулись рабочьи дворы. На крыше большой фонарь, не для видов, но для рассматривания, где и в каком месте и как производились работы.', '202.jpg', 29, '2021-05-05 02:10:49'),
(909, 'Они подъехали к дому.', 'Они подъехали к дому. Хозяина не было; встретила их жена, родная сестра Платонова, белокурая, белоликая, с прямо русским выраженьем, так же красавица, но так же полусонная, как он.', ' Кажется, как будто ее мало заботило то, о чем заботятся, или оттого, что всепоглощающая деятельность мужа ничего не оставила на ее долю, или оттого, что ока принадлежала, по самому сложению своему, к тому философическому разряду людей, которые, имея и чувства, и мысли, и ум, живут как-то вполовину, на жизнь глядят вполглаза и, видя возмутительные тревоги и борьбы, говорят: «Пусть их, дураки, бесятся! Им же хуже».', '302.jpg', 17, '2021-05-02 01:54:50'),
(910, 'Чичиков на хозяйку не обратил вниманья.', 'Чичиков на хозяйку не обратил вниманья. Ему было интересно рассмотреть жилище этого необыкновенного человека. Он думал отыскать в нем свойства самого хозяина, — как по раковине можно судить, какого рода сидела в ней устрица или улитка.', ' Но этого-то и не было. Комнаты были бесхарактерны совершенно — просторны, и ничего больше. Ни фресков, ни картин по стенам, ни бронзы по столам, ни этажерок с фарфором или чашками, ни ваз, ни цветов, ни статуек — словом, как-то голо. Простая обыкновенная мебель да рояль стоял в стороне, и тот покрыт был пылью: как видно, хозяйка редко за него садилась. Из гостиной отворена была дверь в кабинет хозяина; но и там было так же — просто и голо. Видно было, что хозяин приходил в дом только отдохнуть, а не то чтобы жить в нем; что для обдумыванья своих планов и мыслей ему не надобно было кабинета с пружинными креслами и всякими покойными удобствами и что жизнь его заключалась не в очаровательных грезах у пылающего камина, но прямо в деле. Мысль исходила вдруг из обстоятельств, в ту минуту, как они представлялись, и обращалась вдруг в дело, не имея никакой надобности в том, чтобы быть записанной.', '100.jpg', 58, '2021-05-01 01:15:17'),
(911, 'Чичиков тоже устремился к окну.', 'Чичиков тоже устремился к окну. К крыльцу подходил лет сорока человек, живой, смуглой наружности. На нем был триповый картуз. По обеим сторонам его, сняв шапки, шли двое нижнего сословия, — шли, разговаривая и о чем-то с ним толкуя.', ' Один, казалось, — был простой мужик; другой, в синей сибирке, какой-то заезжий кулак и пройдоха.', '301.jpg', 46, '2021-04-28 19:49:22'),
(912, '— Да нет, братец, я уж двадцать раз вам повторял: не возите больше.', '— Да нет, братец, я уж двадцать раз вам повторял: не возите больше. У меня материалу столько накопилось, что девать некуда.', '.', '302.jpg', 15, '2021-04-21 19:30:42'),
(913, '— Да у вас, батюшка Константин Федорович, весь пойдет в дело.', '— Да у вас, батюшка Константин Федорович, весь пойдет в дело. Уж эдакого умного человека во всем свете нельзя сыскать. Ваше здоровье венку вещь в место поставит. Так уж прикажите принять.', '.', '301.jpg', 31, '2021-04-12 15:40:31'),
(914, '— Да уж в работниках не будете иметь недостатку.', '— Да уж в работниках не будете иметь недостатку. У нас целые деревни пойдут в работы: бесхлебье такое, что и не запомним. Уж вот беда-то, что не хотите нас совсем взять, а отслужили бы верою вам, ей-богу, отслужили.', ' У вас всякому уму научишься, Константин Федорович. Так прикажите принять в последний раз.', '101.jpg', 2, '2021-04-11 09:15:47'),
(915, '— Уж в последний раз, Константин Федорович.', '— Уж в последний раз, Константин Федорович. Если вы не возьмете, то у меня никто не возьмет. Так уж прикажите, батюшка, принять.', '.', '202.jpg', 35, '2021-04-10 03:27:50'),
(916, '— Ну, слушай, этот раз возьму, и то из сожаления только.', '— Ну, слушай, этот раз возьму, и то из сожаления только, чтобы не провозился напрасно. Но если ты привезешь в другой раз, хоть три недели канючь — не возьму.', '.', '302.jpg', 11, '2021-04-06 00:04:56'),
(917, '— Слушаю-с, Константин Федорович, уж будьте покойны.', '— Слушаю-с, Константин Федорович; уж будьте покойны, в другой раз уж никак не привезу. Покорнейше благодарю. — Мужик отошел, довольный. Врет, однако же, привезет: авось — великое словцо.', '.', '201.jpg', 58, '2021-03-28 21:14:40'),
(918, '— Так уж того-с, Константин Федорович, уж сделайте милость… посбавьте.', '— Так уж того-с, Константин Федорович, уж сделайте милость… посбавьте, — говорил шедший по другую сторону заезжий кулак в синей сибирке.', '.', '202.jpg', 48, '2021-03-19 20:38:54'),
(919, '— Ведь я тебе на первых порах объявил. Торговаться я не охотник.', '— Ведь я тебе на первых порах объявил. Торговаться я не охотник. Я тебе говорю опять: я не то, что другой помещик, к которому ты подъедешь под самый срок уплаты в ломбард. Ведь я вас знаю всех. У вас есть списки всех, кому когда следует уплачивать.', ' Что ж тут мудреного? Ему приспичит, он тебе и отдаст за полцены.', '202.jpg', 1, '2021-03-14 16:27:02'),
(920, '— Настоящее дело, Константин Федорович.', '— Настоящее дело, Константин Федорович. Да ведь я того-с… оттого только, чтобы и впредь иметь с вами касательство, а не ради какого корыстья. Три тысячи задаточку извольте принять.', '.', '103.jpg', 56, '2021-03-09 10:23:53'),
(921, 'Кулак вынул из-за пазухи пук засаленных ассигнаций.', 'Кулак вынул из-за пазухи пук засаленных ассигнаций. Костанжогло прехладнокровно взял их и, не считая, сунул в задний карман своего сюртука.', '.', '302.jpg', 3, '2021-02-27 04:32:07'),
(922, '— Ба, брат, ты здесь! — сказал он, увидев Платонова.', '— Ба, брат, ты здесь! — сказал он, увидев Платонова. Они обнялись и поцеловались. Платонов рекомендовал Чичикова. Чичиков благоговейно подступил к хозяину, лобызнул его в щеку, принявши и от него впечатленье поцелуя.', '.', '102.jpg', 26, '2021-02-20 01:40:56'),
(923, 'Лицо Костанжогло было очень замечательно.', 'Лицо Костанжогло было очень замечательно. В нем было заметно южное происхожденье. Волосы на голове и на бровях темны и густы, глаза говорящие, блеску сильного. Ум сверкал во всяком выраженье лица, и уж ничего не было в нем сонного.', ' Но заметна, однако же, была примесь чего-то желчного и озлобленного. Какой, собственно, был он нации? Есть много на Руси русских нерусского происхожденья, в душе, однако же, русские. Костанжогло не занимался своим происхожденьем, находя, что это в строку нейдет и в хозяйстве вещь лишняя. Притом не знал и другого языка, кроме русского.', '203.jpg', 48, '2021-02-17 00:36:36'),
(924, '— Прекрасно.', '— Прекрасно! В какие же места, — спросил Костанжогло, приветливо обращаясь к Чичикову, — предполагаете теперь ехать.', '— Прекрасно! В какие же места, — спросил Костанжогло, приветливо обращаясь к Чичикову, — предполагаете теперь ехать.', '302.jpg', 49, '2021-02-06 20:41:31'),
(925, '— Признаюсь, — сказал Чичиков.', '— Признаюсь, — сказал Чичиков, наклоня голову набок и взявщись рукою за ручку кресел, — еду я, покамест, не столько но своей нужде, сколько по нужде другого.', ' Генерал Бетрищев, близкий приятель и, можно сказать, благотворитель, просил навестить родственников. Родственники, конечно, родственниками, но отчасти, так сказать, и для самого себя; потому что, точно, не говоря уже о пользе, которая может быть в геморроидальном отношенье, одно уже то, чтоб увидать свет, коловращенье люден… кто что ни говори, есть так сказать, живая книга, та же наука.', '202.jpg', 50, '2021-02-01 16:08:50'),
(926, '— Превосходно изволили заметить, — отнесся Чичиков, — точно, не мешает.', '— Превосходно изволили заметить, — отнесся Чичиков, — точно, не мешает. Видишь вещи, которых бы не видел; встречаешь людей, которых бы не встретил. Разговор с иным тот же червонец. Научите, почтеннейший Константин Федорович, научите, к вам прибегаю.', ' Жду, как манны, сладких слов ваших.', '103.jpg', 5, '2021-01-29 10:06:19'),
(927, '— Мудрости, почтеннейший, мудрости.', '— Мудрости, почтеннейший, мудрости.', '— Мудрости, почтеннейший, мудрости! мудрости управлять хозяйством, подобно вам; подобно вам уметь извлекать доходы верные; приобресть, подобно вам, имущество не мечтательное, а существенное, и тем исполнить долг гражданина, заслужить уваженье соотечественников.', '103.jpg', 8, '2021-01-27 09:59:55'),
(928, '— Знаете ли что? — сказал Костанжогло, — останьтесь денек у меня.', '— Знаете ли что? — сказал Костанжогло, — останьтесь денек у меня. Я покажу вам все управление и расскажу обо всем. Мудрости тут, как вы увидите, никакой нет.', '.', '301.jpg', 27, '2021-01-26 04:15:44'),
(929, '— Я тоже.', '— Я тоже, я с большим удовольствием… Но вот обстоятельство — нужно посетить родственника генерала Бетрищева.', ' Есть некто полковник.', '301.jpg', 27, '2021-01-20 23:21:29'),
(930, '— Об этом я уже слышал. Мне к нему и дела нет.', '— Об этом я уже слышал. Мне к нему и дела нет. Но так как генерал Бетришев — близкий приятель и даже, так сказать, благотворитель… так уж как-то и неловко.', '.', '203.jpg', 26, '2021-01-17 20:44:50'),
(931, '— В таком случае знаете ли что, — сказал Костанжогло.', '— В таком случае знаете ли что, — сказал Костанжогло,— поезжайте к нему теперь же. У меня стоят готовые пролетки. К нему и десяти верст нет, так вы слетаете духом. Вы даже раньше ужина возвратитесь назад.', '.', '203.jpg', 31, '2021-01-12 20:35:11'),
(932, 'Чичиков с радостью воспользовался предложеньем.', 'Чичиков с радостью воспользовался предложеньем. Пролетки были поданы, и он поехал тот же час к полковнику, который изумил его так, как еще никогда ему не случалось изумляться. Все было у полковника необыкновенно.', ' Вся деревня была вразброску: постройки, перестройки, кучи извести, кирпичу и бревен по всем улицам. Выстроены были какие-то дома вроде присутственных мест. На одном было написано золотыми буквами: «Депо земледельческих орудий», на другом: «Главная счетная экспедиция», на третьем: «Комитет сельских дел»; «Школа нормального просвещенья поселян», — словом, черт знает, чего не было! Он думал, не въехал ли в губернский город. Сам полковник был какой-то чопорный. Лицо какое-то чинное в виде треугольника. Бакенбарды по шекам его были протянуты в струнку; волосы, прическа, нос, губы, подбородок — все как бы лежало дотоле под прессом. Начал он говорить, как бы и дельный человек. С первых начал начал он ему жаловаться на необразованность окружающих помещиков, на великие труды, которые ему предстоят. Принял он Чичикова отменно ласково и радушно, ввел его совершенно в доверенность и рассказал с самоуслажденьем, скольких и скольких стоило ему трудов возвесть именье до нынешнего благосостояния: как трудно было дать понять простому мужику, что есть высшие побуждения, которые доставляют человеку просвещенная роскошь, искусство и художества: сколько нужно было бороться с невежеством русского мужика, чтобы одеть его в немецкие штаны и заставить почувствовать, хотя сколько-нибудь, высшее Достоинство человека; что баб, несмотря на все усилия, он до сих пор не мог заставить надеть корсет, тогда как в Германии, где он стоял с полком в 14-м году, дочь мельника умела играть даже на фортепиано, говорила по-французски и делала книксен.', '203.jpg', 43, '2021-01-06 18:14:54'),
(933, 'На это Чичиков подумал: «Ну, вряд ли выберется такое время.', 'На это Чичиков подумал: «Ну, вряд ли выберется такое время. Вот я выучился грамоте, а «Графиня Лавальер» до сих пор еще не прочитана».', '.', '100.jpg', 23, '2020-12-27 14:56:58'),
(934, '— Ужасное невежество! — сказал в заключенье полковник Кошкарев.', '— Ужасное невежество! — сказал в заключенье полковник Кошкарев. — Тьма средних веков, и нет средств помочь… Поверьте, нет! А я бы мог всему помочь: я знаю одно средство, вернейшее средство.', '.', '301.jpg', 8, '2020-12-22 13:16:55'),
(935, '— Одеть всех до одного в России, как ходят в Германии.', '— Одеть всех до одного в России, как ходят в Германии. Ничего больше, как только это, и я вам ручаюсь, что все пойдет как по маслу: науки возвысятся, торговля подымется, золотой век настанет в России.', '.', '002.jpg', 1, '2020-12-14 11:36:38'),
(936, 'Чичиков глядел на него пристально и думал: «Что ж.', 'Чичиков глядел на него пристально и думал: «Что ж? с этим, кажется, чиниться нечего». Не отлагая дела в дальний ящик, он объяснил полковнику тут же, что так и так: имеется надобность вот в каких душах, с совершеньем таких-то крепостей.', '.', '101.jpg', 39, '2020-12-07 06:42:42'),
(937, '— Сколько могу видеть из слов ваших, — сказал полковник, нимало не смутись.', '— Сколько могу видеть из слов ваших, — сказал полковник, нимало не смутись, — это просьба; не так ли.', '— Сколько могу видеть из слов ваших, — сказал полковник, нимало не смутись, — это просьба; не так ли.', '100.jpg', 29, '2020-11-30 05:33:07'),
(938, '— В таком случае, изложите ее письменно. Она пойдет в комиссию всяких прошений.', '— В таком случае, изложите ее письменно. Она пойдет в комиссию всяких прошений. Комиссия всяких прошений, пометивши, препроводит ее ко мне. От меня поступит она в комитет сельских дел, там сделают всякие справки и выправки по этому делу.', ' Главноуправляющий вместе с конторою в самоскорейшем времени положит свою резолюцию, и дело будет сделано.', '302.jpg', 31, '2020-11-26 02:50:59'),
(939, '— А! — сказал с улыбкой полковник, — вот тут-то и выгода бумажного производства.', '— А! — сказал с улыбкой полковник, — вот тут-то и выгода бумажного производства! Оно, точно, несколько затянется, но зато уже ничто не ускользнет: всякая мелочь будет видна.', '.', '302.jpg', 40, '2020-11-24 01:53:45'),
(940, '— Но позвольте… Как же трактовать об этом письменно.', '— Но позвольте… Как же трактовать об этом письменно? Ведь это такого рода дело… Души ведь некоторым образом… мертвые.', '.', '102.jpg', 46, '2020-11-15 01:32:39'),
(941, '— Но ведь как же — мертвые? Ведь этак же нельзя написать.', '— Но ведь как же — мертвые? Ведь этак же нельзя написать. Они хотя и мертвые, но нужно, чтобы казались как бы были живые.', '.', '102.jpg', 24, '2020-11-10 23:27:54'),
(942, '— Хорошо.', '— Хорошо. Вы так и напишите: «но нужно, или требуется, чтобы казалось, как бы живые».', '.', '203.jpg', 15, '2020-11-03 19:43:59'),
(943, 'Что было делать с полковником.', 'Что было делать с полковником? Чичиков решился отправиться сам поглядеть, что это за комиссии и комитеты; и что нашел он там, то было не только изумительно, но превышало решительно всякое понятье.', ' Комиссия всяких прошений существовала только на вывеске. Председатель ее, прежний камердинер, был переведен во вновь образовавшийся комитет сельских построек. Место его заступил конторщик Тимошка, откомандированный на следствие — разбирать пьяницу приказчика с старостой, мошенником и плутом. Чиновника — нигде.', '301.jpg', 26, '2020-10-29 19:43:17'),
(944, '— Да где ж туг?..', '— Да где ж туг?.. да как добиться какого-нибудь толку? — сказал Чичиков своему сопутнику, чиновнику по особенным поручениям, которого полковник дал ему в проводники.', '.', '101.jpg', 13, '2020-10-22 14:40:07'),
(945, '— Да никакого толку не добьетесь, — сказал проводник, — у нас бестолковщина.', '— Да никакого толку не добьетесь, — сказал проводник, — у нас бестолковщина. У нас всем, изволите видеть, распоряжается комиссия построения, отрывает всех от дела, посылает куды угодно. Только и выгодно у нас, что в комиссии построения.', ' — Он, как видно, был недоволен на комиссию построенья. — У нас так заведено, что все водят за нос барина. Он думает, что всё-с как следует, а ведь это названье только одно.', '301.jpg', 30, '2020-10-14 09:29:49'),
(946, '«Это, однако же, нужно ему сказать», — подумал Чичиков и, пришедши к полковнику.', '«Это, однако же, нужно ему сказать», — подумал Чичиков и, пришедши к полковнику, объявил, что у него каша и никакого толку нельзя добиться, и комиссия построений ворует напропалую.', '.', '100.jpg', 34, '2020-10-10 09:20:59'),
(947, 'Полковник воскипел благородным негодованьем.', 'Полковник воскипел благородным негодованьем.', ' Тут же, схвативши бумагу и перо, написал восемь строжайших запросов: на каком основании комиссия построений самоуправно распорядилась с неподведомственными ей чиновниками? Как мог допустить главноуправляющий, чтобы председатель, не сдавши своего поста, отправился на следствие? и как мог видеть равнодушно комитет сельских дел, что даже не существует комиссии прошений.', '102.jpg', 10, '2020-10-03 07:46:20'),
(948, '— Нет, я вас не отпущу. В два часа, не более, вы будете удовлетворены во всем.', '— Нет, я вас не отпущу. В два часа, не более, вы будете удовлетворены во всем. Дело ваше я поручу теперь особенному человеку, который только что окончил университетский курс. Посидите у меня в библиотеке.', ' Тут все, что для вас нужно: книги, бумага, перья, карандаши — все. Пользуйтесь, пользуйтесь всем — вы господин.', '002.jpg', 32, '2020-09-24 02:04:25'),
(949, 'Так говорил Кошкарев, введя его в книгохранилище.', 'Так говорил Кошкарев, введя его в книгохранилище. Это был огромный зал, снизу доверху уставленный книгами. Были там даже и чучела животных.', ' Книги по всем частям — по части лесоводства, скотоводства, свиноводства, садоводства, тысячи всяких журналов, руководств и множество журналов, представлявших самые позднейшие развития и усовершенствования и по коннозаводству и естественным наукам. Были и такие названия: «Свиноводство как наука». Видя, что здесь вещи не приятного препровождения времени, он обратился к другому шкафу. Из огня — в полымя. Тут были всё книги философии. На одной было заглавие: «Философия, в смысле науки»; шесть томов в ряд под названием: «Предуготовительное вступление к теории мышления в их общности, совокупности, сущности и во применении к уразумению органических начал обоюдного раздвоенья общественной производительности». Что ни разворачивал Чичиков книгу, на всякой странице — проявленье, развитье, абстракт, замкнутость и сомкнутость, и черт знает, чего там не было. «Нет, это все не по мне», — сказал Чичиков и оборотился к третьему шкафу, где были книги всё по части искусств. Тут вытащил он какую-то огромную книгу с нескромными мифологическими картинками и начал их рассматривать. Это было по его вкусу. Такого рода картинки нравятся холостякам средних лет. Говорят, что в последнее время стали они нравиться даже и старичкам, изощрившим вкус на балетах. Что ж делать, человечество нашего века пряные коренья любит. Окончивши рассматриванье этой книги, Чичиков вытащил уже было и другую в том же роде, как вдруг появился полковник Кошкарев, с сияющим видом и бумагою.', '202.jpg', 57, '2020-09-21 19:56:19'),
(950, '— Все сделано, и сделано отлично. Человек этот решительно понимает один за всех.', '— Все сделано, и сделано отлично. Человек этот решительно понимает один за всех. За это я его поставлю выше всех: заведу особенное, высшее управление и поставлю его президентом.', ' Вот что он.', '201.jpg', 32, '2020-09-11 19:35:59'),
(951, '«Ну слава те господи», — подумал Чичиков и приготовился слушать.', '«Ну слава те господи», — подумал Чичиков и приготовился слушать.', ' Полковник стал читать.', '301.jpg', 38, '2020-09-05 16:24:34'),
(952, '— «Приступая к обдумываныо возложенного на меня вашим высокородием поручения.', '— «Приступая к обдумываныо возложенного на меня вашим высокородием поручения, честь имею сим донести на оное, 1) В самой просьбе господина коллежского советника и кавалера Павла Ивановича Чичикова есть уже некоторое недоразумение, в изъясненье того.', '— «Приступая к обдумываныо возложенного на меня вашим высокородием поручения, честь имею сим донести на оное: 1) В самой просьбе господина коллежского советника и кавалера Павла Ивановича Чичикова есть уже некоторое недоразумение: в изъясненье того, что требуются ревизские души, постигнутые всякими внезапностями, вставлены и умершие. Под сим, вероятно, они изволили разуметь близкие к смерти, а не умершие; ибо умершие не приобретаются. Что ж и приобретать, если ничего нет? Об этом говорит и самая логика. Да и в словесных науках они, как видно, не далеко уходили…» — Тут на минуту Кошкарев остановился и сказал: — В этом месте, плут… он немножко кольнул вас. Но судите, однако же, какое бойкое перо — статс-секретарский слог; а ведь всего три года побыл в университете, даже не кончил курса. — Кошкарев продолжал: — «…в словесных науках, как видно, не далеко… ибо выразились о душах умершие, тогда как всякому, изучавшему курс познаний человеческих, известно заподлинно, что душа бессмертна. 2) Оных упомянутых ревижских душ, пришлых, или прибылых, или, как они неправильно изволили выразиться, умерших, нет налицо таковых, которые бы не были в залоге, ибо все в совокупности не только заложены без изъятия, но и перезаложены, с прибавкой по полутораста рублей на душу, кроме небольшой деревни Гурмайловка, находящейся в спорном положении по случаю тяжбы с помещиком Предищевым, и потому ни в продажу, ии в залог поступить не может».', '302.jpg', 24, '2020-08-31 10:06:15'),
(953, '— Так зачем же вы мне этого не объявили прежде? Зачем из пустяков держали.', '— Так зачем же вы мне этого не объявили прежде? Зачем из пустяков держали? — сказал с сердцем Чичиков.', '.', '301.jpg', 21, '2020-08-25 07:12:00'),
(954, '— Да ведь как же я мог знать об этом сначала.', '— Да ведь как же я мог знать об этом сначала? В этом-то и выгода бумажного производства, что вот теперь все, как на ладони, оказалось ясно.', '.', '101.jpg', 4, '2020-08-23 03:49:32'),
(955, '«Дурак ты, глупая скотина! — думал про себя Чичиков.', '«Дурак ты, глупая скотина! — думал про себя Чичиков. — В книгах копался, а чему выучился?» Мимо всяких учтивств и приличий, схватил он шапку — из дома.', ' Кучер стоял, пролетки наготове и лошадей не откладывал: о корме пошла бы письменная просьба, и резолюция — выдать свес лошадям — вышла бы только на другой день. Как ни был Чичиков груб и неучтив, но Кошкарев, несмотря на все, был с ним необыкновенно учтив и деликатен. Он насильно пожал ему руку, и прижал ее к сердцу, и благодарил его за то, что он дал ему случай увидеть на деле ход производства; что передрягу и гонку нужно дать необходимо, потому что способно все задремать и пружины сельского управленья заржавеют и ослабеют; что вследствие этого события пришла ему счастливая мысль: устроить новую комиссию, которая будет называться комиссией наблюдения за комиссией построения, так что уже тогда никто ие осмелится украсть.', '202.jpg', 26, '2020-08-12 21:39:20'),
(956, '«Осел! дурак!» — думал Чичиков, сердитый и недовольный во всю дорогу.', '«Осел! дурак!» — думал Чичиков, сердитый и недовольный во всю дорогу. Ехал он уже при звездах. Ночь была на небе. В деревнях были огни. Подъезжая к крыльцу, он увидел в окнах, что уже стол был накрыт для ужина.', '.', '302.jpg', 58, '2020-08-05 21:12:57'),
(957, '— Это еще ничего! — сказал Костанжогло. — Кошкарев — утешительное явление.', '— Это еще ничего! — сказал Костанжогло. — Кошкарев — утешительное явление. Он нужен затем, что в нем отражаются карикатурно и видней глупости умных людей.', ' Завели конторы и присутствия, и управителей, и мануфактуры, и фабрики, и школы, и комиссию, и черт их знает что такое. Точно как будто бы у них государство какое! Как вам это нравится? я спрашиваю.', '203.jpg', 32, '2020-07-29 20:11:31'),
(958, '— А кто их заводил.', '— А кто их заводил? Сами завелись: накопилось шерсти, сбыть некуды, я и начал ткать сукна, да и сукна толстые, простые; по дешевой цене их тут же на рынках у меня и разбирают.', ' Рыбью шелуху, например, сбрасывали на мой берег шесть лет сряду; ну, куды ее девать? я начал с нее варить клей, да сорок тысяч и взял. Ведь у меня всё так.', '102.jpg', 6, '2020-07-20 17:51:16'),
(959, '«Экой черт.', '«Экой черт! — думал Чичиков, глядя на него в оба глаза, — загребистая какая лапа.', '«Экой черт! — думал Чичиков, глядя на него в оба глаза, — загребистая какая лапа.', '100.jpg', 33, '2020-07-12 12:45:13'),
(960, '— Да я и строений для этого не строю.', '— Да я и строений для этого не строю; у меня нет зданий с колоннами да фронтонами. Мастеров я не выписываю из-за границы. А уж крестьян от хлебопашества ни за что не оторву.', ' На фабриках у меня работают только в голодный год, всё пришлые, из-за куска хлеба. Этаких фабрик наберется много. Рассмотри только попристальнее свое хозяйство, то увидишь — всякая тряпка пойдет в дело, всякая дрянь даст доход, так что после отталкиваешь только да говоришь: не нужно.', '101.jpg', 26, '2020-07-07 07:03:35'),
(961, '— Это изумительно! Изумительнее же всего то, что всякая дрянь даст доход.', '— Это изумительно! Изумительнее же всего то, что всякая дрянь даст доход! — сказал Чичиков.', '.', '201.jpg', 34, '2020-07-03 04:05:50'),
(962, '— Гм! да не только это!..', '— Гм! да не только это!.. — Речи Костанжогло не кончил: желчь в нем пробудилась, и ему хотелось побранить соседей помещиков.', ' — Вон опять один умник — что вы думаете у себя завел? Богоугодные заведения, каменное строение в деревне! Христолюбивое дело!.. Уж хочешь помогать, так ты помогай всякому исполнить этот долг, а не отрывай его от христианского долга. Помоги сыну пригреть у себя больного отца, а не давай ему возможности сбросить его с плеч своих. Дай лучше ему средства приютить у себя в дому ближнего и брата, дай ему на это денег, помоги всеми силами, а не отлучай его: он совсем отстанет от всяких христианских обязанностей. Дон-Кишоты просто по всем частям!.. Двести рублей выходит на человека в год в богоугодном заведении!.. Да я на эти деньги буду у себя в деревне десять человек содержать! — Костанжогло рассердился и плюнул.', '202.jpg', 13, '2020-06-29 22:49:59'),
(963, 'Чичиков не интересовался богоугодным заведеньем, он хотел повести речь о том.', 'Чичиков не интересовался богоугодным заведеньем: он хотел повести речь о том, как всякая дрянь дает доход. Но Костанжогло уже рассердился, желчь в нем закипела, и слова полились.', '.', '203.jpg', 47, '2020-06-21 17:44:27'),
(964, '— А вот другой Дон-Кишот просвещенья: завел школы.', '— А вот другой Дон-Кишот просвещенья: завел школы! Ну, что, например, полезнее человеку, как знанье грамоты? А ведь как распорядился? Ведь ко мне приходят мужики из его деревни.', ' «Что это, говорят, батюшка, такое? сыновья наши совсем от рук отбились, помогать в работах не хотят, все в писари хотят, а ведь писарь нужен один».', '202.jpg', 56, '2020-06-15 12:59:29'),
(965, '— Да ведь этим нечего останавливаться, что теперь не надобны писаря.', '— Да ведь этим нечего останавливаться, что теперь не надобны писаря: после будет надобность. Работать нужно для потомства.', '.', '002.jpg', 12, '2020-06-14 09:53:44'),
(966, '— Да будь, братец, хоть ты умей! Ну, что вам далось это потомство.', '— Да будь, братец, хоть ты умей! Ну, что вам далось это потомство? Все думают, что они какие-то Петры Великие.', ' Да ты смотри себе под ноги, а не гляди в потомство; хлопочи о том, чтобы мужика сделать достаточным да богатым, да чтобы было у него время учиться по охоте своей, а не то что с палкой в руке говорить: «Учись!» Черт знает, с которого конца начинают!.. Ну, послушайте: ну, вот я вам на суд… — Тут Костанжогло подвинулся ближе к Чичикову и, чтобы заставить его получше вникнуть в дело, взял его на абордаж, другими словами — засунул палец в петлю его фрака. — Ну, что может быть яснее? У тебя крестьяне затем, чтобы ты им покровительствовал в их крестьянском быту. В чем же быт? в чем же занятия крестьянина? В хлебопашестве? Так старайся, чтобы он был хорошим хлебопашцем. Ясно? Нет, нашлись умники, говорят: «Из этого состоянья его нужно вывести. Он ведет слишком грубую, простую жизнь: нужно познакомить его с предметами роскоши». Что сами благодаря этой роскоши стали тряпки, а не люди, и болезней черт знает каких понабрались, и уж нет осьмнадцатилетнего мальчишки, который бы не испробовал всего: и зубов у него нет, и плешив, — так хотят теперь и этих заразить. Да слава богу, что у нас осталось хотя одно еще здоровое сословие, которое не познакомилось с этими прихотями! За это мы просто должны благодарить бога. Да, хлебопашцы для меня всех почтеннее.', '203.jpg', 60, '2020-06-06 08:18:51'),
(967, '— Так вы полагаете, что хлебопашеством всего выгоднее заниматься.', '— Так вы полагаете, что хлебопашеством всего выгоднее заниматься? — спросил Чичиков.', '.', '102.jpg', 4, '2020-06-02 02:07:51'),
(968, '— Законнее, а не то что выгоднее. Возделывай землю в поте лица своего.', '— Законнее, а не то что выгоднее. Возделывай землю в поте лица своего. Это нам всем сказано; это недаром сказано. Опытом веков уже это доказано, что в земледельческом звании человек чище нравами.', ' Где хлебопашество легло в основанье быта общественного, там изобилье и довольство; бедности нет, роскоши нет, а есть довольство. Возделывай землю — сказано человеку, трудись… что тут хитрить! Я говорю мужику: «Кому бы ты ни трудился, мне ли, себе ли, соседу ли, только трудись. В деятельности я твой первый помощник. Нет у тебя скотины, вот тебе лошадь, вот тебе корова, вот тебе телега… Всем, что нужно, готов тебя снабдить, но трудись. Для меня смерть, если хозяйство у тебя не в устройстве и вижу у тебя беспорядок и бедность. Не потерплю праздности. Я затем над тобой, чтобы ты трудился». Гм! думают увеличить доходы заведеньями да фабриками! Да ты подумай прежде о том, чтобы всякий мужик был у тебя богат, так тогда ты и сам будешь богат без фабрик, и без заводов, и без глупых затей.', '302.jpg', 42, '2020-05-24 00:49:04'),
(969, '— Чем больше слушаешь вас, почтеннейший Константин Федорович, — сказал Чичиков.', '— Чем больше слушаешь вас, почтеннейший Константин Федорович, — сказал Чичиков, — тем большее получаешь желание слушать.', ' Скажите, досточтимый мною: если бы, например, я возымел намерение сделаться помещиком, положим, здешней губернии, на что преимущественно обратить внимание? как быть, как поступить, чтобы в непродолжительное время разбогатеть, чтобы тем, так сказать, исполнить существенную обязанность гражданина.', '002.jpg', 58, '2020-05-17 00:12:44'),
(970, '— Пойдем ужинать.', '— Пойдем ужинать! — сказала хозяйка, поднявшись с дивана, и выступила на середину комнаты, закутывая в шаль молодые продрогнувшие свои члены.', '.', '203.jpg', 40, '2020-05-13 18:45:00'),
(971, 'Чичиков схватился со стула с ловкостью почти военного человека.', 'Чичиков схватился со стула с ловкостью почти военного человека, подлетел к хозяйке с мягким выраженьем в улыбке деликатного штатского человека, коромыслом подставил ей руку и повел ее парадно через две комнаты в столовую.', 'Чичиков схватился со стула с ловкостью почти военного человека, подлетел к хозяйке с мягким выраженьем в улыбке деликатного штатского человека, коромыслом подставил ей руку и повел ее парадно через две комнаты в столовую, сохраняя во все время приятное наклоненье головы несколько набок. Служитель снял крышку с суповой чашки; все со стульями придвинулись ближе к столу, и началось хлебанье супа.', '202.jpg', 35, '2020-05-03 12:31:41'),
(972, 'Отделавши суп и запивши рюмкой наливки (наливка была отличная).', 'Отделавши суп и запивши рюмкой наливки (наливка была отличная), Чичиков сказал так Костанжоглу.', 'Отделавши суп и запивши рюмкой наливки (наливка была отличная), Чичиков сказал так Костанжоглу.', '102.jpg', 3, '2020-04-26 08:13:03'),
(973, '— Гм! — Чичиков задумался.', '— Гм! — Чичиков задумался.', ' — А отчего же вы сами, — проговорил он с некоторою робостью, — не покупаете его.', '101.jpg', 54, '2025-11-10 14:50:15'),
(974, '— Да нужно знать наконец пределы.', '— Да нужно знать наконец пределы. У меня и без того много хлопот около своих имений. Притом у нас дворяне и без того уже кричат на меня, будто я, пользуясь крайностями и разоренными их положеньями, скупаю земли за бесценок.', ' Это мне уж наконец надоело.', '302.jpg', 12, '2025-11-06 12:29:29'),
(975, '— А уж у нас, в нашей губернии… Вы не можете себе представить.', '— А уж у нас, в нашей губернии… Вы не можете себе представить, что они говорят обо мне. Они меня иначе и не называют, как сквалыгой и скупердяем первой степени. Себя они во всем извиняют.', ' «Я, говорит, конечно, промотался, но потому, что жил высшими потребностями жизни. Мне нужны книги, я должен жить роскошно, чтобы промышленность поощрять; а этак, пожалуй, можно прожить и не разорившись, если бы жить такой свиньею, как Костанжогло».', '100.jpg', 18, '2025-11-05 11:45:07'),
(976, '— Позвольте мне, досточтимый мною.', '— Позвольте мне, досточтимый мною, обратить вас вновь к предмету прекращенного разговора.', ' Если бы, положим, я приобрел то самое имение, о котором вы изволили упомянуть.', '302.jpg', 11, '2025-11-14 11:38:39'),
(977, '— Если вы хотите, — подхватил сурово и отрывисто Костанжогло.', '— Если вы хотите, — подхватил сурово и отрывисто Костанжогло, еще полный нерасположенья духа, — разбогатеть скоро, так вы никогда не разбогатеете; если же хотите разбогатеть, не спрашивая о времени, то разбогатеете скоро.', '.', '302.jpg', 11, '2025-11-12 06:11:42'),
(978, '— Да, — сказал Костанжогло отрывисто.', '— Да, — сказал Костанжогло отрывисто, точно как бы он сердился на самого Чичикова. — Надобно иметь любовь к труду: без этого ничего нельзя сделать. Надобно полюбить хозяйство, да! И, поверьте, это вовсе не скучно.', ' Выдумали, что в деревне тоска… да я бы умер от тоски, если бы хотя один день провел в городе так, как проводят они! Хозяину нет времени скучать. В жизни его нет пустоты — все полнота. Нужно только рассмотреть весь этот многообразный круг годовых занятий — и каких занятий! занятий, истинно возвышающих дух, не говоря уже о разнообразии. Тут человек идет рядом с природой, с временами года, соучастник и собеседник всему, что совершается в творенье. Еще не появилась весна, а уж зачинаются работы: подвозы и дров и всего на время распутицы; подготовка семян; переборка, перемерка по амбарам хлеба и пересушка; установленье новых тягол. Прошли снега и реки, — работы так вдруг и закипят: там погрузки на суда, здесь расчистка дерев по лесам, пересадка дерев по садам, и пошли взрывать повсюду землю. В огородах работает заступ, в полях — соха и борона. И начинаются посевы. Безделица! Грядущий урожай сеют! Наступило лето — покосы, первейший праздник хлебопашца. Безделица! Пойдут жатва за жатвой: за рожью пшеница, за ячменем овес, а тут и дерганье конопли. Мечут стога, кладут клади. А тут и август перевалил за половину — пошла свозка всего на гумны. Наступила осень — запашки и посевы озимых хлебов, чинка амбаров, риг, скотных дворов, хлебный опыт и первый умолот. Наступит зима — и тут не дремлют работы: первые подвозы в город, молотьба по всем гумнам, перевозка перемолотого хлеба из риг в амбары, по лесам рубка и пиленье дров, подвоз кирпичу и материалу для весенних построек. Да просто я и обнять всего не в состоянье. Какое разнообразие работ! Сюда и туда взглянуть идешь: и на мельницу, и на рабочий двор, и на фабрики, и на гумна! Идешь и к мужику взглянуть, как он на себя работает. Безделица! Да для меня праздник, если плотник хорошо владеет топором; я два часа готов пред ним простоять: так веселит меня работа. А если видишь еще, с какой целью все это творится, как вокруг тебя все множится да множится, принося плод да доход. Да я и рассказать вам не могу, какое удовольствие.', '302.jpg', 7, '2025-11-06 03:57:37'),
(979, 'Как пенья райской птички, заслушался Чичиков сладкозвучных хозяйских речей.', 'Как пенья райской птички, заслушался Чичиков сладкозвучных хозяйских речей. Глотали слюнку его уста. Глаза умаслились и выражали сладость, и все бы он слушал.', '.', '002.jpg', 9, '2025-10-30 22:53:30'),
(980, '— Константин! пора вставать, — сказала хозяйка, приподнявшись со стула.', '— Константин! пора вставать, — сказала хозяйка, приподнявшись со стула. Платонов приподнялся, Костанжогло приподнялся, Чичиков приподнялся, хотя хотелось ему все сидеть да слушать. Подставив руку коромыслом, повел он обратно хозяйку.', ' Но голова его не была склонена приветливо набок, недоставало ловкости в его оборотах, потому что мысли были заняты существенными оборотами и соображениями.', '202.jpg', 40, '2025-10-23 18:29:11'),
(981, '— Что ни рассказывай, а все, однако же, скучно, — говорил, идя позади их.', '— Что ни рассказывай, а все, однако же, скучно, — говорил, идя позади их, Платонов.', '.', '100.jpg', 54, '2025-10-16 17:49:00');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(982, '«Гость, кажется, очень неглупый человек, — думал хозяин.', '«Гость, кажется, очень неглупый человек, — думал хозяин, — степенен в словах и не щелкопер». И, подумавши так, стал он еще веселее, точно как бы сам разогрелся от своего разговора и как бы празднуя, что нашел человека, готового слушать умные советы.', '.', '203.jpg', 8, '2025-10-14 16:01:11'),
(983, 'Когда потом поместились они все в маленькой, уютной комнатке.', 'Когда потом поместились они все в маленькой, уютной комнатке, озаренной свечками, насупротив балконной стеклянной двери наместо окна, Чичикову сделалось так приютно, как не бывало давно.', ' Точно как бы после долгих странствований приняла уже его родная крыша и, по совершенье всего, он уже получил все желаемое и бросил скитальческий посох, сказавши: «Довольно!» Такое обаятельное расположенье навел ему на душу разумный разговор хозяина. Есть для всякого человека такие речи, которые как бы ближе и родственней ему других речей. И часто неожиданно, в глухом, забытом захолустье, на безлюдье безлюдном, встретишь человека, которого греющая беседа заставит позабыть тебя и бездорожье дороги, и бесприютность ночлегов, и современный свет, полный глупостей людских, обманов, обманывающих человека. И живо потом навсегда и навеки останется проведенный таким образом вечер, и все, что тогда случилось и было, удержит верная память: и кто соприсутствовал, и кто на каком месте стоял, и что было в руках его, — стены, углы и всякую безделушку.', '103.jpg', 54, '2025-10-09 13:24:20'),
(984, 'Так и Чичикову заметилось все в тот вечер, и эта малая.', 'Так и Чичикову заметилось все в тот вечер, и эта малая, неприхотливо убранная комнатка, и добродушное выраженье, воцарившееся в лице хозяина, и поданная Платонову трубка с янтарным мундштуком, и дым, который он стал пускать в толстую морду Ярбу.', 'Так и Чичикову заметилось все в тот вечер: и эта малая, неприхотливо убранная комнатка, и добродушное выраженье, воцарившееся в лице хозяина, и поданная Платонову трубка с янтарным мундштуком, и дым, который он стал пускать в толстую морду Ярбу, и фырканье Ярба, и смех миловидной хозяйки, прерываемый словами: «Полно, не мучь его», — и веселые свечки, и сверчок в углу, и стеклянная дверь, и весенняя ночь, которая оттоле на них глядела, облокотясь на вершины дерев, из чащи которых высвистывали весенние соловьи.', '002.jpg', 17, '2025-10-04 12:48:13'),
(985, '— Сладки мне ваши речи, досточтимый мною Константин Федорович.', '— Сладки мне ваши речи, досточтимый мною Константин Федорович, — произнес Чичиков. — Могу сказать, что не встречал во всей России человека, подобного вам по уму.', '.', '101.jpg', 16, '2025-09-24 08:16:43'),
(986, '— Нет, Павел Иванович, — сказал он, — уж если хотите знать умного человека.', '— Нет, Павел Иванович, — сказал он, — уж если хотите знать умного человека, так у нас, действительно, есть один, о котором, точно, можно сказать: «умный человек», которого я и подметки не стою.', '.', '102.jpg', 40, '2025-09-21 02:30:18'),
(987, '— Это человек, который не то что именьем помещика, — целым государством управит.', '— Это человек, который не то что именьем помещика, — целым государством управит. Будь у меня государство, я бы его сей же час сделал министром финансов.', '.', '302.jpg', 11, '2025-09-15 20:10:44'),
(988, '— Слышал.', '— Слышал. Говорят, человек, превосходящий меру всякого вероятия, десять миллионов, говорят, нажил.', '.', '202.jpg', 23, '2025-09-12 17:57:01'),
(989, '— Всенепременно. У него теперь приращенье должно идти с быстротой невероятной.', '— Всенепременно. У него теперь приращенье должно идти с быстротой невероятной. Это ясно. Медленно богатеет только тот, у кого какие-нибудь сотни тысяч; а у кого миллионы, у того радиус велик: что ни захватит, так вдвое и втрое противу самого себя.', ' Поле-то, поприще слишком просторно. Тут уж и соперников нет. С ним некому тягаться. Какую цену чему ни назначит, такая и останется: некому перебить.', '100.jpg', 2, '2025-09-04 16:56:21'),
(990, 'Вытаращив глаза и разинувши рот, как вкопанный.', 'Вытаращив глаза и разинувши рот, как вкопанный, смотрел Чичиков в глаза Костанжогло. Захватило дух в груди ему.', '.', '102.jpg', 6, '2025-08-29 15:13:46'),
(991, '— Уму непостижимо! — сказал он, приходя немного в себя.', '— Уму непостижимо! — сказал он, приходя немного в себя. — Каменеет мысль от страха.', ' Изумляются мудрости промысла в рассматриванье букашки; для меня более изумительно то, что в руках смертного могут обращаться такие громадные суммы! Позвольте предложить вам вопрос насчет одного обстоятельства; скажите, ведь это, разумеется, вначале приобретено не без греха.', '203.jpg', 10, '2025-08-22 13:04:28'),
(992, '— Не поверю, почтеннейший, извините, не поверю.', '— Не поверю, почтеннейший, извините, не поверю. Если б это были тысячи, еще бы так, но миллионы… извините, не поверю.', '.', '301.jpg', 33, '2025-08-19 10:54:55'),
(993, '— Напротив, тысячи — трудно без греха, а миллионы наживаются легко.', '— Напротив, тысячи — трудно без греха, а миллионы наживаются легко. Миллионщику нечего прибегать к кривым путям. Прямой таки дорогой так и ступай, все бери, что ни лежит перед тобой! Другой не подымет.', '.', '202.jpg', 42, '2025-08-18 07:32:48'),
(994, '— Уму непостижимо.', '— Уму непостижимо! И что всего непостижимей, это то, что дело ведь началось из копейки.', '— Уму непостижимо! И что всего непостижимей, это то, что дело ведь началось из копейки.', '101.jpg', 39, '2025-08-15 01:38:20'),
(995, '— Да иначе и не бывает. Это законный порядок вещей, — сказал Костанжогло.', '— Да иначе и не бывает. Это законный порядок вещей, — сказал Костанжогло. — Кто родился с тысячами, воспитался на тысячах, тот уже не приобретет: у того уже завелись и прихоти, и мало ли чего нет! Начинать нужно с начала, а не с середины.', ' Снизу, снизу нужно начинать. Тут только узнаешь хорошо люд и быт, среди которых придется потом изворачиваться. Как вытерпишь на собственной коже то да другое, да как узнаешь, что всякая копейка алтынным гвоздем прибита, да как перейдешь все мытарства, тогда тебя умудрит и вышколит так, что уж не дашь промаха ни в каком предприятье и не оборвешься. Поверьте, это правда.', '101.jpg', 39, '2025-08-06 01:26:17'),
(996, 'С начала нужно начинать, а не с середины.', 'С начала нужно начинать, а не с середины. Кто говорит мне: «Дайте мне сто тысяч, я сейчас разбогатею», — я тому не поверю: он бьет наудачу, а не наверняка.', ' С копейки нужно начинать.', '201.jpg', 35, '2025-08-02 23:02:58'),
(997, '— В таком случае я разбогатею, — сказал Чичиков, — потому что начинаю почти.', '— В таком случае я разбогатею, — сказал Чичиков, — потому что начинаю почти, так сказать, с ничего.', '.', '302.jpg', 57, '2025-07-23 22:25:14'),
(998, '— Константин, пора дать Павлу Ивановичу отдохнуть и поспать, — сказала хозяйка.', '— Константин, пора дать Павлу Ивановичу отдохнуть и поспать, — сказала хозяйка, — а ты все болтаешь.', '.', '100.jpg', 55, '2025-07-17 17:59:00'),
(999, '— И непременно разбогатеете, — сказал Костанжогло, не слушая хозяйки.', '— И непременно разбогатеете, — сказал Костанжогло, не слушая хозяйки. — К вам потекут реки, реки золота. Не будете знать, куда девать доходы.', '.', '301.jpg', 13, '2025-07-08 16:32:20'),
(1000, 'Как очарованный, сидел Павел Иванович.', 'Как очарованный, сидел Павел Иванович, и в золотой области возрастающих грез и мечтаний закружилися его мысли.', '.', '202.jpg', 39, '2025-06-30 16:19:27'),
(1001, '— Да что ж тебе.', '— Да что ж тебе? Ну, и ступай, если захотелось! — сказал хозяин и остановился: громко, по всей комнате раздалось храпенье Платонова, а вслед за ним Ярб захрапел еще громче. Уже давно слышался отдаленный стук в чугунные доски.', ' Дело потянуло за полночь. Костанжогло заметил, что в самом деле пора на покой. Все разбрелись, пожелав спокойного сна друг другу, и не замедлили им воспользоваться.', '002.jpg', 41, '2025-06-23 15:12:11'),
(1002, 'Одному Чичикову только не спалось. Его мысли бодрствовали.', 'Одному Чичикову только не спалось. Его мысли бодрствовали. Он обдумывал, как сделаться помещиком, подобным Костанжогло. После разговора с хозяином все становилося так ясно: возможность разбогатеть казалась так очевидной.', ' Трудное дело хозяйства становилось теперь так легко и понятно и так казалось свойственно самой его натуре, что начал помышлять он сурьезно о приобретении не воображаемого, но действительного поместья; он определил тут же на деньги, которые будут выданы ему из ломбарда за фантастические души, приобресть поместье уже не фантастическое. Уже он видел себя действующим и правящим именно так, как поучал Костанжогло, — расторопно, осмотрительно, ничего не заводя нового, не узнавши насквозь всего старого, все высмотревши собственными глазами, всех мужиков узнавши, все излишества от себя оттолкнувши, отдавши себя только труду да хозяйству. Уже заранее предвкушал он то удовольствие, которое будет он чувствовать, когда заведется стройный порядок и бойким ходом двигнутся все пружины хозяйства, деятельно толкая друг друга. Труд закипит, и, подобно тому как в ходкой мельнице шибко вымалывается из зерна мука, пойдет вымалываться изо всякого дрязгу и хламу чистоган да чистоган. Чудный хозяин так и стоял пред ним ежеминутно. Это был первый человек во всей России, к которому почувствовал он уважение личное. Доселе уважал он человека или за хороший чин, или за большие достатки! Собственно за ум он не уважал еще ни одного человека. Костанжогло был первый. Чичиков понял и то, что с этаким нечего толковать о мертвых душах и самая речь об этом будет неуместна. Его занимал теперь другой прожект — купить именье Хлобуева. Десять тысяч у него было: другие десять тысяч предполагал он призанять у Костанжогло, так как он сам объявил уже, что готов помочь всякому, желающему разбогатеть и заняться хозяйством. Остальные десять тысяч можно было обязаться потом, по заложении душ. Заложить все накупленные души еще нельзя было, потому что не было еще земель, на которые следовало переселить их. Хотя уверял он, что в Херсонской губернии есть у него земли, но они существовали больше в предположенье. Предполагалось еще и скупить их в Херсонской губернии, потому что они там продавались за бесценок и даже отдавались даром, лишь бы только на них селились.', '002.jpg', 22, '2025-06-15 10:15:22'),
(1003, 'На другой день все обделалось как нельзя лучше.', 'На другой день все обделалось как нельзя лучше. Костанжогло дал с радостью десять тысяч без процентов, без поручительства — просто под одну расписку. Так был он готов помогать всякому на пути к приобретенью.', ' Этого мало: он сам взялся сопровождать Чичикова к Хлобуеву, с тем чтобы осмотреть вместе с ним имение. После сытного завтрака все они отправились, севши все трое в коляску Павла Ивановича; пролетки хозяина следовали порожняком за ними. Ярб бежал впереди, сгоняя с дороги птиц. В полтора часа с небольшим сделали они восемнадцать верст и увидели деревушку с двумя домами. Один большой и новый, недостроенный и остававшийся вчерне несколько лет, другой маленький и старенький. Хозяина нашли они растрепанного, заспанного, недавно проснувшегося; на сюртуке у него была заплата, а на сапоге дырка.', '102.jpg', 25, '2025-06-11 06:40:24'),
(1004, 'Приезду гостей он обрадовался, как бог весть чему.', 'Приезду гостей он обрадовался, как бог весть чему. Точно как бы увидел он братьев, с которыми надолго расстался.', '.', '101.jpg', 44, '2025-06-09 00:52:02'),
(1005, '— Константин Федорович! Платон Михайлович! — вскрикнул он.', '— Константин Федорович! Платон Михайлович! — вскрикнул он. — Отцы родные! вот одолжили приездом! Дайте протереть глаза! Я уж, право, думал, что ко мне никто не заедет. Всяк бегает меня, как чумы: думает — попрошу взаймы.', ' Ох, трудно, трудно, Константин Федорович! Вижу — сам всему виной! Что делать? свинья свиньей зажил. Извините, господа, что принимаю вас в таком наряде: сапоги, как видите, с дырами.', '203.jpg', 37, '2025-06-05 20:25:52'),
(1006, '— Пожалуйста, без околичностей.', '— Пожалуйста, без околичностей. Мы к вам приехали за делом, — сказал Костанжогло. — Вот вам покупщик, Павел Иванович Чичиков.', '.', '301.jpg', 18, '2025-06-01 19:01:16'),
(1007, '— Хотел бы очень, почтеннейший Павел Иванович, показать вам имение.', '— Хотел бы очень, почтеннейший Павел Иванович, показать вам имение, стоящее внимания… Да что, господа, позвольте спросить, вы обедали.', '— Хотел бы очень, почтеннейший Павел Иванович, показать вам имение, стоящее внимания… Да что, господа, позвольте спросить, вы обедали.', '002.jpg', 24, '2025-05-28 18:22:57'),
(1008, '— Обедали, обедали, — сказал Костанжогло, желая отделаться.', '— Обедали, обедали, — сказал Костанжогло, желая отделаться. — Не будем и мешкать и пойдем теперь же.', '.', '100.jpg', 9, '2025-05-27 14:11:49'),
(1009, 'Хлобуев взял в руки картуз.', 'Хлобуев взял в руки картуз. Гости надели на головы картузы, и все отправились пешком осматривать деревню.', '.', '100.jpg', 59, '2025-05-25 13:00:53'),
(1010, '— Пойдем осматривать беспорядки и беспутство мое, — гозорил Хлобуев.', '— Пойдем осматривать беспорядки и беспутство мое, — гозорил Хлобуев. — Конечно, вы сделали хорошо, что пообедали. Поверите ли, Константин Федорович, курицы нет в доме, — до того дожил.', ' Свиньей себя веду, просто свиньей.', '201.jpg', 29, '2025-05-16 12:15:14'),
(1011, 'Он, глубоко вздохнув и как бы чувствуя.', 'Он, глубоко вздохнув и как бы чувствуя, что мало будет участия со стороны Константина Федоровича и жестковато его сердце, подхватил под руку Платонова и пошел с ним вперед, прижимая крепко его к груди своей.', ' Костанжогло и Чичиков остались позади и, взявшись под руки, следовали за ними в отдалении.', '103.jpg', 3, '2025-05-11 10:05:19'),
(1012, '— Трудно, Платон Михалыч, трудно! — говорил Хлобуев Платонову.', '— Трудно, Платон Михалыч, трудно! — говорил Хлобуев Платонову. — Не можете вообразить, как трудно! Безденежье, бесхлебье, бессапожье! Трын-трава бы это было все, если бы был молод и один.', ' Но когда все эти невзгоды станут тебя ломать под старость, а под боком жена, пятеро детей, — сгрустнется.', '102.jpg', 57, '2025-05-02 04:47:51'),
(1013, '— Какое поправит! — сказал Хлобуев, махнувши рукой.', '— Какое поправит! — сказал Хлобуев, махнувши рукой. — Все пойдет на уплату необходимейших долгов, а затем для себя не останется и тысячи.', '.', '302.jpg', 32, '2025-04-27 22:27:34'),
(1014, '— Ведь я губернский секретарь.', '— Ведь я губернский секретарь. Какое ж мне могут дать выгодное место? Жалованье дадут ничтожное, а ведь у меня жена, пятеро детей.', '.', '302.jpg', 19, '2025-04-24 17:07:20'),
(1015, '— Ну, да если голод и смерть грозят, нужно же что-нибудь предпринимать.', '— Ну, да если голод и смерть грозят, нужно же что-нибудь предпринимать. Я спрошу, не может ли брат мой через кого-либо в городе выхлопотать какую-нибудь должность.', '.', '100.jpg', 23, '2025-04-19 12:55:45'),
(1016, '— Нет, Платон Михайлович, — сказал Хлобуев, вздохнувши и сжавши крепко его руку.', '— Нет, Платон Михайлович, — сказал Хлобуев, вздохнувши и сжавши крепко его руку, — не гожусь я теперь никуды. Одряхлел прежде старости своей, и поясница болит от прежних грехов, и ревматизм в плече.', ' Куды мне! Что разорять казну! И без того теперь завелось много служащих ради доходных мест. Храни бог, чтобы из-за меня, из-за доставки мне жалованья прибавлены были подати на бедное сословие: и без того ему трудно при этом множестве сосущих. Нет, Платон Михайлович, бог с ним.', '102.jpg', 4, '2025-04-17 10:23:25'),
(1017, 'Тем временем Костанжогло и Чичиков, идя позади их на порядочном расстоянии.', 'Тем временем Костанжогло и Чичиков, идя позади их на порядочном расстоянии, так между собою говорили.', 'Тем временем Костанжогло и Чичиков, идя позади их на порядочном расстоянии, так между собою говорили.', '103.jpg', 10, '2025-04-15 06:10:14'),
(1018, '— Вон запустил как все! — говорил Костанжогло, указывая пальцем.', '— Вон запустил как все! — говорил Костанжогло, указывая пальцем. — Довел мужика до какой бедности! Когда случился падеж, так уж тут нечего глядеть на свое добро.', ' Тут все свое продай, да снабди мужика скотиной, чтобы он не оставался и одного дни без средств производить работу. А ведь теперь и годами не поправишь: и мужик уже изленился, и загулял, и стал пьяница.', '100.jpg', 35, '2025-04-14 03:56:39'),
(1019, '— Так, стало быть, теперь не совсем выгодно и покупать эдакое имение.', '— Так, стало быть, теперь не совсем выгодно и покупать эдакое имение? — спросил Чичиков.', '.', '201.jpg', 14, '2025-04-05 00:46:09'),
(1020, 'Тут Костанжогло взглянул на него так, как бы хотел ему сказать.', 'Тут Костанжогло взглянул на него так, как бы хотел ему сказать: «Ты что за невежа! С азбуки, что ли, нужно с тобой начинать.', 'Тут Костанжогло взглянул на него так, как бы хотел ему сказать: «Ты что за невежа! С азбуки, что ли, нужно с тобой начинать.', '201.jpg', 58, '2025-04-03 22:40:44'),
(1021, '— Невыгодно.', '— Невыгодно! да через три года я буду получать двадцать тысяч годового дохода с этого именья. Вот оно как невыгодно! В пятнадцати верстах. Безделица! А земля-то какова? разглядите землю! Всё поемные места.', ' Да я засею льну, да тысяч на пять одного льну отпущу; репой засею — на репе выручу тысячи четыре. А вон смотрите — по косогору рожь поднялась: ведь это все падаль. Он хлеба не сеял — я это знаю. Да этому именью полтораста тысяч, а не сорок.', '102.jpg', 18, '2025-03-28 21:10:53'),
(1022, 'Чичиков стал опасаться, чтобы Хлобуев не услышал, и потому отстал еще подальше.', 'Чичиков стал опасаться, чтобы Хлобуев не услышал, и потому отстал еще подальше.', '.', '201.jpg', 22, '2025-03-21 18:53:28'),
(1023, '— Вон сколько земли оставил впусте! — говорил, начиная сердиться, Костанжогло.', '— Вон сколько земли оставил впусте! — говорил, начиная сердиться, Костанжогло. — Хоть бы повестил вперед, так набрели бы охотники. Ну, уж если нечем пахать, так копай под огород. Огородом бы взял. Мужика заставил пробыть четыре года без труда.', ' Безделица! Да ведь этим одним ты уже его развратил и навеки погубил. Уж он успел привыкнуть к лохмотыо и бродяжничеству! Это стало уже жизнью его.', '103.jpg', 29, '2025-03-20 13:31:37'),
(1024, '— Я не могу здесь больше оставаться.', '— Я не могу здесь больше оставаться: мне смерть глядеть на этот беспорядок и запустенье! Вы теперь можете с ним покончить и без меня. Отберите у этого дурака поскорее сокровище.', ' Он только бесчестит божий дар! И, сказавши это, Костанжогло простился с Чичиковым и, нагнавши хозяина, стал также прощаться.', '002.jpg', 59, '2025-03-14 13:11:24'),
(1025, '— Помилуйте, Константин Федорович, — говорил удивленный хозяин.', '— Помилуйте, Константин Федорович, — говорил удивленный хозяин, — только что приехали — и назад.', '— Помилуйте, Константин Федорович, — говорил удивленный хозяин, — только что приехали — и назад.', '202.jpg', 44, '2025-03-11 10:59:38'),
(1026, '— Не могу.', '— Не могу. Мне крайняя надобность быть дома, — сказал Костанжогло, простился, сел и уехал на своих пролетках.', '.', '203.jpg', 54, '2025-03-04 10:19:57'),
(1027, '— Не выдержал Константин Федорович, — сказал он.', '— Не выдержал Константин Федорович, — сказал он. — Чувствую, что не весело такому хозяину, каков он, глядеть на эдакое беспутное управленье.', ' Верите ли, что не могу, не могу, Павел Иванович… что почти вовсе не сеял хлеба в этом году! Как честный человек. Семян не было, не говоря уже о том, что нечем пахать. Ваш братец, Платон Михайлыч, говорят, необыкновенный хозяин; о Константине Федоровиче что уж говорить — это Наполеон своего рода. Часто, право, думаю: «Ну, зачем столько ума дается в одну голову? ну, что бы хоть каплю его в мою глупую, хоть бы на то, чтобы сумел дом свой держать! Ничего не умею, ничего не могу». Ах, Павел Иванович, возьмите в свое распоряжение! Жаль больше всего мне мужичков бедных. Чувствую, что не умел быть… что прикажете делать, не могу быть взыскательным и строгим. Да и как мог приучить их к порядку, когда сам беспорядочен! Я бы их отпустил сейчас же на волю, да как-то устроен русский человек, как-то не может без понукателя… Так и задремлет, так и заплеснет.', '002.jpg', 25, '2025-03-01 05:21:53'),
(1028, '— Ведь это, точно, странно, — сказал Платонов, — отчего это у нас так.', '— Ведь это, точно, странно, — сказал Платонов, — отчего это у нас так, что если не смотришь во все глаза за простым человеком, сделается и пьяницей и негодяем.', '— Ведь это, точно, странно, — сказал Платонов, — отчего это у нас так, что если не смотришь во все глаза за простым человеком, сделается и пьяницей и негодяем.', '102.jpg', 57, '2025-02-25 03:05:56'),
(1029, '— Ну, бог весть отчего.', '— Ну, бог весть отчего.', ' Вот мы и просветились, а ведь как живем? Я и в университете был, и слушал лекции по всем частям, а искусству и порядку жить не только не выучился, а еще как бы больше выучился искусству побольше издерживать деньги на всякие новые утонченности да комфорты, больше познакомился с такими предметами, на которые нужны деньги. Оттого ли, что я бестолково учился? Только нет: ведь так и другие товарищи. Может быть, два-три человека извлекли себе настоящую пользу, да и то оттого, может, что и без того были умны, а прочие ведь только и стараются узнать то, что портит здоровье, да и выманивает деньги. Ей-богу! Ведь учиться приходили только затем, чтобы аплодировать профессорам, раздавать им награды, а не самим от них получать. Так из просвещенья-то мы все-таки выберем то, что погаже: наружность его схватим, а его самого не возьмем. Нет, Павел Иванович, не умеем мы жить отчего-то другого, а отчего, ей-богу, я не знаю.', '103.jpg', 36, '2025-02-19 01:48:00'),
(1030, '— Иной раз, право, мне кажется.', '— Иной раз, право, мне кажется, что будто русский человек — какой-то пропащий человек. Нет силы воли, нет отваги на постоянство. Хочешь все сделать — и ничего не можешь.', ' Все думаешь — с завтрашнего дли начнешь новую жизнь, с завтрашнего дни примешься за все как следует, с завтрашнего дни сядешь на диету, — ничуть не бывало: к вечеру того же дни так объешься, что только хлопаешь глазами и язык не ворочается, как сова, сидишь, глядя на всех, — право, и эдак все.', '101.jpg', 4, '2025-02-09 20:23:25'),
(1031, '— Нужно в запасе держать благоразумие, — сказал Чичиков.', '— Нужно в запасе держать благоразумие, — сказал Чичиков, — ежеминутно совещаться с благоразумием, вести с ним дружескую беседу.', '.', '201.jpg', 47, '2025-02-08 17:04:27'),
(1032, '— Да что! — сказал Хлобуев.', '— Да что! — сказал Хлобуев. — Право, мне кажется, мы совсем не для благоразумия рождены. Я не верю, чтобы из нас был кто-нибудь благоразумным.', ' Если я вижу, что иной даже и порядочно живет, собирает и копит деньгу, — не верю я и тому! На старости и его черт попутает — спустит потом всё вдруг! И все у нас так: и благородные, и мужики, и просвещенные, и непросвещенные. Вон какой был умный мужик: из ничего нажил сто тысяч, а как нажил сто тысяч, пришла в голову дурь сделать ванну из шампанского, и выкупался в шампанском. Но вот мы, кажется, и все обсмотрели. Больше ничего нет. Хотите разве взглянуть на мельницу? Впрочем, в ней нет колеса, да и строенье никуда не годится.', '301.jpg', 55, '2025-02-02 12:53:13'),
(1033, 'На возвратном пути были виды те же.', 'На возвратном пути были виды те же. Неопрятный беспорядок так и выказывал отовсюду безобразную свою наружность. Все было опущено и запущено. Прибавилась только новая лужа посреди улицы.', ' Сердитая баба, в замасленной дерюге, прибила до полусмерти бедную девчонку и ругала на все бока всех чертей. Поодаль два мужика глядели с равнодушием стоическим на гнев пьяной бабы. Один чесал у себя пониже спины, другой зевал. Зевота видна была на строениях. Крыши также зевали. Платонов, глядя на них, зевнул. «Мое-то будущее достоянье — мужики, — подумал Чичиков, — дыра на дыре и заплата на заплате!» И точно, на одной избе, вместо крыши, лежали целиком ворота; провалившиеся окна подперты были жердями, стащенными с господского амбара. Словом, в хозяйство введена была, кажется, система Тришкина кафтана: отрезывались обшлага и фалды на заплату локтей.', '002.jpg', 4, '2025-01-28 07:05:37'),
(1034, 'Они вошли в комнаты.', 'Они вошли в комнаты. Чичикова несколько поразило смешение нищеты с некоторыми блестящими безделушками позднейшей роскоши. Посреди изорванной утвари и мебели — новенькие бронзы.', ' Какой-то Шекспир сидел на чернильнице; на столе лежала щегольская ручка слоновой кости для почесывания себе самому спины. Хлобуев отрекомендовал им хозяйку жену. Она была хоть куда. В Москве не ударила бы лицом в грязь. Платье на ней было со вкусом, по моде. Говорить любила больше о городе да о театре, который там завелся. По всему было видно, что деревню она любила еще меньше, чем муж, и что зевала она больше Платонова, когда оставалась одна. Скоро комната наполнилась детьми, девочками и мальчиками. Их было пятеро. Шестое принеслось на руках. Все были прекрасны. Мальчики и девочки — загляденье. Они были одеты мило и со вкусом, были резвы и веселы. И от этого было еще грустнее глядеть на них. Лучше бы одеты они были дурно, в простых пестрядевых юбках и рубашках, бегали себе по двору и ничем не отличались от простых крестьянских детей! К хозяйке приехала гостья. Дамы ушли на свою половину. Дети убежали вслед за ними. Мужчины остались одни.', '302.jpg', 12, '2025-01-25 00:49:57'),
(1035, 'Чичиков приступил к покупке.', 'Чичиков приступил к покупке. По обычаю всех покупщиков, сначала он охаял покупаемое имение.', ' И, охаявши его со всех сторон, сказал.', '301.jpg', 15, '2025-01-15 19:38:32'),
(1036, '— Видите ли что? — сказал Хлобуев.', '— Видите ли что? — сказал Хлобуев. — Запрашивать с вас дорого не буду, да и не люблю: это было бы с моей стороны и бессовестно.', ' Я от вас не скрою также и того, что в деревне моей из ста душ, числящихся по ревизии, и пятидесяти нет налицо: прочие или померли от эпидемии ческой болезни, или отлучились беспаспортно, так что вы почитайте их как бы умершими. Поэтому-то я и прошу с вас всего только тридцать тысяч.', '100.jpg', 22, '2025-01-05 17:10:48'),
(1037, '— Ну вот — тридцать тысяч! Именье запущено, люди мертвы, и тридцать тысяч.', '— Ну вот — тридцать тысяч! Именье запущено, люди мертвы, и тридцать тысяч! Возьмите двадцать пять тысяч.', '.', '202.jpg', 49, '2024-12-28 15:51:05'),
(1038, '— Павел Иванович.', '— Павел Иванович! Я могу его заложить в ломбард в двадцать пять тысяч, понимаете ли это? Тогда я получаю двадцать пять тысяч и имение при мне.', ' Продаю я единственно затем, что мне нужны скоро деньги, а при закладке была бы проволочка, надобно бы платить приказным, а платить нечем.', '103.jpg', 38, '2024-12-25 09:28:57'),
(1039, '— Ну, да все-таки возьмите двадцать пять тысяч.', '— Ну, да все-таки возьмите двадцать пять тысяч. Платонову сделалось совестно за Чичикова.', '.', '202.jpg', 24, '2024-12-17 06:29:29'),
(1040, '— Покупайте, Павел Иванович, — сказал он.', '— Покупайте, Павел Иванович, — сказал он. — За имение можно всегда дать эту цену. Если вы не дадите за него тридцать тысяч, мы с братом складываемся и покупаем.', '.', '101.jpg', 36, '2024-12-09 01:06:00'),
(1041, '— Хорошо! — сказал он. — Даю тридцать тысяч.', '— Хорошо! — сказал он. — Даю тридцать тысяч. Вот две тысячи задатку дам вам теперь, восемь тысяч через неделю, а остальные двадцать тысяч через месяц.', '.', '203.jpg', 43, '2024-11-29 23:56:47'),
(1042, '— Нет, Павел Иванович, только на том условии, чтобы деньги как можно скорее.', '— Нет, Павел Иванович, только на том условии, чтобы деньги как можно скорее. Теперь вы мне дайте пятнадцать тысяч, по крайней мере, а остальные никак не дальше, как через две недели.', '.', '301.jpg', 35, '2024-11-24 18:26:31'),
(1043, '— Нет, пожалуйста, Павел Иванович.', '— Нет, пожалуйста, Павел Иванович! я говорю, что необходимо мне нужны пятнадцать тысяч.', '.', '203.jpg', 37, '2024-11-15 15:51:58'),
(1044, '— Разве эдак.', '— Разве эдак! — сказал Чичиков и подумал про себя: «А это, однако же, кстати, что он дает взаймы: в таком случае завтра можно будет привезти».', ' Из коляски была принесена шкатулка и тут же было из нее вынуто десять тысяч Хлобуеву; остальные же пять тысяч обещано было привезти ему завтра: то есть обещано; предполагалось же привезти три; другие потом, денька через два или три, а если можно, то и еще несколько просрочить. Павел Иванович как-то особенно не любил выпускать из рук денег. Если ж настояла крайняя необходимость, то все-таки, казалось ему, лучше выдать деньги завтра, а не сегодня. То есть он поступал, как все мы! Ведь нам приятно же поводить просителя. Пусть его натрет себе спину в передней! Будто уж и нельзя подождать ему! Какое нам дело до того, что, может быть, всякий час ему дорог и терпят оттого дела его! «Приходи, братец, завтра, а сегодня мне как-то некогда».', '103.jpg', 8, '2024-11-12 11:56:21'),
(1045, '— Где ж вы после этого будете жить? — спросил Платонов Хлобуева.', '— Где ж вы после этого будете жить? — спросил Платонов Хлобуева.', ' — Есть у вас другая деревушка.', '103.jpg', 7, '2024-11-06 08:10:55'),
(1046, '— Деревушки нет, а я перееду в город.', '— Деревушки нет, а я перееду в город. Все же равно это было нужно сделать не для себя, а для детей. Им нужны будут учителя закону божию, музыке, танцеванью. Ведь в деревне нельзя достать.', '.', '103.jpg', 1, '2024-10-31 04:15:22'),
(1047, '— Что ж, нужно нам чем-нибудь вспрыснуть сделку, — сказал Хлобуев.', '— Что ж, нужно нам чем-нибудь вспрыснуть сделку, — сказал Хлобуев. — Эй, Кирюшка, принеси, брат, бутылку шампанского.', '.', '101.jpg', 32, '2024-10-24 03:40:13'),
(1048, 'Шампанское было принесено. Они выпили по три бокала и развеселились.', 'Шампанское было принесено. Они выпили по три бокала и развеселились. Хлобуев развязался, стал умен и мил. Остроты и анекдоты сыпались у него беспрерывно.', ' В речах его оказалось столько познанья людей и света! Так хорошо и верно видел он многие вещи, так метко и ловко очерчивал в немногих словах соседей помещиков, так видел ясно недостатки и ошибки всех, так хорошо знал историю разорившихся бар — и почему, и как, и отчего они разорились, так оригинально и метко умел гередавать малейшие их привычки, что они оба были совершенно обворожены его речами и готовы были признать его за умнейшего человека.', '102.jpg', 58, '2024-10-20 03:17:17'),
(1049, '— Послушайте, — сказал Платонов, схвативши его за руку, — как вам при таком уме.', '— Послушайте, — сказал Платонов, схвативши его за руку, — как вам при таком уме, опытности и познаниях житейских не найти средств выпутаться из вашего затруднительного положения.', '— Послушайте, — сказал Платонов, схвативши его за руку, — как вам при таком уме, опытности и познаниях житейских не найти средств выпутаться из вашего затруднительного положения.', '301.jpg', 42, '2024-10-19 00:31:04'),
(1050, '— Средства-то есть.', '— Средства-то есть, — сказал Хлобуев и вслед за тем выгрузил им целую кучу прожектов.', ' Все они были до того нелепы, так странны, так мало истекали из познанья людей и света, что оставалось только пожимать плечами да говорить: «Господи боже! какое необъятное расстояние между знаньем света и уменьем пользоваться этим знаньем!» Почти все прожекты основывались на потребности вдруг достать откуда-нибудь сто или двести тысяч. Тогда, казалось ему, все бы устроилось как следует, и хозяйство бы пошло, и прорехи все бы заплетались, и доходы можно учетверить, и себя привести в возможность выплатить все долги. И оканчивал он речь свою: — Но что прикажете делать? Нет, да и нет такого благодетеля, который бы решился дать двести или хоть сто тысяч взаймы! Видно, уж бог не хочет.', '103.jpg', 14, '2024-10-10 23:20:49'),
(1051, '— Есть у меня, пожалуй, трехмиллионная тетушка, — сказал Хлобуев.', '— Есть у меня, пожалуй, трехмиллионная тетушка, — сказал Хлобуев, — старушка богомольная: на церкви и монастыри дает, но помогать ближнему тугенька. А старушка очень замечательная. Прежних времен тетушка, на которую бы взглянуть стоило.', ' У ней одних канареек сотни четыре. Моськи, и приживалки, и слуги, каких уж теперь нет. Меньшому из слуг будет лет шестьдесят, хоть она и зовет его: «Эй, малый!» Если гость как-нибудь себя не так поведет, так она за обедом прикажет обнести его блюдом. И обнесут, право.', '102.jpg', 39, '2024-10-05 22:02:35'),
(1052, '— Отчего ж вы не обратитесь к ней? — сказал с участьем Платонов.', '— Отчего ж вы не обратитесь к ней? — сказал с участьем Платонов. — Мне кажется, если бы она только поближе вошла в положенье вашего семейства, она бы не в силах была отказать вам, как бы ни была туга.', '.', '101.jpg', 39, '2024-09-26 20:43:03'),
(1053, '— Ну нет, в силах! У тетушки натура крепковата.', '— Ну нет, в силах! У тетушки натура крепковата. Это старушка — кремень, Платон Михайлыч! Да к тому ж есть и без меня угодники, которые около нее увиваются.', ' Там есть один, который метит в губернаторы, приплелся ей в родню… бог с ним! может быть, и успеет! Бог с ними со всеми! Я подъезжать и прежде не умел, а теперь и подавно: спина уж не гнется.', '103.jpg', 32, '2024-09-19 16:07:53'),
(1054, '«Дурак! — подумал Чичиков.', '«Дурак! — подумал Чичиков.', ' — Да я бы за этакой тетушкой ухаживал, как нянька за ребенком.', '103.jpg', 53, '2024-09-14 14:05:35'),
(1055, '— Что ж, ведь этак разговаривать сухо, — сказал Хлобуев.', '— Что ж, ведь этак разговаривать сухо, — сказал Хлобуев. — Эй, Кирюшка! принеси-ка еще другую бутылку шампанского.', '.', '202.jpg', 40, '2024-09-07 12:07:35'),
(1056, '— Ну, так, по крайней мере, дайте мне слово побывать у меня в городе.', '— Ну, так, по крайней мере, дайте мне слово побывать у меня в городе: восьмого июня я даю обед нашим городским сановникам.', '.', '102.jpg', 47, '2024-08-28 11:31:41'),
(1057, '— Помилуйте! — воскликнул Платонов.', '— Помилуйте! — воскликнул Платонов.', ' — В таком состоянии, разорившись совершенно, — и еще обед.', '103.jpg', 56, '2024-08-24 06:35:10'),
(1058, '«Что с ним делать?» — подумал Платонов.', '«Что с ним делать?» — подумал Платонов. Он еще не знал того, что на Руси, на Москве и других городах, водятся такие мудрецы, которых жизнь — необъяснимая загадка.', ' Все, кажется, прожил, кругом в долгах, ниоткуда никаких средств, и обед, который задается, кажется, последний; и думают обедающие, что завтра же хозяина потащат в тюрьму. Проходит после того десять лет — мудрец все еще держится на свете, еще больше прежнего кругом в долгах и так же задает обед, и все думают, что он последний, и все уверены, что завтра же потащат хозяина в тюрьму. Такой же мудрец был Хлобуев. Только на одной Руси можно было существовать таким образом. Не имея ничего, он угощал и хлебосольничал, и даже оказывал покровительство, поощрял всяких артистов, приезжавших в город, давал им у себя приют и квартиру. Если бы кто заглянул в дом его, находившийся в городе, он бы никак не узнал, кто в нем хозяин. Сегодня поп в ризе служил там молебен, завтра давали репетицию французские актеры. В иной день какой-нибудь, не известный никому почти в дому, поселялся в самой гостиной с бумагами и заводил там кабинет, и это не смущало, не беспокоило никого в доме, как бы было житейское дело. Иногда по целым дням не бывало крохи в доме, иногда же задавали в нем такой обед, который удовлетворил бы вкусу утонченнейшего гастронома. Хозяин являлся праздничный, веселый, с осанкой богатого барина, с походкой человека, которого жизнь протекает в избытке и довольстве. Зато временами бывали такие тяжелые минуты, что другой давно бы на его месте повесился или застрелился. Но его спасало религиозное настроение, которое странным образом совмещалось в нем с беспутною его жизнью. В эти горькие, тяжелые минуты развертывал он книгу и читал жития страдальцев и тружеников, воспитывавших дух свой быть превыше страданий и несчастий. Душа его в это время вся размягчалась, умилялся дух и слезами исполнялись глаза его. И — странное дело! — почти всегда приходила к нему в то время откуда-нибудь неожиданная помощь.', '101.jpg', 19, '2024-08-16 03:05:23'),
(1059, '— Жалок он мне, право, жалок.', '— Жалок он мне, право, жалок! — сказал Чичикову Платонов, когда они, простившись с ним, выехали от него.', '.', '101.jpg', 40, '2024-08-09 01:25:46'),
(1060, 'И скоро они оба перестали о нем думать, Платонов — потому.', 'И скоро они оба перестали о нем думать: Платонов — потому, что лениво и полусонно смотрел на положенья людей, так же как и на все в мире.', ' Сердце его сострадало и щемило при виде страданий других, но впечатленья как-то не впечатлевались глубоко в его душе. Он потому не думал о Хлобуеве, что и о себе самом не думал. Чичиков потому не думал о Хлобуеве, что все мысли были заняты приобретенною покупкою. Он исчислял, рассчитывал и соображал все выгоды купленного имения. И как ни рассматривал, на какую сторону ни оборачивал дело, видел, что во всяком случае покупка была выгодна. Можно было поступить и так, чтобы заложить имение в ломбард. Можно было поступить и так, чтобы заложить одних только мертвецов и беглых. Можно было поступить и так, чтобы прежде выпродать по частям все лучшие земли, а потом уже заложить в ломбард. Можно было распорядиться и так, чтобы заняться самому хозяйством и сделаться помещиком, по образцу Костанжогла, пользуясь его советами, как соседа и благодетеля. Можно было поступить даже и так, чтобы перепродать в частные руки имение (разумеется, если не захочется самому хозяйничать), оставивши при себе беглых и мертвецов. Тогда представлялась и другая выгода: можно было вовсе улизнуть из этих мест и не заплатить Костанжогле денег, взятых у него взаймы. Словом, всячески, как ни оборачивал он это дело, видел, что во всяком случае покупка была выгодна. Он почувствовал удовольствие, — удовольствие оттого, что стал теперь помещиком, помещиком не фантастическим, но действительным, помещиком, у которого есть уже и земли, и угодья, и люди — люди не мечтательные, не в воображенье пребываемые, но существующие. И понемногу начал он и подпрыгивать, и потирать себе руки, и подпевать, и приговаривать, и вытрубил на кулаке, приставивши его себе ко рту, как бы на трубе, какой-то марш, и даже выговорил вслух несколько поощрительных слов и названий себе самому, вроде мордашки и каплунчика. Но потом, вспомнивши, что он не один, притихнул вдруг, постарался кое-как замять неумеренный порыв восторгновенья, и когда Платонов, принявши кое-какие из этих звуков за обращенную к нему речь, спросил у него: «Чего?» — он отвечал: «Ничего».', '302.jpg', 26, '2024-08-01 21:33:44'),
(1061, 'Тут только, оглянувшись вокруг себя, он заметил, что они ехали прекрасною рощей.', 'Тут только, оглянувшись вокруг себя, он заметил, что они ехали прекрасною рощей; миловидная березовая ограда тянулась у них справа и слева. Между дерев мелькала белая каменная церковь.', ' В конце улицы показался господин, шедший к ним навстречу, в картузе, с суковатой палкой в руке. Облизанный аглицкий пес на высоких ножках бежал перед ним.', '100.jpg', 35, '2024-07-30 20:26:23'),
(1062, 'Чичиков вышел вслед за ним также из коляски.', 'Чичиков вышел вслед за ним также из коляски. Они пошли пешком навстречу господину.', ' Ярб уже успел облобызаться с аглицким псом, с которым, как видно, был знаком уже давно, потому что принял равнодушно в свою толстую морду живое лобызанье Азора (так назывался аглицкий пес). Проворный пес, именем Азор, облобызавши Ярба, подбежал к Платонову, лизнул проворным языком ему руки, вскочил на грудь Чичикова с намереньем лизнуть его в губы, но не достал и, оттолкнутый им, побежал снова к Платонову, пробуя лизнуть его хоть в ухо.', '302.jpg', 16, '2024-07-29 14:16:08'),
(1063, '— Да как же в самом деле: три дни от тебя ни слуху ни духу.', '— Да как же в самом деле: три дни от тебя ни слуху ни духу! Конюх от Петуха привел твоего жеребца. «Поехал, говорит, с каким-то барином».', ' Ну, хоть бы слово сказал: куды, зачем, на сколько времени? Помилуй, братец, как же можно этак поступать.', '002.jpg', 28, '2024-07-28 10:05:50'),
(1064, '— Ну что ж делать? позабыл, — сказал Платонов.', '— Ну что ж делать? позабыл, — сказал Платонов. — Мы заехали к Константину Федоровичу… Он тебе кланяется, сестра также. Рекомендую тебе Павла Ивановича Чичикова. Павел Иванович, — брат Василий. Прошу полюбить его так же, как и меня.', '.', '301.jpg', 57, '2024-07-18 05:47:52'),
(1065, '«Кто бы такой был этот Чичиков? — думал брат Василий.', '«Кто бы такой был этот Чичиков? — думал брат Василий. — Брат Платон на знакомства неразборчив и, верно, не узнал, что он за человек».', ' И оглянул он Чичикова, насколько позволяло приличие, и увидел, что он стоял, несколько наклонивши голову и сохранив приятное выраженье в лице.', '102.jpg', 57, '2024-07-17 05:45:51'),
(1066, 'Со своей стороны Чичиков оглянул также, насколько позволяло приличие.', 'Со своей стороны Чичиков оглянул также, насколько позволяло приличие, брата Василия. Он был ростом пониже Платона, волосом темней его и лицом далеко не так красив; но в чертах его лица было много жизни и одушевленья.', ' Видно было, что он не пребывал в дремоте и спячке.', '103.jpg', 45, '2024-07-08 04:22:22'),
(1067, '— Проездиться по святой Руси, вот именно с Павлом Ивановичем.', '— Проездиться по святой Руси, вот именно с Павлом Ивановичем: авось-либо это размычет и растеребит хандру мою.', '.', '202.jpg', 42, '2024-07-03 23:40:27'),
(1068, '— Как же так вдруг решился?..', '— Как же так вдруг решился?..', ' — начал было говорить Василий, озадаченный не на шутку таким решеньем, и чуть было не прибавил: «И еще замыслил ехать с человеком, которого видишь в первый раз, который, может быть, и дрянь, и черт знает что!» И, полный недоверия, стал он рассматривать искоса Чичикова и увидел, что он держался необыкновенно прилично, сохраняя все то же приятное наклоненье головы несколько набок и почтительно-приветное выражение в лице, так что никак нельзя было узнать, какого роду был Чичиков.', '302.jpg', 33, '2024-06-24 22:22:22'),
(1069, 'В молчанье они пошли все трое по дороге.', 'В молчанье они пошли все трое по дороге, по левую руку которой находилась мелькавшая промеж дерев белая каменная церковь, по правую — начинавшие показываться, также промеж дерев, строенья господского двора. Наконец показались и ворота.', ' Они вступили на двор, где был старинный господский дом под высокой крышей. Две огромные липы, росшие посреди двора, покрывали почти половину его своею тенью. Сквозь опущенные вниз развесистые их ветви едва сквозили стены дома, находившегося позади их. Под липами стояло несколько длинных скамеек. Брат Василий пригласил Чичикова садиться. Чичиков сел, и Платонов сел. По всему двору разливалось благоуханье цветущих сиреней и черемух, которые, нависши отовсюду из саду в двор через миловидную березовую ограду, кругом его обходившую, казалися цветущею цепью или бисерным ожерельем, его короновавшим.', '203.jpg', 49, '2024-06-14 17:40:19'),
(1070, 'Ухватливый и ловкий детина лет семнадцати.', 'Ухватливый и ловкий детина лет семнадцати, в красивой рубашке розовой ксандрейки, принес и поставил перед ними графины с водой и разноцветными квасами всех сортов, шипевшими, как газовые лимонады.', ' Поставивши пред ними графины, он подошел к дереву и, взявши прислоненный к нему заступ, отправился в сад. У братьев Платоновых вся дворня работала в саду, все слуги были садовники, или лучше сказать, слуг не было, но садовники исправляли иногда эту должность. Брат Василий все утверждал, что без слуг можно обойтись. Подать что-нибудь может всякий, и для этого не стоит заводить особого сословья; что будто русский человек по тех пор только хорош, и расторопен, и красив, и развязен, и много работает, покуда он ходит в рубашке и зипуне, но что, как только заберется в немецкий сертук — станет и неуклюж, и некрасив, и нерасторопен, и лентяй. Он утверждал, что и чистоплотность у него содержится по тех пор, покуда он еще носит рубашку и зипун, и что, как только заберется в немецкий сертук — и рубашки не переменяет, и в баню не ходит, и спит в сертуке, и заведутся у него под сертуком и клопы, и блохи, и черт знает что. В этом, может быть, он был и прав. В деревне их народ одевался как-то особенно щеголевато и опрятно, и таких красивых рубашек и зипунов нужно было далеко поискать.', '102.jpg', 59, '2024-06-05 11:18:48'),
(1071, '— Не угодно ли вам прохладиться.', '— Не угодно ли вам прохладиться? — сказал брат Василий Чичикову, указывая на графины. — Это квасы нашей фабрики; ими издавна славится дом наш.', '.', '100.jpg', 20, '2024-05-29 07:20:00'),
(1072, 'Чичиков налил стакан из первого графина — точно липец.', 'Чичиков налил стакан из первого графина — точно липец, который он некогда пивал в Польше: игра как у шампанского, а газ так и шибнул приятным кручком изо рта в нос.', '.', '102.jpg', 1, '2024-05-26 02:50:45'),
(1073, '— В какую же сторону и в какие места предполагаете преимущественно ехать.', '— В какую же сторону и в какие места предполагаете преимущественно ехать? — спросил брат Василий.', '.', '101.jpg', 51, '2024-05-23 21:20:16'),
(1074, '— Еду я, — сказал Чичиков, потирая себе рукой по колену.', '— Еду я, — сказал Чичиков, потирая себе рукой по колену, в сопровожденье легкого покачиванья всего туловища и наклоняя голову набок, — не столько по своей нужде, сколько по нужде другого.', ' Генерал Бетрищев, близкий приятель и, можно сказать, благотворитель, просил навестить родственников. Родственники, конечно, родственниками, но отчасти, так сказать, и для самого себя, ибо, — не говоря уже о пользе в геморроидальном отношении, — видеть свет и коловращенье людей — есть уже само по себе, так сказать, живая книга и вторая наука.', '100.jpg', 23, '2024-05-20 19:49:06'),
(1075, 'Брат Василий задумался.', 'Брат Василий задумался. «Говорит этот человек несколько витиевато, но в словах его есть правда, — думал он. — Брату моему Платону недостает познания людей, света и жизни».', ' Несколько помолчав, сказал так вслух.', '103.jpg', 21, '2024-05-11 16:31:25'),
(1076, '— Я начинаю думать, Платон, что путешествие может, точно, расшевелить тебя.', '— Я начинаю думать, Платон, что путешествие может, точно, расшевелить тебя. У тебя душевная спячка. Ты просто заснул, и заснул не от пресыщения или усталости, но от недостатка живых впечатлений и ощущений. Вот я совершенно напротив.', ' Я бы очень желал не так живо чувствовать и не так близко принимать к сердцу все, что ни случается.', '203.jpg', 9, '2024-05-09 12:34:32'),
(1077, '— Вольно ж принимать все близко к сердцу! — сказал Платон.', '— Вольно ж принимать все близко к сердцу! — сказал Платон. — Ты выискиваешь себе беспокойства и сам сочиняешь себе тревоги.', '.', '301.jpg', 14, '2024-05-01 06:48:56'),
(1078, '— Как сочинять, когда и без того на всяком шагу неприятность? — сказал Василий.', '— Как сочинять, когда и без того на всяком шагу неприятность? — сказал Василий. — Слышал ты, какую без тебя сыграл с нами штуку Леницын? Захватил пустошь, где у нас празднуют Красную горку.', '.', '102.jpg', 49, '2024-04-22 02:33:46'),
(1079, '— Не знает, потому и захватил, — сказал Платон, — человек новый.', '— Не знает, потому и захватил, — сказал Платон, — человек новый, только что приехал из Петербурга. Ему нужно объяснить, растолковать.', '.', '201.jpg', 7, '2024-04-12 00:18:46'),
(1080, '— Ну, нет. Он чересчур уже заважничал. Я к нему не поеду.', '— Ну, нет. Он чересчур уже заважничал. Я к нему не поеду. Поезжай, если хочешь, ты.', '.', '002.jpg', 41, '2024-04-06 20:19:29'),
(1081, '— Да если угодно, так я поеду, — сказал Чичиков.', '— Да если угодно, так я поеду, — сказал Чичиков.', ' Василий взглянул на него и подумал: «Экой охотник ездить.', '201.jpg', 29, '2024-04-02 17:43:38'),
(1082, '— Вы мне подайте только понятие, какого рода он человек, — сказал Чичиков.', '— Вы мне подайте только понятие, какого рода он человек, — сказал Чичиков, — и в чем дело.', '.', '101.jpg', 14, '2024-03-24 11:38:13'),
(1083, '— Мне совестно наложить на вас такую неприятную комиссию.', '— Мне совестно наложить на вас такую неприятную комиссию, потому что одно изъяснение с таким человеком для меня уже неприятная комиссия.', ' Надобно вам сказать, что он из простых, мелкопоместных дворян нашей губернии, выслужился в Петербурге, вышел кое-как в люди, женившись там на чьей-то побочной дочери, и заважничал. Задает здесь тоны. Да у нас в губернии, слава богу, народ живет не глупый: мода нам не указ, а Петербург — не церковь.', '100.jpg', 11, '2024-03-22 08:25:23'),
(1084, '— А дело, по-настоящему, вздор.', '— А дело, по-настоящему, вздор.', ' У него нет достаточно земли, — ну, он и захватил чужую пустошь, то есть он рассчитывал, что она не нужна, и о ней хозяева забыли, а у нас, как нарочно, уже испокон века собираются крестьяне праздновать там Красную горку. По этому-то поводу я готов пожертвовать лучше другими, лучшими землями, чем отдать ее. Обычаи для меня — святыня.', '302.jpg', 6, '2024-03-18 04:41:23'),
(1085, '— То есть, если бы он не так со мной поступил, но он хочет, как я вижу.', '— То есть, если бы он не так со мной поступил; но он хочет, как я вижу, знаться судом. Пожалуй, посмотрим, кто выиграет. Хоть на плане и не так ясно, но есть свидетели — старики еще живы и помнят.', '.', '302.jpg', 42, '2024-03-13 22:24:50'),
(1086, '«Вот тебе на! — подумал Леницын. — Это что-то престранное».', '«Вот тебе на! — подумал Леницын. — Это что-то престранное». И несколько даже отодвинулся со стулом назад, потому что совершенно озадачился.', '.', '301.jpg', 37, '2025-11-09 04:31:17'),
(1087, '— Я никак в том не сомневаюсь, что вы на это дело совершенно будете согласны.', '— Я никак в том не сомневаюсь, что вы на это дело совершенно будете согласны, — сказал Чичиков, — потому что это дело совершенно в том роде, как мы сейчас говорили. Совершено оно будет между солидными людьми втайне, и соблазна никому.', '.', '302.jpg', 31, '2025-11-04 01:39:41');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(1088, 'Что тут делать? Леницын очутился в затруднительном положении.', 'Что тут делать? Леницын очутился в затруднительном положении. Он никак не мог предвидеть, чтобы мнение, им незадолго изъявленное, привело его к такому быстрому осуществленыо на деле. Предложение было до крайности неожиданно.', ' Конечно, ничего вредоносного ни для кого не могло быть в этом поступке: помещики все равно заложили бы также эти души наравне с живыми, стало быть, казне убытку не может быть никакого; разница в том, что они были бы в одних руках, а тогда были бы в разных. Но тем не менее он затруднился. Он был законник и делец, и делец в хорошую сторону: неправо не решил бы он дела ни за какие подкупы. Но тут он остановился, не зная, какое имя дать этому действию — правое ли оно или неправое. Если бы кто-нибудь другой обратился к нему с таким предложением, он мог бы сказать: «Это вздор! пустяки! Я не хочу играть в куклы или дурачиться». Но гость уже так ему понравился, так они сошлись во многом насчет успехов просвещенья и наук, — как отказать? Леницын находился в презатруднительном положении.', '101.jpg', 16, '2025-10-30 00:20:06'),
(1089, 'Но в это время, точно как будто затем, чтобы помочь горю.', 'Но в это время, точно как будто затем, чтобы помочь горю, вошла в комнату молодая курносенькая хозяйка, супруга Леницына, и бледная, и худенькая, и низенькая, и одетая со вкусом, как все петербургские дамы.', ' За нею был вынесен мамкой на руках ребенок-первенец, плод нежной любви недавно бракосочетавшихся супругов. Чичиков, разумеется, подошел тот же час к даме и, не говоря уже о приличном приветствии, одним приятным наклоненьем головы набок много расположил ее в свою пользу. Затем подбежал к ребенку. Тот было разревелся; но, однако же, Чичикову удалось словами: «Агу, агу, душенька!» — пощелкиваньем пальцев и сердоликовой печаткой от часов переманить его на руки к себе. Взявши его к себе на руки, начал он приподымать его кверху и тем возбудил в ребенке приятную усмешку, которая очень обрадовала обоих родителей.', '101.jpg', 34, '2025-10-19 21:08:31'),
(1090, 'Но от удовольствия ли или от чего-нибудь другого.', 'Но от удовольствия ли или от чего-нибудь другого, ребенок вдруг повел себя нехорошо.', ' Жена Леницына закричала.', '301.jpg', 18, '2025-10-11 15:39:23'),
(1091, 'Чичиков посмотрел: рукав новешенького фрака был весь испорчен.', 'Чичиков посмотрел: рукав новешенького фрака был весь испорчен. «Пострел бы тебя побрал, чертенок проклятый!» — пробормотал он в сердцах про себя.', '.', '201.jpg', 0, '2025-10-07 10:49:19'),
(1092, 'Хозяин, и хозяйка, и мамка — все побежали за одеколоном.', 'Хозяин, и хозяйка, и мамка — все побежали за одеколоном; со всех сторон принялись его вытирать.', '.', '100.jpg', 40, '2025-09-27 05:48:17'),
(1093, '— Ничего, ничего, совершенно ничего, — говорил Чичиков.', '— Ничего, ничего, совершенно ничего, — говорил Чичиков.', ' — Может ли что-нибудь невинный ребенок? — И в то же время думал про себя: «Да ведь как метко обделал, канальчонок проклятый!» — Золотой возраст! — сказал он, когда уже его совершенно вытерли и приятное выражение возвратилось на его лицо.', '002.jpg', 52, '2025-09-18 04:11:47'),
(1094, '— А ведь точно, — сказал хозяин, обратившись к Чичикову.', '— А ведь точно, — сказал хозяин, обратившись к Чичикову, тоже с приятной улыбкой, — что может быть завидней ребяческого возраста, никаких забот.', '— А ведь точно, — сказал хозяин, обратившись к Чичикову, тоже с приятной улыбкой, — что может быть завидней ребяческого возраста, никаких забот.', '302.jpg', 41, '2025-09-16 03:04:15'),
(1095, 'Но, кажется, оба соврали, предложи им такой обмен.', 'Но, кажется, оба соврали: предложи им такой обмен, они бы тут же на попятный двор.', ' Да и что за радость сидеть у мамки на руках да портить фраки.', '002.jpg', 47, '2025-09-05 23:51:46'),
(1096, 'Молодая хозяйка и первенец удалились с мамкой.', 'Молодая хозяйка и первенец удалились с мамкой, потому что и на нем требовалось кое-что поправить: наградив Чичикова, он и себя не позабыл.', '.', '101.jpg', 28, '2025-08-26 18:23:53'),
(1097, 'Это, по-видимому.', 'Это, по-видимому, незначительное обстоятельство совершенно преклонило хозяина к удовлетворению Чичикова.', ' Как, в самом деле, отказать такому гостю, который столько ласк оказал его малютке и великодушно поплатился за то собственным фраком? Леницын думал так: «Почему ж, в самом деле, не исполнить его просьбы, если уж такое его желание?» …….', '102.jpg', 57, '2025-08-20 13:51:46'),
(1098, 'В то самое время.', 'В то самое время, когда Чичиков в персидском новом халате из золотистой термаламы, развалясь на диване, торговался с заезжим контрабандистом-купцом жидовского происхождения и немецкого выговора.', 'В то самое время, когда Чичиков в персидском новом халате из золотистой термаламы, развалясь на диване, торговался с заезжим контрабандистом-купцом жидовского происхождения и немецкого выговора, и перед ними уже лежали купленная штука первейшего голландского полотна на рубашки и две бумажные коробки с отличнейшим мылом первостатейнейшего свойства (это было мыло то именно, которое он некогда приобретал на радзивилловской таможне: оно имело действительно свойство сообщать нежность и белизну щекам изумительную), — в то время, когда он, как знаток, покупал эти необходимые для воспитанного человека продукты, раздался гром подъехавшей кареты, отозвавшийся легким дрожаньем комнатных окон и стен, и вошел его превосходительство Алексей Иванович Леницын.', '100.jpg', 57, '2025-08-18 11:28:04'),
(1099, '— На суд вашего превосходительства представляю, каково полотно, и каково мыло.', '— На суд вашего превосходительства представляю: каково полотно, и каково мыло, и какова эта вчерашнего дни купленная вещица.', '— На суд вашего превосходительства представляю: каково полотно, и каково мыло, и какова эта вчерашнего дни купленная вещица! — При этом Чичиков надел на голову ермолку, вышитую золотом и бусами, и очутился, как персидский шах, исполненный достоинства и величия.', '103.jpg', 23, '2025-08-11 11:02:31'),
(1100, 'В лице его заметно было расстройство.', 'В лице его заметно было расстройство. Почтенный купец немецкого выговора был тот же час выслан, и они остались одни.', '.', '202.jpg', 0, '2025-08-06 06:51:25'),
(1101, '— Знаете ли вы, какая неприятность.', '— Знаете ли вы, какая неприятность? Отыскалось другое завещание старухи, сделанное назад тому пять лет. Половина именья отдается на монастырь, а другая — обеим воспитанницам пополам и ничего больше никому.', '.', '102.jpg', 48, '2025-07-30 02:44:38'),
(1102, '— Это само собою разумеется: последнее уничтожает первое.', '— Это само собою разумеется: последнее уничтожает первое. Первое завещанье никуда не годится. Я знаю хорошо волю покойницы. Я был при ней.', ' Кто его подписал? кто были свидетели.', '202.jpg', 23, '2025-07-25 20:35:42'),
(1103, '«Худо, — подумал Чичиков, — Хаванов, говорят, честен, Бурмилов — старый ханжа.', '«Худо, — подумал Чичиков, — Хаванов, говорят, честен; Бурмилов — старый ханжа, читает по праздникам «Апостола» в церквях».', '.', '301.jpg', 31, '2025-07-20 15:45:07'),
(1104, '— Но вздор, вздор.', '— Но вздор, вздор, — сказал он вслух и тут же почувствовал решимость на все штуки. — Я знаю это лучше: я участвовал при последних минутах покойницы. Мне это лучше всех известно. Я готов присягнуть самолично.', '.', '302.jpg', 60, '2025-07-19 11:27:29'),
(1105, 'Слова эти и решимость на минуту успокоили Леницына.', 'Слова эти и решимость на минуту успокоили Леницына. Он был очень взволнован и уже начинал было подозревать, не было ли со стороны Чичикова какой-нибудь фабрикации относительно завещания. Теперь укорил себя в подозрении.', ' Готовность присягнуть была явным доказательством, что Чичиков невинен. Не знаем мы, точно ли достало бы духу у Павла Ивановича присягнуть на святом, но сказать это достало духа.', '203.jpg', 38, '2025-07-17 05:42:19'),
(1106, '— Будьте покойны, я переговорю об этом деле с некоторыми юрисконсультами.', '— Будьте покойны, я переговорю об этом деле с некоторыми юрисконсультами. С вашей стороны тут ничего не должно прилагать: вы должны быть совершенно в стороне. Я же теперь могу жить в городе, сколько мне угодно.', '.', '100.jpg', 44, '2025-07-15 02:29:42'),
(1107, 'Чичиков тот же час приказал подать экипаж и отправился к юрисконсульту.', 'Чичиков тот же час приказал подать экипаж и отправился к юрисконсульту. Этот юрисконсульт был опытности необыкновенной. Уже пятнадцать лет как он находился под судом, и так умел распорядиться, что никак нельзя было отрешить от должности.', ' Все знали его, за подвиги его следовало бы шесть раз уже послать на поселенье. Кругом и со всех сторон был он в подозрениях, но никаких нельзя было возвести явных и доказанных улик. Тут было действительно что-то таинственное, и его бы можно было смело признать колдуном, если бы история, нами описанная, принадлежала временам невежества.', '102.jpg', 24, '2025-07-09 20:48:07'),
(1108, 'Юрисконсульт поразил холодностью своего вида, замасленностью своего халата.', 'Юрисконсульт поразил холодностью своего вида, замасленностью своего халата, представлявшего совершенную противуположность хорошим мебелям красного дерева, золотым часам под стеклянным колпаком, люстре, сквозившей сквозь кисейный чехол.', 'Юрисконсульт поразил холодностью своего вида, замасленностью своего халата, представлявшего совершенную противуположность хорошим мебелям красного дерева, золотым часам под стеклянным колпаком, люстре, сквозившей сквозь кисейный чехол, ее сохранявший, и вообще всему, что было вокруг и носило на себе яркую печать блистательного европейского просвещения.', '201.jpg', 3, '2025-06-29 17:07:39'),
(1109, 'Не останавливаясь, однако ж, скептической наружностью юрисконсульта.', 'Не останавливаясь, однако ж, скептической наружностью юрисконсульта, Чичиков объяснил затруднительные пункты дела и в заманчивой перспективе изобразил необходимо последующую благодарность за добрый совет и участие.', '.', '103.jpg', 9, '2025-06-24 13:15:30'),
(1110, 'Юрисконсульт отвечал на это изображеньем неверности всего земного и дал тоже.', 'Юрисконсульт отвечал на это изображеньем неверности всего земного и дал тоже искусно заметить, что журавль в небе ничего не значит, а нужно синицу в руку.', '.', '100.jpg', 40, '2025-06-16 09:21:51'),
(1111, 'Нечего делать: нужно было дать синицу в руки.', 'Нечего делать: нужно было дать синицу в руки. Скептическая холодность философа вдруг исчезла. Оказалось, что это был наидобродушнейший человек, наиразговорчивый и наиприятнейший в разговорах, не уступавший ловкостью оборотов самому Чичикову.', '.', '301.jpg', 6, '2025-06-10 08:42:13'),
(1112, '— Позвольте вам вместо того, чтобы заводить длинное дело, вы, верно.', '— Позвольте вам вместо того, чтобы заводить длинное дело, вы, верно, не хорошо рассмотрели самое завещание: там, верно, есть какая-нибудь приписочка. Вы возьмите его на время к себе.', ' Хотя, конечно, подобных вещей на дом брать запрещено, но если хорошенько попросить некоторых чиновников… Я с своей стороны употреблю мое участие.', '301.jpg', 47, '2025-06-02 04:43:23'),
(1113, '— В самом деле, я, точно, хорошо не помню, есть ли там приписочка или нет.', '— В самом деле, я, точно, хорошо не помню, есть ли там приписочка или нет, — точно как будто и не сам писал это завещание.', '.', '201.jpg', 48, '2025-05-25 03:39:49'),
(1114, '— Лучше всего вы это посмотрите.', '— Лучше всего вы это посмотрите. Впрочем, во всяком случае, — продолжал он весьма добродушно, — будьте всегда покойны и не смущайтесь ничем, даже если бы и хуже что произошло. Никогда и ни в чем не отчаивайтесь: нет дела неисправимого.', ' Смотрите на меня: я всегда покоен. Какие бы ни были возводимы на меня казусы, спокойствие мое непоколебимо.', '100.jpg', 28, '2025-05-21 23:41:45'),
(1115, 'Лицо юрисконсульта-философа пребывало действительно в необыкновенном.', 'Лицо юрисконсульта-философа пребывало действительно в необыкновенном спокойствии.', 'Лицо юрисконсульта-философа пребывало действительно в необыкновенном спокойствии.', '202.jpg', 2, '2025-05-17 18:50:20'),
(1116, '— Конечно, это первая вещь, — сказал он.', '— Конечно, это первая вещь, — сказал он. — Но согласитесь, однако ж, что могут быть такие случаи и дела, такие дела и такие поклепы со стороны врагов, и такие затруднительные положения, что отлетит всякое спокойствие.', '.', '103.jpg', 14, '2025-05-13 15:27:22'),
(1117, '— Поверьте мне, это малодушие.', '— Поверьте мне, это малодушие, — отвечал очень покойно и добродушно философ-юрист. — Старайтесь только, чтобы производство дела было все основано на бумагах, чтобы на словах ничего не было.', ' И как только увидите, что дело идет к развязке и удобно к решению, старайтесь — не то чтобы оправдывать и защищать себя, — нет, просто спутать новыми вводными и так посторонними статьями.', '301.jpg', 21, '2025-05-12 11:00:21'),
(1118, '— Спутать, спутать, — и ничего больше, — отвечал философ.', '— Спутать, спутать, — и ничего больше, — отвечал философ, — ввести в это дело посторонние, другие обстоятельства, которые запутали бы сюда и других, сделать сложным — и ничего больше. И там пусть приезжий петербургский чиновник разбирает.', ' Пусть разбирает, пусть его разбирает! — повторил он, смотря с необыкновенным удовольствием в глаза Чичикову, как смотрит учитель ученику, когда объясняет ему заманчивое место из русской грамматики.', '201.jpg', 7, '2025-05-03 10:03:50'),
(1119, '— Да, хорошо, если подберешь такие обстоятельства.', '— Да, хорошо, если подберешь такие обстоятельства, которые способны пустить в глаза мглу, — сказал Чичиков, смотря тоже с удовольствием в глаза философа, как ученик, который понял заманчивое место, объясняемое учителем.', '.', '301.jpg', 6, '2025-04-28 07:35:19'),
(1120, '— Подберутся обстоятельства, подберутся.', '— Подберутся обстоятельства, подберутся! Поверьте: от частого упражнения и голова сделается находчивою. Прежде всего помните, что вам будут помогать.', ' В сложности дела выигрыш многим: и чиновников нужно больше, и жалованья им больше… Словом, втянуть в дело побольше лиц. Нет нужды, что иные напрасно попадут: да ведь им же оправдаться легко, им нужно отвечать на бумаги, им нужно откупиться… Вот уж и хлеб… Поверьте мне, что, как только обстоятельства становятся критические, первое дело спутать. Так можно спутать, так все перепутать, что никто ничего не поймет. Я почему спокоен? Потому что знаю: пусть только дела мои пойдут похуже, да я всех впутаю в свое — и губернатора, и вице-губернатора, и полицеймейстера, и казначея, — всех запутаю. Я знаю все их обстоятельства: и кто на кого сердится, и кто на кого дуется, и кто кого хочет упечь. Там, пожалуй, пусть их выпутываются, да покуда они выпутаются, другие успеют нажиться. Ведь только в мутной воде и ловятся раки. Все только ждут, чтобы запутать. — Здесь юрист-философ посмотрел Чичикову в глаза опять с тем наслажденьем, с каким учитель объясняет ученику еще заманчивейшее место из русской грамматики.', '301.jpg', 52, '2025-04-22 04:02:19'),
(1121, '«Нет, этот человек, точно, мудрец».', '«Нет, этот человек, точно, мудрец», — подумал про себя Чичиков и расстался с юрисконсультом в наиприятнейшем и в наилучшем расположении духа.', '.', '103.jpg', 30, '2025-04-19 00:54:07'),
(1122, 'Совершенно успокоившись и укрепившись.', 'Совершенно успокоившись и укрепившись, он с небрежною ловкостью бросился на эластические подушки коляски, приказал Селифану откинуть кузов назад (к юрисконсульту он ехал с поднятым кузовом и даже застегнутой кожей) и расположился.', 'Совершенно успокоившись и укрепившись, он с небрежною ловкостью бросился на эластические подушки коляски, приказал Селифану откинуть кузов назад (к юрисконсульту он ехал с поднятым кузовом и даже застегнутой кожей) и расположился, точь-в-точь как отставной гусарский полковник или сам Вишнепокромов — ловко подвернувши одну ножку под другую, обратя с приятностью ко встречным лицо, сиявшее из-под шелковой новой шляпы, надвинутой несколько на ухо. Селифану было приказано держать направленье к гостиному двору. Купцы, и приезжие и туземные, стоя у дверей лавок, почтительно снимали шляпы, и Чичиков, не без достоинства, приподнимал им в ответ свою. Многие из них уже были ему знакомы; другие были хоть приезжие, но, очарованные ловким видом умеющего держать себя господина, приветствовали его, как знакомые. Ярмарка в городе Тьфуславле не прекращалась. Отошла конная и земледельческая, началась — с красными товарами для господ просвещенья высшего. Купцы, приехавшие на колесах, располагали назад не иначе возвращаться, как на санях.', '103.jpg', 59, '2025-04-13 18:31:25'),
(1123, '— Пожалуте-с, пожалуте-с.', '— Пожалуте-с, пожалуте-с.', '— Пожалуте-с, пожалуте-с! — говорил у суконной лавки, учтиво рисуясь, с открытою головою, немецкий сюртук московского шитья, с шляпой в руке на отлете, только чуть державший двумя пальцами бритый круглый подбородок и выраженье тонкости просвещенья в лице.', '202.jpg', 13, '2025-04-07 17:17:04'),
(1124, 'Благоприятный купец тотчас приподнял вверх открывавшуюся доску с стола и.', 'Благоприятный купец тотчас приподнял вверх открывавшуюся доску с стола и, сделавши таким образом себе проход, очутился в лавке, спиною к товару и лицом к покупателю.', '.', '201.jpg', 18, '2025-03-30 15:48:00'),
(1125, 'Ставши спиной к товарам и лицом к покупателю, купец.', 'Ставши спиной к товарам и лицом к покупателю, купец, с обнаженной головою и шляпой на отлете, еще раз приветствовал Чичикова.', ' Потом надел шляпу и, приятно нагнувшись, обеими же руками упершись в стол, сказал так.', '102.jpg', 11, '2025-03-24 15:37:12'),
(1126, '— Какого рода сукон-с.', '— Какого рода сукон-с? английских мануфактур или отечественной фабрикации предпочитаете.', '— Какого рода сукон-с? английских мануфактур или отечественной фабрикации предпочитаете.', '100.jpg', 12, '2025-03-18 12:57:33'),
(1127, '— Отечественной фабрикации, — сказал Чичиков, — но только именно лучшего сорта.', '— Отечественной фабрикации, — сказал Чичиков, — но только именно лучшего сорта, который называется аглицким.', '.', '102.jpg', 49, '2025-03-11 11:01:36'),
(1128, '— Каких цветов пожелаете иметь.', '— Каких цветов пожелаете иметь? — вопросил купец, все так же приятно колеблясь на двух упершихся в стол руках.', '.', '201.jpg', 14, '2025-03-02 07:57:56'),
(1129, '— Цветов темных, оливковых или бутылочных с искрою, приближающихся, так сказать.', '— Цветов темных, оливковых или бутылочных с искрою, приближающихся, так сказать, к бруснике, — сказал Чичиков.', '.', '301.jpg', 4, '2025-03-01 01:38:28'),
(1130, '— Могу сказать, что получите первейшего сорта.', '— Могу сказать, что получите первейшего сорта, лучше которого нет в обеих столицах, — говорил купец, потащившись доставать сверху штуку; бросил ее ловко на стол, разворотил с другого конца и поднес к свету.', ' — Каков отлив-с! Самого модного, последнего вкуса.', '102.jpg', 49, '2025-02-26 22:20:38'),
(1131, 'Сукно блистало, как шелковое.', 'Сукно блистало, как шелковое. Купец чутьем пронюхал, что пред ним стоит знаток сукон, и не захотел начинать с десятирублевого.', '.', '103.jpg', 10, '2025-02-22 18:23:59'),
(1132, '— Порядочное, — сказал Чичиков, слегка погладивши.', '— Порядочное, — сказал Чичиков, слегка погладивши. — Но знаете ли, почтеннейший? покажите мне сразу то, что вы напоследок показываете, да и цвету больше того… больше искрасна, чтобы искры были.', '.', '201.jpg', 24, '2025-02-19 16:54:28'),
(1133, 'О цене условились.', 'О цене условились. Железный аршин, подобный жезлу чародея, отхватал тут же Чичикову на фрак и на панталоны.', ' Сделавши ножницами нарезку, купец произвел обеими руками ловкое дранье сукна во всю его ширину, при окончанье которого поклонился Чичикову с наиобольстительнейшею приятностью. Сукно тут же было свернуто и ловко заворочено в бумагу; сверток завертелся под легкой бечевкой.', '201.jpg', 32, '2025-11-07 04:00:50'),
(1134, '— Приятное столкновение, — сказал голос того же самого.', '— Приятное столкновение, — сказал голос того же самого, который окружил его поясницу. Это был Вишнепокромов.', ' — Готовился было пройти лавку без вниманья, вдруг вижу знакомое лицо — как отказаться от приятного удовольствия! Нечего сказать, сукна в этом году несравненно лучше. Ведь это стыд, срам! Я никак не мог было отыскать… Я готов тридцать рублей, сорок рублей… возьми пятьдесят даже, но дай хорошего. По мне, или иметь вещь, которая бы, точно, была уже отличнейшая, или уж лучше вовсе не иметь.', '302.jpg', 24, '2025-11-06 02:49:12'),
(1135, '— Совершенно так! — сказал Чичиков.', '— Совершенно так! — сказал Чичиков.', ' — Зачем же трудиться, как не затем, чтобы, точно, иметь хорошую вещь.', '002.jpg', 22, '2025-10-30 02:39:13'),
(1136, '— Покажите мне сукна средних цен, — раздался позади голос.', '— Покажите мне сукна средних цен, — раздался позади голос, показавшийся Чичикову знакомым. Он оборотился: это был Хлобуев. По всему видно было, что он покупал сукно не для прихоти, потому что сертучок был больно протерт.', '.', '203.jpg', 32, '2025-10-19 22:35:24'),
(1137, '— Ах, Павел Иванович! позвольте мне с вами наконец поговорить.', '— Ах, Павел Иванович! позвольте мне с вами наконец поговорить. Вас нигде не встретишь. Я был несколько раз — все вас нет и нет.', '.', '302.jpg', 50, '2025-10-13 20:21:35'),
(1138, '— Почтеннейший, я так был занят, что, ей-ей, нет времени.', '— Почтеннейший, я так был занят, что, ей-ей, нет времени. — Он поглядел по сторонам, как бы от объясненья улизнуть, и увидел входящего в лавку Муразова. — Афанасий Васильевич! Ах, боже мой! — сказал Чичиков.', ' — Вот приятное столкновение.', '302.jpg', 11, '2025-10-11 19:13:59'),
(1139, 'И, наконец, благовоспитанный купец, отнеся шляпу от головы настолько.', 'И, наконец, благовоспитанный купец, отнеся шляпу от головы настолько, сколько могла рука, и, весь подавшись вперед, произнес.', 'И, наконец, благовоспитанный купец, отнеся шляпу от головы настолько, сколько могла рука, и, весь подавшись вперед, произнес.', '302.jpg', 4, '2025-10-07 18:44:30'),
(1140, '— Афанасию Васильевичу наше нижайшее почтенье.', '— Афанасию Васильевичу наше нижайшее почтенье! На лицах напечатлелась та собачья услужливость, какую оказывает миллионщикам собачье отродье людей.', '.', '201.jpg', 40, '2025-09-30 14:24:06'),
(1141, '— Извините меня, я, увидевши издали, как вы вошли в лавку.', '— Извините меня: я, увидевши издали, как вы вошли в лавку, решился вас побеспокоить. Если вам будет после свободно и по дороге мимо моего дома, так сделайте милость, зайдите на малость времени. Мне с вами нужно будет переговорить.', '.', '203.jpg', 45, '2025-09-20 13:55:43'),
(1142, '— Не правда ли, Афанасий Васильевич, — подхватил Вишнепокромов.', '— Не правда ли, Афанасий Васильевич, — подхватил Вишнепокромов, — ведь это необыкновенно.', '.', '202.jpg', 47, '2025-09-12 08:47:31'),
(1143, '— Да, дождичка бы очень не мешало, — сказал Чичиков.', '— Да, дождичка бы очень не мешало, — сказал Чичиков, которому не нужно было дождика, но как уже приятно согласиться с тем, у кого миллион.', '.', '002.jpg', 19, '2025-09-10 05:18:39'),
(1144, '— У меня просто голова кружится, — сказал Чичиков, — как подумаешь.', '— У меня просто голова кружится, — сказал Чичиков, — как подумаешь, что у этого человека десять миллионов. Это просто даже невероятно.', '.', '102.jpg', 20, '2025-08-31 04:40:55'),
(1145, '— Противузаконная, однако ж, вещь, — сказал Вишнепокромов.', '— Противузаконная, однако ж, вещь, — сказал Вишнепокромов, — капиталы не должны быть в одних руках. Это теперь предмет трактатов во всей Европе.', ' Имеешь деньги, — ну, сообщай другим: угощай, давай балы, производи благодетельную роскошь, которая дает хлеб мастерам, ремесленникам.', '302.jpg', 57, '2025-08-27 03:30:37'),
(1146, '— Это я не могу понять, — сказал Чичиков.', '— Это я не могу понять, — сказал Чичиков. — Десять миллионов — и живет как простой мужик! Ведь это с десятью мильонами черт знает что можно сделать. Ведь это можно так завести, что и общества другого у тебя не будет, как генералы да князья.', '.', '100.jpg', 26, '2025-08-26 01:26:06'),
(1147, '— Да-с, — прибавил купец.', '— Да-с, — прибавил купец, — у Афанасия Васильевича при всех почтенных качествах непросветительности много. Если купец почтенный, так уж он не купец, он некоторым образом есть уже негоциант.', ' Я уж тогда должен себе взять и ложу в театре, и дочь уж я за простого полковника — нет-с, не выдам: я за генерала, иначе я ее не выдам.', '203.jpg', 60, '2025-08-21 21:48:00'),
(1148, '— Да что говорить.', '— Да что говорить! помилуйте, — сказал Вишнепокромов, — с десятью миллионами чего не сделать.', '— Да что говорить! помилуйте, — сказал Вишнепокромов, — с десятью миллионами чего не сделать.', '203.jpg', 26, '2025-08-15 17:18:17'),
(1149, '«Нет, — подумал Чичиков, — ты-то не много сделаешь толку с десятью миллионами.', '«Нет, — подумал Чичиков, — ты-то не много сделаешь толку с десятью миллионами. А вот если б мне десять миллионов, я бы, точно, кое-что сделал».', '.', '302.jpg', 29, '2025-08-09 12:32:11'),
(1150, '«Нет, если бы мне теперь, после этих страшных опытов, десять миллионов.', '«Нет, если бы мне теперь, после этих страшных опытов, десять миллионов! — подумал Хлобуев.', ' — Э, теперь бы я не так: опытом узнаешь цену всякой копейки», и потом, минуту подумавши, спросил себя внутренно: «Точно ли бы теперь умней распорядился.', '101.jpg', 5, '2025-08-06 08:03:10'),
(1151, '— Вас жду, Петр Петрович! — сказал Муразов, увидевши входящего Хлобуева.', '— Вас жду, Петр Петрович! — сказал Муразов, увидевши входящего Хлобуева. — Пожалуйста ко мне в комнатку.', '.', '202.jpg', 37, '2025-07-27 06:22:17'),
(1152, 'И он повел Хлобуева в комнатку, уже знакомую читателю.', 'И он повел Хлобуева в комнатку, уже знакомую читателю, неприхотливее которой нельзя было найти и у чиновника, получающего семьсот рублей в год жалованья.', '.', '100.jpg', 46, '2025-07-18 00:11:50'),
(1153, '— Скажите, ведь теперь, я полагаю, обстоятельства ваши получше.', '— Скажите, ведь теперь, я полагаю, обстоятельства ваши получше? После тетушки все-таки вам досталось кое-что.', '— Скажите, ведь теперь, я полагаю, обстоятельства ваши получше? После тетушки все-таки вам досталось кое-что.', '302.jpg', 59, '2025-07-16 21:51:39'),
(1154, '— Да как вам сказать, Афанасий Васильевич.', '— Да как вам сказать, Афанасий Васильевич? Я не знаю, лучше ли мои обстоятельства. Мне досталось всего пятьдесят душ крестьян и тридцать тысяч денег, которыми я должен был расплатиться с частью моих долгов, — и у меня вновь ровно ничего.', ' А главное дело, что дело по этому завещанью самое нечистое. Тут, Афанасий Васильевич, завелись такие мошенничества! Я вам сейчас расскажу, и вы подивитесь, что такое делается.', '100.jpg', 39, '2025-07-12 17:23:17'),
(1155, '— Позвольте, Петр Петрович, прежде чем говорить об этом Чичикове.', '— Позвольте, Петр Петрович: прежде чем говорить об этом Чичикове, позвольте поговорить собственно о вас.', ' Скажите мне: сколько, по вашему заключению, было бы для вас удовлетворительно и достаточно затем, чтобы совершенно выпутаться из обстоятельств.', '101.jpg', 16, '2025-07-11 16:05:51'),
(1156, '— Мои обстоятельства трудные, — сказал Хлобуев.', '— Мои обстоятельства трудные, — сказал Хлобуев. — Да чтобы выпутаться из обстоятельств, расплатиться совсем и быть в возможности жить самым умеренным образом, мне нужно, по крайней мере, сто тысяч, если не больше. Словом, мне это невозможно.', '.', '201.jpg', 33, '2025-07-07 12:02:27'),
(1157, '— Ну, я бы тогда нанял себе квартирку, занялся бы воспитанием детей.', '— Ну, я бы тогда нанял себе квартирку, занялся бы воспитанием детей, потому что мне самому не служить: я уж никуды не гожусь.', '.', '103.jpg', 14, '2025-07-02 08:23:52'),
(1158, '— Да куды ж мне, сами посудите! Мне нельзя начинать с канцелярского писца.', '— Да куды ж мне, сами посудите! Мне нельзя начинать с канцелярского писца. Вы позабыли, что у меня семейство. Мне сорок, у меня уж и поясница болит, я обленился; а должности мне поважнее не дадут: я ведь не на хорошем счету.', ' Я признаюсь вам: я бы и сам не взял наживной должности. Я человек хоть и дрянной, и картежник, и все что хотите, но взятков брать я не стану. Мне не ужиться с Красноносовым да Самосвистовым.', '202.jpg', 47, '2025-06-27 06:31:19'),
(1159, '— Но все, извините-с, я не могу понять, как же быть без дороги.', '— Но все, извините-с, я не могу понять, как же быть без дороги; как идти не по дороге; как ехать, когда нет земли под ногами; как плыть, когда челн не на воде? А ведь жизнь — путешествие.', ' Извините, Петр Петрович, те господа ведь, про которых вы говорите, всё же они на какой-нибудь дороге, всё же они трудятся. Ну, положим, как-нибудь своротили, как случается со всяким грешным; да есть надежда, что опять набредут. Кто идет — нельзя, чтоб не пришел; есть надежда, что и набредет. Но как тому попасть на какую-нибудь дорогу, кто остается праздно? Ведь дорога не придет ко мне.', '201.jpg', 11, '2025-06-24 04:26:34'),
(1160, '— Поверьте мне, Афанасий Васильевич, я чувствую совершенно справедливость вашу.', '— Поверьте мне, Афанасий Васильевич, я чувствую совершенно справедливость вашу, но говорю вам, что во мне решительно погибла, умерла всякая деятельность: не вижу я, что могу сделать какую-нибудь пользу кому-нибудь на свете.', ' Я чувствую, что я решительно бесполезное бревно. Прежде, покамест был помоложе, так мне казалось, что все дело в деньгах, что, если бы мне в руки сотни тысяч, я бы осчастливил множество: помог бы бедным художникам, завел бы библиотеки, полезные заведения, собрал бы коллекции. Я человек не без вкуса и, знаю, во многом мог бы гораздо лучше распорядиться тех наших богачей, которые все это делают бестолково. А теперь вижу, что и это суета, и в этом немного толку. Нет, Афанасий Васильевич, никуда не гожусь, ровно никуда, говорю вам. На малейшее дело не способен.', '203.jpg', 19, '2025-06-18 00:20:38'),
(1161, '— Послушайте, Петр Петрович.', '— Послушайте, Петр Петрович! Но ведь вы же молитесь, ходите в церковь, не пропускаете, я знаю, ни утрени, ни вечерни. Вам хоть и не хочется рано вставать, но ведь вы встаете и идете, — идете в четыре часа утра, когда никто не подымается.', '.', '203.jpg', 28, '2025-06-11 18:23:46'),
(1162, '— Это — другое дело, Афанасий Васильевич.', '— Это — другое дело, Афанасий Васильевич. Я это делаю для спасения души, потому что в убеждении, что этим хоть сколько-нибудь заглажу праздную жизнь, что как я ни дурен, но молитвы все-таки что-нибудь значат у бога.', ' Скажу вам, что я молюсь, — даже и без веры, но все-таки молюсь. Слышится только, что есть господин, от которого все зависит, как лошадь и скотина, которою пашем, знает чутьем того, кто запрягает.', '100.jpg', 15, '2025-06-07 16:11:05'),
(1163, '— Стало быть, вы молитесь затем, чтобы угодить тому, которому молитесь.', '— Стало быть, вы молитесь затем, чтобы угодить тому, которому молитесь, чтобы спасти свою душу, и это дает вам силы и заставляет вас подыматься рано с постели.', ' Поверьте, что, если бы вы взялись за должность свою таким образом, как бы в уверенности, что служите тому, кому вы молитесь, у вас бы появилась деятельность, и вас никто из людей не в силах был бы охладить.', '002.jpg', 1, '2025-05-31 13:37:45'),
(1164, '— Афанасий Васильевич! вновь скажу вам — это другое.', '— Афанасий Васильевич! вновь скажу вам — это другое. В первом случае я вижу, что я все-таки делаю. Говорю вам, что я готов пойти в монастырь, и самые тяжкие, какие на меня ни наложат, труды и подвиги я буду исполнять там.', ' Я уверен, что не мое дело рассуждать, что взыщется с тех, которые заставили меня делать: там я повинуюсь и знаю, что богу повинуюсь.', '201.jpg', 10, '2025-05-30 07:22:29'),
(1165, '— А зачем же так вы не рассуждаете и в делах света.', '— А зачем же так вы не рассуждаете и в делах света? Ведь и в свете мы должны служить богу, а не кому иному. Если и другому кому служим, мы потому только служим, будучи уверены, что так бог велит, а без того мы бы и не служили.', ' Что ж другое все способности и дары, которые розные у всякого? Ведь это орудия моленья нашего: то — словами, а это делом. Ведь вам же в монастырь нельзя идти: вы прикреплены к миру, у вас семейство.', '203.jpg', 51, '2025-05-29 06:21:58'),
(1166, '— Так вы полагаете, что если бы, например, у вас было двести тысяч.', '— Так вы полагаете, что если бы, например, у вас было двести тысяч, так вы могли бы упрочить жизнь и повести отныне жизнь расчетливее.', '— Так вы полагаете, что если бы, например, у вас было двести тысяч, так вы могли бы упрочить жизнь и повести отныне жизнь расчетливее.', '203.jpg', 47, '2025-05-25 06:11:24'),
(1167, '— То есть, по крайней мере, я займусь тем, что можно будет сделать.', '— То есть, по крайней мере, я займусь тем, что можно будет сделать, — займусь воспитаньем детей, буду иметь в возможности доставить им хороших учителей.', '.', '301.jpg', 16, '2025-05-20 04:07:55'),
(1168, '— А сказать ли вам на это, Петр Петрович.', '— А сказать ли вам на это, Петр Петрович, что чрез два года будете опять кругом в долгах, как в шнурках.', '— А сказать ли вам на это, Петр Петрович, что чрез два года будете опять кругом в долгах, как в шнурках.', '002.jpg', 21, '2025-05-10 04:07:04'),
(1169, '— Да что ж опыты, — сказал Муразов. — Ведь я вас знаю.', '— Да что ж опыты, — сказал Муразов. — Ведь я вас знаю.', ' Вы человек с доброй душой: к вам придет приятель попросить взаймы — вы ему дадите; увидите бедного человека — вы захотите помочь; приятный гость придет к вам — захотите получше угостить, да и покоритесь первому доброму движенью, а расчет и позабываете.', '201.jpg', 52, '2025-05-01 00:01:12'),
(1170, 'И позвольте вам наконец сказать по искренности.', 'И позвольте вам наконец сказать по искренности, что детей-то своих вы не в состоянии воспитать. Детей своих воспитать может только тот отец, который уж сам выполнил долг свой.', ' Да и супруга ваша… она и доброй души… она совсем не так воспитана, чтобы детей воспитать.', '002.jpg', 44, '2025-04-23 19:34:25'),
(1171, 'Хлобуез призадумался.', 'Хлобуез призадумался; он начал себя мысленно осматривать со всех сторон и наконец почувствовал, что Муразов был прав отчасти.', '.', '101.jpg', 17, '2025-04-19 15:07:35'),
(1172, '— Знаете ли, Петр Петрович.', '— Знаете ли, Петр Петрович? отдайте мне на руки это — детей, дела; оставьте и семью вашу, и детей: я их приберегу. Ведь обстоятельства ваши таковы, что вы в моих руках: ведь дело идет к тому, чтобы умирать с голоду. Тут уже на все нужно решаться.', ' Знаете ли вы Ивана Потапыча.', '202.jpg', 18, '2025-04-12 13:11:27'),
(1173, '— Иван Потапыч был миллионщик, выдал дочерей своих за чиновников, жил как царь.', '— Иван Потапыч был миллионщик, выдал дочерей своих за чиновников, жил как царь; а как обанкрутил-ся — что ж делать? — пошел в приказчики.', ' Не весело-то было ему с серебряного блюда перейти за простую миску: казалось-то, что и руки ни к чему не подымались. Теперь Иван Потапыч мог бы хлебать с серебряного блюда, да уж не хочет. У него уж набралось бы опять, да он говорит: «Нет, Афанасий Иванович, служу я теперь уж не себе и не для себя, а потому, что бог так судил. По своей воле не хочу ничего делать. Слушаю вас, потому что бога хочу слушаться, а не людей, и так как бог устами лучших людей только говорит. Вы умнее меня, а потому не я отвечаю, а вы». Вот что говорит Иван Потапыч; а он, если сказать по правде, в несколько раз умнее меня.', '100.jpg', 52, '2025-04-05 08:08:23'),
(1174, '— Афанасий Васильевич.', '— Афанасий Васильевич! вашу власть и я готов над собою признать, ваш слуга и что хотите: отдаюсь вам. Но не давайте работы свыше сил: я не Потапыч и говорю вам, что ни на что доброе не гожусь.', '.', '201.jpg', 1, '2025-04-02 04:40:56'),
(1175, '— Не я-с, Петр Петрович, наложу-с на вас, а так как вы хотели бы послужить.', '— Не я-с, Петр Петрович, наложу-с на вас, а так как вы хотели бы послужить, как говорите сами, так вот богоугодное дело. Строится в одном месте церковь доброхотным дательством благочестивых людей. Денег нестает, нужен сбор.', ' Наденьте простую сибирку… ведь вы теперь простой человек, разорившийся дворянин и тот же нищий: что ж тут чиниться? — да с книгой в руках, на простой тележке и отправляйтесь по городам и деревням. От архиерея вы получите благословенье и шнурованную книгу, да и с богом.', '002.jpg', 43, '2025-04-01 03:36:56'),
(1176, 'Петр Петрович был изумлен этой совершенно новой должностью.', 'Петр Петрович был изумлен этой совершенно новой должностью. Ему, все-таки дворянину некогда древнего рода, отправиться с книгой в руках просить на церковь, притом трястись на телеге! А между тем вывернуться и уклониться нельзя: дело богоугодное.', '.', '201.jpg', 54, '2025-03-24 02:37:52'),
(1177, '— Призадумались? — сказал Муразов.', '— Призадумались? — сказал Муразов. — Вы здесь две службы сослужите: одну службу богу, а другую — мне.', '.', '301.jpg', 33, '2025-03-23 02:30:44'),
(1178, '— А вот какую.', '— А вот какую. Так как вы отправитесь по тем местам, где я еще не был, так вы узнаете-с на месте все: как там живут мужички, где побогаче, где терпят нужду и в каком состоянье все.', ' Скажу вам, что мужичков люблю оттого, может быть, что я и сам из мужиков. Но дело в том, что завелось меж ними много всякой мерзости. Раскольники там и всякие-с бродяги смущают их, против властей их восстановляют, против властей и порядков, а если человек притеснен, так он легко восстает. Что ж, будто трудно подстрекнуть человека, который, точно, терпит. Да дело в том, что не снизу должна начинаться расправа. Уж тогда плохо, когда пойдут на кулаки: уж тут толку не будет — только ворам пожива. Вы человек умный, вы рассмотрите, узнаете, где действительно терпит человек от других, а где от собственного неспокойного нрава, да и расскажете мне потом все это. Я вам на всякий случай небольшую сумму дам на раздачу тем, которые уже и действительно терпят безвинно. С вашей стороны будет также полезно утешить их словом и получше истолковать им то, что бог велит переносить безропотно, и молиться в это время, когда несчастлив, а не буйствовать и расправляться самому. Словом, говорите им, никого не возбуждая ни против кого, а всех примиряя. Если увидите в ком противу кого бы то ни было ненависть, употребите все усилие.', '002.jpg', 47, '2025-03-14 20:11:12'),
(1179, '— Афанасий Васильевич.', '— Афанасий Васильевич! дело, которое вы мне поручаете, — сказал Хлобуев, — святое дело; но вы вспомните, кому вы его поручаете. Поручить его можно человеку почти святой жизни, который бы и сам уже умел прощать другим.', '.', '002.jpg', 41, '2025-03-04 17:08:25'),
(1180, '— Да я и не говорю, чтобы все это вы исполнили, а по возможности, что можно.', '— Да я и не говорю, чтобы все это вы исполнили, а по возможности, что можно. Дело-то в том, что вы все-таки приедете с познаньями тех мест, и будете иметь понятие, в каком положении находится тот край.', ' Чиновник никогда не столкнется с лицом, да и мужик-то с ним не будет откровенен. А бы, прося на церковь, заглянете ко всякому — и к мещанину и к купцу, и будете иметь случай расспросить всякого. Говорю-с вам это по той причине, что генерал-губернатор особенно теперь нуждается в таких людях; и вы, мимо всяких канцелярских повышений, получите такое место, где не бесполезна будет ваша жизнь.', '301.jpg', 43, '2025-02-28 12:16:08'),
(1181, '— Попробую, приложу старанья, сколько хватит сил, — сказал Хлобуев.', '— Попробую, приложу старанья, сколько хватит сил, — сказал Хлобуев. И в голосе его было заметно ободренье, спина распрямилась, и голова приподнялась, как у человека, которому светит надежда.', ' — Вижу, что вас бог наградил разуменьем, и вы знаете иное лучше нас, близоруких людей.', '201.jpg', 5, '2025-02-21 06:23:52'),
(1182, '— Теперь позвольте вас спросить, — сказал Муразов.', '— Теперь позвольте вас спросить, — сказал Муразов, — что ж Чичиков и какого роду дело.', '— Теперь позвольте вас спросить, — сказал Муразов, — что ж Чичиков и какого роду дело.', '301.jpg', 17, '2025-02-15 02:25:33'),
(1183, '— А про Чичикова я вам расскажу вещи неслыханные.', '— А про Чичикова я вам расскажу вещи неслыханные. Делает он такие дела… Знаете ли, Афанасий Васильевич, что завещание ведь ложное? Отыскалось настоящее, где все имение принадлежит воспитанницам.', '.', '002.jpg', 29, '2025-02-04 23:14:04'),
(1184, '— В том-то и дело, что премерзейшее дело.', '— В том-то и дело, что премерзейшее дело! Говорят, что Чичиков и что подписано завещание уже после смерти: нарядили какую-то бабу, наместо покойницы, и она уж подписала. Словом, дело соблазнительнейшее.', ' Говорят, тысячи просьб поступило с разных сторон. К Марье Еремеевне теперь подъезжают женихи; двое уж чиновных лиц из-за нее дерутся.', '302.jpg', 24, '2025-01-26 20:13:55'),
(1185, '— Не слышал я об этом ничего, а дело, точно, не без греха.', '— Не слышал я об этом ничего, а дело, точно, не без греха. Павел Иванович Чичиков, признаюсь, для меня презагадочен, — сказал Муразов.', '.', '102.jpg', 35, '2025-01-19 14:03:58'),
(1186, '— Я подал от себя также просьбу, затем, чтобы напомнить.', '— Я подал от себя также просьбу, затем, чтобы напомнить.', '— Я подал от себя также просьбу, затем, чтобы напомнить.', '201.jpg', 26, '2025-01-17 13:38:51'),
(1187, '«А мне пусть их все передерутся, — думал Хлобуев, выходя.', '«А мне пусть их все передерутся, — думал Хлобуев, выходя. — Афанасий Васильевич не глуп. Он дал мне это порученье, верно, обдумавши. Исполнить его — вот и все».', ' Он стал думать о дороге, в то время, когда Муразов все еще повторял в себе: «Презагадочный для меня человек Павел Иванович Чичиков! Ведь если бы с этакой волей и настойчивостью да на доброе дело.', '100.jpg', 18, '2025-01-09 08:54:30'),
(1188, 'А между тем, в самом деле, по судам шли просьбы за просьбой.', 'А между тем, в самом деле, по судам шли просьбы за просьбой. Оказались родственники, о которых и не слышал никто. Как птицы слетаются на мертвечину, так все налетело на несметное имущество, оставшееся после старухи.', ' Доносы на Чичикова, на подложность последнего завещания, доносы на подложность и первого завещания, улики в покраже и в утаении сумм. Явились улики на Чичикова в покупке мертвых душ, в провозе контрабанды во время бытности его еще при таможне. Выкопали все, разузнали его прежнюю историю. Бог весть откуда все это пронюхали и знали. Только были улики даже и в таких делах, об которых думал Чичиков, кроме его и четырех стен никто не знал. Покамест все это было еще судейская тайна и до ушей его не дошло, хотя верная записка юрисконсульта, которую он вскоре получил, несколько дала ему понять, что каша заварится. Записка была краткого содержания: «Спешу вас уведомить, что по делу будет возня: но помните, что тревожиться никак не следует. Главное дело — спокойствие. Обделаем все». Записка эта успокоила совершенно его. «Этот человек, точно, гений», — сказал Чичиков.', '201.jpg', 53, '2025-01-08 04:43:45'),
(1189, 'В довершение хорошего, портной в это время принес платье.', 'В довершение хорошего, портной в это время принес платье. Чичиков получил желанье сильное посмотреть па самого себя в новом фраке наваринского пламени с дымом. Натянул штаны, которые обхватили его чудесным образом со всех сторон, так что хоть рисуй.', ' Ляжки так славно обтянуло, икры тоже, сукно обхватило все малости, сообща им еще большую упругость. Как затянул он позади себя пряжку, живот стал точно барабан. Он ударил по нем тут щеткой, прибавив: «Ведь какой дурак, а в целом он составляет картину!» Фрак, казалось, был сшит еще лучше штанов: ни морщинки, все бока обтянул, выгнулся на перехвате, показавши весь его перегиб. Под правой мышкой немного жало, но от этого еще лучше прихватывало на талии. Портной, который стоял в полном торжестве, говорил только: «Будьте покойны, кроме Петербурга, нигде так не сошьют». Портной был сам из Петербурга и на вывеске выставил: «Иностранец из Лондона и Парижа». Шутить он не любил и двумя городами разом хотел заткнуть глотку всем другим портным, так, чтобы впредь никто не появился с такими городами, а пусть себе пишет из какого-нибудь «Карлсеру» или «Копенгара».', '203.jpg', 36, '2025-01-04 22:30:09'),
(1190, 'Чичиков великодушно расплатился с портным и, оставшись один.', 'Чичиков великодушно расплатился с портным и, оставшись один, стал рассматривать себя на досуге в зеркале, как артист с эстетическим чувством и con amore.', ' Оказалось, что все как-то было еще лучше, чем прежде: щечки интереснее, подбородок заманчивей, белые воротнички давали тон щеке, атласный синий галстук давал тон воротничкам; новомодные складки манишки давали тон галстуку, богатый бархатный жилет давал тон манишке, а фрак наваринского дыма с пламенем, блистая, как шелк, давал тон всему. Поворотился направо — хорошо! Поворотился налево — еще лучше! Перегиб такой, как у камергера или у такого господина, который так чешет по-французски, что перед ним сам француз ничего, который, даже и рассердись, не срамит себя непристойно русским словом, даже и выбраниться не умеет на русском языке, а распечет французским диалектом. Деликатность такая! Он попробовал, склоня голову несколько набок, принять позу, как бы адресовался к даме средних лет и последнего просвещения: выходила просто картина. Художник, бери кисть и пиши! В удовольствии, он совершил тут же легкий прыжок, вроде антраша. Вздрогнул комод и шлепнулась на землю склянка с одеколоном; но это не причинило никакого помешательства.', '203.jpg', 7, '2025-01-03 17:50:38'),
(1191, 'Как вдруг в передней — вроде некоторого бряканья сапогов с шпорами и жандарм в.', 'Как вдруг в передней — вроде некоторого бряканья сапогов с шпорами и жандарм в полном вооружении, как будто в лице его было целое войско. «Приказано сей же час явиться к генерал-губернатору!» Чичиков так и обомлел.', ' Перед ним торчало страшилище с усами, лошадиный хвост на голове, через плечо перевязь, через другое перевязь, огромнейший палаш привешен к боку. Ему показалось, что при другом боку висело и ружье, и черт знает что: целое войско в одном только! Он начал было возражать, страшило грубо заговорило: «Приказано сей же час!» Сквозь дверь в переднюю он увидел, что там мелькало и другое страшило, взглянул в окошко — и экипаж. Что тут делать? Так, как был, в фраке наваринского пламени с дымом, должен был сесть и, дрожа всем телом, отправился к генерал-губернатору, и жандарм с ним.', '301.jpg', 1, '2024-12-30 16:19:59'),
(1192, 'В передней не дали даже и опомниться ему.', 'В передней не дали даже и опомниться ему. «Ступайте! вас князь уже ждет», — сказал дежурный чиновник.', ' Перед ним, как в тумане, мелькнула передняя с курьерами, принимавшими пакеты, потом зала, через которую он прошел, думая только: «Вот как схватит, да без суда, без всего, прямо в Сибирь!» Сердце его забилось с такой силою, с какой не бьется даже у наиревнивейшего любовника. Наконец растворилась пред ним дверь: предстал кабинет, с портфелями, шкафами и книгами, и князь гневный, как сам гнев.', '302.jpg', 4, '2024-12-24 10:05:39'),
(1193, '— Губитель, губитель! — сказал Чичиков.', '— Губитель, губитель! — сказал Чичиков.', ' — Он мою душу погубит, зарежет, как волк агнца.', '101.jpg', 54, '2024-12-19 05:16:52'),
(1194, '— Я вас пощадил, я позволил вам остаться в городе.', '— Я вас пощадил, я позволил вам остаться в городе, тогда как вам следовало бы в острог; а вы запятнали себя вновь бесчестнейшим мошенничеством, каким когда-либо запятнал себя человек.', '.', '202.jpg', 25, '2024-12-09 04:26:16'),
(1195, '— Каким же, ваше сиятельство, бесчестнейшим поступком и мошенничеством.', '— Каким же, ваше сиятельство, бесчестнейшим поступком и мошенничеством? — спросил Чичиков, дрожа всем телом.', '.', '100.jpg', 42, '2024-12-02 03:13:44'),
(1196, '— Женщина, — произнес князь.', '— Женщина, — произнес князь, подступая несколько ближе и смотря прямо в глаза Чичикову, — женщина, которая подписывала по вашей диктовке завещание, схвачена и станет с вами на очную ставку.', '.', '203.jpg', 35, '2024-11-30 21:24:43'),
(1197, '— Ваше сиятельство! Скажу всю истину дела.', '— Ваше сиятельство! Скажу всю истину дела. Я виноват; точно, виноват; но не так виноват. Меня обнесли враги.', '.', '103.jpg', 10, '2024-11-23 20:33:40'),
(1198, '— Вас не может никто обнесть.', '— Вас не может никто обнесть, потому что в вас мерзостей в несколько раз больше того, что может выдумать последний лжец. Вы во всю свою жизнь, я думаю, не делали небесчестного дела.', ' Всякая копейка, добытая вами, добыта бесчестно, есть воровство и бесчестнейшее дело, за которое кнут и Сибирь! Нет, теперь полно! С сей же минуты будешь отведен в острог и там, наряду с последними мерзавцами и разбойниками, ты должен ждать разрешенья участи своей.', '002.jpg', 24, '2024-11-20 17:30:12'),
(1199, 'Он взглянул на фрак наваринского пламени с дымом и, взявшись за шнурок.', 'Он взглянул на фрак наваринского пламени с дымом и, взявшись за шнурок, позвонил.', '.', '301.jpg', 24, '2024-11-14 11:08:43'),
(1200, '— Ваше сиятельство, — вскрикнул Чичиков, — умилосердитесь! Вы отец семейства.', '— Ваше сиятельство, — вскрикнул Чичиков, — умилосердитесь! Вы отец семейства.', ' Не меня пощадите — старуха мать.', '202.jpg', 42, '2024-11-12 06:27:32'),
(1201, '— Врешь! — вскрикнул гневно князь.', '— Врешь! — вскрикнул гневно князь.', ' — Так же ты меня тогда умолял детьми и семейством, которых у тебя никогда не было, теперь — матерью.', '101.jpg', 49, '2024-11-06 01:51:01'),
(1202, '— Ваше сиятельство, я мерзавец и последний негодяй.', '— Ваше сиятельство, я мерзавец и последний негодяй, — сказал Чичиков голосом… — Я действительно лгал, я не имел ни детей, ни семейства, но, вот бог свидетель, я всегда хотел иметь жену, исполнить долг человека и гражданина.', '— Ваше сиятельство, я мерзавец и последний негодяй, — сказал Чичиков голосом… — Я действительно лгал, я не имел ни детей, ни семейства; но, вот бог свидетель, я всегда хотел иметь жену, исполнить долг человека и гражданина, чтобы действительно потом заслужить уваженье граждан и начальства… Но что за бедственные стечения обстоятельств! Кровью, ваше сиятельство, кровью нужно было добывать насущное существование. На всяком шагу соблазны и искушенье… враги, и губители, и похитители. Вся жизнь была — точно вихорь буйный или судно среди волн по воле ветров.', '002.jpg', 19, '2024-10-31 22:08:46');
INSERT INTO `articles` (`id`, `title`, `description`, `body`, `picture`, `hits`, `created_at`) VALUES
(1203, 'Слезы вдруг хлынули ручьями из глаз его.', 'Слезы вдруг хлынули ручьями из глаз его. Он повалился в ноги князю, так, как был, во фраке наваринского пламени с дымом, в бархатном жилете с атласным галстуком, новых штанах и причесанных волосах, изливавших чистый запах одеколона.', '.', '102.jpg', 35, '2024-10-24 20:41:02'),
(1204, '— Поди прочь от меня! Позвать, чтобы его взяли, солдат.', '— Поди прочь от меня! Позвать, чтобы его взяли, солдат! — сказал князь взошедшим.', '.', '100.jpg', 13, '2024-10-15 17:52:14'),
(1205, '— Подите прочь, говорю вам.', '— Подите прочь, говорю вам! — сказал он, усиливаясь вырвать свою ногу из объятья Чичикова.', '.', '002.jpg', 39, '2024-10-12 14:34:30'),
(1206, '— Ваше сиятельство! не сойду с места, покуда не получу милости.', '— Ваше сиятельство! не сойду с места, покуда не получу милости! — говорил Чичиков, не выпуская сапог князя и проехавшись, вместе с ногой, по полу в фраке наваринского пламени и дыма.', '.', '103.jpg', 38, '2024-10-10 08:21:16'),
(1207, '— Подите, говорю вам.', '— Подите, говорю вам! — говорил он с тем неизъяснимым чувством отвращенья, какое чувствует человек при виде безобразнейшего насекомого, которого нет духу раздавить ногой.', ' Он стряхнул так, что Чичиков почувствовал удар сапога в нос, губы и округленный подбородок, но не выпустил сапога и еще с большей силой держал ногу в своих объятьях. Два дюжих жандарма в силах оттащили его и, взявши под руки, повели через все комнаты.', '202.jpg', 41, '2024-10-07 02:07:11'),
(1208, 'В самых дверях на лестницу навстречу — Муразов. Луч надежды вдруг скользнул.', 'В самых дверях на лестницу навстречу — Муразов. Луч надежды вдруг скользнул. В один миг с силой неестественной вырвался он из рук обоих жандармов и бросился в ноги изумленному старику.', '.', '100.jpg', 11, '2024-10-01 00:15:28'),
(1209, 'Промозглый сырой чулан с запахом сапогов и онуч гарнизонных солдат.', 'Промозглый сырой чулан с запахом сапогов и онуч гарнизонных солдат, некрашеный стол, два скверных стула, с железною решеткой окно, дряхлая печь, сквозь щели которой шел дым и не давало тепла, — вот обиталище, где помещен был наш герой.', 'Промозглый сырой чулан с запахом сапогов и онуч гарнизонных солдат, некрашеный стол, два скверных стула, с железною решеткой окно, дряхлая печь, сквозь щели которой шел дым и не давало тепла, — вот обиталище, где помещен был наш герой, уже было начинавший вкушать сладость жизни и привлекать вниманье соотечественников в тонком новом фраке наваринского пламени и дыма. Не дали даже ему распорядиться взять с собой необходимые вещи, взять шкатулку, где были деньги. Бумаги, крепости на мертвые души — все было теперь у чиновников! Он повалился на землю, и плотоядный червь грусти страшной, безнадежной обвился около его сердца. С возрастающей быстротой стала точить она это сердце, ничем не защищенное. Еще день такой, день такой грусти, и не было бы Чичикова вовсе на свете. Но и над Чичиковым не дремствовала чья-то всеспасающая рука. Час спустя двери тюрьмы растворились: взошел старик Муразов.', '301.jpg', 11, '2024-09-26 19:04:58'),
(1210, 'Если бы терзаемому палящей жаждой влил кто в засохнувшее горло струю ключевой.', 'Если бы терзаемому палящей жаждой влил кто в засохнувшее горло струю ключевой воды, то он бы не оживился так, как оживился бедный Чичиков.', '.', '100.jpg', 17, '2024-09-22 16:14:13'),
(1211, '— Спаситель мой.', '— Спаситель мой! — сказал Чичиков и, схвативши вдруг его руку, быстро поцеловал и прижал к груди.', ' — Бог да наградит вас за то, что посетили несчастного.', '301.jpg', 24, '2024-09-20 11:42:03'),
(1212, '— Я подлец… Виноват… Я преступил… Но посудите, посудите.', '— Я подлец… Виноват… Я преступил… Но посудите, посудите, разве можно так поступать? Я — дворянин.', ' Без суда, без следствия, бросить в тюрьму, отобрать все от меня, вещи, шкатулка… там деньги, там все имущество, там все мое имущество, Афанасий Васильевич, — имущество.', '201.jpg', 21, '2024-09-13 05:39:01'),
(1213, 'И, не в силах будучи удерживать порыва вновь подступившей к сердцу грусти.', 'И, не в силах будучи удерживать порыва вновь подступившей к сердцу грусти, он громко зарыдал голосом, проникнувшим толщу стен острога и глухо отозвавшимся в отдаленье, сорвал с себя атласный галстук и, схвативши рукою около воротника.', 'И, не в силах будучи удерживать порыва вновь подступившей к сердцу грусти, он громко зарыдал голосом, проникнувшим толщу стен острога и глухо отозвавшимся в отдаленье, сорвал с себя атласный галстук и, схвативши рукою около воротника, разорвал на себе фрак наваринского пламени с дымом.', '102.jpg', 59, '2024-09-08 05:37:10'),
(1214, '— Павел Иванович, все равно, и с имуществом, и со всем, что ни есть на свете.', '— Павел Иванович, все равно: и с имуществом, и со всем, что ни есть на свете, вы должны проститься. Вы подпали под неумолимый закон, а не под власть какого человека.', '.', '102.jpg', 19, '2024-09-02 02:08:37'),
(1215, '— Сам погубил себя, сам знаю — не умел вовремя остановиться.', '— Сам погубил себя, сам знаю — не умел вовремя остановиться. Но за что же такая страшная кара, Афанасий Васильевич? Я разве разбойник? От меня разве пострадал кто-нибудь? Разве я сделал кого несчастным? Трудом и потом, кровавым потом добывал копейку.', ' Зачем добывал копейку? Затем, чтобы в довольстве прожить остаток дней, оставить что-нибудь детям, которых намеревался приобрести для блага, для службы отечеству. Покривил, не спорю, покривил… что ж делать? Но ведь покривил, увидя, что прямой дорогой не возьмешь и что косой дорогой больше напрямик. Но ведь я трудился, я изощрялся. А эти мерзавцы, которые по судам берут тысячи с казны иль небогатых людей грабят, последнюю копейку сдирают с того, у кого нет ничего!.. Афанасий Васильевич! Я не блудничал, я не пьянствовал. Да ведь сколько трудов, сколько железного терпенья! Да я, можно сказать, выкупил всякую добытую копейку страданьями, страданьями! Пусть их кто-нибудь выстрадает то, что я! Ведь что вся жизнь моя: лютая борьба, судно среди волн.', '002.jpg', 1, '2024-08-25 23:44:50'),
(1216, 'Он не договорил и зарыдал громко от нестерпимой боли сердца, упал на стул.', 'Он не договорил и зарыдал громко от нестерпимой боли сердца, упал на стул, и оторвал совсем висевшую разорванную полу фрака, и швырнул ее прочь от себя, и, запустивши обе руки себе в волосы, об укрепление которых прежде старался, безжалостно рвал их.', 'Он не договорил и зарыдал громко от нестерпимой боли сердца, упал на стул, и оторвал совсем висевшую разорванную полу фрака, и швырнул ее прочь от себя, и, запустивши обе руки себе в волосы, об укрепление которых прежде старался, безжалостно рвал их, услаждаясь болью, которою хотел заглушить ничем не угасимую боль сердца.', '301.jpg', 33, '2024-08-23 20:27:21'),
(1217, '— Ах, Павел Иванович, Павел Иванович.', '— Ах, Павел Иванович, Павел Иванович! — говорил Муразов, скорбно смотря на него и качая головой.', ' — Я все думаю о том, какой бы из вас был человек, если бы так же, и силою и терпеньем, да подвизались бы на добрый труд и для лучшей цели! Если бы хоть кто-нибудь из тех людей, которые любят добро, да употребили бы столько усилий для него, как вы для добыванья своей копейки!., да умели бы так пожертвовать для добра и собственным самолюбием, и честолюбием, не жалея себя, как вы не жалели для добыванья своей копейки!..', '102.jpg', 49, '2024-08-21 14:16:37'),
(1218, '— Афанасий Васильевич.', '— Афанасий Васильевич! — сказал бедный Чичиков и схватил его обеими руками за руки.', ' — О, если бы удалось мне освободиться, возвратить мое имущество! клянусь вам, повел бы отныне совсем другую жизнь! Спасите, благодетель, спасите.', '203.jpg', 30, '2024-08-20 12:53:47'),
(1219, '— Что ж могу я сделать? Я должен воевать с законом.', '— Что ж могу я сделать? Я должен воевать с законом. Положим, если бы я даже и решился на это, но ведь князь справедлив, — он ни за что не отступит.', '.', '100.jpg', 12, '2024-08-18 06:29:55'),
(1220, '— Благодетель! вы все можете сделать.', '— Благодетель! вы все можете сделать.', ' Не закон меня страшит, — я перед законом найду средства, — но то, что неповинно я брошен в тюрьму, что я пропаду здесь, как собака, и что мое имущество, бумаги, шкатулка… спасите.', '201.jpg', 56, '2024-08-17 02:59:41'),
(1221, '— Ах, Павел Иванович, Павел Иванович! — говорил старик Муразов, качая головою.', '— Ах, Павел Иванович, Павел Иванович! — говорил старик Муразов, качая головою.', ' — Как вас ослепило это имущество! Из-за него вы и бедной души своей не слышите.', '301.jpg', 12, '2024-08-13 00:20:33'),
(1222, '— Павел Иванович! — сказал старик Муразов и остановился.', '— Павел Иванович! — сказал старик Муразов и остановился. — Спасти вас не в моей власти, — вы сами видите. Но приложу старанье, какое могу, чтобы облегчить вашу участь и освободить. Не знаю, удастся ли это сделать, но буду стараться.', ' Если же, паче чаянья, удастся, Павел Иванович, — я попрошу у вас награды за труды: бросьте все эти поползновенья на эти приобретения. Говорю вам по чести, что, если бы я и всего лишился моего имущества, — а у меня его больше, чем у вас, — я бы не заплакал. Ей-ей, дело не в этом имуществе, которое могут у меня конфисковать, а в том, которого никто не может украсть и отнять! Вы уж пожили на свете довольно. Вы сами называете жизнь свою судном среди волн. У вас есть уже чем прожить остаток дней. Поселитесь себе в тихом уголке, поближе к церкви и простым, добрым людям; или, если знобит сильное желанье оставить по себе потомков, женитесь на небогатой доброй девушке, привыкшей к умеренности и простому хозяйству. Забудьте этот шумный мир и все его обольстительные-прихоти; пусть и он вас позабудет. В нем нет успокоенья. Вы видите: все в нем враг, искуситель или предатель.', '101.jpg', 18, '2024-08-05 20:13:11'),
(1223, 'Чичиков задумался.', 'Чичиков задумался.', ' Что-то странное, какие-то неведомые дотоле, незнаемые чувства, ему необъяснимые, пришли к нему: как будто хотело в нем что-то пробудиться, что-то подавленное из детства суровым, мертвым поученьем, бесприветностыо скучного детства, пустынностью родного жилища, бессемейным одиночеством, нищетой и бедностью первоначальных впечатлений, суровым взглядом судьбы, взглянувшей на него скучно, сквозь какое-то мутно занесенное зимней вьюгой окно.', '103.jpg', 0, '2024-08-03 17:53:51'),
(1224, '— Спасите только, Афанасий Васильевич.', '— Спасите только, Афанасий Васильевич! — вскричал он, — поведу другую жизнь, последую вашему совету! Вот вам мое слово.', '— Спасите только, Афанасий Васильевич! — вскричал он, — поведу другую жизнь, последую вашему совету! Вот вам мое слово.', '002.jpg', 47, '2024-07-24 16:55:31'),
(1225, '— Смотрите же, Павел Иванович, от слова не отступитесь.', '— Смотрите же, Павел Иванович, от слова не отступитесь. — сказал Муразов, держа его руку.', '.', '002.jpg', 44, '2024-07-14 13:13:40'),
(1226, '— Отступился бы, может быть, если бы не такой страшный урок, — сказал.', '— Отступился бы, может быть, если бы не такой страшный урок, — сказал, вздохнувши, бедный Чичиков и прибавил: — Но урок тяжел; тяжел, тяжел урок, Афанасий Васильевич.', '— Отступился бы, может быть, если бы не такой страшный урок, — сказал, вздохнувши, бедный Чичиков и прибавил: — Но урок тяжел; тяжел, тяжел урок, Афанасий Васильевич.', '202.jpg', 43, '2024-07-12 12:40:30'),
(1227, '— Хорошо, что тяжел. Благодарите за это бога, помолитесь.', '— Хорошо, что тяжел. Благодарите за это бога, помолитесь. Я пойду о вас стараться.', '.', '203.jpg', 51, '2024-07-10 07:09:02'),
(1228, '— Нет! полно! — сказал он наконец, — другую, другую жизнь.', '— Нет! полно! — сказал он наконец, — другую, другую жизнь. Пора в самом деле сделаться порядочным. О, если бы мне как-нибудь только выпутаться и уехать хоть с небольшим капиталом, поселюсь вдали от… А купчие?..', ' — Он подумал: «Что ж? зачем оставить это дело, стольким трудом приобретенное?.. Больше не стану покупать, но заложить те нужно. Ведь приобретенье это стоило трудов! Это я заложу, заложу, с тем чтобы купить па деньги поместье. Сделаюсь помещиком, потому что тут можно сделать много хорошего». И в мыслях его пробудились те чувства, которые овладели им, когда он был у Костанжогло, и милая, при греющем свете вечернем, умная беседа хозяина о том, как плодотворно и полезно занятье поместьем. Деревня так вдруг представилась ему прекрасно, точно как бы он в силах был почувствовать все перелести деревни.', '203.jpg', 51, '2024-07-07 02:23:46'),
(1229, '— Глупы мы, за суетой гоняемся! — сказал он наконец.', '— Глупы мы, за суетой гоняемся! — сказал он наконец. — Право, от безделья! Все близко, все под рукой, а мы бежим за тридевять земель. Чем не жизнь, если займешься хоть бы и в глуши? Ведь удовольствие действительно в труде.', ' И ничего нет слаще, как плод собственных трудов… Нет, займусь трудом, поселюсь в деревне, и займусь честно, так, чтобы иметь доброе влиянье и на других. Что ж в самом деле, будто я уже совсем негодный? У меня есть способности к хозяйству: я имею качества и бережливости, и расторопности, и благоразумия, даже постоянства. Стоит только решиться, чувствую, что есть. Теперь только истинно и ясно чувствую, что есть какой-то долг, который нужно исполнять человеку на земле, не отрываясь от того места и угла, на котором он постановлен.', '002.jpg', 11, '2024-06-26 20:45:27'),
(1230, 'И трудолюбивая жизнь, удаленная от шума городов и тех обольщений.', 'И трудолюбивая жизнь, удаленная от шума городов и тех обольщений, которые от праздности выдумал, позабывши труд, человек, так сильно стала перед ним рисоваться, что он уже почти позабыл всю неприятность своего положения и, может быть.', 'И трудолюбивая жизнь, удаленная от шума городов и тех обольщений, которые от праздности выдумал, позабывши труд, человек, так сильно стала перед ним рисоваться, что он уже почти позабыл всю неприятность своего положения и, может быть, готов был даже возблагодарить провиденье за этот тяжелый урок, если только выпустят его и отдадут хотя часть. Но… одностворчатая дверь его нечистого чулана растворилась, вошла чиновная особа — Самосвистов, эпикуреец, собой лихач, отличный товарищ, кутила и продувная бестия, как выражались о нем сами товарищи. В военное время человек этот наделал бы чудес: его бы послать куда-нибудь пробраться сквозь непроходимые, опасные места, украсть перед носом у самого неприятеля пушку, — это его бы дело. Но, за неимением военного поприща, на котором бы, может быть, он был честным человеком, он пакостил и гадил.', '100.jpg', 24, '2024-06-16 14:25:13'),
(1231, '— Знаем все об вашем положении, все услышали.', '— Знаем все об вашем положении, все услышали! — сказал он, когда увидел, что дверь за ним плотно затворилась. — Ничего, ничего! Не робейте: все будет поправлено. Все станет работать за вас и — ваши слуги! Тридцать тысяч на всех — и ничего больше.', '.', '102.jpg', 7, '2024-06-07 13:30:21'),
(1232, '— Тридцать тысяч.', '— Тридцать тысяч. Тут уже все вместе — и нашим, и генерал-губернаторским, и секретарю.', '.', '100.jpg', 47, '2024-06-04 07:19:43'),
(1233, '— Но позвольте, как же я могу.', '— Но позвольте, как же я могу.', '— Но позвольте, как же я могу.', '201.jpg', 2, '2024-06-02 05:46:00'),
(1234, '— Пока прощайте.', '— Пока прощайте! Поручил вам сказать наш общий приятель, что главное дело — спокойствие и присутствие духа.', '.', '103.jpg', 22, '2024-05-25 05:27:10'),
(1235, 'Самосвистов скрылся.', 'Самосвистов скрылся. Чичиков, оставшись, все еще не доверял словам, как не прошло часа после этого разговора, как была принесена шкатулка: бумаги, деньги — и всё в наилучшем порядке.', ' Самосвистов явился в качестве распорядителя: выбранил поставленных часовых за то, что небдительно смотрели, приказал приставить еще лишних солдат для усиленья присмотра, взял не только шкатулку, но отобрал даже все такие бумаги, которые могли бы чем-нибудь компрометировать Чичикова; связал все это вместе, запечатал и повелел самому солдату отнести немедленно к самому Чичикову, в виде необходимых ночных и спальных вещей, так что Чичиков, вместе с бумагами, получил даже и все теплое, что нужно было для покрытия бренного его тела. Это скорое доставление обрадовало его несказанно. Он возымел сильную надежду, и уже начали ему вновь грезиться кое-какие приманки: вечером театр, плясунья, за которою он волочился.', '302.jpg', 11, '2024-05-17 02:05:27'),
(1236, 'А между тем завязалось дело размера беспредельного в судах и палатах.', 'А между тем завязалось дело размера беспредельного в судах и палатах. Работали перья писцов, и, понюхивая табак, трудились казусные головы, любуясь, как художники, крючковатой строкой.', ' Юрисконсульт, как скрытый маг, незримо ворочал всем механизмом; всех опутал решительно, прежде чем кто успел осмотреться. Путаница увеличилась. Самосвистов превзошел самого себя отважностью и дерзостью неслыханною.', '201.jpg', 43, '2024-05-09 22:22:40'),
(1237, 'И, уехав домой, ни минуты не медля.', 'И, уехав домой, ни минуты не медля, чтобы не замешивать никого и все концы в воду, сам нарядился жандармом, оказался в усах и бакенбардах — сам черт бы не узнал.', ' Явился в доме, где был Чичиков, и, схвативши первую бабу, какая попалась, сдал ее двум чиновным молодцам, докам тоже, а сам прямо явился, в усах и с ружьем, как следует, к часовым.', '101.jpg', 21, '2024-05-08 18:23:37'),
(1238, '— Ступай, меня прислал командир выстоять, наместо тебя, смену.', '— Ступай, меня прислал командир выстоять, наместо тебя, смену. — Обменился с часовым и стал сам с ружьем.', '.', '002.jpg', 6, '2024-05-07 15:55:36'),
(1239, 'Только этого было и нужно.', 'Только этого было и нужно. В это время наместо прежней бабы очутилась другая, ничего не знавшая и не понимавшая. Прежнюю запрятали куды-то так, что и потом не узнали, куда она делась.', ' В то время, когда Самосвистов подвизался в лице воина, юрисконсульт произвел чудеса на гражданском поприще: губернатору дал знать стороною, что прокурор на него пишет донос; жандармскому чиновнику дал знать, что секретно проживающий чиновник пишет на него доносы; секретно проживавшего чиновника уверил, что есть еще секретнейший чиновник, который на него доносит, — и всех привел в такое положение, что к нему должны были обратиться за советами. Произошла такая бестолковщина: донос сел верхом на доносе, и пошли открываться такие дела, которых и солнце не видало, и даже такие, которых и не было. Все пошло в работу и в дело: и кто незаконнорожденный сын, и какого рода и званья у кого любовница, и чья жена за кем волочится. Скандалы, соблазны и все так замешалось и сплелось вместе с историей Чичикова, с мертвыми душами, что никоим образом нельзя было понять, которое из этих дел было главнейшая чепуха: оба казались равного достоинства. Когда стали наконец поступать бумаги к генерал-губернатору, бедный князь ничего не мог понять. Весьма умный и расторопный чиновник, которому поручено было сделать экстракт, чуть не сошел с ума: никаким образом нельзя было поймать нити дела. Князь был в это время озабочен множеством других дел, одно другого неприятнейших. В одной части губернии оказался голод. Чиновники, посланные раздать хлеб, как-то не так распорядились, как следовало. В другой части губернии расшевелились раскольники. Кто-то пропустил между ними, что народился антихрист, который и мертвым не дает покоя, скупая какие-то мертвые души. Каялись и грешили и, под видом изловить антихриста, укокошили неантихристов. В другом месте мужики взбунтовались против помещиков и капитан-исправников. Какие-то бродяги пропустили между ними слухи, что наступает такое время, что мужики должны быть помещики и нарядиться во фраки, а помещики нарядятся в армяки и будут мужики, — и целая волость, не размысля того, что слишком много выйдет тогда помещиков и капитан-исправников, отказалась платить всякую подать.', '100.jpg', 42, '2024-05-01 13:04:21'),
(1240, '— Вот вам Чичиков! Вы стояли за него и защищали.', '— Вот вам Чичиков! Вы стояли за него и защищали. Теперь он попался в таком деле, на какое последний вор не решится.', '.', '201.jpg', 25, '2024-04-26 10:15:05'),
(1241, '— Ваше сиятельство, скажу не с тем, чтобы защищать Чичикова.', '— Ваше сиятельство, скажу не с тем, чтобы защищать Чичикова. Но ведь это дело не доказанное: следствие еще не сделано.', '.', '102.jpg', 19, '2024-04-24 08:31:07'),
(1242, '— Улика: женщина, которая была наряжена наместо умершей, схвачена.', '— Улика: женщина, которая была наряжена наместо умершей, схвачена. Я ее хочу расспросить нарочно при вас. — Князь позвонил и дал приказ позвать ту женщину.', '.', '201.jpg', 32, '2024-04-22 04:15:11'),
(1243, '— Бесчестнейшее дело.', '— Бесчестнейшее дело! И, к стыду, замешались первые чиновники города, сам губернатор. Он не должен быть там, где воры и бездельники! — сказал князь с жаром.', '.', '102.jpg', 56, '2024-04-19 22:45:40'),
(1244, '— Ведь губернатор — наследник, он имеет право на притязания.', '— Ведь губернатор — наследник: он имеет право на притязания; а что другие-то со всех сторон прицепились так это-с, ваше сиятельство, человеческое дело.', ' Умерла-с богатая, распоряженья умного и справедливого не сделала.', '101.jpg', 31, '2024-04-16 16:48:18'),
(1245, '— Но ведь мерзости зачем же делать?..', '— Но ведь мерзости зачем же делать?.. Подлецы! — сказал князь с чувством негодованья.', ' — Ни одного чиновника нет у меня хорошего: все — мерзавцы.', '302.jpg', 56, '2024-04-14 14:52:40'),
(1246, '— Ваше сиятельство! да кто ж из нас, как следует, хорош.', '— Ваше сиятельство! да кто ж из нас, как следует, хорош? Все чиновники нашего города — люди, имеют достоинства и многие очень знающие в деле, а от греха всяк близок.', '.', '101.jpg', 47, '2024-04-08 10:07:16'),
(1247, '— Послушайте, Афанасий Васильевич, скажите мне.', '— Послушайте, Афанасий Васильевич, скажите мне, я вас одного знаю за честного человека, что у вас за страсть защищать всякого рода мерзавцев.', '— Послушайте, Афанасий Васильевич, скажите мне, я вас одного знаю за честного человека, что у вас за страсть защищать всякого рода мерзавцев.', '100.jpg', 31, '2024-04-05 05:47:33'),
(1248, '— Ваше сиятельство, — сказал Муразов, — кто бы ни был человек.', '— Ваше сиятельство, — сказал Муразов, — кто бы ни был человек, которого вы называете мерзавцем, но ведь он человек.', ' Как же не защищать человека, когда знаешь, что он половину зол делает от грубости и неведенья? Ведь мы делаем несправедливости на всяком шагу и всякую минуту бываем причиной несчастья другого, даже и не с дурным намереньем. Ведь ваше сиятельство сделали также большую несправедливость.', '301.jpg', 9, '2024-03-28 02:21:44'),
(1249, '— Как.', '— Как! — воскликнул в изумлении князь, совершенно пораженный таким нежданным оборотом речи.', '.', '302.jpg', 54, '2024-03-17 20:20:20'),
(1250, '— Афанасий Васильевич.', '— Афанасий Васильевич! Преступление против коренных государственных законов, равное измене земле своей.', '— Афанасий Васильевич! Преступление против коренных государственных законов, равное измене земле своей.', '103.jpg', 22, '2024-03-10 17:20:06'),
(1251, '— Я не оправдываю его.', '— Я не оправдываю его.', ' Но справедливо ли то, если юношу, который по неопытности своей был обольщен и сманен другими, осудить так, как и того, который был один из зачинщиков? Ведь участь постигла ровная и Дерпенникова, и какого-нибудь Вороного-Дрянного; а ведь преступленья их не равны.', '301.jpg', 8, '2024-03-07 14:03:04'),
(1252, '— Ради бога… — сказал князь с заметным волненьем.', '— Ради бога… — сказал князь с заметным волненьем, — вы что-нибудь знаете об этом? скажите. Я именно недавно послал еще прямо в Петербург об смягчении его участи.', '.', '100.jpg', 40, '2024-03-05 12:52:35'),
(1253, '— Нет, ваше сиятельство, я не насчет того говорю, чтобы я знал что-нибудь такое.', '— Нет, ваше сиятельство, я не насчет того говорю, чтобы я знал что-нибудь такое, чего вы не знаете. Хотя, точно, есть одно такое обстоятельство, которое бы послужило в его пользу, да он сам не согласится, потому что через это пострадал бы другой.', ' А я думаю только то, что не изволили ли вы тогда слишком поспешить. Извините, ваше сиятельство, я сужу по своему слабому разуму. Вы несколько раз приказывали мне откровенно говорить. У меня-с, когда я еще был начальником, много было всяких работников, и дурных и хороших… Следовало бы тоже принять во внимание и прежнюю жизнь человека, потому что, если не рассмотришь все хладнокровно, а накричишь с первого раза, — запугаешь только его, да и признанья настоящего не добьешься: а как с участием его расспросишь, как брат брата, — сам все выскажет и даже не просит о смягчении, и ожесточенья ни против кого нет, потому что ясно видит, что не я его наказываю, а закон.', '100.jpg', 28, '2024-03-02 08:35:25'),
(1254, '— Вас может только наградить один бог за такую службу, Афанасий Васильевич.', '— Вас может только наградить один бог за такую службу, Афанасий Васильевич. А я вам не скажу ни одного слова, потому что, — вы сами можете чувствовать, — всякое слово тут бессильно. Но позвольте мне одно сказать насчет той просьбы.', ' Скажите сами: имею ли я право оставить это дело без внимания и справедливо ли, честно ли с моей стороны будет простить мерзавцев.', '002.jpg', 24, '2025-10-31 04:04:39'),
(1255, '— Ваше сиятельство, ей-богу, этак нельзя называть.', '— Ваше сиятельство, ей-богу, этак нельзя называть, тем более что из них есть многие весьма достойные. Затруднительны положенья человека, ваше сиятельство, очень, очень затруднительны.', ' Бывает так, что, кажется, кругом виноват человек; а как войдешь — даже и не он.', '002.jpg', 36, '2025-10-23 21:45:41'),
(1256, '— Но что скажут они сами, если оставлю.', '— Но что скажут они сами, если оставлю? Ведь есть из них, которые после этого еще больше подымут нос и будут даже говорить, что они напугали.', ' Они первые будут не.', '301.jpg', 11, '2025-10-15 16:05:24'),
(1257, '— Ваше сиятельство, позвольте мне вам дать свое мнение, соберите их всех.', '— Ваше сиятельство, позвольте мне вам дать свое мнение, соберите их всех, дайте им знать, что вам все известно, и представьте им ваше собственное положение точно таким самым образом, как вы его изволили изобразить сейчас передо мной.', '— Ваше сиятельство, позвольте мне вам дать свое мнение: соберите их всех, дайте им знать, что вам все известно, и представьте им ваше собственное положение точно таким самым образом, как вы его изволили изобразить сейчас передо мной, и спросите у них совета: что бы из них каждый сделал на вашем положении.', '203.jpg', 40, '2025-10-12 11:20:15'),
(1258, '— Да вы думаете, им будут доступны движенья благороднейшие.', '— Да вы думаете, им будут доступны движенья благороднейшие, чем каверзничать и наживаться? Поверьте, они надо мной посмеются.', '.', '101.jpg', 58, '2025-10-06 08:22:09'),
(1259, '— Не думаю-с, ваше сиятельство.', '— Не думаю-с, ваше сиятельство. У русского человека, даже и у того, кто похуже других, все-таки чувство справедливо. Разве жид какой-нибудь, а не русский. Нет, ваше сиятельство, вам нечего скрываться. Скажите так точно, как изволили перед мной.', ' Ведь они вас поносят, как человека честолюбивого, гордого, который и слышать ничего не хочет, уверен в себе, — так пусть же увидят всё, как оно есть. Что ж вам? Ведь ваше дело правое. Скажите им так, как бы вы не пред ними, а пред самим богом принесли свою исповедь.', '203.jpg', 6, '2025-10-01 08:08:35'),
(1260, '— Афанасий Васильевич, — сказал князь в раздумье, — я об этом подумаю.', '— Афанасий Васильевич, — сказал князь в раздумье, — я об этом подумаю, а покуда благодарю вас очень за совет.', '.', '301.jpg', 60, '2025-09-26 02:42:51'),
(1261, '— Скажите этому Чичикову, чтобы он убирался отсюда как можно поскорей.', '— Скажите этому Чичикову, чтобы он убирался отсюда как можно поскорей, и чем дальше, тем лучше. Его-то уже я бы никогда не простил.', '.', '100.jpg', 14, '2025-09-20 21:21:39'),
(1262, 'Муразов поклонился и прямо от князя отправился к Чичикову.', 'Муразов поклонился и прямо от князя отправился к Чичикову. Он нашел Чичикова уже в духе, весьма покойно занимавшегося довольно порядочным обедом, который был ему принесен в фаянсовых судках из какой-то весьма порядочной кухни.', ' По первым фразам разговора старик заметил тотчас, что Чичиков уже успел переговорить кое с кем из чиновников-казусников. Он даже понял, что сюда вмешалось невидимое участие знатока-юрисконсульта.', '203.jpg', 7, '2025-09-16 19:08:18'),
(1263, '— Послушайте-с, Павел Иванович, — сказал он.', '— Послушайте-с, Павел Иванович, — сказал он, — я привез вам свободу на таком условии, чтобы сейчас вас не было в городе. Собирайте все пожитки свои — да и с богом, не откладывая ни минуту, потому что дело еще хуже.', ' Я знаю-с, вас тут один человек настраивает; так объявляю вам по секрету, что такое еще дело одно открывается, что уж никакие силы не спасут этого. Он, конечно, рад других топить, чтобы нескучно, да дело к разделке. Я вас оставил в расположенье хорошем, — лучшем, нежели в каком теперь. Советую вам-с не в шутку. Ей-ей дело не в этом имуществе, из-за которого спорят и режут друг друга люди, точно как можно завести благоустройство в здешней жизни, не помысливши о другой жизни. Поверьте-с, Павел Иванович, что покамест, брося все то, из-за чего грызут и едят друг друга на земле, не подумают о благоустройстве душевного имущества, не установится благоустройство и земного имущества. Наступят времена голода и бедности как во всем народе, так и порознь во всяком… Это-с ясно. Что ни говорите, ведь от души зависит тело. Как же хотеть, чтобы шло как следует. Подумайте не о мертвых душах, а о своей живой душе, да и с богом на другую дорогу! Я тож выезжаю завтрашний день. Поторопитесь! не то без меня беда будет.', '302.jpg', 40, '2025-09-12 18:10:27'),
(1264, 'Значенье жизни опять показалось немаловажным «Муразов прав, — сказал он.', 'Значенье жизни опять показалось немаловажным «Муразов прав, — сказал он, — пора на другую дорогу!» Сказавши это, он вышел из тюрьмы. Часовой потащил за ним шкатулку, другой — чемодан белья.', ' Селифан и Петрушка обрадовались, как бог знает чему, освобожденью барина.', '301.jpg', 21, '2025-09-11 17:18:26'),
(1265, '— Ну, любезные, — сказал Чичиков, обратившись к ним милостиво.', '— Ну, любезные, — сказал Чичиков, обратившись к ним милостиво, — нужно укладываться да ехать.', '.', '301.jpg', 30, '2025-09-03 16:11:37'),
(1266, '— Покатим, Павел Иванович, — сказал Селифан.', '— Покатим, Павел Иванович, — сказал Селифан. — Дорога, должно быть, установилась: снегу выпало довольно. Пора уж, право, выбраться из города. Надоел он так, что и глядеть на него не хотел бы.', '.', '203.jpg', 47, '2025-08-31 11:35:51'),
(1267, '— Ступай к каретнику, чтобы поставил коляску на полозки, — сказал Чичиков.', '— Ступай к каретнику, чтобы поставил коляску на полозки, — сказал Чичиков, а сам пошел в город, но ни к кому не хотел заходить отдавать прощальных визитов.', ' После всего этого события было и неловко, — тем более что о нем множество ходило в городе самых неблагоприятных историй. Он избегал всяких встреч и зашел потихоньку только к тому купцу, у которого купил сукна наваринского пламени с дымом, взял вновь четыре аршина на фрак и на штаны и отправился сам к тому же портному. За двойную цену мастер решился усилить рвение и засадил всю ночь работать при свечах портное народонаселение — иглами, утюгами и зубами, и фрак на другой день был готов, хотя и немножко поздно. Лошади все были запряжены. Чичиков, однако ж, фрак примерил. Он был хорош, точь-точь как прежний. Но, увы! он заметил, что в голове уже белело что-то гладкое, и примолвил грустно: «И зачем было предаваться так сильно сокрушенью? А рвать волос не следовало бы и подавно». Расплатившись с портным, он выехал наконец из города в каком-то странном положении. Это был не прежний Чичиков. Это была какая-то развалина прежнего Чичикова. Можно было сравнить его внутреннее состояние души с разобранным строеньем, которое разобрано с тем, чтобы строить из него же новое; а новое еще не начиналось, потому что не пришел от архитектора определительный план и работники остались в недоуменье. Часом прежде его отправился старик Муразов, в рогоженной кибитке, вместе с Потапычем, а часом после отъезда Чичикова пошло приказание, что князь, по случаю отъезда в Петербург, желает видеть всех чиновников до едина.', '103.jpg', 6, '2025-08-29 11:02:22'),
(1268, 'В большом зале генерал-губернаторского дома собралось все чиновное сословие.', 'В большом зале генерал-губернаторского дома собралось все чиновное сословие города, начиная от губернатора до титулярного советника, правители канцелярий и дел, советники, асессоры, Кислоедов, Красноносов, Самосвистов, не бравшие, бравшие.', 'В большом зале генерал-губернаторского дома собралось все чиновное сословие города, начиная от губернатора до титулярного советника: правители канцелярий и дел, советники, асессоры, Кислоедов, Красноносов, Самосвистов, не бравшие, бравшие, кривившие душой, полукривившие и вовсе не кривившие, — все ожидало с некоторым не совсем спокойным ожиданием генеральского выхода. Князь вышел ни мрачный, ни ясный: взор его был тверд, так же как и шаг… Все чиновное собрание поклонилось, многие — в пояс.', '100.jpg', 21, '2025-08-23 10:57:28'),
(1269, '— Уезжая в Петербург.', '— Уезжая в Петербург, я почел приличным повидаться с вами всеми и даже объяснить вам отчасти причину. У нас завязалось дело очень соблазнительное. Я полагаю, что многие из предстоящих знают, о каком деле я говорю.', ' Дело это повело за собою открытие и других, не менее бесчестных дел, в которых замешались даже наконец и такие люди, которых я доселе почитал честными. Известна мне даже и сокровенная цель спутать таким образом все, чтобы оказалась полная невозможность решить формальным порядком. Знаю даже, и кто главная пружина и чьим сокровенным… хотя он и очень искусно скрыл свое участие. Но дело в том, что я намерен это следить не формальным следованьем по бумагам, а военным быстрым судом, как в военное время, и надеюсь, что государь мне даст это право, когда я изложу все это дело. В таком случае, когда нет возможности произвести дело гражданским образом, когда горят шкафы с бумагами и, наконец, излишеством лживых посторонних показаний и ложными доносами стараются затемнить и без того довольно темное дело, — я полагаю военный суд единственным средством и желаю знать мнение ваше.', '002.jpg', 38, '2025-08-16 10:10:17'),
(1270, 'Князь остановился, как бы ожидая ответа. Все стояло, потупив глаза в землю.', 'Князь остановился, как бы ожидая ответа. Все стояло, потупив глаза в землю. Многие были бледны.', '.', '202.jpg', 24, '2025-08-08 04:00:04'),
(1271, '— Известно мне также еще одно дело, хотя производившие его в полной уверенности.', '— Известно мне также еще одно дело, хотя производившие его в полной уверенности, что оно никому не может быть известно. Производство его уже пойдет не по бумагам, потому что истцом и челобитчиком я буду уже сам и представлю очевидные доказательства.', '.', '301.jpg', 35, '2025-08-04 03:03:37'),
(1272, 'Кто-то вздрогнул среди чиновного собрания.', 'Кто-то вздрогнул среди чиновного собрания; некоторые из боязливейших тоже смутились.', '.', '301.jpg', 24, '2025-08-02 21:27:33'),
(1273, '— Само по себе.', '— Само по себе, что главным зачинщикам должно последовать лишенье чинов и имущества, прочим — отрешенье от мест. Само собою разумеется, что в числе их пострадает и множество невинных. Что ж делать? Дело слишком бесчестное и вопиет о правосудии.', ' Хотя я знаю, что это будет даже и не в урок другим, потому что на место выгнанных явятся другие, и те самые, которые дотоле были честны, сделаются бесчестными, и те самые, которые удостоены будут доверенности, обманут и продадут, — несмотря на все это, я должен поступить жестоко, потому что вопиет правосудие. Знаю, что меня будут обвинять в суровой жестокости, но знаю, что те будут еще… меня те же обвинять… Я должен обратиться теперь только в одно бесчувственное орудие правосудия, в топор, который должен упасть на головы.', '103.jpg', 57, '2025-07-23 19:46:50'),
(1274, 'Содроганье невольно пробежало по всем лицам. Князь был спокоен.', 'Содроганье невольно пробежало по всем лицам. Князь был спокоен. Ни гнева, ни возмущенья душевного не выражало его лицо.', '.', '301.jpg', 52, '2025-07-20 14:13:39');
INSERT INTO `categories` (`id`, `title`, `description`, `created_at`) VALUES
(1, 'Когда экипаж въехал на двор, господин был встречен трактирным слугою.', 'Когда экипаж въехал на двор, господин был встречен трактирным слугою, или половым, как их называют в русских трактирах, живым и вертлявым до такой степени, что даже нельзя было рассмотреть, какое у него было лицо.', '2026-04-19 22:29:02'),
(2, 'Весь следующий день посвящен был визитам.', 'Весь следующий день посвящен был визитам; приезжий отправился делать визиты всем городским сановникам.', '2026-04-11 19:38:27'),
(3, 'На другой день Чичиков отправился на обед и вечер к полицеймейстеру.', 'На другой день Чичиков отправился на обед и вечер к полицеймейстеру, где с трех часов после обеда засели в вист и играли до двух часов ночи.', '2026-04-05 18:46:16'),
(4, 'На вопрос, далеко ли деревня Заманиловка, мужики сняли шляпы, и один из них.', 'На вопрос, далеко ли деревня Заманиловка, мужики сняли шляпы, и один из них, бывший поумнее и носивший бороду клином, отвечал.', '2026-04-01 14:26:35'),
(5, 'Ко дню рождения приготовляемы были сюрпризы.', 'Ко дню рождения приготовляемы были сюрпризы: какой-нибудь бисерный чехольчик на зубочистку.', '2026-03-25 10:12:36'),
(6, 'В столовой уже стояли два мальчика, сыновья Манилова, которые были в тех летах.', 'В столовой уже стояли два мальчика, сыновья Манилова, которые были в тех летах, когда сажают уже детей за стол, но еще на высоких стульях. При них стоял учитель, поклонившийся вежливо и с улыбкою.', '2026-03-18 09:22:37'),
(7, 'В ответ на это Чичиков свернул три блина вместе и.', 'В ответ на это Чичиков свернул три блина вместе и, обмакнувши их в растопленное масло, отправил в рот, а губы и руки вытер салфеткой. Повторивши это раза три, он попросил хозяйку приказать заложить его бричку.', '2026-03-12 08:37:33'),
(8, 'Порфирий положил щенка на пол, который, растянувшись на все четыре лапы.', 'Порфирий положил щенка на пол, который, растянувшись на все четыре лапы, нюхал землю.', '2026-03-03 03:55:03'),
(9, 'Когда Ноздрев это говорил, Порфирий принес бутылку.', 'Когда Ноздрев это говорил, Порфирий принес бутылку. Но Чичиков отказался решительно как играть, так и пить.', '2026-02-25 23:33:47'),
(10, '— Отчего ж по три? Это по ошибке.', '— Отчего ж по три? Это по ошибке. Одна подвинулась нечаянно, я ее отодвину, изволь.', '2026-02-18 21:37:48'),
(11, '— Бейте его.', '— Бейте его! — кричал Ноздрев, порываясь вперед с черешневым чубуком, весь в жару, в поту, как будто подступал под неприступную крепость.', '2026-02-13 21:10:32'),
(12, 'На такую сумятицу успели, однако ж, собраться мужики из деревни, которая была.', 'На такую сумятицу успели, однако ж, собраться мужики из деревни, которая была, к счастию, неподалеку.', '2026-02-09 17:01:23'),
(13, 'Чичиков подошел к ручке Феодулии Ивановны.', 'Чичиков подошел к ручке Феодулии Ивановны, которую она почти впихнула ему в губы, причем он имел случай заметить, что руки были вымыты огуречным рассолом.', '2026-01-30 14:48:27'),
(14, 'Чичиков открыл рот, с тем чтобы заметить, что Михеева, однако же.', 'Чичиков открыл рот, с тем чтобы заметить, что Михеева, однако же, давно нет на свете, но Собакевич вошел, как говорится, в самую силу речи, откуда взялась рысь и дар слова.', '2026-01-22 09:16:48'),
(15, 'Последние слова он уже сказал.', 'Последние слова он уже сказал, обратившись к висевшим на стене портретам Багратиона и Колокотрони, как обыкновенно случается с разговаривающими, когда один из них вдруг, неизвестно почему, обратится не к тому лицу, к которому относятся слова.', '2026-01-17 06:07:57'),
(16, '— Вот посмотрите, батюшка, какая рожа.', '— Вот посмотрите, батюшка, какая рожа! — сказал Плюшкин Чичикову, указывая пальцем на лицо Прошки.', '2026-01-12 23:49:06'),
(17, '«Эхе, хе! двенадцать часов! — сказал наконец Чичиков, взглянув на часы.', '«Эхе, хе! двенадцать часов! — сказал наконец Чичиков, взглянув на часы. — Что ж я так закопался? Да еще пусть бы дело делал, а то ни с того ни с другого сначала загородил околесину, а потом задумался.', '2026-01-07 18:12:08'),
(18, 'Чичиков, вынув из кармана бумажку, положил ее перед Иваном Антоновичем.', 'Чичиков, вынув из кармана бумажку, положил ее перед Иваном Антоновичем, которую тот совершенно не заметил и накрыл тотчас ее книгою. Чичиков хотел было указать ему ее, но Иван Антонович движением головы дал знать, что не нужно показывать.', '2026-01-03 12:29:11'),
(19, 'Появление его на бале произвело необыкновенное действие.', 'Появление его на бале произвело необыкновенное действие.', '2025-12-27 07:35:31'),
(20, 'Он отвечал, что уже имел счастие нечаянным образом познакомиться.', 'Он отвечал, что уже имел счастие нечаянным образом познакомиться; попробовал еще кое-что прибавить, но кое-что совсем не вышло.', '2025-12-19 03:40:31'),
(21, 'Но прокурор и Чичиков, и сам губернатор пришли в такое замешательство.', 'Но прокурор и Чичиков, и сам губернатор пришли в такое замешательство, что не нашлись совершенно, что отвечать, а между тем Ноздрев, нимало не обращая внимания, нес полутрезвую речь.', '2025-12-13 00:35:21'),
(22, 'Гостья уже хотела было приступить к делу и сообщить новость.', 'Гостья уже хотела было приступить к делу и сообщить новость. Но восклицание, которое издала в это время дама приятная во всех отношениях, вдруг дало другое направление разговору.', '2025-12-04 00:23:41'),
(23, 'В то время, когда обе дамы так удачно и остроумно решили.', 'В то время, когда обе дамы так удачно и остроумно решили, такое запутанное обстоятельство, вошел в гостиную прокурор с вечно неподвижною своей физиономией, густыми бровями и моргавшим глазом.', '2025-11-29 00:13:35'),
(24, '— Только позволь, Иван Андреевич, — сказал вдруг, прервавши его, полицеймейстер.', '— Только позволь, Иван Андреевич, — сказал вдруг, прервавши его, полицеймейстер, — ведь капитан Копейкин ты сам сказал, без руки и ноги.', '2025-11-26 20:43:22'),
(25, '— Именье, за которое если бы он запросил и сорок тысяч, я б ему тут же отсчитал.', '— Именье, за которое если бы он запросил и сорок тысяч, я б ему тут же отсчитал.', '2025-11-18 19:20:23'),
(26, 'Здесь Костанжогло плюнул.', 'Здесь Костанжогло плюнул, и чуть-чуть не выговорил несколько неприличных и бранных слов в присутствии супруги. Суровая тень темной ипохондрии омрачила его живое лицо.', '2025-11-16 15:36:02'),
(27, '…что и для вас самих будет очень выгодно перевесть, например.', '…что и для вас самих будет очень выгодно перевесть, например, на мое имя всех умерших душ, какие по сказкам последней ревизии числятся в имениях ваших, так, чтобы я за них платил подати.', '2025-11-13 09:33:34'),
(28, 'Штука упала сверху, купец ее развернул еще с большим искусством.', 'Штука упала сверху, купец ее развернул еще с большим искусством, поймал другой конец и развернул точно шелковую материю, поднес ее Чичикову так, что тот имел возможность не только рассмотреть его, но даже понюхать, сказавши только.', '2025-11-12 05:19:40'),
(29, '— …хлебом в местах, где голод, я эту часть получше знаю чиновников.', '— …хлебом в местах, где голод; я эту часть получше знаю чиновников: рассмотрю самолично, что кому нужно. Да если позволите, ваше сиятельство, я поговорю и с раскольниками. Они-то с нашим братом, с простым человеком, охотнее разговорятся.', '2025-11-09 04:36:47');
